async def results_day(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text
    day = get_day(text)

    if is_locked(day):
        await update.message.reply_text(f"Ш§Щ„ЩҠЩҲЩ… {day} Щ…ЩӮЩҒЩ„ вң…\nЩ„ЩҒШӘШӯЩҮ Ш§ЩғШӘШЁ: /ЩҒШӘШӯ_ЩҠЩҲЩ… {day}")
        return

    if not os.path.exists(excel_file(day)):
        await update.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„ЩҒ Ш§Щ„ЩҠЩҲЩ… {day}. ШЈШ¶ЩҒ Ш§Щ„ШӘШҙЩғЩҠЩ„Ш§ШӘ ШЈЩҲЩ„ЩӢШ§.")
        return

    goals_count, clean_sheets = parse_results(text)
    goal_missing, clean_missing = validate_results_names(day, goals_count, clean_sheets)

    backup_files(f"before_results_day_{day}", files=[excel_file(day), LOCKED_FILE])
    file_name = calculate_points(day, goals_count, clean_sheets)

    goals_text = "\n".join([f"- {name}: {count} ЩҮШҜЩҒ = {GOAL_POINTS.get(count, count * 5)} ЩҶЩӮШ·Ш©" for name, count in goals_count.items()]) or "Щ„Ш§ ЩҠЩҲШ¬ШҜ"
    clean_text = "\n".join([f"- {name}" for name in clean_sheets]) or "Щ„Ш§ ЩҠЩҲШ¬ШҜ"

    rows = read_day_rows(day)
    max_score = max([r["total"] for r in rows], default=0)
    winners = [r["participant"] for r in rows if r["total"] == max_score and max_score > 0]
    legends_text = "ШҢ ".join(winners) if winners else "Щ„Ш§ ЩҠЩҲШ¬ШҜ"

    warnings = []
    if goal_missing:
        warnings.append("вҡ пёҸ ЩҮШҜШ§ЩҒЩҲЩҶ ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜЩҠЩҶ ЩҒЩҠ ШӘШҙЩғЩҠЩ„Ш§ШӘ Ш§Щ„ЩҠЩҲЩ…:\n" + "\n".join(goal_missing))
    if clean_missing:
        warnings.append("вҡ пёҸ ШӯШұШ§Ші ЩғЩ„ЩҠЩҶ ШҙЩҠШӘ ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜЩҠЩҶ ЩҒЩҠ ШӘШҙЩғЩҠЩ„Ш§ШӘ Ш§Щ„ЩҠЩҲЩ…:\n" + "\n".join(clean_missing))

    caption = (
        f"ШӘЩ… ШӯШіШ§ШЁ ЩҶЩӮШ§Ш· Ш§Щ„ЩҠЩҲЩ… {day} вң…\n\n"
        f"Ш§Щ„ШЈЩҮШҜШ§ЩҒ:\n{goals_text}\n\n"
        f"Ш§Щ„ЩғЩ„ЩҠЩҶ ШҙЩҠШӘ:\n{clean_text}\n\n"
        f"рҹҸҶ ШЈШіШ·ЩҲШұШ© Ш§Щ„ЩҠЩҲЩ…: {legends_text} вҖ” {max_score} ЩҶЩӮШ·Ш©"
    )
    if warnings:
        caption += "\n\n" + "\n\n".join(warnings)

    with open(file_name, "rb") as file:
        await update.message.reply_document(document=file, filename=file_name, caption=caption)

    if load_settings().get("auto_images", True):
        try:
            path = create_daily_result_image(day, goals_count=goals_count, clean_sheets=clean_sheets)
            await send_photo_path(update, path, build_result_announcement(day, winners))
        except Exception as e:
            await update.message.reply_text(f"ШӘЩ… ШӯШіШ§ШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ШҢ Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШҘЩҶШҙШ§ШЎ Ш§Щ„ШөЩҲШұШ© Ш§Щ„ШӘЩ„ЩӮШ§ШҰЩҠШ© вқҢ\n{e}")



