    y = 545
    rounded_rect(draw, (80, y, 1320, y+58), radius=18, fill="#FFFFFF22", outline="#FFFFFF30", width=1)
    headers = [(1180, "Ш§Щ„Щ…ШҙШ§ШұЩғ"), (850, "Ш§Щ„ЩҶЩӮШ§Ш·"), (640, "Ш§Щ„ШӯШ§ШұШі"), (410, "Ш§Щ„ЩғШ§ШЁШӘЩҶ"), (170, "Ш§Щ„Щ…ШұЩғШІ")]
