    lines = ["рҹҸҶ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… рҹҸҶ", ""]
    for a,sa,sb,b in results:
        lines.append(f"{a} {sa} - {sb} {b}")
    lines.append("\nШ§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«")
