# ==================== V25 FIXTURES DESIGN OVERRIDE ====================
# ЩҮШ°Ш§ Ш§Щ„ЩӮШіЩ… ЩҠШӘШ№Щ…ШҜ ШӘШ№ШұЩҠЩҒ ШҜЩҲШ§Щ„ /Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ШұШ© ШЈШ®ЩҠШұШ© ЩӮШЁЩ„ Ш§Щ„ШӘШҙШәЩҠЩ„.
# Ш§Щ„ЩҮШҜЩҒ:
# - /Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06 = ЩҶЩҒШі ШӘШөЩ…ЩҠЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ШұШҰЩҠШіЩҠ (ШӘШөЩ…ЩҠЩ… 2)
# - Ш§Ш®ШӘЩҠШ§Шұ ЩҠЩҲЩ… Щ…ЩҶ Ш§Щ„ШЈШІШұШ§Шұ = ЩҠШёЩҮШұ ШІШұЩҠЩҶ ШӘШөЩ…ЩҠЩ… 1 ЩҲШӘШөЩ…ЩҠЩ… 2
# - ШӘШөЩ…ЩҠЩ… 1 = Щ…Ш¶ШәЩҲШ· ШЁШ®Щ„ЩҒЩҠШ© Ш§Щ„ШӘЩ…Ш«Ш§Щ„ ШЁШҜЩҲЩҶ Ш§Щ„ЩғЩ„Ш§Щ… Ш§Щ„ЩғШЁЩҠШұ ЩҒЩҲЩӮ
# - ШӘШөЩ…ЩҠЩ… 2 = Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„ШұШҰЩҠШіЩҠ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ V31 /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ…
# - /Щ…ШЁШ§ШұЩҠШ§ШӘ_Щ…Ш¬Щ…Ш№Ш© = ШӘШөЩ…ЩҠЩ… Щ…Ш¶ШәЩҲШ· Щ„Ш№ШҜШ© ШЈЩҠШ§Щ…
# - ШӯШ°ЩҒ ШӘЩғШұШ§Шұ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜШ§Ш®Щ„ ЩҶЩҒШі Ш§Щ„ЩҠЩҲЩ…

def _v25_safe_txt(x):
    return str(x or "").strip()


def _v25_dedupe_fixture_matches(matches):
    seen = set()
    out = []
    for m in matches or []:
        t1 = _v25_safe_txt(m.get("team1"))
        t2 = _v25_safe_txt(m.get("team2"))
        tm = _v25_safe_txt(m.get("time"))
        dt = _v25_safe_txt(m.get("date"))
        key = (
            re.sub(r"\s+", " ", t1.replace("ЩҖ", "")).strip(),
            re.sub(r"\s+", " ", t2.replace("ЩҖ", "")).strip(),
            re.sub(r"\s+", " ", tm).strip(),
            dt,
        )
        if key in seen:
            continue
        seen.add(key)
        out.append(dict(m))
    return out


def _v25_fixture_simple_matches(date):
    rows = _v25_dedupe_fixture_matches(_fixtures_for_date(date))
    simple = []
    for m in rows:
        simple.append((
            _v25_safe_txt(m.get("team1")),
            _v25_safe_txt(m.get("team2")),
            _v25_safe_txt(m.get("time")),
        ))
    return rows, simple


def _v25_fixture_title(date):
    d = _normalize_date_arg(date)
    day = ""
    for x, dy in _fixture_dates():
        if x == d:
            day = dy
            break
    return f"{day} {d[:5]}".strip()


def _fixtures_caption(date_or_title, source="PDF Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©"):
    return f"{date_or_title}\nШ§Щ„Щ…ШөШҜШұ: {source}\nШ§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«"


def _v25_compact_bg(w=1080, h=1350):
    """
    Ш®Щ„ЩҒЩҠШ© Ш§Щ„ШӘЩ…Ш«Ш§Щ„ Ш§Щ„ЩҶШёЩҠЩҒШ© Щ„Щ„Щ…Ш¶ШәЩҲШ· ШЁШҜЩҲЩҶ Ш№ЩҶЩҲШ§ЩҶ GAMES Ш§Щ„ЩғШЁЩҠШұ.
    """
    candidates = [
        "games_v31_clean_bg.png",
        os.path.join("assets", "templates", "games_v31_clean_bg.png"),
        "games_v31_full_bg.png",
        os.path.join("assets", "templates", "games_v31_full_bg.png"),
    ]
    for p in candidates:
        if os.path.exists(p):
            try:
                bg = Image.open(p).convert("RGB").resize((w, h))
                ov = Image.new("RGBA", (w, h), (0, 10, 30, 120))
                return Image.alpha_composite(bg.convert("RGBA"), ov).convert("RGB")
            except Exception:
                pass
    return Image.new("RGB", (w, h), "#071329")


def _v25_draw_compact_match(draw, box, m):
    x0, y0, x1, y1 = box
    try:
        draw.rounded_rectangle(box, radius=22, fill=(5,24,58,225), outline=(38,151,255,190), width=2)
    except Exception:
        draw.rectangle(box, fill=(5,24,58), outline=(38,151,255), width=2)

    # Ш§Щ„ЩҲЩӮШӘ ЩҠЩ…ЩҠЩҶ
    draw_text(draw, (x1-35, y0+38), _v25_safe_txt(m.get("time")), get_font(27), fill="#FBBF24", anchor="rm", max_width=190)

    # Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ШЁШ§Щ„ЩҶШө
    text = f"{_v25_safe_txt(m.get('team1'))} Г— {_v25_safe_txt(m.get('team2'))}"
    draw_text(draw, ((x0+x1)//2, y0+36), text, get_font(30), fill="#FFFFFF", max_width=(x1-x0)-260)

    sub = _v25_safe_txt(m.get("stage"))
    if m.get("group"):
        sub += f" - {_v25_safe_txt(m.get('group'))}"
    draw_text(draw, ((x0+x1)//2, y0+75), sub, get_font(21), fill="#CBD5E1", max_width=(x1-x0)-160)


def _render_fixture_day_compact(date):
    """
    ШӘШөЩ…ЩҠЩ… 1: Щ…Ш¶ШәЩҲШ·ШҢ Ш®Щ„ЩҒЩҠШ© Ш§Щ„ШӘЩ…Ш«Ш§Щ„ШҢ ШЁШҜЩҲЩҶ Ш§Щ„ЩғЩ„Ш§Щ… Ш§Щ„ЩғШЁЩҠШұ ЩҒЩҲЩӮ.
    """
    rows = _v25_dedupe_fixture_matches(_fixtures_for_date(date))
    if not rows:
        return []

    chunks = [rows[i:i+8] for i in range(0, len(rows), 8)]
    paths = []

    for page, chunk in enumerate(chunks, 1):
        h = 1350
        img = _v25_compact_bg(1080, h)
        draw = ImageDraw.Draw(img, "RGBA")

        y = 105
        # ШҙШұЩҠШ· Ш§Щ„ШӘШ§ШұЩҠШ® ЩҒЩӮШ· ШЁШҜЩҲЩҶ Ш№ЩҶЩҲШ§ЩҶ ЩғШЁЩҠШұ
        try:
            draw.rounded_rectangle((120, y, 960, y+62), radius=22, fill=(251,191,36,235))
        except Exception:
            draw.rectangle((120, y, 960, y+62), fill=(251,191,36))
        title = _v25_fixture_title(date)
        if len(chunks) > 1:
            title += f" | {page}/{len(chunks)}"
        draw_text(draw, (540, y+31), title, get_font(34), fill="#061329", max_width=780)

        y += 92
        for m in chunk:
            _v25_draw_compact_match(draw, (70, y, 1010, y+104), m)
            y += 122

        draw.line((250, 1238, 830, 1238), fill=(255,255,255,180), width=2)
        draw_text(draw, (540, 1284), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(30), fill="#FBBF24")

        path = os.path.join(GENERATED_DIR, f"fixtures_compact_{date.replace('/','_')}_{page}.png")
        img.save(path, quality=96)
        paths.append(path)

    return paths


def _render_fixture_day_by_design(date, design=2):
    """
    design=1 => Щ…Ш¶ШәЩҲШ·
    design=2 => ЩҶЩҒШі ШӘШөЩ…ЩҠЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ШұШҰЩҠШіЩҠ
    """
    rows, simple_matches = _v25_fixture_simple_matches(date)
    if not simple_matches:
        return []

    if int(design) == 1:
        return _render_fixture_day_compact(date)

    # ШӘШөЩ…ЩҠЩ… 2: ЩҶЩҒШі ШӘШөЩ…ЩҠЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ…
    chunks = [simple_matches[i:i+7] for i in range(0, len(simple_matches), 7)]
    paths = []

    for page_idx, chunk in enumerate(chunks, start=1):
        page_title = _v25_fixture_title(date)
        if len(chunks) > 1:
            page_title = f"{page_title} | {page_idx}/{len(chunks)}"

        # ЩҮШ°Ш§ ЩҮЩҲ Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…Ш№ШӘЩ…ШҜ ЩҶЩҒШіЩҮ ШӯЩӮ /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ…
        path = create_matches_today_v31_full_image(page_title, chunk)
        final_path = os.path.join(
            GENERATED_DIR,
            f"fixtures_day_design2_{date.replace('/','_')}_{page_idx}.png"
        )
        try:
            Image.open(path).save(final_path, quality=96)
            paths.append(final_path)
        except Exception:
            paths.append(path)

    return paths


def render_fixtures_combined_images(dates):
    """
    ШӘШөЩ…ЩҠЩ… Щ…Ш¬Щ…Ш№: Ш®Щ„ЩҒЩҠШ© Ш§Щ„ШӘЩ…Ш«Ш§Щ„ ШЁШҜЩҲЩҶ Ш§Щ„ЩғЩ„Ш§Щ… Ш§Щ„ЩғШЁЩҠШұ ЩҒЩҲЩӮ.
    ШҘШ°Ш§ ЩғШ«ШұШӘ Ш§Щ„ШЈЩҠШ§Щ… ЩҠЩӮШіЩ… ЩғЩ„ 3 ШЈЩҠШ§Щ… ЩҒЩҠ ШөЩҲШұШ©.
    """
    dates = [_normalize_date_arg(d) for d in dates if _normalize_date_arg(d)]
    dates = [d for d in dates if _fixtures_for_date(d)]
    # ШҘШІШ§Щ„Ш© ШӘЩғШұШ§Шұ Ш§Щ„ШӘЩҲШ§ШұЩҠШ® Щ…Ш№ Ш§Щ„ШӯЩҒШ§Шё Ш№Щ„Щү Ш§Щ„ШӘШұШӘЩҠШЁ
    clean_dates = []
    for d in dates:
        if d not in clean_dates:
            clean_dates.append(d)
    dates = clean_dates

    if not dates:
        return []

    date_chunks = [dates[i:i+3] for i in range(0, len(dates), 3)]
    paths = []

    for page, dchunk in enumerate(date_chunks, 1):
        rows = []
        for d in dchunk:
            rows.append(("date", d))
            for m in _v25_dedupe_fixture_matches(_fixtures_for_date(d)):
                rows.append(("match", m))

        h = max(1350, 170 + len(rows)*112 + 140)
        h = min(h, 2400)
        img = _v25_compact_bg(1080, h)
        draw = ImageDraw.Draw(img, "RGBA")

        y = 90
        if len(date_chunks) > 1:
            draw_text(draw, (540, 42), f"ШөЩҒШӯШ© {page}/{len(date_chunks)}", get_font(24), fill="#FBBF24")

        for kind, val in rows:
            if y > h - 135:
                break

            if kind == "date":
                try:
                    draw.rounded_rectangle((90, y, 990, y+54), radius=20, fill=(251,191,36,235))
                except Exception:
                    draw.rectangle((90, y, 990, y+54), fill=(251,191,36))
                draw_text(draw, (540, y+27), _v25_fixture_title(val), get_font(31), fill="#061329", max_width=830)
                y += 72
            else:
                _v25_draw_compact_match(draw, (75, y, 1005, y+96), val)
                y += 112

        draw.line((250, h-88, 830, h-88), fill=(255,255,255,180), width=2)
        draw_text(draw, (540, h-48), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(29), fill="#FBBF24")

        path = os.path.join(GENERATED_DIR, f"fixtures_combined_v25_{page}_{datetime.now().strftime('%H%M%S')}.png")
        img.save(path, quality=96)
        paths.append(path)

    return paths


def _fixtures_day_keyboard(date):
    rows = [
        [
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 1", callback_data=f"fx|render1|{date}"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 2", callback_data=f"fx|render2|{date}")
        ]
    ]

    miss = [m for m in _fixtures_for_date(date) if _has_unknown(m)]
    for i, m in enumerate(miss, 1):
        rows.append([InlineKeyboardButton(f"ШӘШӯШҜЩҠШ« Щ…ШЁШ§ШұШ§Ш© {i} вҖ” {m.get('time')}", callback_data=f"fx|upd|{m.get('id')}")])

    rows.append([InlineKeyboardButton("ШұШ¬ЩҲШ№ Щ„Щ„ШЈЩҠШ§Щ…", callback_data="fx|menu")])
    return InlineKeyboardMarkup(rows)


def _fixtures_dates_keyboard(mode="single", selected=None):
    selected = set(selected or [])
    rows = []
    row = []

    for d, day in _fixture_dates():
        label = f"{'вң… ' if d in selected else ''}{day} {d[:5]}"
        data = f"fx|toggle|{d}" if mode == "multi" else f"fx|day|{d}"
        row.append(InlineKeyboardButton(label, callback_data=data))
        if len(row) == 2:
            rows.append(row)
            row = []

    if row:
        rows.append(row)

    if mode == "multi":
        rows.append([
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… ЩғЩ„ ЩҠЩҲЩ…", callback_data="fx|render_each"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… ЩҲШ§ШӯШҜ", callback_data="fx|render_combo"),
        ])
        rows.append([
            InlineKeyboardButton("ШӘШөЩҒЩҠШұ Ш§Щ„Ш§Ш®ШӘЩҠШ§Шұ", callback_data="fx|clear"),
            InlineKeyboardButton("ШұШ¬ЩҲШ№", callback_data="fx|menu"),
        ])
    else:
        rows.append([InlineKeyboardButton("Ш§Ш®ШӘЩҠШ§Шұ ШЈЩғШ«Шұ Щ…ЩҶ ЩҠЩҲЩ…", callback_data="fx|multi")])

    return InlineKeyboardMarkup(rows)


def _fixtures_day_text(date):
    rows, matches = _v25_fixture_simple_matches(date)
    if not matches:
        return "Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ШӘШ§ШұЩҠШ®."

    lines = [f"{_v25_fixture_title(date)}", ""]
    for i, m in enumerate(rows, 1):
        lines.append(f"{i}) {_v25_safe_txt(m.get('team1'))} Г— {_v25_safe_txt(m.get('team2'))} вҖ” {_v25_safe_txt(m.get('time'))}")
        extra = []
        if m.get("stage"):
            extra.append(_v25_safe_txt(m.get("stage")))
        if m.get("group"):
            extra.append(_v25_safe_txt(m.get("group")))
        if extra:
            lines.append("   " + " | ".join(extra))
        if _has_unknown(m) and m.get("note"):
            lines.append(f"   {_v25_safe_txt(m.get('note'))}")

    return "\n".join(lines)


async def fixtures_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ""
    dates = _extract_fixture_dates_from_text(text)

    if dates:
        # ШӘШ§ШұЩҠШ® ЩҲШ§ШӯШҜ: ЩҠШөЩ…Щ… Щ…ШЁШ§ШҙШұШ© ШЁШӘШөЩ…ЩҠЩ… 2ШҢ ЩҶЩҒШі /Щ…ШЁШ§ШұЩҠШ§ШӘ_Ш§Щ„ЩҠЩҲЩ…
        if len(dates) == 1:
            d = dates[0]
            wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                paths = _render_fixture_day_by_design(d, design=2)
                if not paths:
                    await wait.edit_text(f"Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШЁШӘШ§ШұЩҠШ® {d}")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(update.message, p, _fixtures_caption(_v25_fixture_title(d)))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        # ШЈЩғШ«Шұ Щ…ЩҶ ШӘШ§ШұЩҠШ®: Щ…Ш¬Щ…Ш№
        wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш¬Щ…Ш№Ш©...")
        try:
            paths = render_fixtures_combined_images(dates)
            if not paths:
                await wait.edit_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„Щ„ШӘЩҲШ§ШұЩҠШ® Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ©.")
                return
            try:
                await wait.delete()
            except Exception:
                pass
            for p in paths:
                await send_photo_path(update.message, p, _fixtures_caption("Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…Ш¬Щ…Ш№Ш©"))
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЈЩҠШ§Щ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
        return

    await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ЩғШӘШЁ:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))


