def build_design_matches_caption(day_name, matches):
    lines = ["рҹҸҶ Щ…ЩҲЩҶШҜЩҠШ§Щ„ Ш§Щ„Щ…ШөЩҠЩҒ 2026 рҹҸҶ", f"рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… ( {day_name} ) рҹ”Ҙ", ""]
    for a, b, t in matches:
        lines.append(f"{a} Г— {b}" + (f" вҖ” {t}" if t else ""))
    lines.append("")
    lines.append("Ш§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«")
    return "\n".join(lines)


def build_design_results_caption(day_name, results):
    lines = ["рҹҸҶ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… рҹҸҶ", f"Ш§Щ„ЩҠЩҲЩ… ( {day_name} )", ""]
    for a, sa, sb, b in results:
        lines.append(f"{a} {sa} - {sb} {b}")
    lines.append("")
    lines.append("Ш§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«")
    return "\n".join(lines)


def build_match_results_caption(results):
    # Щ„Щ„ШӘЩҲШ§ЩҒЩӮ Щ…Ш№ Ш§Щ„ШЈЩҲШ§Щ…Шұ Ш§Щ„ЩӮШҜЩҠЩ…Ш© Ш§Щ„ШӘЩҠ Щ„Ш§ ШӘЩ…ШұШұ Ш§Щ„ЩҠЩҲЩ…
    lines = ["рҹҸҶ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… рҹҸҶ", ""]
    for a, sa, sb, b in results:
        lines.append(f"{a} {sa} - {sb} {b}")
    lines.append("\nШ§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«")
    return "\n".join(lines)


def build_top_scorers_caption(items):
    lines = ["рҹҸҶ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© рҹҸҶ", ""]
    for i, (name, goals, team) in enumerate(sorted(items, key=lambda x: (-x[1], x[0])), start=1):
        team_part = f" вҖ” {team}" if team else ""
        lines.append(f"{i}. {name}{team_part} вҖ” {goals} ШЈЩҮШҜШ§ЩҒ")
    lines.append("\nШ§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«")
    return "\n".join(lines)


