async def sports_source_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    if not query:
        return
    await query.answer()
    if not is_admin_user(update):
        await query.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    parts = (query.data or "").split("|")
    if len(parts) != 3:
        await query.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
        return
    _tag, token, mode = parts
    payload = context.bot_data.get("sports_source_requests", {}).get(token)
    if not payload:
        await query.message.reply_text("Ш§ЩҶШӘЩҮШӘ ШөЩ„Ш§ШӯЩҠШ© Ш§Щ„Ш®ЩҠШ§ШұШҢ ШЈШ№ШҜ ШӘЩҶЩҒЩҠШ° Ш§Щ„ШЈЩ…Шұ Щ…ЩҶ Ш¬ШҜЩҠШҜ.")
        return
    kind = payload.get("kind")
    try:
        if kind == "standings":
            groups, _src = fetch_current_groups(mode)
            kb = source_keyboard(context, payload)
            if not groups:
                await query.message.reply_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}.\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=kb)
                return
            path = create_all_groups_image(groups)
            await send_photo_path_markup(query.message, path, f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ Ш§Щ„ШӯШ§Щ„ЩҠ: {mode_label_ar(mode)}", kb)
            await query.message.reply_text(build_groups_text(groups, mode_label_ar(mode)))
        elif kind == "live":
            team1 = payload.get("team1")
            team2 = payload.get("team2")
            kb = source_keyboard(context, payload)
            data = fetch_live_match_data(team1, team2, mode, date_hint=payload.get("date_hint"))
            if not data:
                await query.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұШ§Ш© {team1} Ш¶ШҜ {team2} Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)}.\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=kb)
                return
            path = render_live_match_card(data, mode_label_ar(mode))
            await send_photo_path_markup(query.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
        else:
            await query.message.reply_text("ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШҜ ЩҶЩҲШ№ Ш§Щ„Ш·Щ„ШЁ.")
    except Exception:
        if kind == "live":
            await query.message.reply_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=source_keyboard(context, payload))
        elif kind == "standings":
            await query.message.reply_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=source_keyboard(context, payload))
        else:
            await query.message.reply_text("ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШўЩҶ.")


