def _env_value(name, default=""):
    try:
        return (os.getenv(name) or default or "").strip()
    except Exception:
        return default or ""


def serpapi_search_json(query, hl="ar", gl="sa", timeout=8, **kwargs):
    """SerpApi Google JSON. ЩҠЩӮШЁЩ„ timeout ШӯШӘЩү Щ„Ш§ ЩҠШӘШ№Ш·Щ„ /ШЁШӯШ«_ЩӮЩҲЩӮЩ„ ЩҲ/Щ…ШЁШ§ШҙШұ."""
    key = _serpapi_key() if '_serpapi_key' in globals() else _env_value('SERPAPI_KEY')
    if not key:
        raise RuntimeError("SERPAPI_KEY ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ ЩҒЩҠ Railway")
    params = {"engine": "google", "q": query, "hl": hl, "gl": gl, "api_key": key}
    params.update(kwargs or {})
    return _http_json_get("https://serpapi.com/search.json", params=params, timeout=timeout)


def _norm_source_mode(mode):
    m = normalize_name(mode or "").lower().strip()
    table = {
        "ШіШұЩҠШ№": "google", "fast": "google", "google": "google", "ЩӮЩҲЩӮЩ„": "google", "Ш¬ЩҲШ¬Щ„": "google",
        "365": "365", "ЩЈЩҰЩҘ": "365", "365scores": "365", "365score": "365",
        "ЩғЩҲШұШ©": "kooora", "ЩғЩҲШұЩҮ": "kooora", "kooora": "kooora", "koora": "kooora",
        "ШұШіЩ…ЩҠ": "official", "official": "official", "api": "official", "api-football": "official",
        "Ш§Щ„ШЈШӯШҜШ«": "latest", "Ш§Щ„Ш§ШӯШҜШ«": "latest", "latest": "latest",
    }
    return table.get(m, m or "official")


def mode_label_ar(mode):
    m = _norm_source_mode(mode)
    return {
        "google": "ЩӮЩҲЩӮЩ„",
        "365": "365",
        "kooora": "ЩғЩҲШұШ©",
        "official": "ШұШіЩ…ЩҠ",
        "latest": "Ш§Щ„ШЈШӯШҜШ«",
    }.get(m, normalize_name(mode or "ШұШіЩ…ЩҠ"))


