    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait_msg = await update.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}\nШ§Щ„Щ…ШөШҜШұ: {mode_label_ar(mode)}" + (f"\nШ§Щ„ШӘШ§ШұЩҠШ®: {date_hint}" if date_hint else ""))
