# ==================== V22 HARD STABLE PATCH: ESPN RESULTS -> GROUP STANDINGS ====================
# Ш§Щ„ЩҮШҜЩҒ: ШҘЩҠЩӮШ§ЩҒ ШҜЩҲШ§Щ…Ш© Google/Playwright/Docker ЩҶЩҮШ§ШҰЩҠЩӢШ§.
# ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҮЩҶШ§ ЩҠШіШӯШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ЩҶ ESPN JSON Ш§Щ„Щ…ШЁШ§ШҙШұШҢ Ш«Щ… ЩҠШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ ЩҒЩҲШұЩӢШ§.
# Щ„Ш§ ЩҠШӯШӘШ§Ш¬ Docker ЩҲЩ„Ш§ Playwright ЩҲЩ„Ш§ Chromium. requests ЩҒЩӮШ·.

V22_GROUPS_SOURCE_LABEL = "ESPN Live Results"


def _v22_event_is_countable(event, obj):
    """ЩҶШӯШіШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ШҘШ°Ш§ ШЁШҜШЈШӘ ШЈЩҲ Ш§ЩҶШӘЩҮШӘ. ЩҶШіШӘШЁШ№ШҜ Ш§Щ„Щ…Ш¬ШҜЩҲЩ„Ш© ЩҒЩӮШ·."""
    try:
        comp = (event.get("competitions") or [event])[0]
        st = comp.get("status") or event.get("status") or {}
        typ = st.get("type") or {}
        state = normalize_name(typ.get("state") or typ.get("name") or typ.get("description") or typ.get("detail") or "").lower()
        detail = normalize_name(typ.get("detail") or typ.get("shortDetail") or st.get("displayClock") or obj.get("status") or obj.get("minute") or "").lower()
        if any(x in state + " " + detail for x in ["pre", "scheduled", "not started", "Щ„Щ… ШӘШЁШҜШЈ"]):
            return False
        # ШҘШ°Ш§ ЩҒЩҠЩҮ ЩҶШӘЩҠШ¬Ш© ШұЩӮЩ…ЩҠШ© ЩҶШ№ШҜЩҮШ§ШҢ ШӯШӘЩү Щ„ЩҲ Щ…ШЁШ§ШҙШұ.
        int(float(obj.get("score1", 0)))
        int(float(obj.get("score2", 0)))
        return True
    except Exception:
        return False


def _v22_date_range_for_worldcup():
    """Щ…ЩҶ ШЁШҜШ§ЩҠШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШҘЩ„Щү Ш§Щ„ЩҠЩҲЩ… + ЩҠЩҲЩ…ЩҠЩҶ. Ш«Ш§ШЁШӘ ЩҲШ®ЩҒЩҠЩҒ."""
    start = datetime(2026, 6, 11).date()
    # Щ„Ш§ ЩҶШ®Щ„ЩҠ Ш§Щ„ШӘШ§ШұЩҠШ® ЩӮШЁЩ„ ШЁШҜШ§ЩҠШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШӯШӘЩү Щ„ЩҲ ШіШ§Ш№Ш© Ш§Щ„ШіЩҠШұЩҒШұ Щ…Ш®ШӘЩ„ЩҒШ©
    today = max(datetime.utcnow().date(), start)
    end = min(today + timedelta(days=2), datetime(2026, 7, 1).date())
    dates = []
    d = start
    while d <= end:
        dates.append(d.strftime("%Y%m%d"))
        d += timedelta(days=1)
    return dates


def fetch_standings_from_espn_live_results():
    """ЩҠШіШӯШЁ ЩҶШӘШ§ШҰШ¬ ESPN Щ„ЩғЩ„ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘШҢ Ш«Щ… ЩҠШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ.
    ЩҠШұШ¬Ш№ ЩҶЩҒШі ШҙЩғЩ„ Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…Ш№ШӘЩ…ШҜ: [(Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЈ, [(team, played, gd, pts), ...]), ...]
    """
    # Ш¬ШҜЩҲЩ„ ЩғШ§Щ…Щ„ Щ„ЩғЩ„ Щ…ЩҶШӘШ®ШЁ ШҜШ§Ш®Щ„ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ
    group_by_team = {}
    for g, teams in WORLD_CUP_GROUPS:
        for t in teams:
            group_by_team[t] = g
    table = {t: {"played": 0, "wins": 0, "draws": 0, "losses": 0, "gf": 0, "ga": 0, "gd": 0, "pts": 0} for t in WORLD_CUP_TEAMS}

    found_any = False
    seen = set()
    for dv in _v22_date_range_for_worldcup():
        events = []
        try:
            events = _fetch_espn_events_by_date(dv) or []
        except Exception:
            events = []
        for event in events:
            try:
                eid = str(event.get("id") or event.get("uid") or "")
                if eid and eid in seen:
                    continue
                if eid:
                    seen.add(eid)
                obj = _parse_espn_match_from_event(event)
                if not obj:
                    continue
                t1 = canonical_team_name(obj.get("team1")) or normalize_name(obj.get("team1"))
                t2 = canonical_team_name(obj.get("team2")) or normalize_name(obj.get("team2"))
                if t1 not in table or t2 not in table:
                    continue
                # Щ„Ш§ ЩҶШӯШіШЁ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ЩҶ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…Ш®ШӘЩ„ЩҒШ© ШЈЩҲ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҲШҜЩҠШ©/Ш®Ш§ШұШ¬ Ш§Щ„ШЁШ·ЩҲЩ„Ш©
                if group_by_team.get(t1) != group_by_team.get(t2):
                    continue
                if not _v22_event_is_countable(event, obj):
                    continue
                s1 = int(float(obj.get("score1", 0)))
                s2 = int(float(obj.get("score2", 0)))
                found_any = True
                table[t1]["played"] += 1
                table[t2]["played"] += 1
                table[t1]["gf"] += s1
                table[t1]["ga"] += s2
                table[t2]["gf"] += s2
                table[t2]["ga"] += s1
                table[t1]["gd"] = table[t1]["gf"] - table[t1]["ga"]
                table[t2]["gd"] = table[t2]["gf"] - table[t2]["ga"]
                if s1 > s2:
                    table[t1]["wins"] += 1; table[t2]["losses"] += 1
                    table[t1]["pts"] += 3
                elif s2 > s1:
                    table[t2]["wins"] += 1; table[t1]["losses"] += 1
                    table[t2]["pts"] += 3
                else:
                    table[t1]["draws"] += 1; table[t2]["draws"] += 1
                    table[t1]["pts"] += 1; table[t2]["pts"] += 1
            except Exception:
                continue
    if not found_any:
        return []

    groups = []
    ar_letters = {"A":"ШЈ", "B":"ШЁ", "C":"Ш¬", "D":"ШҜ", "E":"ЩҮЩҖ", "F":"ЩҲ", "G":"ШІ", "H":"Шӯ", "I":"Ш·", "J":"ЩҠ", "K":"Щғ", "L":"Щ„"}
    for g, teams in WORLD_CUP_GROUPS:
        rows = []
        for t in teams:
            r = table[t]
            rows.append((t, int(r["played"]), int(r["gd"]), int(r["pts"])))
        # ШӘШұШӘЩҠШЁ ЩӮЩҠШ§ШіЩҠ: ЩҶЩӮШ§Ш·ШҢ ЩҒШ§ШұЩӮШҢ ШЈЩҮШҜШ§ЩҒ Щ„ЩҮШҢ Ш§Щ„Ш§ШіЩ… Щ„Ш¶Щ…Ш§ЩҶ Ш«ШЁШ§ШӘ Ш§Щ„ШӘШұШӘЩҠШЁ
        rows.sort(key=lambda row: (row[3], row[2], table[row[0]]["gf"], row[0]), reverse=True)
        groups.append((f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {ar_letters.get(g, g)}", rows))
    return groups


def fetch_current_groups(mode="latest"):
    """V22: Ш§Щ„Щ…ШөШҜШұ Ш§Щ„Ш«Ш§ШЁШӘ Щ„ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ = ЩҶШӘШ§ШҰШ¬ ESPN Ш§Щ„Щ…ШЁШ§ШҙШұШ© ЩҒЩӮШ·."""
    groups = fetch_standings_from_espn_live_results()
    if groups:
        return groups, V22_GROUPS_SOURCE_LABEL
    return [], ""


def _source_help_text(kind, mode):
    if kind == "standings":
        return (
            "ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ESPN ШӯШ§Щ„ЩҠЩӢШ§ вқҢ\n"
            "Ш§Щ„ШЁЩҲШӘ ШҙШәШ§Щ„ШҢ Щ„ЩғЩҶ Щ…ШөШҜШұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Щ„Щ… ЩҠШұШ¬Ш№ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩғШ§ЩҒЩҠШ© Ш§Щ„ШўЩҶ.\n\n"
            "Ш¬ШұЩ‘ШЁ ШЁШ№ШҜ ШҜЩӮЩҠЩӮШ© ШЈЩҲ Ш§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ."
        )
    return f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ"


async def current_groups_now_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    """V22: ШЈЩ…Шұ Ш«Ш§ШЁШӘ Щ„Ш§ ЩҠШіШӘШ®ШҜЩ… Google/PlaywrightШҢ ЩҒЩӮШ· ESPN JSON."""
    payload = {"kind": "standings"}
    kb = source_keyboard(context, payload)
    wait = await update.message.reply_text("вҸі ШЈШіШӯШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ESPN ЩҲШЈШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ...")
    try:
        groups, source_label = await _asyncio_v6.wait_for(_asyncio_v6.to_thread(fetch_current_groups, "espn"), timeout=35)
    except Exception as e:
        groups, source_label = [], ""
        try:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ вқҢ\n{str(e)[:250]}", reply_markup=kb)
            return
        except Exception:
            pass
    if not groups:
        await wait.edit_text(_source_help_text("standings", "espn") + "\n\nШ§Ш®ШӘШұ Щ…ШөШҜШұ ШўШ®Шұ:", reply_markup=kb)
        return
    try:
        path = create_all_groups_newlook_image(groups) if 'create_all_groups_newlook_image' in globals() else create_all_groups_image(groups)
    except Exception:
        path = None
    caption = "ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШўЩҶ вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN вҖ” Щ…ШӯШіЩҲШЁ Щ…ЩҶ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШЁШ§ШҙШұШ©"
    try:
        await wait.delete()
    except Exception:
        pass
    if path and os.path.exists(path):
        await send_photo_path_markup(update.message, path, caption, kb)
    else:
        await update.message.reply_text(caption, reply_markup=kb)
    await update.message.reply_text(build_groups_text(groups, "ESPN Live Results"))


async def google_search_debug_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """ЩҶШӘШұЩғ Ш§ШіЩ… Ш§Щ„ШЈЩ…Шұ ЩғЩ…Ш§ ЩҮЩҲШҢ Щ„ЩғЩҶ Щ„Щ„ШӘШұШӘЩҠШЁ ЩҶШ№ШұШ¶ ШӘШҙШ®ЩҠШө ESPN Ш§Щ„Ш«Ш§ШЁШӘ ШЁШҜЩ„ ШҜЩҲШ§Щ…Ш© ЩӮЩҲЩӮЩ„."""
    body = parse_command_body_lines(update.message.text)
    query = " ".join(body).strip() or "Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ЩғШіЩҠЩғ ЩғЩҲШұЩҠШ§ Ш§Щ„Ш¬ЩҶЩҲШЁЩҠШ©"
    if any(x in normalize_name(query) for x in ["ШӘШұШӘЩҠШЁ", "ШӘШұШӘЩҠШЁШ§ШӘ", "standings", "Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ"]):
        msg = await update.message.reply_text("вҸі ШЈЩҒШӯШө ESPN Щ„ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ...")
        try:
            groups = await _asyncio_v6.wait_for(_asyncio_v6.to_thread(fetch_standings_from_espn_live_results), timeout=35)
        except Exception as e:
            await msg.edit_text("ЩҶШӘЩҠШ¬Ш© ЩҒШӯШө ESPN:\n" + f"error: {str(e)[:500]}")
            return
        if not groups:
            await msg.edit_text("ЩҶШӘЩҠШ¬Ш© ЩҒШӯШө ESPN:\nЩ„Щ… ЩҠШұШ¬Ш№ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩғШ§ЩҒЩҠШ© Щ„ШӯШіШ§ШЁ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„ШўЩҶ.")
            return
        lines = ["ЩҶШӘЩҠШ¬Ш© ЩҒШӯШө ESPN:", f"groups_read: {len(groups)}"]
        for title, rows in groups[:4]:
            lines.append(f"{title}: " + "ШҢ ".join([f"{r[0]} {r[3]}" for r in rows[:4]]))
        await msg.edit_text("\n".join(lines[:25]))
        return
    # Щ„Щ„ШЁШӯШ« Ш§Щ„Ш№Ш§ШҜЩҠ ЩҶШіШӘШ®ШҜЩ… Ш§Щ„ШЈЩ…Шұ Ш§Щ„ШіШ§ШЁЩӮ ШҘЩҶ ЩҲШ¬ШҜШҢ ЩҲШҘЩ„Ш§ ШұШҜ Щ…Ш®ШӘШөШұ
    try:
        if '_V11_PREV_GOOGLE_SEARCH_DEBUG_COMMAND' in globals() and _V11_PREV_GOOGLE_SEARCH_DEBUG_COMMAND:
            return await _V11_PREV_GOOGLE_SEARCH_DEBUG_COMMAND(update, context)
    except Exception:
        pass
    await update.message.reply_text("Ш§ШіШӘШ®ШҜЩ… /ШӘШұШӘЩҠШЁ_Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ_Ш§Щ„Ш§ЩҶ Щ„ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШЈЩҲ /Щ…ШЁШ§ШҙШұ Щ„Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ.")


