async def import_excel_file(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id
    document = update.message.document
    if document:
        filename = document.file_name or "import.xlsx"
        if not filename.lower().endswith((".xlsx", ".xlsm")):
            await update.message.reply_text("Ш§Щ„Щ…Щ„ЩҒ Щ„Ш§ШІЩ… ЩҠЩғЩҲЩҶ Excel ШЁШөЩҠШәШ© .xlsx ШЈЩҲ .xlsm")
            return
        local_path, _ = await _download_document_to_folder(update, context, "imports")
        LAST_UPLOADED_FILES.setdefault(chat_id, {})["excel"] = local_path
    else:
        local_path = LAST_UPLOADED_FILES.get(chat_id, {}).get("excel")
        if not local_path or not os.path.exists(local_path):
            await update.message.reply_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„ЩҒ Excel Щ…ШӯЩҒЩҲШё. ШЈШұШіЩ„ Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„ Щ„ШӯШ§Щ„ЩҮ ШЈЩҲЩ„ЩӢШ§ШҢ ЩҲШЁШ№ШҜЩҮШ§ Ш§ЩғШӘШЁ:\n/Ш§ШіШӘЩҠШұШ§ШҜ_Щ…Щ„ЩҒ")
            return
    wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ЩӮШұШ§ШЎШ© Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„...")
    try:
        imported = await asyncio.wait_for(asyncio.to_thread(parse_import_excel, local_path), timeout=45)
    except Exception as e:
        await wait.edit_text(f"ШөШ§Шұ Ш®Ш·ШЈ ШЈШ«ЩҶШ§ШЎ ЩӮШұШ§ШЎШ© Ш§Щ„ШҘЩғШіЩ„ вқҢ\n{str(e)[:400]}")
        return
    if not imported:
        await wait.edit_text("Щ…Ш§ ЩӮШҜШұШӘ ШЈШіШӘШ®ШұШ¬ ШЈЩҠШ§Щ… Щ…ЩҶ Ш§Щ„Щ…Щ„ЩҒ. ШӘШЈЩғШҜ ШЈЩҶ Ш§Щ„ШөЩҒШӯШ§ШӘ ШЁШ§ШіЩ…: ЩҠЩҲЩ… 1ШҢ ЩҠЩҲЩ… 2 ...")
        return
    PENDING_IMPORTS[chat_id] = {"path": local_path, "data": imported}
    await wait.edit_text(import_summary_text(imported))


async def dashboard(update: Update, context: ContextTypes.DEFAULT_TYPE):
    wait = await update.message.reply_text("Ш¬Ш§ШұЩҠ ШҘЩҶШҙШ§ШЎ Щ…Щ„ЩҒ Ш§Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ... вҸі")
    try:
        nums = get_numbers(update.message.text)
        if len(nums) >= 2:
            start_day, end_day = nums[0], nums[1]
            if start_day > end_day:
                start_day, end_day = end_day, start_day
        elif len(nums) == 1:
            start_day, end_day = 1, nums[0]
        else:
            start_day, end_day = 1, 31
        file_name, stats = await asyncio.wait_for(asyncio.to_thread(create_dashboard, start_day, end_day), timeout=70)
        if not stats.get("days"):
            await wait.edit_text("Щ…Ш§ Щ„ЩӮЩҠШӘ ШЈЩҠШ§Щ… Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШҜШ§ШҙШЁЩҲШұШҜ.")
            return
        try:
            add_matchups_sheet_to_dashboard(file_name, start_day, end_day)
        except Exception:
            pass
        caption = (
            "ШӘЩ… ШҘЩҶШҙШ§ШЎ Щ…Щ„ЩҒ Ш§Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ЩғШ§Щ…Щ„ вң…\n"
            f"Ш§Щ„ЩҶШ·Ш§ЩӮ: Щ…ЩҶ Ш§Щ„ЩҠЩҲЩ… {start_day} ШҘЩ„Щү Ш§Щ„ЩҠЩҲЩ… {end_day}\n"
            f"Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӯШіЩҲШЁШ©: {', '.join(map(str, stats['days']))}"
        )
        try:
            await wait.delete()
        except Exception:
            pass
        with open(file_name, "rb") as file:
            await update.message.reply_document(document=file, filename=file_name, caption=caption)
    except Exception as e:
        await wait.edit_text(f"ШөШ§Шұ Ш®Ш·ШЈ ШЈШ«ЩҶШ§ШЎ ШҘЩҶШҙШ§ШЎ Ш§Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ вқҢ\n\nШ§Щ„ШіШЁШЁ:\n{str(e)[:500]}")


async def live_match_command(update: Update, context: ContextTypes.DEFAULT_TYPE, mode_override=None):
    team1, team2, mode, date_hint = parse_live_command_text(update.message.text)
    if mode_override:
        mode = _norm_source_mode(mode_override)
    if not team1 or not team2:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Щ…ШЁШ§ШҙШұ Ш§Щ„ШЁШұШ§ШІЩҠЩ„ * ЩҮШ§ЩҠШӘЩҠ * ЩӮЩҲЩӮЩ„\nШЈЩҲ:\n/Щ…ШЁШ§ШҙШұ Ш§Щ„ШЁШұШ§ШІЩҠЩ„ * ЩҮШ§ЩҠШӘЩҠ * ШұШіЩ…ЩҠ")
        return
    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait = await update.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ Ш§Щ„ШЁШӯШ« Ш№ЩҶ Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}\nШ§Щ„Щ…ШөШҜШұ: {mode_label_ar(mode)}")
    try:
        data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, mode, date_hint), timeout=22)
    except Exception as e:
        data = None
        err = str(e)[:160]
    if not data:
        await wait.edit_text(
            f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ Щ…ШөШҜШұ {mode_label_ar(mode)} вқҢ\n"
            f"Щ…ШЁШ§ШұШ§Ш©: {team1} Г— {team2}\n"
            f"Ш¬ШұШЁ Щ…ШөШҜШұ Ш«Ш§ЩҶЩҠ Щ…ЩҶ Ш§Щ„ШЈШІШұШ§Шұ.",
            reply_markup=kb,
        )
        return
    try:
        path = render_live_match_card(data, mode_label_ar(mode))
        await send_photo_path_markup(update.message, path, build_live_caption(data, mode_label_ar(mode)), kb)
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘЩ… Ш¬Щ„ШЁ Ш§Щ„ЩҶШӘЩҠШ¬Ш© Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШөЩҲШұШ© вқҢ\n{str(e)[:180]}\n\n" + build_live_caption(data, mode_label_ar(mode)), reply_markup=kb)


# ==================== V26 FINAL OVERRIDE: fixtures + excel safety ====================
# ЩҮШ°Ш§ Ш§Щ„ЩӮШіЩ… ШўШ®Шұ ШӘШ№ШұЩҠЩҒ Щ„Щ„ШҜЩҲШ§Щ„ ЩӮШЁЩ„ main()ШҢ Щ„Ш°Щ„Щғ ЩҮЩҲ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ ЩҲЩӮШӘ Ш§Щ„ШӘШҙШәЩҠЩ„.
# Ш§Щ„ШҘШөЩ„Ш§ШӯШ§ШӘ:
# 1) Ш§Ш®ШӘШөШ§Шұ Ш§Щ„ЩҲЩӮШӘ: 3:00 Шө / 10:00 Щ… / 12:00 Шө
# 2) Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Щ…Ш¬Щ…Ш№ Ш§Щ„Ш¬ШҜЩҠШҜ: ЩҠЩҲЩ…ЩҠЩҶ Ш¬ЩҶШЁ ШЁШ№Ш¶
# 3) Ш®ЩҠШ§Шұ ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ + ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӘШ№ШҜШҜШ©
# 4) ЩғШ§ШЁШҙЩҶ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… Щ…Ш№ ЩҶЩ…ЩҲШ°Ш¬ ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ
# 5) ШӘШ«ШЁЩҠШӘ Ш§ШіШӘЩҠШұШ§ШҜ Ш§Щ„ШҘЩғШіЩ„ ЩҲШ№ШҜЩ… ЩғШіШұЩҮ
# 6) ШөЩҠШә ШҘШ¶Ш§ЩҒШ©/ШӯШ°ЩҒ Щ…ШӘШіШ§ШЁЩӮ Щ…ШӘШ№ШҜШҜШ© ШЁШҜЩҲЩҶ ШӘШ№Ш§ШұШ¶ Щ…Ш№ /Ш§Ш¶Ш§ЩҒЩҮ

FANTASY_MATCH_DAY_FORM_V26 = (
    "рҹҸҶ ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ 2026  рҹҸҶ\n"
    "ЩӢ     рҹ”Ҙрҹ”Ҙрҹ”Ҙ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„Ш№Ш§ШҙШұрҹ”Ҙрҹ”Ҙ  \n"
    "рҹ“Ӣ ЩҶЩ…ЩҲШ°Ш¬ Ш§Щ„Щ…ШҙШ§ШұЩғШ© Ш§Щ„ШұШіЩ…ЩҠ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ\n"
    "рҹҸҶ ШӘШҙЩғЩҠЩ„Ш© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ - Ш§Щ„ЩҠЩҲЩ… (    )\n"
    "рҹ§Ө Ш§Щ„ШӯШ§ШұШі:\n"
    " Ш§Щ„Щ„Ш§Ш№ШЁ 1:\n"
    " Ш§Щ„Щ„Ш§Ш№ШЁ 2:\n"
    " Ш§Щ„Щ„Ш§Ш№ШЁ 3:\n"
    "рҹ‘‘ Ш§Щ„ЩғШ§ШЁШӘЩҶ :"
)


def _v26_safe_txt(x):
    return str(x or "").strip()


def _v26_short_time(t):
    s = _v26_safe_txt(t)
    if not s:
        return ""

    # ШӘЩҶШёЩҠЩҒ Ш§Щ„Щ…ШіШ§ЩҒШ§ШӘ ЩҲШ§Щ„ШұЩ…ЩҲШІ
    s = s.replace("ШөШЁШ§ШӯШ§ЩӢ", "Шө").replace("ШөШЁШ§ШӯЩӢШ§", "Шө").replace("ШөШЁШ§ШӯШ§", "Шө")
    s = s.replace("Щ…ШіШ§ШЎЩӢ", "Щ…").replace("Щ…ШіШ§ШЎШ§", "Щ…").replace("Щ…ШіШ§ШЎ", "Щ…")
    s = s.replace("ЩҒШ¬ШұШ§ЩӢ", "Шө").replace("ЩҒШ¬ШұЩӢШ§", "Шө").replace("ЩҒШ¬ШұШ§", "Шө")
    s = s.replace("Щ„ЩҠЩ„Ш§ЩӢ", "Щ…").replace("Щ„ЩҠЩ„ЩӢШ§", "Щ…").replace("Щ„ЩҠЩ„Ш§", "Щ…")
    s = s.replace("Щ…ЩҶШӘШөЩҒ Ш§Щ„Щ„ЩҠЩ„", "Шө")
    s = s.replace("Ш§Щ„ШёЩҮШұ", "Щ…").replace("ШёЩҮШұШ§ЩӢ", "Щ…").replace("ШёЩҮШұЩӢШ§", "Щ…")
    s = s.replace("AM", "Шө").replace("am", "Шө").replace("A.M.", "Шө").replace("a.m.", "Шө")
    s = s.replace("PM", "Щ…").replace("pm", "Щ…").replace("P.M.", "Щ…").replace("p.m.", "Щ…")
    s = re.sub(r"\s+", " ", s).strip()

    # Щ„ЩҲ Ш§Щ„ШөЩҠШәШ© ШөШ§ШұШӘ 3:00 Шө ШЈЩҲ 10:00 Щ…
    m = re.search(r"(\d{1,2})(?::(\d{2}))?\s*([ШөЩ…])", s)
    if m:
        hh = int(m.group(1))
        mm = m.group(2) or "00"
        ap = m.group(3)
        return f"{hh}:{mm} {ap}"

    # Щ„ЩҲ ЩҒЩҠЩҮ ЩғЩ„Щ…Ш© Шө/Щ… ЩӮШЁЩ„ Ш§Щ„ШұЩӮЩ… ШЁШ·ШұЩҠЩӮШ© ШәШұЩҠШЁШ©
    m = re.search(r"([ШөЩ…])\s*(\d{1,2})(?::(\d{2}))?", s)
    if m:
        ap = m.group(1)
        hh = int(m.group(2))
        mm = m.group(3) or "00"
        return f"{hh}:{mm} {ap}"

    return s


def _v26_dedupe_fixture_matches(matches):
    seen = set()
    out = []
    for m in matches or []:
        t1 = _v26_safe_txt(m.get("team1"))
        t2 = _v26_safe_txt(m.get("team2"))
        tm = _v26_short_time(m.get("time"))
        dt = _v26_safe_txt(m.get("date"))
        key = (
            re.sub(r"\s+", " ", t1.replace("ЩҖ", "")).strip(),
            re.sub(r"\s+", " ", t2.replace("ЩҖ", "")).strip(),
            tm,
            dt,
        )
        if key in seen:
            continue
        seen.add(key)
        x = dict(m)
        x["time"] = tm
        out.append(x)
    return out


def _v26_fixture_title(date):
    d = _normalize_date_arg(date)
    day = ""
    for x, dy in _fixture_dates():
        if x == d:
            day = dy
            break
    return f"{day} {d[:5]}".strip()


def _v26_fixture_simple_matches(date):
    rows = _v26_dedupe_fixture_matches(_fixtures_for_date(date))
    simple = []
    for m in rows:
        simple.append((
            _v26_safe_txt(m.get("team1")),
            _v26_safe_txt(m.get("team2")),
            _v26_short_time(m.get("time")),
        ))
    return rows, simple


def _v26_fixtures_caption(date_or_title, matches=None, source="PDF Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", include_fantasy=True):
    lines = [
        "рҹҸҶ Щ…ЩҲЩҶШҜЩҠШ§Щ„ Ш§Щ„Щ…ШөЩҠЩҒ 2026 рҹҸҶ",
        f"рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… ( {date_or_title} ) рҹ”Ҙ",
        "",
    ]
    for i, m in enumerate(matches or [], start=1):
        if isinstance(m, dict):
            a = _v26_safe_txt(m.get("team1"))
            b = _v26_safe_txt(m.get("team2"))
            t = _v26_short_time(m.get("time"))
        else:
            a, b, t = m
            t = _v26_short_time(t)
        lines.append(f"{i}. {a} Г— {b}" + (f" вҖ” {t}" if t else ""))

    lines.extend(["", f"Ш§Щ„Щ…ШөШҜШұ: {source}", "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«"])

    if include_fantasy:
        lines.extend(["", FANTASY_MATCH_DAY_FORM_V26])

    return "\n".join(lines)


def _fixtures_caption(date_or_title, source="PDF Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©"):
    # ЩҶШ®Щ„ЩҠ Ш§Щ„ШҜШ§Щ„Ш© Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШӘШұШ¬Ш№ ЩҶЩҒШі Ш§Щ„ЩҮЩҲЩҠШ© Ш§Щ„Ш¬ШҜЩҠШҜШ© ШҘШ°Ш§ Ш§ШіШӘЩҸШ®ШҜЩ…ШӘ ЩҒЩҠ Щ…ШіШ§Шұ ЩӮШҜЩҠЩ…
    return _v26_fixtures_caption(date_or_title, [], source=source, include_fantasy=True)


def _v26_compact_bg(w=1080, h=1350):
    candidates = [
        "games_v31_clean_bg.png",
        os.path.join("assets", "templates", "games_v31_clean_bg.png"),
        "games_v31_full_bg.png",
        os.path.join("assets", "templates", "games_v31_full_bg.png"),
    ]
    for p in candidates:
        if os.path.exists(p):
            try:
                bg = Image.open(p).convert("RGB").resize((w, h))
                ov = Image.new("RGBA", (w, h), (0, 10, 30, 118))
                return Image.alpha_composite(bg.convert("RGBA"), ov).convert("RGB")
            except Exception:
                pass
    return Image.new("RGB", (w, h), "#071329")


def _v26_draw_day_block(draw, box, date, matches):
    x0, y0, x1, y1 = box
    try:
        draw.rounded_rectangle(box, radius=26, fill=(4, 18, 50, 218), outline=(38,151,255,190), width=2)
        draw.rounded_rectangle((x0+16, y0+16, x1-16, y0+70), radius=18, fill=(251,191,36,238))
    except Exception:
        draw.rectangle(box, fill=(4, 18, 50), outline=(38,151,255), width=2)
        draw.rectangle((x0+16, y0+16, x1-16, y0+70), fill=(251,191,36))

    draw_text(draw, ((x0+x1)//2, y0+43), _v26_fixture_title(date), get_font(28), fill="#061329", max_width=(x1-x0)-45)

    yy = y0 + 94
    row_h = 58
    if len(matches) >= 5:
        row_h = 50

    for idx, m in enumerate(matches[:6], start=1):
        if yy + row_h > y1 - 18:
            break
        time_txt = _v26_short_time(m.get("time"))
        teams = f"{_v26_safe_txt(m.get('team1'))} Г— {_v26_safe_txt(m.get('team2'))}"

        # Ш®Ш· ЩҒШ§ШөЩ„ Ш®ЩҒЩҠЩҒ
        if idx > 1:
            draw.line((x0+26, yy-9, x1-26, yy-9), fill=(255,255,255,45), width=1)

        # Ш§Щ„ЩҲЩӮШӘ ЩғШЁЩҠЩ„ ШөШәЩҠШұ Щ„Ш§ ЩҠЩҶЩғШіШұ
        try:
            draw.rounded_rectangle((x0+22, yy+4, x0+115, yy+38), radius=12, fill=(2,10,27,230), outline=(251,191,36,180), width=1)
        except Exception:
            draw.rectangle((x0+22, yy+4, x0+115, yy+38), fill=(2,10,27))
        draw_text(draw, (x0+68, yy+21), time_txt, get_font(19), fill="#FBBF24", max_width=86)

        draw_text(draw, ((x0+x1)//2+35, yy+22), teams, get_font(23 if len(teams) < 28 else 20), fill="#FFFFFF", max_width=(x1-x0)-155)
        yy += row_h

    if len(matches) > 6:
        draw_text(draw, ((x0+x1)//2, y1-24), f"+ {len(matches)-6} Щ…ШЁШ§ШұШ§Ш©", get_font(19), fill="#FBBF24")


def render_fixtures_combined_images(dates):
    """
    Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Ш¬ШҜЩҠШҜ Щ„Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӘШ№ШҜШҜШ©:
    ЩҠЩҲЩ…ЩҠЩҶ Ш¬ЩҶШЁ ШЁШ№Ш¶ вҖ” Ш§Щ„ШіШЁШӘ/Ш§Щ„ШЈШӯШҜ Ш«Щ… Ш§Щ„Ш§Ш«ЩҶЩҠЩҶ/Ш§Щ„Ш«Щ„Ш§Ш«Ш§ШЎ...
    """
    dates = [_normalize_date_arg(d) for d in dates if _normalize_date_arg(d)]
    clean_dates = []
    for d in dates:
        if d and _fixtures_for_date(d) and d not in clean_dates:
            clean_dates.append(d)
    dates = clean_dates
    if not dates:
        return []

    # 4 ШЈЩҠШ§Щ… Щ„ЩғЩ„ ШөЩҲШұШ© = ШөЩҒЩҠЩҶШҢ ЩҲЩғЩ„ ШөЩҒ ЩҠЩҲЩ…ЩҠЩҶ
    chunks = [dates[i:i+4] for i in range(0, len(dates), 4)]
    paths = []

    for page, dchunk in enumerate(chunks, start=1):
        w, h = 1080, 1350
        img = _v26_compact_bg(w, h)
        draw = ImageDraw.Draw(img, "RGBA")

        # Ш№ЩҶЩҲШ§ЩҶ ШөШәЩҠШұ ЩҒЩӮШ·ШҢ ШЁШҜЩҲЩҶ Ш§Щ„ЩғЩ„Ш§Щ… Ш§Щ„ЩғШЁЩҠШұ Ш§Щ„ЩӮШҜЩҠЩ…
        if len(chunks) > 1:
            draw_text(draw, (540, 44), f"ШөЩҒШӯШ© {page}/{len(chunks)}", get_font(24), fill="#FBBF24")

        left_x, right_x = 55, 555
        col_w = 470
        block_h = 520
        top_y = 95
        gap_y = 42
        positions = [
            (left_x, top_y, left_x+col_w, top_y+block_h),
            (right_x, top_y, right_x+col_w, top_y+block_h),
            (left_x, top_y+block_h+gap_y, left_x+col_w, top_y+block_h+gap_y+block_h),
            (right_x, top_y+block_h+gap_y, right_x+col_w, top_y+block_h+gap_y+block_h),
        ]

        for d, box in zip(dchunk, positions):
            _v26_draw_day_block(draw, box, d, _v26_dedupe_fixture_matches(_fixtures_for_date(d)))

        draw.line((250, h-76, 830, h-76), fill=(255,255,255,160), width=2)
        draw_text(draw, (540, h-39), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(28), fill="#FBBF24")
        path = os.path.join(GENERATED_DIR, f"fixtures_combined_v26_new_{page}_{datetime.now().strftime('%H%M%S')}.png")
        img.save(path, quality=96)
        paths.append(path)

    return paths


def _v26_render_fixtures_10_images(dates):
    """
    ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ: ЩӮШ§ШҰЩ…Ш© ЩҲШ§Ш¶ШӯШ©ШҢ ЩғЩ„ ШөЩҒШӯШ© ШӯШӘЩү 10 Щ…ШЁШ§ШұЩҠШ§ШӘ.
    """
    dates = [_normalize_date_arg(d) for d in dates if _normalize_date_arg(d)]
    flat = []
    for d in dates:
        for m in _v26_dedupe_fixture_matches(_fixtures_for_date(d)):
            x = dict(m)
            x["_date_title"] = _v26_fixture_title(d)
            flat.append(x)

    if not flat:
        return []

    chunks = [flat[i:i+10] for i in range(0, len(flat), 10)]
    paths = []

    for page, chunk in enumerate(chunks, start=1):
        w, h = 1080, 1350
        img = _v26_compact_bg(w, h)
        draw = ImageDraw.Draw(img, "RGBA")

        draw_text(draw, (540, 64), "Ш¬ШҜЩҲЩ„ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", get_font(42), fill="#FFFFFF", max_width=760)
        draw_text(draw, (540, 112), f"ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ" + (f" | ШөЩҒШӯШ© {page}/{len(chunks)}" if len(chunks) > 1 else ""), get_font(26), fill="#FBBF24", max_width=820)

        y = 170
        for i, m in enumerate(chunk, start=1):
            try:
                draw.rounded_rectangle((70, y, 1010, y+92), radius=18, fill=(5,24,58,225), outline=(38,151,255,170), width=2)
            except Exception:
                draw.rectangle((70, y, 1010, y+92), fill=(5,24,58), outline=(38,151,255), width=2)

            draw_text(draw, (950, y+27), str(i + (page-1)*10), get_font(24), fill="#FBBF24")
            draw_text(draw, (820, y+28), _v26_safe_txt(m.get("_date_title")), get_font(20), fill="#CBD5E1", max_width=210)
            draw_text(draw, (540, y+34), f"{_v26_safe_txt(m.get('team1'))} Г— {_v26_safe_txt(m.get('team2'))}", get_font(28), fill="#FFFFFF", max_width=560)
            try:
                draw.rounded_rectangle((95, y+25, 205, y+62), radius=13, fill=(2,10,27,230), outline=(251,191,36,180), width=1)
            except Exception:
                draw.rectangle((95, y+25, 205, y+62), fill=(2,10,27))
            draw_text(draw, (150, y+44), _v26_short_time(m.get("time")), get_font(21), fill="#FBBF24", max_width=96)
            y += 106

        draw.line((250, h-76, 830, h-76), fill=(255,255,255,160), width=2)
        draw_text(draw, (540, h-39), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(28), fill="#FBBF24")
        path = os.path.join(GENERATED_DIR, f"fixtures_10_v26_{page}_{datetime.now().strftime('%H%M%S')}.png")
        img.save(path, quality=96)
        paths.append(path)

    return paths


def _render_fixture_day_compact(date):
    rows = _v26_dedupe_fixture_matches(_fixtures_for_date(date))
    if not rows:
        return []

    chunks = [rows[i:i+8] for i in range(0, len(rows), 8)]
    paths = []

    for page, chunk in enumerate(chunks, 1):
        h = 1350
        img = _v26_compact_bg(1080, h)
        draw = ImageDraw.Draw(img, "RGBA")

        y = 105
        try:
            draw.rounded_rectangle((120, y, 960, y+62), radius=22, fill=(251,191,36,235))
        except Exception:
            draw.rectangle((120, y, 960, y+62), fill=(251,191,36))
        title = _v26_fixture_title(date)
        if len(chunks) > 1:
            title += f" | {page}/{len(chunks)}"
        draw_text(draw, (540, y+31), title, get_font(34), fill="#061329", max_width=780)

        y += 92
        for m in chunk:
            try:
                draw.rounded_rectangle((70, y, 1010, y+104), radius=22, fill=(5,24,58,225), outline=(38,151,255,190), width=2)
            except Exception:
                draw.rectangle((70, y, 1010, y+104), fill=(5,24,58), outline=(38,151,255), width=2)

            time_txt = _v26_short_time(m.get("time"))
            try:
                draw.rounded_rectangle((835, y+26, 982, y+70), radius=14, fill=(2,10,27,230), outline=(251,191,36,180), width=1)
            except Exception:
                draw.rectangle((835, y+26, 982, y+70), fill=(2,10,27))
            draw_text(draw, (908, y+48), time_txt, get_font(24), fill="#FBBF24", max_width=130)

            draw_text(draw, (485, y+39), f"{m.get('team1')} Г— {m.get('team2')}", get_font(30), fill="#FFFFFF", max_width=620)
            sub = _v26_safe_txt(m.get("stage"))
            if m.get("group"):
                sub += f" - {_v26_safe_txt(m.get('group'))}"
            draw_text(draw, (485, y+76), sub, get_font(21), fill="#CBD5E1", max_width=650)
            y += 122

        draw.line((250, 1238, 830, 1238), fill=(255,255,255,180), width=2)
        draw_text(draw, (540, 1284), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(30), fill="#FBBF24")

        path = os.path.join(GENERATED_DIR, f"fixtures_compact_v26_{date.replace('/','_')}_{page}.png")
        img.save(path, quality=96)
        paths.append(path)

    return paths


def _render_fixture_day_by_design(date, design=2):
    rows, simple_matches = _v26_fixture_simple_matches(date)
    if not simple_matches:
        return []

    if int(design) == 1:
        return _render_fixture_day_compact(date)

    chunks = [simple_matches[i:i+7] for i in range(0, len(simple_matches), 7)]
    paths = []

    for page_idx, chunk in enumerate(chunks, start=1):
        page_title = _v26_fixture_title(date)
        if len(chunks) > 1:
            page_title = f"{page_title} | {page_idx}/{len(chunks)}"

        path = create_matches_today_v31_full_image(page_title, chunk)
        final_path = os.path.join(
            GENERATED_DIR,
            f"fixtures_day_design2_v26_{date.replace('/','_')}_{page_idx}.png"
        )
        try:
            Image.open(path).save(final_path, quality=96)
            paths.append(final_path)
        except Exception:
            paths.append(path)

    return paths


def _fixtures_day_keyboard(date):
    rows = [
        [
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 1", callback_data=f"fx|render1|{date}"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 2", callback_data=f"fx|render2|{date}"),
        ]
    ]

    miss = [m for m in _fixtures_for_date(date) if _has_unknown(m)]
    for i, m in enumerate(miss, 1):
        rows.append([InlineKeyboardButton(f"ШӘШӯШҜЩҠШ« Щ…ШЁШ§ШұШ§Ш© {i} вҖ” {_v26_short_time(m.get('time'))}", callback_data=f"fx|upd|{m.get('id')}")])

    rows.append([InlineKeyboardButton("ШұШ¬ЩҲШ№ Щ„Щ„ШЈЩҠШ§Щ…", callback_data="fx|menu")])
    return InlineKeyboardMarkup(rows)


def _fixtures_dates_keyboard(mode="single", selected=None):
    selected = set(selected or [])
    rows = []
    row = []

    for d, day in _fixture_dates():
        label = f"{'вң… ' if d in selected else ''}{day} {d[:5]}"
        data = f"fx|toggle|{d}" if mode == "multi" else f"fx|day|{d}"
        row.append(InlineKeyboardButton(label, callback_data=data))
        if len(row) == 2:
            rows.append(row)
            row = []

    if row:
        rows.append(row)

    if mode == "multi":
        rows.append([
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ", callback_data="fx|render_combo_new"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="fx|render_combo_10"),
        ])
        rows.append([
            InlineKeyboardButton("ШӘШөЩҒЩҠШұ Ш§Щ„Ш§Ш®ШӘЩҠШ§Шұ", callback_data="fx|clear"),
            InlineKeyboardButton("ШұШ¬ЩҲШ№", callback_data="fx|menu"),
        ])
    else:
        rows.append([InlineKeyboardButton("Ш§Ш®ШӘЩҠШ§Шұ ШЈЩғШ«Шұ Щ…ЩҶ ЩҠЩҲЩ…", callback_data="fx|multi")])

    return InlineKeyboardMarkup(rows)


def _fixtures_day_text(date):
    rows, matches = _v26_fixture_simple_matches(date)
    if not matches:
        return "Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ШӘШ§ШұЩҠШ®."

    lines = [f"{_v26_fixture_title(date)}", ""]
    for i, m in enumerate(rows, 1):
        lines.append(f"{i}) {_v26_safe_txt(m.get('team1'))} Г— {_v26_safe_txt(m.get('team2'))} вҖ” {_v26_short_time(m.get('time'))}")
        extra = []
        if m.get("stage"):
            extra.append(_v26_safe_txt(m.get("stage")))
        if m.get("group"):
            extra.append(_v26_safe_txt(m.get("group")))
        if extra:
            lines.append("   " + " | ".join(extra))
        if _has_unknown(m) and m.get("note"):
            lines.append(f"   {_v26_safe_txt(m.get('note'))}")

    return "\n".join(lines)


def _v26_combo_choice_keyboard():
    return InlineKeyboardMarkup([
        [
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ", callback_data="fx|render_combo_new"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="fx|render_combo_10"),
        ]
    ])


async def fixtures_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ""
    dates = _extract_fixture_dates_from_text(text)

    if dates:
        if len(dates) == 1:
            d = dates[0]
            wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                rows, simple = _v26_fixture_simple_matches(d)
                paths = _render_fixture_day_by_design(d, design=2)
                if not paths:
                    await wait.edit_text(f"Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШЁШӘШ§ШұЩҠШ® {d}")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(update.message, p, _v26_fixtures_caption(_v26_fixture_title(d), simple, include_fantasy=True))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        # ШЈЩғШ«Шұ Щ…ЩҶ ШӘШ§ШұЩҠШ®: Щ„Ш§ ЩҠШөЩ…Щ… Щ…ШЁШ§ШҙШұШ©ШҢ ЩҠШ№Ш·ЩҠ ШІШұЩҠЩҶ
        clean_dates = []
        for d in dates:
            if d not in clean_dates:
                clean_dates.append(d)
        context.user_data["fx_selected_dates"] = clean_dates
        await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ… Щ„Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӯШҜШҜШ©:", reply_markup=_v26_combo_choice_keyboard())
        return

    await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ЩғШӘШЁ:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))


async def fixtures_combined_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    dates = _extract_fixture_dates_from_text(update.message.text)
    if not dates:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ_Щ…Ш¬Щ…Ш№Ш© 20/06 21/06 22/06")
        return

    clean_dates = []
    for d in dates:
        if d not in clean_dates:
            clean_dates.append(d)
    context.user_data["fx_selected_dates"] = clean_dates
    await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ… Щ„Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӯШҜШҜШ©:", reply_markup=_v26_combo_choice_keyboard())


async def fixtures_review_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    dates = _extract_fixture_dates_from_text(update.message.text)
    if not dates:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Щ…ШұШ§Ш¬Ш№Ш©_Щ…ШЁШ§ШұШ§Ш© 20/07")
        return
    for d in dates:
        await update.message.reply_text(_fixtures_day_text(d), reply_markup=_fixtures_day_keyboard(d))


async def fixtures_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return

    await q.answer()

    if not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return

    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else ""

    try:
        if action == "menu":
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲ Ш§ШіШӘШ®ШҜЩ… /Щ…ШЁШ§ШұЩҠШ§ШӘ 20/06", reply_markup=_fixtures_dates_keyboard("single"))
            return

        if action == "multi":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return

        if action == "toggle" and len(parts) >= 3:
            d = parts[2]
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if d in sel:
                sel.remove(d)
            else:
                sel.append(d)
            context.user_data["fx_selected_dates"] = sel
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", sel))
            return

        if action == "clear":
            context.user_data["fx_selected_dates"] = []
            await q.message.edit_text("Ш§Ш®ШӘШұ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…Ш·Щ„ЩҲШЁШ© Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„ШӘШөЩ…ЩҠЩ…:", reply_markup=_fixtures_dates_keyboard("multi", []))
            return

        if action == "day" and len(parts) >= 3:
            d = parts[2]
            await q.message.edit_text(_fixtures_day_text(d), reply_markup=_fixtures_day_keyboard(d))
            return

        if action in ["render1", "render2"] and len(parts) >= 3:
            d = parts[2]
            design = 1 if action == "render1" else 2
            wait = await q.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
            try:
                rows, simple = _v26_fixture_simple_matches(d)
                paths = _render_fixture_day_by_design(d, design=design)
                if not paths:
                    await wait.edit_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ….")
                    return
                try:
                    await wait.delete()
                except Exception:
                    pass
                for p in paths:
                    await send_photo_path(q.message, p, _v26_fixtures_caption(_v26_fixture_title(d), simple, include_fantasy=True))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ЩҠЩҲЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        if action in ["render_combo_new", "render_combo_10", "render_combo"]:
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if not sel:
                await q.message.reply_text("Ш§Ш®ШӘШұ ЩҠЩҲЩ…ЩӢШ§ ЩҲШ§ШӯШҜЩӢШ§ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
                return

            title = "Ш§Щ„ШӘШөЩ…ЩҠЩ… Ш§Щ„Ш¬ШҜЩҠШҜ" if action != "render_combo_10" else "ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ"
            wait = await q.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… {title}...")
            try:
                if action == "render_combo_10":
                    paths = _v26_render_fixtures_10_images(sel)
                else:
                    paths = render_fixtures_combined_images(sel)

                if not paths:
                    await wait.edit_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„Щ„ШӘЩҲШ§ШұЩҠШ® Ш§Щ„Щ…ШӯШҜШҜШ©.")
                    return

                try:
                    await wait.delete()
                except Exception:
                    pass

                for p in paths:
                    await send_photo_path(q.message, p, _v26_fixtures_caption("Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…Ш¬Щ…Ш№Ш©", [], include_fantasy=False))
            except Exception as e:
                await wait.edit_text(f"ШӘШ№Ш°Шұ Ш§Щ„ШӘШөЩ…ЩҠЩ… вқҢ\nШ§Щ„ШіШЁШЁ: {str(e)[:400]}")
            return

        # ШӘЩҲШ§ЩҒЩӮ ЩӮШҜЩҠЩ… Щ„ЩҲ ЩҒЩҠЩҮ ШІШұ render_each
        if action == "render_each":
            sel = list(context.user_data.get("fx_selected_dates") or [])
            if not sel:
                await q.message.reply_text("Ш§Ш®ШӘШұ ЩҠЩҲЩ…ЩӢШ§ ЩҲШ§ШӯШҜЩӢШ§ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
                return
            for d in sel:
                rows, simple = _v26_fixture_simple_matches(d)
                for p in _render_fixture_day_by_design(d, design=2):
                    await send_photo_path(q.message, p, _v26_fixtures_caption(_v26_fixture_title(d), simple, include_fantasy=True))
            return

        if action == "upd" and len(parts) >= 3:
            mid = parts[2]
            m = _fixture_by_id(mid)
            if not m:
                await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.")
                return

            context.user_data["fixture_update_match_id"] = mid
            await q.message.reply_text(
                f"Ш§ЩғШӘШЁ Ш·ШұЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„ЩҖ {mid} ({m.get('date')} {_v26_short_time(m.get('time'))}) ЩғШ°Ш§:\n"
                "Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„ * Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ\n\n"
                "Щ…Ш«Ш§Щ„: Ш§Щ„Щ…ЩғШіЩҠЩғ * ШЈШіШӘШұШ§Щ„ЩҠШ§\n"
                "Щ…Щ„Ш§ШӯШёШ©: ШіЩҠШӘЩ… Ш§Щ„ШӯЩҒШё ЩҒЩӮШ·ШҢ ЩҲЩ„ЩҶ ЩҠШӘЩ… Ш§Щ„ШӘШөЩ…ЩҠЩ… ШҘЩ„Ш§ Ш№ЩҶШҜЩ…Ш§ ШӘШ·Щ„ШЁ /Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӘШ§ШұЩҠШ®."
            )
            return

        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")
    except Exception as e:
        await q.message.reply_text(f"ШӘШ№Ш°Шұ ШӘЩҶЩҒЩҠШ° Ш®ЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ вқҢ\n{str(e)[:400]}")


async def fixtures_update_text_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    mid = context.user_data.get("fixture_update_match_id")
    if not mid:
        return

    text = (update.message.text or "").strip()

    if "*" in text:
        a, b = [x.strip() for x in text.split("*", 1)]
    elif "Г—" in text:
        a, b = [x.strip() for x in text.split("Г—", 1)]
    elif "-" in text:
        a, b = [x.strip() for x in text.split("-", 1)]
    else:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§: Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„ * Ш§Щ„ЩҒШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ")
        return

    if not a or not b:
        await update.message.reply_text("Ш§ЩғШӘШЁ Ш§ШіЩ… Ш§Щ„ЩҒШұЩҠЩӮЩҠЩҶ ЩғШ§Щ…Щ„ЩҠЩҶ.")
        return

    data = _load_fixture_updates()
    data.setdefault(mid, {})
    data[mid]["team1"] = canonical_team_name(a) or normalize_name(a)
    data[mid]["team2"] = canonical_team_name(b) or normalize_name(b)
    _save_fixture_updates(data)

    context.user_data.pop("fixture_update_match_id", None)

    m = _apply_fixture_updates(_fixture_by_id(mid) or {"id": mid})
    await update.message.reply_text(
        f"вң… ШӘЩ… ШӯЩҒШё ШӘШӯШҜЩҠШ« Ш§Щ„Щ…ШЁШ§ШұШ§Ш©\n"
        f"{m.get('team1')} Г— {m.get('team2')} вҖ” {_v26_short_time(m.get('time', ''))}\n\n"
        f"Щ„ЩҶ ШЈШөЩ…Щ… Ш§Щ„ШўЩҶ. ЩҲЩӮШӘ Щ…Ш§ ШӘШЁЩҠЩҮШ§ Ш§ЩғШӘШЁ:\n/Щ…ШЁШ§ШұЩҠШ§ШӘ {m.get('date', '')}"
    )


def _v26_extract_name_after_command(text, mode="add"):
    s = normalize_name(text or "")
    if mode == "add":
        pat = r"^/(?:ШҘШ¶Ш§ЩҒШ©_Щ…ШӘШіШ§ШЁЩӮ|Ш§Ш¶Ш§ЩҒШ©_Щ…ШӘШіШ§ШЁЩӮ|ШҘШ¶Ш§ЩҒЩҮ_Щ…ШӘШіШ§ШЁЩӮ|Ш§Ш¶Ш§ЩҒЩҮ_Щ…ШӘШіШ§ШЁЩӮ|ШҘШ¶Ш§ЩҒШ©\s+Щ…ШӘШіШ§ШЁЩӮ|Ш§Ш¶Ш§ЩҒШ©\s+Щ…ШӘШіШ§ШЁЩӮ|ШҘШ¶Ш§ЩҒЩҮ\s+Щ…ШӘШіШ§ШЁЩӮ|Ш§Ш¶Ш§ЩҒЩҮ\s+Щ…ШӘШіШ§ШЁЩӮ)\s*"
    else:
        pat = r"^/(?:ШӯШ°ЩҒ_Щ…ШӘШіШ§ШЁЩӮ|Ш§ШІШ§Щ„Ш©_Щ…ШӘШіШ§ШЁЩӮ|ШҘШІШ§Щ„Ш©_Щ…ШӘШіШ§ШЁЩӮ|ШӯШ°ЩҒ\s+Щ…ШӘШіШ§ШЁЩӮ|Ш§ШІШ§Щ„Ш©\s+Щ…ШӘШіШ§ШЁЩӮ|ШҘШІШ§Щ„Ш©\s+Щ…ШӘШіШ§ШЁЩӮ)\s*"
    s = re.sub(pat, "", s, flags=re.I).strip()
    return normalize_name(s)


async def add_participant_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    name = _v26_extract_name_after_command(update.message.text, "add")
    if not name:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШҘШ¶Ш§ЩҒШ©_Щ…ШӘШіШ§ШЁЩӮ Ш№ШЁШҜШ§Щ„Щ„ЩҮ Щ…ШӯЩ…ШҜ")
        return
    if name in PARTICIPANTS:
        await update.message.reply_text(f"вң… {name} Щ…ЩҲШ¬ЩҲШҜ Щ…ШіШЁЩӮЩӢШ§ ЩҒЩҠ ЩӮШ§ШҰЩ…Ш© Ш§Щ„Щ…ШӘШіШ§ШЁЩӮЩҠЩҶ")
        return
    PARTICIPANTS.append(name)
    _save_participants_state()
    await update.message.reply_text(f"вң… ШӘЩ…ШӘ ШҘШ¶Ш§ЩҒШ© Ш§Щ„Щ…ШӘШіШ§ШЁЩӮ: {name}\nШ§Щ„Щ…Ш¬Щ…ЩҲШ№ Ш§Щ„ШӯШ§Щ„ЩҠ: {len(PARTICIPANTS)}")


async def remove_participant_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    name = _v26_extract_name_after_command(update.message.text, "remove")
    if not name:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӯШ°ЩҒ_Щ…ШӘШіШ§ШЁЩӮ Ш№ШЁШҜШ§Щ„Щ„ЩҮ Щ…ШӯЩ…ШҜ")
        return
    target = name if name in PARTICIPANTS else None
    if not target:
        close = difflib.get_close_matches(name, PARTICIPANTS, n=1, cutoff=0.75)
        target = close[0] if close else None
    if not target:
        await update.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Ш§Щ„Щ…ШӘШіШ§ШЁЩӮ: {name} вқҢ")
        return
    PARTICIPANTS.remove(target)
    _save_participants_state()
    await update.message.reply_text(f"вң… ШӘЩ… ШӯШ°ЩҒ Ш§Щ„Щ…ШӘШіШ§ШЁЩӮ: {target}\nШ§Щ„Щ…Ш¬Щ…ЩҲШ№ Ш§Щ„ШӯШ§Щ„ЩҠ: {len(PARTICIPANTS)}")


def _v26_is_import_command_text(text):
    s = normalize_name(text or "")
    return bool(re.match(r"^/(?:Ш§ШіШӘЩҠШұШ§ШҜ_Щ…Щ„ЩҒ|Ш§ШіШӘЩҠШұШ§ШҜ\s+Щ…Щ„ЩҒ|Ш§ШіШӘЩҠШұШ§ШҜ|Ш§ШіШӘЩҠШұШ§ШҜ_Ш§ЩғШіЩ„|Ш§ШіШӘЩҠШұШ§ШҜ_ШҘЩғШіЩ„|Ш§ШіШӘЩҠШұШ§ШҜ_excel)(?:\s|$)", s))


def _v26_find_latest_excel_for_chat(chat_id):
    candidates = []
    for folder in ["uploads", "imports"]:
        if not os.path.isdir(folder):
            continue
        for name in os.listdir(folder):
            low = name.lower()
            if not low.endswith((".xlsx", ".xlsm")):
                continue
            # Ш§Щ„Щ…Щ„ЩҒШ§ШӘ Ш§Щ„Щ…ШӯЩҒЩҲШёШ© ШӘШЁШҜШЈ ШәШ§Щ„ШЁЩӢШ§ ШЁШұЩӮЩ… Ш§Щ„ШҙШ§ШӘ
            p = os.path.join(folder, name)
            if str(chat_id) in name or True:
                try:
                    candidates.append((os.path.getmtime(p), p))
                except Exception:
                    pass
    if not candidates:
        return None
    candidates.sort(reverse=True)
    return candidates[0][1]


async def _v26_run_import_from_path(update: Update, context: ContextTypes.DEFAULT_TYPE, local_path):
    if not local_path or not os.path.exists(local_path):
        await update.message.reply_text("Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„ ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ. ШЈШұШіЩ„ЩҮ Щ…ШұШ© Ш«Ш§ЩҶЩҠШ©.")
        return
    wait = await update.message.reply_text("вҸі Ш¬Ш§ШұЩҠ ЩӮШұШ§ШЎШ© Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„...")
    try:
        imported = await asyncio.wait_for(asyncio.to_thread(parse_import_excel, local_path), timeout=60)
    except Exception as e:
        await wait.edit_text(f"ШөШ§Шұ Ш®Ш·ШЈ ШЈШ«ЩҶШ§ШЎ ЩӮШұШ§ШЎШ© Ш§Щ„ШҘЩғШіЩ„ вқҢ\n{str(e)[:500]}")
        return
    if not imported:
        await wait.edit_text("Щ…Ш§ ЩӮШҜШұШӘ ШЈШіШӘШ®ШұШ¬ ШЈЩҠШ§Щ… Щ…ЩҶ Ш§Щ„Щ…Щ„ЩҒ. ШӘШЈЩғШҜ ШЈЩҶ Ш§Щ„ШөЩҒШӯШ§ШӘ ШЁШ§ШіЩ…: ЩҠЩҲЩ… 1ШҢ ЩҠЩҲЩ… 2 ...")
        return
    chat_id = update.effective_chat.id
    PENDING_IMPORTS[chat_id] = {"path": local_path, "data": imported}
    await wait.edit_text(import_summary_text(imported))


async def import_excel_file(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id
    document = update.message.document

    if document:
        filename = document.file_name or "import.xlsx"
        if not filename.lower().endswith((".xlsx", ".xlsm")):
            await update.message.reply_text("Ш§Щ„Щ…Щ„ЩҒ Щ„Ш§ШІЩ… ЩҠЩғЩҲЩҶ Excel ШЁШөЩҠШәШ© .xlsx ШЈЩҲ .xlsm")
            return
        local_path, _ = await _download_document_to_folder(update, context, "imports")
        LAST_UPLOADED_FILES.setdefault(chat_id, {})["excel"] = local_path
        await _v26_run_import_from_path(update, context, local_path)
        return

    local_path = LAST_UPLOADED_FILES.get(chat_id, {}).get("excel")
    if not local_path or not os.path.exists(local_path):
        local_path = _v26_find_latest_excel_for_chat(chat_id)

    if not local_path or not os.path.exists(local_path):
        await update.message.reply_text(
            "Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„ЩҒ Excel Щ…ШӯЩҒЩҲШё.\n"
            "ШЈШұШіЩ„ Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„ Щ„ШӯШ§Щ„ЩҮ ШЈЩҲЩ„ЩӢШ§ШҢ ЩҲШЁШ№ШҜЩҮШ§ Ш§ЩғШӘШЁ:\n"
            "/Ш§ШіШӘЩҠШұШ§ШҜ_Щ…Щ„ЩҒ"
        )
        return

    LAST_UPLOADED_FILES.setdefault(chat_id, {})["excel"] = local_path
    await _v26_run_import_from_path(update, context, local_path)


async def remember_last_file(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    ШӯЩҒШё Щ…Щ„ЩҒШ§ШӘ Excel/ZIPШҢ Щ…Ш№ ШҜШ№Щ… ЩғШ§ШЁШҙЩҶ Ш§Щ„Ш§ШіШӘЩҠШұШ§ШҜ ШЁЩғЩ„ Ш§Щ„ШөЩҠШә.
    """
    local_path, filename = await _download_document_to_folder(update, context, "uploads")
    if not local_path:
        return

    chat_id = update.effective_chat.id
    LAST_UPLOADED_FILES.setdefault(chat_id, {})
    lower = (filename or "").lower()
    caption = (update.message.caption or "").strip()

    if lower.endswith((".xlsx", ".xlsm")):
        LAST_UPLOADED_FILES[chat_id]["excel"] = local_path
        if _v26_is_import_command_text(caption):
            await _v26_run_import_from_path(update, context, local_path)
        else:
            await update.message.reply_text(
                "ЩҲШөЩ„ Щ…Щ„ЩҒ Ш§Щ„ШҘЩғШіЩ„ вң…\n"
                "Ш§ЩғШӘШЁ Ш§Щ„ШўЩҶ:\n"
                "/Ш§ШіШӘЩҠШұШ§ШҜ_Щ…Щ„ЩҒ"
            )
        return

    if lower.endswith(".zip"):
        LAST_UPLOADED_FILES[chat_id]["zip"] = local_path
        if caption.startswith("/Ш§ШіШӘШұШ¬Ш§Ш№_ЩҶШіШ®Ш©"):
            await _run_restore_from_zip_path(update, context, local_path)
        else:
            await update.message.reply_text(
                "ЩҲШөЩ„ Щ…Щ„ЩҒ ZIP вң…\n"
                "Щ„Щ„Ш§ШіШӘШұШ¬Ш§Ш№ Ш§ЩғШӘШЁ Ш§Щ„ШўЩҶ:\n"
                "/Ш§ШіШӘШұШ¬Ш§Ш№_ЩҶШіШ®Ш©"
            )
        return

    await update.message.reply_text("ЩҲШөЩ„ Ш§Щ„Щ…Щ„ЩҒ вң…")


# ==================== V28 RESULTS + ESPN SCORERS + RTL STANDINGS ====================
# Ш§Щ„Ш§Ш№ШӘЩ…Ш§ШҜ:
# - /Щ…ШЁШ§ШұЩҠШ§ШӘ: ЩҠШ№ШұШ¶ Щ…ЩҶ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҠЩҲЩ… ЩҒЩ…Ш§ ШЁШ№ШҜ ЩҒЩӮШ·.
# - /ЩҶШӘШ§ШҰШ¬_Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ: ЩҠШ№ШұШ¶ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„ШіШ§ШЁЩӮШ© ЩҒЩӮШ·ШҢ ЩҲЩ„Ш§ ЩҠШӯШ°ЩҒ Ш§Щ„ШіШ§ШЁЩӮ.
# - Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШ§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPNШҢ ЩҲШ§Щ„ШӘЩҲШ§ШұЩҠШ®/Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ЩҶ PDF.
# - /Щ…ШЁШ§ШҙШұ: ЩҠШ«ШұЩҠ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN.
# - ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҠШЁШҜШЈ Щ…ЩҶ Ш§Щ„ЩҠЩ…ЩҠЩҶШҢ ЩҲШҜШ§Ш®Щ„ Ш§Щ„Ш¬ШҜЩҲЩ„: Ш§Щ„Щ…ЩҶШӘШ®ШЁ | Щ„Ш№ШЁ | ЩҒШ§ШұЩӮ | ЩҶЩӮШ§Ш·.

def _v28_riyadh_today():
    try:
        return (datetime.utcnow() + timedelta(hours=3)).date()
    except Exception:
        return datetime.now().date()


def _v28_date_tuple(d):
    try:
        d = _normalize_date_arg(d)
        a, b, c = d.split("/")
        return (int(c), int(b), int(a))
    except Exception:
        return (9999, 99, 99)


def _v28_today_tuple():
    t = _v28_riyadh_today()
    return (t.year, t.month, t.day)


def _v28_is_past_date(d):
    return _v28_date_tuple(d) < _v28_today_tuple()


def _v28_is_today_or_future_date(d):
    return _v28_date_tuple(d) >= _v28_today_tuple()


def _v28_espn_date(d):
    d = _normalize_date_arg(d)
    try:
        day, mo, year = d.split("/")
        return f"{int(year):04d}{int(mo):02d}{int(day):02d}"
    except Exception:
        return ""


def _v28_short_time(t):
    try:
        return _v26_short_time(t)
    except Exception:
        return str(t or "").strip()


def _v28_team_same(a, b):
    ca = canonical_team_name(a) or normalize_name(a)
    cb = canonical_team_name(b) or normalize_name(b)
    if ca == cb:
        return True
    try:
        sa = simple_key(ca)
        sb = simple_key(cb)
        return sa == sb or sa in sb or sb in sa
    except Exception:
        return False


def _v28_event_competitors(event):
    try:
        comp = (event.get("competitions") or [event])[0]
        return comp, comp.get("competitors") or []
    except Exception:
        return {}, []


def _v28_event_match_obj(event, req1, req2):
    comp, competitors = _v28_event_competitors(event)
    if len(competitors) < 2:
        return None

    teams = []
    for c in competitors:
        name = ((c.get("team") or {}).get("displayName")
                or (c.get("team") or {}).get("shortDisplayName")
                or (c.get("team") or {}).get("name")
                or c.get("displayName")
                or "")
        teams.append((name, c))

    if not _teams_match(teams[0][0], teams[1][0], req1, req2):
        return None

    s1 = s2 = None
    for name, c in teams:
        score = c.get("score", "")
        if isinstance(score, dict):
            score = score.get("value") or score.get("displayValue") or score.get("score")
        score = str(score if score is not None else "")
        if _v28_team_same(name, req1):
            s1 = score
        elif _v28_team_same(name, req2):
            s2 = score

    if s1 is None:
        s1 = str(teams[0][1].get("score", "0"))
    if s2 is None:
        s2 = str(teams[1][1].get("score", "0"))

    status = comp.get("status") or event.get("status") or {}
    st_type = status.get("type") or {}
    detail = normalize_name(st_type.get("detail") or status.get("displayClock") or "")
    short_detail = normalize_name(st_type.get("shortDetail") or "")
    state = normalize_name(st_type.get("name") or st_type.get("state") or "")
    status_ar = _normalize_status_text(detail or short_detail or state) if '_normalize_status_text' in globals() else (detail or short_detail or state)

    event_id = str(event.get("id") or comp.get("id") or "")
    obj = {
        "team1": canonical_team_name(req1) or normalize_name(req1),
        "team2": canonical_team_name(req2) or normalize_name(req2),
        "score1": s1 or "0",
        "score2": s2 or "0",
        "status": status_ar,
        "minute": detail or short_detail or "",
        "event_id": event_id,
        "source": "ESPN",
        "actual_source": "ESPN",
        "goals_source": "",
        "scorers": [],
        "summary_url": f"https://www.espn.com/soccer/match/_/gameId/{event_id}" if event_id else "",
    }

    scorers = []
    # ШЈШӯЩҠШ§ЩҶЩӢШ§ ШӘЩғЩҲЩҶ ШЁШ№Ш¶ Ш§Щ„ШЈШӯШҜШ§Ш« ШҜШ§Ш®Щ„ scoreboard
    try:
        for d in comp.get("details", []) or []:
            txt = normalize_name(d.get("text") or d.get("detail") or d.get("description") or "")
            if txt and re.search(r"\bgoal\b|ЩҮШҜЩҒ|scores", txt, re.I):
                scorers.append(txt)
    except Exception:
        pass

    if event_id:
        scorers2 = _v28_fetch_espn_scorers(event_id)
        if scorers2:
            scorers = scorers2

    obj["scorers"] = _v28_sanitize_scorers(scorers)
    obj["goals_source"] = "ESPN" if obj["scorers"] else "ШәЩҠШұ Щ…ШӘЩҲЩҒШұ"
    return obj


def _v28_walk_json(obj):
    stack = [obj]
    while stack:
        x = stack.pop()
        yield x
        if isinstance(x, dict):
            stack.extend(x.values())
        elif isinstance(x, list):
            stack.extend(x)


def _v28_clean_scorer_name(name):
    name = str(name or "").strip()
    name = re.sub(r"\s+", " ", name)
    name = re.sub(r"^(Goal|Penalty Goal|Own Goal)\s*[-:]\s*", "", name, flags=re.I).strip()
    name = re.sub(r"\s+(Goal|scores|scored).*$", "", name, flags=re.I).strip()
    name = name.strip(" -вҖ“вҖ”:вҖў|ШҢ")
    if len(name) < 2 or len(name) > 60:
        return ""
    bad = ["goal", "scores", "world cup", "fifa", "team", "match", "highlight", "video", "espn"]
    if name.lower() in bad:
        return ""
    return name


def _v28_extract_minutes(text):
    text = str(text or "")
    vals = []
    for m in re.finditer(r"(\d{1,3}(?:\+\d{1,2})?)\s*['вҖҷ]", text):
        vals.append(m.group(1) + "'")
    # ШЈШӯЩҠШ§ЩҶЩӢШ§ Ш§Щ„ШҜЩӮЩҠЩӮШ© ШұЩӮЩ… ШЁШҜЩҲЩҶ Ш№Щ„Ш§Щ…Ш© ШЁШ¬Ш§ЩҶШЁ ЩғЩ„Щ…Ш© goal
    if not vals:
        for m in re.finditer(r"(?:minute|min|ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮШ©)\s*(\d{1,3}(?:\+\d{1,2})?)", text, re.I):
            vals.append(m.group(1) + "'")
    return vals


def _v28_records_to_lines(records):
    by = {}
    for name, minutes in records:
        name = _v28_clean_scorer_name(name)
        if not name:
            continue
        by.setdefault(name, [])
        if isinstance(minutes, str):
            minutes = _v28_extract_minutes(minutes) or ([minutes] if minutes.strip() else [])
        for mn in minutes or []:
            mn = str(mn).strip()
            if mn and not mn.endswith("'") and re.fullmatch(r"\d{1,3}(?:\+\d{1,2})?", mn):
                mn += "'"
            if mn and mn not in by[name]:
                by[name].append(mn)

    lines = []
    for name, mins in by.items():
        if mins:
            lines.append(f"{name} вҖ” {'ШҢ '.join(mins)}")
        else:
            lines.append(name)
    return lines[:10]


def _v28_extract_scorers_from_json(data):
    records = []

    # 1) ШөЩҠШә ЩҶШөЩҠШ© Щ…ШЁШ§ШҙШұШ© Щ…Ш«Щ„: Brian Brobbey - 5', 17'
    try:
        dump = json.dumps(data, ensure_ascii=False)
    except Exception:
        dump = str(data)
    for m in re.finditer(r"([A-Z][A-Za-zГҖ-Г–Гҳ-Г¶Гё-Гҝ'\-. ]{2,60})\s*[-вҖ“вҖ”]\s*((?:\d{1,3}(?:\+\d{1,2})?['вҖҷ]\s*,?\s*)+)", dump):
        name = _v28_clean_scorer_name(m.group(1))
        mins = _v28_extract_minutes(m.group(2))
        if name and mins:
            records.append((name, mins))

    # 2) ШӘЩҒШ§ШөЩҠЩ„ ШЈШӯШҜШ§Ш« ESPN
    for node in _v28_walk_json(data):
        if not isinstance(node, dict):
            continue

        # ЩҶШө Ш§Щ„ШӯШҜШ« ЩҲЩҶЩҲШ№ЩҮ
        fields = []
        for k in ["text", "description", "detail", "displayText", "shortText", "headline", "summary", "type", "playType", "eventType"]:
            v = node.get(k)
            if isinstance(v, dict):
                fields.extend(str(v.get(x, "")) for x in ["name", "displayName", "text", "description"])
            elif v is not None:
                fields.append(str(v))
        type_obj = node.get("type")
        if isinstance(type_obj, dict):
            fields.extend(str(type_obj.get(x, "")) for x in ["name", "displayName", "text", "description", "abbreviation"])
        blob = " ".join(fields)
        if not re.search(r"\bgoal\b|\bscores\b|\bscored\b|ЩҮШҜЩҒ", blob, re.I):
            continue
        if re.search(r"goals against|goals for|total goals|expected goals", blob, re.I):
            continue

        # Ш§ШіЩ… Ш§Щ„Щ„Ш§Ш№ШЁ Щ…ЩҶ athlete/player/participant ШЈЩҲ Щ…ЩҶ Ш§Щ„ЩҶШө
        name = ""
        for k in ["athlete", "player", "participant", "scorer"]:
            v = node.get(k)
            if isinstance(v, dict):
                name = v.get("displayName") or v.get("shortName") or v.get("name") or ""
                if name:
                    break
        if not name:
            # Brian Brobbey Goal - Header - 5'
            m = re.search(r"([A-Z][A-Za-zГҖ-Г–Гҳ-Г¶Гё-Гҝ'\-. ]{2,60})\s+(?:Goal|scores|scored)\b", blob, re.I)
            if m:
                name = m.group(1)
        if not name:
            m = re.search(r"([A-Z][A-Za-zГҖ-Г–Гҳ-Г¶Гё-Гҝ'\-. ]{2,60})\s*[-вҖ“вҖ”]\s*\d{1,3}", blob)
            if m:
                name = m.group(1)

        minutes = []
        for k in ["clock", "time", "minute", "displayTime", "shortDisplayTime", "gameTime"]:
            v = node.get(k)
            if isinstance(v, dict):
                v = v.get("displayValue") or v.get("value") or v.get("text") or ""
            if v is not None:
                minutes.extend(_v28_extract_minutes(str(v)))
                if not minutes and re.fullmatch(r"\d{1,3}(?:\+\d{1,2})?", str(v).strip()):
                    minutes.append(str(v).strip() + "'")
        minutes.extend(_v28_extract_minutes(blob))

        if name:
            records.append((name, minutes))

    return _v28_records_to_lines(records)


def _v28_fetch_json_urls(urls, timeout=14):
    if not requests:
        return None
    for url in urls:
        try:
            r = _requests_get(url, timeout=timeout)
            if int(getattr(r, "status_code", 200) or 200) >= 400:
                continue
            return r.json()
        except Exception:
            continue
    return None


def _v28_fetch_espn_scorers(event_id):
    if not event_id:
        return []
    urls = [
        f"https://site.api.espn.com/apis/site/v2/sports/soccer/fifa.world/summary?event={event_id}",
        f"https://site.web.api.espn.com/apis/site/v2/sports/soccer/fifa.world/summary?event={event_id}",
        f"https://site.api.espn.com/apis/site/v2/sports/soccer/all/summary?event={event_id}",
        f"https://site.web.api.espn.com/apis/site/v2/sports/soccer/all/summary?event={event_id}",
    ]
    data = _v28_fetch_json_urls(urls, timeout=14)
    if not data:
        return []
    return _v28_extract_scorers_from_json(data)


def _v28_sanitize_scorers(items):
    out = []
    for item in items or []:
        s = normalize_name(item)
        s = re.sub(r"\s+", " ", s).strip()
        # ЩҶШіЩ…Шӯ ШЁШ§Щ„ШҘЩҶШ¬Щ„ЩҠШІЩҠ Щ„ШЈЩҶ ESPN ЩҠШұШ¬Ш№ ШЈШіЩ…Ш§ШЎ Ш§Щ„Щ„Ш§Ш№ШЁЩҠЩҶ ШЁШ§Щ„ШҘЩҶШ¬Щ„ЩҠШІЩҠ ШәШ§Щ„ШЁЩӢШ§
        if not s or len(s) > 90:
            continue
        if re.search(r"goals against|goals for|expected goals|highlight|video|Щ…Щ„Ш®Шө", s, re.I):
            continue
        if s not in out:
            out.append(s)
    return out[:10]


def _v28_espn_date_candidates(date_hint=None):
    dates = []
    if date_hint:
        d = _normalize_date_arg(date_hint)
        if d:
            dates.append(_v28_espn_date(d))
        elif re.fullmatch(r"\d{8}", str(date_hint or "")):
            dates.append(str(date_hint))
    today = _v28_riyadh_today()
    for off in range(-4, 3):
        dates.append((today + timedelta(days=off)).strftime("%Y%m%d"))
    # ЩҶШ¶ЩҠЩҒ ШЈЩҠШ§Щ… Щ…Щ„ЩҒ PDF Ш§Щ„ЩӮШұЩҠШЁШ© ЩҒЩӮШ· Ш№ШҙШ§ЩҶ Щ„Ш§ ЩҠШ·ЩҲЩ„ Ш§Щ„ШЁШӯШ«
    try:
        pdf_dates = [d for d, _dy in _fixture_dates()]
        pdf_dates = sorted(pdf_dates, key=_v28_date_tuple)
        for d in pdf_dates:
            if abs((_v28_date_tuple(d)[0]*372 + _v28_date_tuple(d)[1]*31 + _v28_date_tuple(d)[2]) - (today.year*372 + today.month*31 + today.day)) <= 10:
                dates.append(_v28_espn_date(d))
    except Exception:
        pass
    out, seen = [], set()
    for d in dates:
        if d and d not in seen:
            seen.add(d)
            out.append(d)
    return out


def _v28_fetch_espn_match(team1, team2, date_hint=None):
    for d in _v28_espn_date_candidates(date_hint):
        for event in _fetch_espn_events_by_date(d):
            obj = _v28_event_match_obj(event, team1, team2)
            if obj:
                return obj
    return None


def _v28_fetch_espn_match_by_fixture(date, fixture):
    espn_date = _v28_espn_date(date)
    for event in _fetch_espn_events_by_date(espn_date):
        obj = _v28_event_match_obj(event, fixture.get("team1"), fixture.get("team2"))
        if obj:
            return obj
    return None


_v28_old_fetch_live_match_data = fetch_live_match_data

def fetch_live_match_data(team1, team2, mode="google", date_hint=None):
    """
    ЩҶШіШӘШ®ШҜЩ… Ш§Щ„Щ…ЩҶШ·ЩӮ Ш§Щ„ЩӮШҜЩҠЩ… Щ„Щ„ЩҶШӘЩҠШ¬Ш©ШҢ Ш«Щ… ЩҶШ«ШұЩҠ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN ШҘШ°Ш§ ШӘЩҲЩҒШұЩҲШ§.
    """
    old_obj = None
    try:
        old_obj = _v28_old_fetch_live_match_data(team1, team2, mode, date_hint)
    except Exception:
        old_obj = None

    espn_obj = None
    try:
        espn_obj = _v28_fetch_espn_match(team1, team2, date_hint)
    except Exception:
        espn_obj = None

    if old_obj:
        scorers = _v28_sanitize_scorers(old_obj.get("scorers") or [])
        if (not scorers) and espn_obj and espn_obj.get("scorers"):
            old_obj["scorers"] = espn_obj.get("scorers")
            old_obj["goals_source"] = "ESPN"
            if espn_obj.get("summary_url"):
                old_obj["summary_url"] = espn_obj.get("summary_url")
        elif scorers:
            old_obj["scorers"] = scorers
        return old_obj

    return espn_obj


def _v28_previous_result_dates():
    out = []
    for d, day in _fixture_dates():
        if _v28_is_past_date(d):
            out.append((d, day))
    return out


def _v28_previous_results_keyboard():
    rows, row = [], []
    for d, day in _v28_previous_result_dates():
        row.append(InlineKeyboardButton(f"{day} {d[:5]}", callback_data=f"res|day|{d}"))
        if len(row) == 2:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    return InlineKeyboardMarkup(rows)


def _v28_result_text_for_date(date):
    d = _normalize_date_arg(date)
    matches = _v26_dedupe_fixture_matches(_fixtures_for_date(d)) if '_v26_dedupe_fixture_matches' in globals() else _fixtures_for_date(d)
    if not matches:
        return f"Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШЁШӘШ§ШұЩҠШ® {d}"

    title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
    lines = [f"рҹҸҶ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘ {title} рҹҸҶ", "Ш§Щ„Щ…ШөШҜШұ: ESPN", ""]

    for i, m in enumerate(matches, start=1):
        obj = _v28_fetch_espn_match_by_fixture(d, m)
        if obj:
            lines.append(f"{i}) {m.get('team1')} {obj.get('score1','-')} - {obj.get('score2','-')} {m.get('team2')}")
            scorers = _v28_sanitize_scorers(obj.get("scorers") or [])
            if scorers:
                lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ:")
                for s in scorers[:8]:
                    lines.append(f"- {s}")
            else:
                lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ: ШәЩҠШұ Щ…ШӘЩҲЩҒШұЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
        else:
            lines.append(f"{i}) {m.get('team1')} Г— {m.get('team2')} вҖ” Щ„Щ… ШӘШӘЩҲЩҒШұ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ШЁШ№ШҜ")
            lines.append("вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ: ШәЩҠШұ Щ…ШӘЩҲЩҒШұЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
        lines.append("")

    lines.append("Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«")
    return "\n".join(lines).strip()


async def previous_results_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    dates = _extract_fixture_dates_from_text(update.message.text)
    if dates:
        d = dates[0]
        wait = await update.message.reply_text("вҸі ШЈШіШӯШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШ§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN...")
        try:
            text = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d), timeout=35)
            await wait.edit_text(text)
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҶШӘШ§ШҰШ¬ ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ… вқҢ\n{str(e)[:400]}")
        return

    prev = _v28_previous_result_dates()
    if not prev:
        await update.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ШіШ§ШЁЩӮШ© Щ„Щ„ЩҶШӘШ§ШҰШ¬ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
        return

    await update.message.reply_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())


async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    if not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    parts = (q.data or "").split("|")
    if len(parts) >= 3 and parts[1] == "day":
        d = parts[2]
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШ§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN...")
        try:
            text = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d), timeout=35)
            await wait.edit_text(text)
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҶШӘШ§ШҰШ¬ ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ… вқҢ\n{str(e)[:400]}")
        return


def _fixtures_dates_keyboard(mode="single", selected=None):
    """
    /Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҠШ№ШұШ¶ Щ…ЩҶ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ШӯШ§Щ„ЩҠ ЩҒЩ…Ш§ ШЁШ№ШҜ ЩҒЩӮШ·.
    """
    selected = set(selected or [])
    rows = []
    row = []

    source_dates = []
    for d, day in _fixture_dates():
        if mode == "multi":
            if _v28_is_today_or_future_date(d):
                source_dates.append((d, day))
        else:
            if _v28_is_today_or_future_date(d):
                source_dates.append((d, day))

    for d, day in source_dates:
        label = f"{'вң… ' if d in selected else ''}{day} {d[:5]}"
        data = f"fx|toggle|{d}" if mode == "multi" else f"fx|day|{d}"
        row.append(InlineKeyboardButton(label, callback_data=data))
        if len(row) == 2:
            rows.append(row)
            row = []

    if row:
        rows.append(row)

    if mode == "multi":
        rows.append([
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… Ш¬ШҜЩҠШҜ", callback_data="fx|render_combo_new"),
            InlineKeyboardButton("ШӘШөЩ…ЩҠЩ… 10 Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="fx|render_combo_10"),
        ])
        rows.append([
            InlineKeyboardButton("ШӘШөЩҒЩҠШұ Ш§Щ„Ш§Ш®ШӘЩҠШ§Шұ", callback_data="fx|clear"),
            InlineKeyboardButton("ШұШ¬ЩҲШ№", callback_data="fx|menu"),
        ])
    else:
        rows.append([InlineKeyboardButton("Ш§Ш®ШӘЩҠШ§Шұ ШЈЩғШ«Шұ Щ…ЩҶ ЩҠЩҲЩ…", callback_data="fx|multi")])

    return InlineKeyboardMarkup(rows)


def _v28_standings_card(draw, img, box, title, rows, compact=False):
    x, y, x2, y2 = box
    w = x2 - x
    try:
        rounded_rect(draw, (x, y, x2, y2), radius=28, fill="#0638A5E8", outline="#14B8F5", width=3)
        rounded_rect(draw, (x+16, y+16, x2-16, y+66), radius=16, fill="#FBBF24", outline="#00000055", width=1)
    except Exception:
        draw.rectangle((x, y, x2, y2), fill="#0638A5", outline="#14B8F5")
        draw.rectangle((x+16, y+16, x2-16, y+66), fill="#FBBF24")
    gt = clean_group_title_for_design(title) if 'clean_group_title_for_design' in globals() else str(title)
    if not str(gt).startswith("Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©"):
        gt = f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {gt}"
    draw_text(draw, (x+w//2, y+41), gt, get_font(28 if compact else 29), fill="#061633", max_width=w-44)

    label_y = y + 88
    # Ш§Щ„ШЈШ№Щ…ШҜШ© Щ…ЩҶ Ш§Щ„ЩҠЩ…ЩҠЩҶ: Ш§Щ„Щ…ЩҶШӘШ®ШЁ | Щ„Ш№ШЁ | ЩҒШ§ШұЩӮ | ЩҶЩӮШ§Ш·
    team_x = x2 - 34
    played_x = x2 - 245
    diff_x = x2 - 330
    pts_x = x2 - 415
    draw_text(draw, (team_x, label_y), "Ш§Щ„Щ…ЩҶШӘШ®ШЁ", get_font(18), fill="#FDE68A", anchor="rm")
    draw_text(draw, (played_x, label_y), "Щ„Ш№ШЁ", get_font(18), fill="#FDE68A")
    draw_text(draw, (diff_x, label_y), "ЩҒШ§ШұЩӮ", get_font(18), fill="#FDE68A")
    draw_text(draw, (pts_x, label_y), "ЩҶЩӮШ§Ш·", get_font(18), fill="#FDE68A")

    yy = y + 108
    row_h = 62 if not compact else 67
    row_gap = 8 if not compact else 0
    for pos, r in enumerate(rows[:4], start=1):
        team, played, diff, pts = r[0], r[1], r[2], r[3]
        try:
            rounded_rect(draw, (x+16, yy, x2-16, yy+row_h), radius=15, fill="#061633B8", outline="#FFFFFF30", width=1)
        except Exception:
            draw.rectangle((x+16, yy, x2-16, yy+row_h), fill="#061633")
        cy = yy + row_h//2
        team_name = f"{pos}. {_clean_display_name(team)}"
        team_font = _fit_font_to_width(draw, team_name, 23 if not compact else 21, 185 if not compact else 160, min_size=16)
        draw_text(draw, (team_x, cy), team_name, team_font, fill="#FFFFFF", anchor="rm", max_width=190 if not compact else 165)
        draw_text(draw, (played_x, cy), str(played), get_font(23 if not compact else 21), fill="#FFFFFF")
        draw_text(draw, (diff_x, cy), f"{int(diff):+d}" if isinstance(diff, int) else str(diff), get_font(22 if not compact else 20), fill="#E5E7EB")
        draw_text(draw, (pts_x, cy), str(pts), get_font(29 if not compact else 24), fill="#FBBF24")
        yy += row_h + row_gap


def create_all_groups_newlook_image(groups, style=2):
    ensure_generated_dir()
    groups = list(groups or [])[:12]
    width = 1800
    cols = 3
    margin_x, gap_x = 72, 34
    card_w = (width - 2*margin_x - (cols-1)*gap_x) // cols
    row_h, row_gap, grid_gap_y = 62, 8, 32
    min_card_h, header_h, label_h, bottom_pad = 285, 74, 34, 24
    row_heights = []
    for r in range(4):
        chunk = groups[r*cols:(r+1)*cols]
        max_rows = max([min(len(rows), 4) for _title, rows in chunk] + [1])
        ch = header_h + label_h + 18 + max_rows * row_h + max(0, max_rows-1) * row_gap + bottom_pad
        row_heights.append(max(min_card_h, ch))
    start_y, footer_space = 300, 110
    height = int(start_y + sum(row_heights) + grid_gap_y*(len(row_heights)-1) + footer_space)
    height = max(1640, min(height, 2320))
    img, draw = _games_day_background(width, height)
    overlay = Image.new("RGBA", (width, height), (0, 0, 0, 0))
    od = ImageDraw.Draw(overlay)
    rounded_rect(od, (45, 40, width-45, height-45), radius=40, fill="#06152F55", outline="#FFFFFF22", width=2)
    img = Image.alpha_composite(img.convert("RGBA"), overlay).convert("RGB")
    draw = ImageDraw.Draw(img)
    draw_text(draw, (width//2, 82), "MONDIAL AL MASEEF 2026", _v31_latin_font(42) if '_v31_latin_font' in globals() else get_font(40), fill="#FFFFFF", max_width=900)
    draw_text(draw, (width//2, 160), "ALL GROUP STANDINGS", _v31_latin_font(74) if '_v31_latin_font' in globals() else get_font(72), fill="#FFFFFF", max_width=width-170)
    draw_text(draw, (width//2, 230), "ШӘШұШӘЩҠШЁ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", get_font(40), fill="#FBBF24", max_width=800)

    y_cursor = start_y
    for idx, (title, rows) in enumerate(groups):
        c = idx % cols
        r = idx // cols
        if c == 0 and idx != 0:
            y_cursor += row_heights[r-1] + grid_gap_y
        # RTL: ШЈЩҲЩ„ Щ…Ш¬Щ…ЩҲШ№Ш© ЩҠЩ…ЩҠЩҶ
        x = margin_x + (cols - 1 - c) * (card_w + gap_x)
        y = y_cursor
        card_h = row_heights[r]
        _v28_standings_card(draw, img, (x, y, x+card_w, y+card_h), title, rows, compact=False)
    draw_text(draw, (width//2, height-50), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠЩҶЩӮЩ„ Щ„ЩғЩ… Ш§Щ„ШӯШҜШ«", get_font(38), fill="#FBBF24", max_width=700)
    path = os.path.join(GENERATED_DIR, f"all_groups_rtl_v28.png")
    img.save(path, quality=95)
    return path


def _standings_page_image(groups, page_no=1, total_pages=3):
    chunk = groups[(page_no-1)*4:page_no*4]
    img = _fixture_bg(1080, 1350)
    draw = ImageDraw.Draw(img, "RGBA")
    draw_text(draw, (540, 76), "MONDIAL AL MASEEF 2026", get_font(32), fill="#FFFFFF")
    draw_text(draw, (540, 122), "GROUP STANDINGS", get_font(54), fill="#FFFFFF")
    draw_text(draw, (540, 174), f"ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ | {page_no}/{total_pages}", get_font(30), fill="#FBBF24")
    # RTL: ШЈШ№Щ„Щү ЩҠЩ…ЩҠЩҶ Ш«Щ… ШЈШ№Щ„Щү ЩҠШіШ§ШұШҢ ШЈШіЩҒЩ„ ЩҠЩ…ЩҠЩҶ Ш«Щ… ШЈШіЩҒЩ„ ЩҠШіШ§Шұ
    positions = [(570,230,1020,680),(60,230,510,680),(570,715,1020,1165),(60,715,510,1165)]
    for (title, rows), box in zip(chunk, positions):
        _v28_standings_card(draw, img, box, title, rows, compact=True)
    draw.line((250, 1242, 830, 1242), fill=(255,255,255,180), width=2)
    draw_text(draw, (540, 1284), "Ш§Щ„Щ…ШөЩҠЩҒ ЩҠШ¶Ш№ЩғЩ… ШЁШ§Щ„ШӯШҜШ«", get_font(28), fill="#FBBF24")
    path = os.path.join(GENERATED_DIR, f"group_standings_page_rtl_v28_{page_no}.png")
    img.save(path, quality=95)
    return path

