async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text(
        "ШӯЩҠЩ‘Ш§Щғ ЩҒЩҠ ШЁЩҲШӘ Щ…ЩҲЩҶШҜЩҠШ§Щ„ Ш§Щ„Щ…ШөЩҠЩҒ 2026 рҹҸҶ\n"
        "Ш§Ш®ШӘШұ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©ШҢ ЩҲЩғЩ„ ШҙШ®Шө ЩҠШ¶ШәШ· Ш§Щ„ШІШұ ЩҲЩҠШ·Щ„Ш№ Щ„ЩҮ Ш§Щ„ШұШҜ Щ„ШӯШ§Щ„ЩҮ ШЁШ§Щ„Ш®Ш§Шө:",
        reply_markup=_public_main_keyboard(),
    )


async def public_menu_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await start(update, context)


async def _send_public_matches_today(message):
    d = _v29_active_fixture_date() if '_v29_active_fixture_date' in globals() else None
    if not d:
        await message.reply_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…Щ„ЩҒ PDF.")
        return
    wait = await message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШӘШөЩ…ЩҠЩ… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ…...")
    try:
        rows = _v26_dedupe_fixture_matches(_fixtures_for_date(d)) if '_v26_dedupe_fixture_matches' in globals() else _fixtures_for_date(d)
        if not rows:
            await wait.edit_text("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ….")
            return
        title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
        path = create_matches_today_v31_full_image(title, rows)
        try:
            await wait.delete()
        except Exception:
            pass
        await send_photo_path(message, path, build_matches_today_v31_caption(title, rows))
    except Exception as e:
        await wait.edit_text(f"ШӘШ№Ш°Шұ ШӘШ¬ЩҮЩҠШІ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… вқҢ\n{str(e)[:300]}")


async def public_top_scorers_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    wait = await update.message.reply_text("вҸі ШЈШіШӯШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN...")
    try:
        items = await asyncio.wait_for(asyncio.to_thread(fetch_espn_top_scorers), timeout=35)
        path = render_top_scorers_v29(items)
        await send_photo_path(update, path, "ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN Scoring Stats")
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вқҢ\n{str(e)[:300]}")


async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    action = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "home"
    if action == "home":
        await q.message.reply_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ©:", reply_markup=_public_main_keyboard())
        return
    if action == "live":
        d = _v29_active_fixture_date() if '_v29_active_fixture_date' in globals() else None
        await q.message.reply_text(_v29_live_today_text(d), reply_markup=_v29_live_today_keyboard(d))
        return
    if action == "fixtures":
        await _send_public_matches_today(q.message)
        return
    if action == "groups":
        await q.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЈЩҲ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ:", reply_markup=_v29_group_menu_keyboard())
        return
    if action == "scorers":
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN...")
        try:
            items = await asyncio.wait_for(asyncio.to_thread(fetch_espn_top_scorers), timeout=35)
            path = render_top_scorers_v29(items)
            await send_photo_path(q.message, path, "ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN Scoring Stats")
            try:
                await wait.delete()
            except Exception:
                pass
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вқҢ\n{str(e)[:300]}")
        return
    if action == "results":
        prev = _v28_previous_result_dates() if '_v28_previous_result_dates' in globals() else []
        if not prev:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ШіШ§ШЁЩӮШ© Щ„Щ„ЩҶШӘШ§ШҰШ¬ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
            return
        await q.message.reply_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())
        return
    if action == "fantasy":
        await q.message.reply_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())
        return
    if action == "help":
        await q.message.reply_text(
            "Ш·ШұЩҠЩӮШ© Ш§Щ„Ш§ШіШӘШ®ШҜШ§Щ… в„№пёҸ\n\n"
            "Ш§Ш¶ШәШ· Ш§Щ„ШІШұ Ш§Щ„Щ…Ш·Щ„ЩҲШЁ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©ШҢ ЩҲШ§Щ„ШұШҜ ЩҠШ·Щ„Ш№ Щ„Щғ Щ„ШӯШ§Щ„Щғ ЩҒЩҠ Ш§Щ„Ш®Ш§Шө.\n"
            "Щ„Щ„Щ…ШӘШ§ШЁШ№Ш© Ш§Щ„Щ…ШЁШ§ШҙШұШ©: Ш§Ш®ШӘШұ рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.\n"
            "Щ„ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ: Ш§Ш®ШӘШұ рҹ“Ҡ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш«Щ… Ш§Ш®ШӘШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЈЩҲ Ш¬Щ…ЩҠШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.\n"
            "Щ„Щ„ЩҒШ§ЩҶШӘШІЩҠ: Ш§Ш®ШӘШұ рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ Ш«Щ… ЩҶЩҲШ№ Ш§Щ„ШӘЩӮШұЩҠШұ.\n\n"
            "Щ„ШҘШёЩҮШ§Шұ Ш§Щ„ЩӮШ§ШҰЩ…Ш© Щ…ШұШ© Ш«Ш§ЩҶЩҠШ© Ш§ЩғШӘШЁ /Ш§Щ„ЩӮШ§ШҰЩ…Ш©"
        )
        return
    await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")


async def public_status_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    kind = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "qualified"
    state = load_status_state()
    if kind == "qualified":
        teams = _status_effective_teams("qualified", state)
        path = render_qualified32_board(teams)
        await send_photo_path(q.message, path, _status_caption("qualified", teams, state))
    elif kind == "eliminated":
        teams = _status_effective_teams("eliminated", state)
        path = render_eliminated_board(teams)
        await send_photo_path(q.message, path, _status_caption("eliminated", teams, state))
    else:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")


def _latest_fantasy_day():
    days = get_existing_days(1, 99)
    return max(days) if days else None


async def fantasy_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    action = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "menu"
    if action == "ranking":
        days = get_existing_days(1, 99)
        end_day = max(days) if days else 31
        stats = collect_stats(1, end_day)
        if not stats.get("days"):
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ЩҒШ§ЩҶШӘШІЩҠ Щ…ШӯШіЩҲШЁШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.", reply_markup=_fantasy_public_keyboard())
            return
        await q.message.reply_text(build_ranking_text(stats, 1, end_day), reply_markup=_fantasy_public_keyboard())
        return
    if action == "today_points":
        day = _latest_fantasy_day()
        if not day:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒ ЩҶЩӮШ§Ш· Щ„Щ„ЩҠЩҲЩ… ШӯШӘЩү Ш§Щ„ШўЩҶ.", reply_markup=_fantasy_public_keyboard())
            return
        rows = sorted(read_day_rows(day), key=lambda r: r.get("total", 0), reverse=True)
        lines = [f"рҹ”Ҙ ЩҶЩӮШ§Ш· Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}", ""]
        for i, r in enumerate(rows, start=1):
            lines.append(f"{i}. {r['participant']} вҖ” {r['total']} ЩҶЩӮШ·Ш©")
        await q.message.reply_text("\n".join(lines), reply_markup=_fantasy_public_keyboard())
        return
    if action == "legends":
        days = get_existing_days(1, 99)
        end_day = max(days) if days else 31
        stats = collect_stats(1, end_day)
        wins = stats.get("daily_wins", {})
        ordered = sorted([(n, wins[n]) for n in PARTICIPANTS if wins.get(n, 0) > 0], key=lambda x: x[1], reverse=True)
        lines = ["вӯҗ ШЈШіШ§Ш·ЩҠШұ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ", ""]
        lines += [f"{i}. {n} вҖ” {c} Щ…ШұШ©" for i, (n, c) in enumerate(ordered, start=1)] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈШіШ§Ш·ЩҠШұ Щ…ШіШ¬Щ„ЩҠЩҶ ШӯШӘЩү Ш§Щ„ШўЩҶ."]
        await q.message.reply_text("\n".join(lines), reply_markup=_fantasy_public_keyboard())
        return
    if action == "template":
        day = _latest_fantasy_day()
        next_day = (int(day) + 1) if day else ""
        await q.message.reply_text(
            "рҹ“Ӣ ЩҶЩ…ЩҲШ°Ш¬ Ш§Щ„Щ…ШҙШ§ШұЩғШ© Ш§Щ„ШұШіЩ…ЩҠ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ\n"
            f"рҹҸҶ ШӘШҙЩғЩҠЩ„Ш© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ - Ш§Щ„ЩҠЩҲЩ… ( {next_day} )\n"
            "рҹ§Ө Ш§Щ„ШӯШ§ШұШі: \n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 1: \n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 2: \n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 3: \n"
            "рҹ‘‘ Ш§Щ„ЩғШ§ШЁШӘЩҶ: ",
            reply_markup=_fantasy_public_keyboard(),
        )
        return
    await q.message.reply_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())


# ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ: ШЈШІШұШ§Шұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Ш№Ш§Щ…Ш© ЩҲЩ„ЩҠШіШӘ Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ·.
async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    if len(parts) >= 3 and parts[1] == "day":
        d = parts[2]
        wait = await q.message.reply_text("вҸі ШЈШіШӯШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШ§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN...")
        try:
            text = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d), timeout=35)
            await wait.edit_text(text)
        except Exception as e:
            await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҶШӘШ§ШҰШ¬ ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ… вқҢ\n{str(e)[:400]}")
        return

