async def public_status_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    kind = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "qualified"
    state = load_status_state()
    # Щ„ЩҲ Щ…Ш§ Ш№ЩҶШҜЩҶШ§ ЩӮШ§ШҰЩ…Ш© ШӘЩ„ЩӮШ§ШҰЩҠШ© ЩҶШӯШ§ЩҲЩ„ ШЈЩҲЩ„ ШіШӯШЁ Щ…ЩҶ ESPN ЩӮШЁЩ„ Ш§Щ„Ш№ШұШ¶.
    prefix = "qualified" if kind == "qualified" else "eliminated"
    if not state.get(f"{prefix}_auto"):
        try:
            groups, _src = await asyncio.wait_for(asyncio.to_thread(fetch_current_groups, "espn"), timeout=35)
            if groups:
                q_auto, e_auto = _auto_status_from_groups(groups)
                state["qualified_auto"] = q_auto
                state["eliminated_auto"] = e_auto
                if not state.get("updated_at"):
                    state["updated_at"] = _now_riyadh_text()
                state["source"] = "ESPN ШӘШұШӘЩҠШЁ + ШЁШӯШ« ШҘЩҶШ¬Щ„ЩҠШІЩҠ"
                save_status_state(state)
        except Exception:
            pass
        state = load_status_state()
    if kind == "qualified":
        teams = _status_effective_teams("qualified", state)
        path = render_qualified32_board(teams)
        await send_photo_path(q.message, path, _status_caption("qualified", teams, state))
    elif kind == "eliminated":
        teams = _status_effective_teams("eliminated", state)
        path = render_eliminated_board(teams)
        await send_photo_path(q.message, path, _status_caption("eliminated", teams, state))
    else:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Щ„Ш®ЩҠШ§Шұ.")


async def fantasy_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    action = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "menu"
    if action == "home":
        await q.edit_message_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ©:", reply_markup=_public_main_keyboard())
        return
    if action == "menu":
        await q.edit_message_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())
        return
    if action == "ranking":
        days = get_existing_days(1, 99)
        end_day = max(days) if days else 31
        stats = collect_stats(1, end_day)
        if not stats.get("days"):
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ЩҒШ§ЩҶШӘШІЩҠ Щ…ШӯШіЩҲШЁШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.")
            return
        await q.message.reply_text(build_ranking_text(stats, 1, end_day))
        return
    if action == "today_points":
        day = _latest_fantasy_day()
        if not day:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒ ЩҶЩӮШ§Ш· Щ„Щ„ЩҠЩҲЩ… ШӯШӘЩү Ш§Щ„ШўЩҶ.")
            return
        rows = sorted(read_day_rows(day), key=lambda r: r.get("total", 0), reverse=True)
        lines = [f"рҹ”Ҙ ЩҶЩӮШ§Ш· Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}", ""]
        for i, r in enumerate(rows, start=1):
            lines.append(f"{i}. {r['participant']} вҖ” {r['total']} ЩҶЩӮШ·Ш©")
        await q.message.reply_text("\n".join(lines))
        return
    if action == "legends":
        days = get_existing_days(1, 99)
        end_day = max(days) if days else 31
        stats = collect_stats(1, end_day)
        wins = stats.get("daily_wins", {})
        ordered = sorted([(n, wins[n]) for n in PARTICIPANTS if wins.get(n, 0) > 0], key=lambda x: x[1], reverse=True)
        lines = ["вӯҗ ШЈШіШ§Ш·ЩҠШұ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ", ""]
        lines += [f"{i}. {n} вҖ” {c} Щ…ШұШ©" for i, (n, c) in enumerate(ordered, start=1)] or ["Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈШіШ§Ш·ЩҠШұ Щ…ШіШ¬Щ„ЩҠЩҶ ШӯШӘЩү Ш§Щ„ШўЩҶ."]
        await q.message.reply_text("\n".join(lines))
        return
    if action == "template":
        day = _latest_fantasy_day()
        next_day = (int(day) + 1) if day else ""
        await q.message.reply_text(
            "рҹ“Ӣ ЩҶЩ…ЩҲШ°Ш¬ Ш§Щ„Щ…ШҙШ§ШұЩғШ© Ш§Щ„ШұШіЩ…ЩҠ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ\n"
            f"рҹҸҶ ШӘШҙЩғЩҠЩ„Ш© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ - Ш§Щ„ЩҠЩҲЩ… ( {next_day} )\n"
            "рҹ§Ө Ш§Щ„ШӯШ§ШұШі:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 1:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 2:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 3:\n"
            "рҹ‘‘ Ш§Щ„ЩғШ§ШЁШӘЩҶ:"
        )
        return
    await q.edit_message_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())


async def live_today_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    if len(parts) < 3:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© Ш§Ш®ШӘЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©.")
        return
    action, mid = parts[1], parts[2]
    if action != "match":
        return
    m = _fixture_by_id(mid)
    if not m:
        await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ЩҒЩҠ Щ…Щ„ЩҒ PDF.")
        return
    if _has_unknown(m):
        await q.message.reply_text("ШЈШ·ШұШ§ЩҒ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„Щ… ШӘШӘШӯШҜШҜ ШЁШ№ШҜ.")
        return
    team1, team2 = m.get("team1"), m.get("team2")
    date_hint = _v28_espn_date(m.get("date")) if '_v28_espn_date' in globals() else m.get("date")
    payload = {"kind": "live", "team1": team1, "team2": team2, "date_hint": date_hint}
    kb = source_keyboard(context, payload)
    wait = await q.message.reply_text(f"вҸі ШЈШ¬ЩҮШІ ШЁШ·Ш§ЩӮШ© {team1} Г— {team2} Щ…ЩҶ ESPN...")
    try:
        data = await asyncio.wait_for(asyncio.to_thread(fetch_live_match_data, team1, team2, "espn", date_hint), timeout=26)
    except Exception:
        data = None
    if not data:
        try:
            fallback = _v28_fetch_espn_match_by_fixture(m.get("date"), m)
        except Exception:
            fallback = None
        if fallback:
            data = fallback
        else:
            try:
                path, caption = _v29_render_fixture_fallback_card(m, "ESPN")
                await send_photo_path_markup(q.message, path, caption, kb)
                try:
                    await wait.delete()
                except Exception:
                    pass
                return
            except Exception:
                await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҶ ESPN вқҢ\n{team1} Г— {team2}\n\nШ¬ШұЩ‘ШЁ Щ…ШөШҜШұЩӢШ§ ШўШ®Шұ Щ…ЩҶ Ш§Щ„ШЈШІШұШ§Шұ.", reply_markup=kb)
                return
    try:
        path = render_live_match_card(data, "ESPN")
        await send_photo_path_markup(q.message, path, build_live_caption(data, "ESPN"), kb)
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘЩ… Ш¬Щ„ШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Щ„ЩғЩҶ ШӘШ№Ш°Шұ ШӘШөЩ…ЩҠЩ… Ш§Щ„ШЁШ·Ш§ЩӮШ© вқҢ\n{str(e)[:180]}\n\n" + build_live_caption(data, "ESPN"), reply_markup=kb)


