async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    action = (q.data or "").split("|", 1)[1] if "|" in (q.data or "") else "home"
    if action == "home":
        await q.edit_message_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ©:", reply_markup=_public_main_keyboard())
