def _fantasy_public_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹҸҶ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„Ш№Ш§Щ…", callback_data="fantasy|ranking")],
        [InlineKeyboardButton("рҹ”Ҙ ЩҶЩӮШ§Ш· Ш§Щ„ЩҠЩҲЩ…", callback_data="fantasy|today_points")],
        [InlineKeyboardButton("рҹ‘Ҙ Ш§Ш®ШӘЩҠШ§ШұШ§ШӘ Ш§Щ„Щ…ШҙШ§ШұЩғЩҠЩҶ", callback_data="fantasy|participants")],
        [InlineKeyboardButton("вӯҗ ШЈШіШ§Ш·ЩҠШұ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ", callback_data="fantasy|legends")],
        [InlineKeyboardButton("рҹ“Ӣ ЩҶЩ…ЩҲШ°Ш¬ Ш§Щ„Щ…ШҙШ§ШұЩғШ©", callback_data="fantasy|template")],
        [InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")],
    ])


def _latest_fantasy_day():
    days = get_existing_days(1, 39)
    return max(days) if days else None


def _fantasy_days_keyboard(action_prefix, selected=None):
    days = get_existing_days(1, 39)
    rows, row = [], []
    for day in days:
        label = f"Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}"
        row.append(InlineKeyboardButton(label, callback_data=f"fantasy|{action_prefix}|{day}"))
        if len(row) == 2:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№ Щ„ЩҒШ§ЩҶШӘШІЩҠ", callback_data="fantasy|menu")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _fantasy_participants_keyboard(day):
    rows, row = [], []
    data_rows = read_day_rows(day)
    names = [r.get("participant") for r in data_rows if normalize_name(r.get("participant"))]
    if not names:
        names = list(PARTICIPANTS)
    for idx, name in enumerate(names):
        row.append(InlineKeyboardButton(name, callback_data=f"fantasy|participant|{day}|{idx}"))
        if len(row) == 2:
            rows.append(row)
            row = []
    if row:
        rows.append(row)
    rows.append([InlineKeyboardButton("ШұШ¬ЩҲШ№ Щ„Щ„ШЈЩҠШ§Щ…", callback_data="fantasy|participants")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _points_word(v):
    try:
        n = int(v or 0)
    except Exception:
        n = 0
    if n == 0:
        return "ШөЩҒШұЩҠ"
    if n == 1:
        return "ЩҶЩӮШ·Ш© ЩҲШ§ШӯШҜШ©"
    if 2 <= n <= 10:
        return f"{n} ЩҶЩӮШ§Ш·"
    return f"{n} ЩҶЩӮШ·Ш©"


def _day_points_text(day):
    rows = sorted(read_day_rows(day), key=lambda r: r.get("total", 0), reverse=True)
    if not rows:
        return f"Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒ ЩҶЩӮШ§Ш· Щ„Щ„ЩҠЩҲЩ… {day}."
    lines = [f"рҹ”Ҙ ЩҶЩӮШ§Ш· Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}", ""]
    for i, r in enumerate(rows, start=1):
        total = int(r.get("total", 0) or 0)
        val = "ШөЩҒШұЩҠ" if total == 0 else f"{total} ЩҶЩӮШ·Ш©"
        lines.append(f"{i}. {r['participant']} вҖ” {val}")
    return "\n".join(lines)


def _participant_choices_text(day, idx):
    rows = read_day_rows(day)
    if not rows:
        return f"Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒ ЩҶЩӮШ§Ш· Щ„Щ„ЩҠЩҲЩ… {day}."
    try:
        idx = int(idx)
    except Exception:
        idx = 0
    if idx < 0 or idx >= len(rows):
        return "ШӘШ№Ш°Шұ Ш§Щ„Ш№Ш«ЩҲШұ Ш№Щ„Щү Ш§Щ„Щ…ШҙШ§ШұЩғ."
    r = rows[idx]
    name = r.get("participant") or "Ш§Щ„Щ…ШҙШ§ШұЩғ"
    total = int(r.get("total", 0) or 0)
    lines = [f"рҹ‘Ҙ Ш§Ш®ШӘЩҠШ§ШұШ§ШӘ {name} - Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}", ""]
    lines.append(f"рҹ§Ө Ш§Щ„ШӯШ§ШұШі: {r.get('keeper') or '-'} / {_points_word(r.get('keeper_points'))}")
    lines.append(f"вҡҪ Ш§Щ„Щ„Ш§Ш№ШЁ 1: {r.get('p1') or '-'} / {_points_word(r.get('p1_points'))}")
    lines.append(f"вҡҪ Ш§Щ„Щ„Ш§Ш№ШЁ 2: {r.get('p2') or '-'} / {_points_word(r.get('p2_points'))}")
    lines.append(f"вҡҪ Ш§Щ„Щ„Ш§Ш№ШЁ 3: {r.get('p3') or '-'} / {_points_word(r.get('p3_points'))}")
    lines.append(f"рҹ‘‘ Ш§Щ„ЩғШ§ШЁШӘЩҶ: {r.get('captain') or '-'} / {_points_word(r.get('captain_points'))}")
    lines.append("")
    lines.append(f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№: {'ШөЩҒШұЩҠ' if total == 0 else str(total) + ' ЩҶЩӮШ·Ш©'}")
    return "\n".join(lines)


def _fantasy_legends_text():
    days = get_existing_days(1, 39)
    wins = Counter()
    detail_lines = []
    for day in days:
        rows = [r for r in read_day_rows(day) if r.get("participated")]
        if not rows:
            continue
        max_total = max(int(r.get("total", 0) or 0) for r in rows)
        if max_total <= 0:
            continue
        names = [r.get("participant") for r in rows if int(r.get("total", 0) or 0) == max_total]
        for n in names:
            wins[n] += 1
        detail_lines.append(f"Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}: {' + '.join(names)} ({max_total} ЩҶЩӮШ·Ш©)")
    ordered = sorted(wins.items(), key=lambda x: (-x[1], x[0]))
    lines = ["вӯҗ ШЈШіШ§Ш·ЩҠШұ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ ШӯШӘЩү Ш§Щ„ШўЩҶ вӯҗ", ""]
    if ordered:
        for i, (name, count) in enumerate(ordered, start=1):
            word = "Щ…ШұШ©" if count == 1 else "Щ…ШұШ§ШӘ"
            lines.append(f"{i}. {name} вҖ” {count} {word}")
    else:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈШіШ§Ш·ЩҠШұ Щ…ШіШ¬Щ„ЩҠЩҶ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
    if detail_lines:
        lines.append("")
        lines.append("рҹ“Ң Ш§Щ„ШӘЩҒШ§ШөЩҠЩ„ ШӯШіШЁ Ш§Щ„ШЈЩҠШ§Щ…:")
        lines.extend(detail_lines)
    return "\n".join(lines)


async def fantasy_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    parts = (q.data or "").split("|")
    action = parts[1] if len(parts) > 1 else "menu"
    if action == "home":
        await q.edit_message_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ©:", reply_markup=_public_main_keyboard())
        return
    if action == "menu":
        await q.edit_message_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())
        return
    if action == "ranking":
        days = get_existing_days(1, 39)
        end_day = max(days) if days else 39
        stats = collect_stats(1, end_day)
        if not stats.get("days"):
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ ШЈЩҠШ§Щ… ЩҒШ§ЩҶШӘШІЩҠ Щ…ШӯШіЩҲШЁШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.")
            return
        await q.message.reply_text(build_ranking_text(stats, 1, end_day), reply_markup=_fantasy_public_keyboard())
        return
    if action == "today_points":
        days = get_existing_days(1, 39)
        if not days:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒШ§ШӘ ЩҶЩӮШ§Ш· ШӯШӘЩү Ш§Щ„ШўЩҶ.", reply_markup=_fantasy_public_keyboard())
            return
        await q.edit_message_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… Щ„Ш№ШұШ¶ Ш§Щ„ЩҶЩӮШ§Ш·:", reply_markup=_fantasy_days_keyboard("daypoints"))
        return
    if action == "daypoints" and len(parts) >= 3:
        await q.message.reply_text(_day_points_text(parts[2]), reply_markup=_fantasy_public_keyboard())
        return
    if action == "participants":
        days = get_existing_days(1, 39)
        if not days:
            await q.message.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…Щ„ЩҒШ§ШӘ ЩҒШ§ЩҶШӘШІЩҠ ШӯШӘЩү Ш§Щ„ШўЩҶ.", reply_markup=_fantasy_public_keyboard())
            return
        await q.edit_message_text("Ш§Ш®ШӘШұ Ш§Щ„ЩҠЩҲЩ… ШЈЩҲЩ„ЩӢШ§:", reply_markup=_fantasy_days_keyboard("pday"))
        return
    if action == "pday" and len(parts) >= 3:
        day = parts[2]
        await q.edit_message_text(f"Ш§Ш®ШӘШұ Ш§Щ„Щ…ШҙШ§ШұЩғ - Ш§Щ„ЩҠЩҲЩ… {ordinal_day(day)}:", reply_markup=_fantasy_participants_keyboard(day))
        return
    if action == "participant" and len(parts) >= 4:
        day, idx = parts[2], parts[3]
        await q.message.reply_text(_participant_choices_text(day, idx), reply_markup=_fantasy_participants_keyboard(day))
        return
    if action == "legends":
        await q.message.reply_text(_fantasy_legends_text(), reply_markup=_fantasy_public_keyboard())
        return
    if action == "template":
        day = _latest_fantasy_day()
        next_day = (int(day) + 1) if day else ""
        await q.message.reply_text(
            "рҹ“Ӣ ЩҶЩ…ЩҲШ°Ш¬ Ш§Щ„Щ…ШҙШ§ШұЩғШ© Ш§Щ„ШұШіЩ…ЩҠ Ш§Щ„Щ…Ш№ШӘЩ…ШҜ\n"
            f"рҹҸҶ ШӘШҙЩғЩҠЩ„Ш© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ - Ш§Щ„ЩҠЩҲЩ… ( {next_day} )\n"
            "рҹ§Ө Ш§Щ„ШӯШ§ШұШі:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 1:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 2:\n"
            "Ш§Щ„Щ„Ш§Ш№ШЁ 3:\n"
            "рҹ‘‘ Ш§Щ„ЩғШ§ШЁШӘЩҶ:",
            reply_markup=_fantasy_public_keyboard(),
        )
        return
    await q.edit_message_text("ЩӮШ§ШҰЩ…Ш© ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ:", reply_markup=_fantasy_public_keyboard())


def _group_teams_from_fixtures():
    data = {label: [] for _code, label in GROUP_BUTTONS_V29}
    for m in TOURNAMENT_FIXTURES:
        group = m.get("group")
        if group not in data:
            continue
        for k in ["team1", "team2"]:
            team = canonical_team_name(m.get(k)) or normalize_name(m.get(k))
            if team and "ШӘШӯШҜШҜ" not in team and team not in data[group]:
                data[group].append(team)
    return data


def _status_picker_keyboard(kind="qualified", selected=None):
    selected = set(_unique_teams(selected or []))
    group_data = _group_teams_from_fixtures()
    rows = []
    for _code, label in GROUP_BUTTONS_V29:
        rows.append([InlineKeyboardButton(f"вҖ” {label} вҖ”", callback_data=f"spick|noop|{kind}")])
        teams = group_data.get(label, [])[:4]
        row = []
        for team in teams:
            mark = "вң… " if team in selected else ""
            row.append(InlineKeyboardButton(mark + team, callback_data=f"spick|toggle|{kind}|{team}"))
            if len(row) == 2:
                rows.append(row)
                row = []
        if row:
            rows.append(row)
    rows.append([InlineKeyboardButton("вң… ШӘШЈЩғЩҠШҜ", callback_data=f"spick|confirm|{kind}"), InlineKeyboardButton("ШӘШөЩҒЩҠШұ", callback_data=f"spick|clear|{kind}")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


