    await update.message.reply_text("Ш§Ш®ШӘШұ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…ШӘШЈЩҮЩ„Ш© Щ…ШЁШ§ШҙШұШ© Ш«Щ… Ш§Ш¶ШәШ· ШӘШЈЩғЩҠШҜ:", reply_markup=_status_picker_keyboard("qualified", []))


