    draw_text(draw, (name_x-145, y0+25), "Ш§Щ„Щ„Ш§Ш№ШЁ", get_font(24), fill="#061633")
    draw_text(draw, (team_x, y0+25), "Ш§Щ„Щ…ЩҶШӘШ®ШЁ", get_font(24), fill="#061633")
    draw_text(draw, (played_x, y0+25), "Щ„Ш№ШЁ", get_font(24), fill="#061633")
    draw_text(draw, (goals_x, y0+25), "ШЈЩҮШҜШ§ЩҒ", get_font(24), fill="#061633")
    y = y0 + 62
    if not items:
        rounded_rect(draw, (x0, y, x1, y+85), radius=22, fill="#061633D9", outline="#FFFFFF33", width=1)
        draw_text(draw, (width//2, y+43), "ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҮШҜШ§ЩҒЩҠ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN ШӯШ§Щ„ЩҠЩӢШ§", get_font(31), fill="#FFFFFF", max_width=850)
    for idx, it in enumerate(items, start=1):
        rounded_rect(draw, (x0, y, x1, y+row_h-10), radius=18, fill="#061633D9", outline="#FFFFFF22", width=1)
        cy = y + (row_h-10)//2
        rank_box = (rank_x-23, cy-22, rank_x+23, cy+22)
