def _fixtures_for_date(date):
    d = _normalize_date_arg(date)
    out = _v317_prev_fixtures_for_date(d)
    if out:
        return out
    return [_apply_fixture_updates(m) for m in _EARLY_GROUP_FIXTURES_1106_1906 if m.get("date") == d]

