def _v28_previous_results_keyboard():
    rows = []
    today = _today_riyadh_date()
    for d, day in _fixture_dates():
        try:
            # Ш№ШұШ¶ ШЈЩҠШ§Щ… Ш§Щ„ЩҶШӘШ§ШҰШ¬ Щ…ЩҶ 11 ЩҠЩҲЩҶЩҠЩҲ ШҘЩ„Щү ШӘШ§ШұЩҠШ® Ш§Щ„ЩҠЩҲЩ… ЩҒЩӮШ·ШҢ ЩҲЩ„Ш§ ЩҶШ®ЩҒЩҠ Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„ЩӮШҜЩҠЩ…Ш©.
            if _date_key(d) <= _date_key(today):
                rows.append([InlineKeyboardButton(f"{day} {d}", callback_data=f"res|{d}")])
        except Exception:
            rows.append([InlineKeyboardButton(f"{day} {d}", callback_data=f"res|{d}")])
    if not rows:
        for d, day in _fixture_dates():
            rows.append([InlineKeyboardButton(f"{day} {d}", callback_data=f"res|{d}")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)

