async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    data = q.data or ''
    if data == 'noop':
        return
    parts = data.split('|')
    d = ''
    if len(parts) >= 3 and parts[1] == 'day':
        d = _normalize_date_arg(parts[2])
    elif len(parts) >= 2:
        d = _normalize_date_arg(parts[1])
    if not d:
        await q.message.reply_text("ШӘШ№Ш°Шұ ЩӮШұШ§ШЎШ© ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬.")
        return
    try:
        await q.message.edit_text(f"вҸі ШЈШӯШҜШ« ЩҶШӘШ§ШҰШ¬ {d} Щ…ЩҶ football-data.org Ш«Щ… ESPN Щ„Щ„ЩҮШҜШ§ЩҒЩҠЩҶ...")
    except Exception:
        pass
    try:
        txt = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d, False), timeout=16)
    except Exception:
        txt = f"вҡҪ ЩҶШӘШ§ШҰШ¬ {d}\nШ§Щ„ШӯШ§Щ„Ш©: ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«\nШ§Щ„Щ…ШөШҜШұ ШӘШЈШ®ШұШҢ Ш¬ШұЩ‘ШЁ ШЁШ№ШҜ ЩӮЩ„ЩҠЩ„ ШЈЩҲ Ш§ШіШӘШ®ШҜЩ… /ШӘШӯШҜЩҠШ«_ЩҶШӘШ§ШҰШ¬ {d[:5]}"
    try:
        await q.message.edit_text(txt)
    except Exception:
        await q.message.reply_text(txt)


async def refresh_results_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    dates = _extract_fixture_dates_from_text(update.message.text)
    if not dates:
        await update.message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӘШӯШҜЩҠШ«_ЩҶШӘШ§ШҰШ¬ 13/06')
        return
    d = _normalize_date_arg(dates[0])
    wait = await update.message.reply_text(f"вҸі ШЈШ¬ШЁШұ ШӘШӯШҜЩҠШ« ЩҶШӘШ§ШҰШ¬ {d} Щ…ЩҶ football-data.org Ш«Щ… ESPN...")
    try:
        txt = await asyncio.wait_for(asyncio.to_thread(_v28_result_text_for_date, d, True), timeout=20)
        await wait.edit_text(txt)
    except Exception:
        await wait.edit_text(f"вҡ пёҸ ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШ« ЩҶШӘШ§ШҰШ¬ {d} Ш®Щ„Ш§Щ„ Ш§Щ„ЩҲЩӮШӘ Ш§Щ„Щ…ШӯШҜШҜ. ШЁЩӮЩҠШӘ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШіШ§ШЁЩӮШ© ЩғЩ…Ш§ ЩҮЩҠ.")


async def _v315_send_live_result_from_message(msg, team1, team2, date_hint=None, source='auto', admin=False):
    # ШұШҜ ШіШұЩҠШ№ШҢ Щ„Ш§ ШӘШ№Щ„ЩҠЩӮ 4 ШҜЩӮШ§ЩҠЩӮ.
    try:
        await msg.edit_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« {team1} Г— {team2}\nfootball-data ШЈЩҲЩ„ЩӢШ§ШҢ Ш«Щ… ESPN Щ„Щ„ЩҮШҜШ§ЩҒЩҠЩҶ...")
        wait_msg = msg
    except Exception:
        wait_msg = await msg.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« {team1} Г— {team2}\nfootball-data ШЈЩҲЩ„ЩӢШ§ШҢ Ш«Щ… ESPN Щ„Щ„ЩҮШҜШ§ЩҒЩҠЩҶ...")
    try:
        data = await asyncio.wait_for(asyncio.to_thread(_v32_fetch_live_fast, team1, team2, date_hint, False), timeout=12)
    except Exception:
        data = _patch6_placeholder_live(team1, team2, date_hint)
    if not data:
        data = _patch6_placeholder_live(team1, team2, date_hint)
    if not data:
        text = f"вҡҪ {team1} Г— {team2}\nШ§Щ„ШӯШ§Щ„Ш©: ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«\nШўШ®Шұ Щ…ШӯШ§ЩҲЩ„Ш©: Ш§Щ„ШўЩҶ"
        try:
            await wait_msg.edit_text(text)
        except Exception:
            await wait_msg.reply_text(text)
        return
    label = data.get('actual_source') or data.get('source') or 'football-data.org'
    try:
        path = render_live_match_card(data, label)
        try:
            await wait_msg.delete()
        except Exception:
            pass
        await send_photo_path(wait_msg, path, build_live_caption(data, label))
    except Exception:
        text = build_live_caption(data, label)
        try:
            await wait_msg.edit_text(text)
        except Exception:
            await wait_msg.reply_text(text)

