    if not rows:
        rows.append([InlineKeyboardButton("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", callback_data="noop")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
