def _v29_live_today_text(date_str=None):
    active = _normalize_date_arg(date_str) if date_str else _v40_active_live_date()
    if not active:
        return "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ ШӯШіШЁ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©."
    title = _v26_fixture_title(active) if '_v26_fixture_title' in globals() else active
    return f"рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ вҖ” {title}\nЩҠШ№ШұШ¶ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ЩҶШҙШ·. Ш§Щ„Щ…ЩҶШӘЩҮЩҠШ© ШӘШЁЩӮЩү ЩҮЩҶШ§ Щ…ШӨЩӮШӘЩӢШ§ ШЁЩҶШӘЩҠШ¬ШӘЩҮШ§ ШӯШӘЩү ЩҠЩҶШӘЩӮЩ„ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„Ш¬ШҜЩҠШҜ."


