def _v29_live_today_keyboard(date_str=None):
    rows = []
    active = _normalize_date_arg(date_str) if date_str else _v41_active_live_date()
    # ШІШұ ШӘШӯШҜЩҠШ« Ш¬Щ…Ш§Ш№ЩҠ Щ„Щ„Щ…ШЁШ§ШҙШұ
    if active:
        rows.append([InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", callback_data=f"livefx|refreshday|{active}")])
    for m in _v40_live_rows(active):
        rows.append([InlineKeyboardButton(_v40_live_button_label(m)[:62], callback_data=f"livefx|match|{m.get('id')}")])
    if not rows or (len(rows) == 1 and active):
        rows.append([InlineKeyboardButton("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", callback_data="noop")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _v29_live_today_text(date_str=None):
    active = _normalize_date_arg(date_str) if date_str else _v41_active_live_date()
    if not active:
        return "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ ШӯШіШЁ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©."
    title = _v26_fixture_title(active) if '_v26_fixture_title' in globals() else active
    return f"рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ вҖ” {title}\nШ§Щ„ЩҠЩҲЩ… Ш§Щ„ЩҶШҙШ· Щ…ЩҶ 4 Ш§Щ„Ш№ШөШұ ШҘЩ„Щү 4 Ш§Щ„Ш№ШөШұ ШЁШӘЩҲЩӮЩҠШӘ Щ…ЩғШ©.\nШ§Щ„Щ…ЩҶШӘЩҮЩҠШ© ШӘШЁЩӮЩү ЩҮЩҶШ§ ШЁЩҶШӘЩҠШ¬ШӘЩҮШ§ ШӯШӘЩү ЩҠЩҶШӘЩӮЩ„ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ШӘШ§Щ„ЩҠ."


def _v40_fetch_live_for_fixture(m, force=False):
    if not force:
        try:
            cached = _v34_get_fast_live_cache_for_fixture(m)
            if isinstance(cached, dict) and _patch6_numeric_score(cached):
                return cached
        except Exception:
            pass
        cached = _v33_get_cached_match_result(m) if '_v33_get_cached_match_result' in globals() else None
        if isinstance(cached, dict) and _patch6_numeric_score(cached):
            return cached
    d = _normalize_date_arg(m.get('date'))
    obj = _v41_fetch_result_for_fixture(m, d, force=force, allow_seed=False)
    if isinstance(obj, dict):
        try:
            _save_fast_live_cache(m.get('team1'), m.get('team2'), d, obj)
        except Exception:
            pass
    return obj


async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    data = q.data or ''
    if data == 'noop':
        return
    parts = data.split('|')
    if data == 'res|dates':
        await q.message.edit_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())
        return
    if len(parts) >= 3 and parts[0] == 'res' and parts[1] == 'day':
        d = _normalize_date_arg(parts[2])
        title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
        # Щ„Ш§ ЩҶШӯШҜШ« ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§ Ш№ШҙШ§ЩҶ Щ…Ш§ ЩҠШ·ЩҲЩ„ШҢ Щ„ЩғЩҶ ШЈШ№Ш·Щҗ ШІШұ ШӘШӯШҜЩҠШ« ЩҲШ§Ш¶Шӯ.
        await q.message.edit_text(f"вҡҪ ЩҶШӘШ§ШҰШ¬ {title}\nШ§Ш®ШӘШұ Щ…ШЁШ§ШұШ§Ш© Щ„Щ„ШӘЩҒШ§ШөЩҠЩ„ ШЈЩҲ Ш§Ш¶ШәШ· ШӘШӯШҜЩҠШ« Ш§Щ„ЩҠЩҲЩ…:", reply_markup=_v33_results_matches_keyboard(d))
        return
    if len(parts) >= 3 and parts[0] == 'res' and parts[1] == 'refreshday':
        d = _normalize_date_arg(parts[2])
        try:
            await q.message.edit_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« ЩғЩ„ Щ…ШЁШ§ШұЩҠШ§ШӘ {d} Щ…ЩҶ ESPN Ш«Щ… Ш§Щ„Щ…ШөШ§ШҜШұ Ш§Щ„Ш§ШӯШӘЩҠШ§Ш·ЩҠШ©...", reply_markup=None)
        except Exception:
            pass
        try:
            updated, dbg = await asyncio.wait_for(asyncio.to_thread(_v41_update_day_results, d, True), timeout=25)
        except Exception as e:
            updated, dbg = 0, [f"Ш§ЩҶШӘЩҮЩү Ш§Щ„ЩҲЩӮШӘ/Ш®Ш·ШЈ: {str(e)[:80]}"]
        title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
        txt = f"вҡҪ ЩҶШӘШ§ШҰШ¬ {title}\nШӘЩ… ШӘШӯШҜЩҠШ« {updated} Щ…ШЁШ§ШұШ§Ш©.\nШ§Ш®ШӘШұ Щ…ШЁШ§ШұШ§Ш© Щ„Щ„ШӘЩҒШ§ШөЩҠЩ„ ШЈЩҲ ШЈШ№ШҜ Ш§Щ„ШӘШӯШҜЩҠШ«:"
        try:
            if '_is_admin' in globals() and _is_admin(q.from_user.id) and updated == 0 and dbg:
                txt += "\n\nрҹ”Һ Ш§Щ„ШӘШҙШ®ЩҠШө:\n" + "\n".join(f"- {x}" for x in dbg[-6:])
        except Exception:
            pass
        await q.message.edit_text(txt, reply_markup=_v33_results_matches_keyboard(d))
        return
    if len(parts) >= 4 and parts[0] == 'res' and parts[1] == 'match':
        d = _normalize_date_arg(parts[2])
        mid = parts[3]
        m = _fixture_by_id(mid) if '_fixture_by_id' in globals() else None
        if not m:
            for x in _v40_fixtures_for_date(d):
                if str(x.get('id')) == str(mid):
                    m = x; break
        if not m:
            await q.message.edit_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ЩҒЩҠ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©.", reply_markup=_v33_results_matches_keyboard(d))
            return
        cached = _v33_get_cached_match_result(m) if '_v33_get_cached_match_result' in globals() else None
        if not cached:
            try:
                await q.message.edit_text(f"вҸі ШЈШЁШӯШ« Ш№ЩҶ ЩҶШӘЩҠШ¬Ш© {m.get('team1')} Г— {m.get('team2')} Щ…ЩҶ ESPN Ш§Щ„ЩҠЩҲЩ… ЩғШ§Щ…Щ„ЩӢШ§...", reply_markup=None)
            except Exception:
                pass
            try:
                cached = await asyncio.wait_for(asyncio.to_thread(_v41_fetch_result_for_fixture, m, d, True, True), timeout=20)
            except Exception:
                cached = None
        if isinstance(cached, dict) and _patch6_numeric_score(cached):
            txt = _v41_result_detail_text(m, cached)
        else:
            txt = f"вҡ пёҸ Щ„Щ… ШЈШ¬ШҜ ЩҶШӘЩҠШ¬Ш© {m.get('team1')} Г— {m.get('team2')} ШӯШ§Щ„ЩҠЩӢШ§.\nШЁШ§ЩӮЩҠШ© вқҢ ШӯШӘЩү ЩҠШӘЩ… ШӘШӯШҜЩҠШ«ЩҮШ§."
            try:
                if '_is_admin' in globals() and _is_admin(q.from_user.id):
                    data_dbg = _v41_load_json_file(V41_RESULT_DEBUG_FILE, {})
                    key = _v33_fixture_key(m) if '_v33_fixture_key' in globals() else str(m)
                    dbg = (data_dbg.get(key) or {}).get('lines') or []
                    if dbg:
                        txt += "\n\nрҹ”Һ Ш§Щ„ШӘШҙШ®ЩҠШө:\n" + "\n".join(f"- {x}" for x in dbg[-8:])
            except Exception:
                pass
        await q.message.edit_text(txt, reply_markup=_v33_results_matches_keyboard(d))
        return
    # ШӘЩҲШ§ЩҒЩӮ ЩӮШҜЩҠЩ… res|date
    if len(parts) >= 2 and parts[0] == 'res':
        d = _normalize_date_arg(parts[1])
        title = _v26_fixture_title(d) if '_v26_fixture_title' in globals() else d
        await q.message.edit_text(f"вҡҪ ЩҶШӘШ§ШҰШ¬ {title}\nШ§Ш®ШӘШұ Щ…ШЁШ§ШұШ§Ш© Щ„Щ„ШӘЩҒШ§ШөЩҠЩ„ ШЈЩҲ Ш§Ш¶ШәШ· ШӘШӯШҜЩҠШ« Ш§Щ„ЩҠЩҲЩ…:", reply_markup=_v33_results_matches_keyboard(d))


async def live_today_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    data = q.data or ''
    if data == 'noop':
        return
    parts = data.split('|')
    if len(parts) >= 3 and parts[1] == 'refreshday':
        d = _normalize_date_arg(parts[2])
        try:
            await q.message.edit_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ {d} Щ…ЩҶ ESPN...", reply_markup=None)
        except Exception:
            pass
        try:
            await asyncio.wait_for(asyncio.to_thread(_v41_update_day_results, d, True), timeout=25)
        except Exception:
            pass
        await q.message.edit_text(_v29_live_today_text(d), reply_markup=_v29_live_today_keyboard(d))
        return
    if len(parts) < 3 or parts[1] != 'match':
        return
    mid = parts[2]
    m = _fixture_by_id(mid) if '_fixture_by_id' in globals() else None
    if not m:
        await q.message.reply_text("Щ„Щ… ШЈШ¬ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ЩҒЩҠ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©.")
        return
    active = _normalize_date_arg(_v41_active_live_date())
    if _normalize_date_arg(m.get('date')) != active:
        d = _normalize_date_arg(m.get('date'))
        await q.message.reply_text("ЩҮШ°ЩҮ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„ЩҠШіШӘ Ш¶Щ…ЩҶ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ЩҶШҙШ· Щ„Щ„Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ. ШӘЩ„ЩӮШ§ЩҮШ§ ЩҒЩҠ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ ШҘШ°Ш§ Ш§ЩҶШӘЩҮШӘ.", reply_markup=_v33_results_matches_keyboard(d))
        return
    try:
        await q.message.edit_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« {m.get('team1')} Г— {m.get('team2')} Щ…ЩҶ ESPN...", reply_markup=None)
        wait_msg = q.message
    except Exception:
        wait_msg = await q.message.reply_text(f"вҸі Ш¬Ш§ШұЩҠ ШӘШӯШҜЩҠШ« {m.get('team1')} Г— {m.get('team2')} Щ…ЩҶ ESPN...")
    try:
        obj = await asyncio.wait_for(asyncio.to_thread(_v40_fetch_live_for_fixture, m, True), timeout=18)
    except Exception:
        obj = None
    if not isinstance(obj, dict) or not _patch6_numeric_score(obj):
        await wait_msg.edit_text(f"вҡҪ {m.get('team1')} Г— {m.get('team2')}\nШ§Щ„ШӯШ§Щ„Ш©: ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«\nШ§Щ„Щ…ШөШҜШұ: Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", reply_markup=_v29_live_today_keyboard(active))
        return
    label = obj.get('actual_source') or obj.get('source') or 'ESPN'
    try:
        path = render_live_match_card(obj, label)
        try:
            await wait_msg.delete()
        except Exception:
            pass
        await send_photo_path(q.message, path, build_live_caption(obj, label))
    except Exception:
        await wait_msg.edit_text(build_live_caption(obj, label), reply_markup=_v29_live_today_keyboard(active))


async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    txt = normalize_name(update.message.text or '')
    trigger_words = {"Ш§Щ„ЩӮШ§ШҰЩ…Ш©", "Ш§ШЁШҜШ§", "Ш§Ш·Щ„", "ШІШЁШҜ", "Ш§Щ„Щ…ШөЩҠЩҒ", "ШіШӘШ§ШұШӘ", "ШҘЩ„ШәШ§ШЎ", "Ш§Щ„ШәШ§ШЎ", "вҶ©пёҸ ШҘЩ„ШәШ§ШЎ"}
    if txt in trigger_words:
        await public_menu_command(update, context)
        return
    if txt == "рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ":
        await update.message.reply_text(_v29_live_today_text(), reply_markup=_v29_live_today_keyboard())
        return
    if txt == "рҹ“Ӣ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ":
        await update.message.reply_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())
        return
    try:
        if callable(_PATCH11_OLD_PUBLIC_REPLY_MENU_ROUTER):
            return await _PATCH11_OLD_PUBLIC_REPLY_MENU_ROUTER(update, context)
    except Exception:
        pass


async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    if data == 'mainmenu|live':
        await q.answer()
        try:
            await q.edit_message_text(_v29_live_today_text(), reply_markup=_v29_live_today_keyboard())
        except Exception:
            await q.message.reply_text(_v29_live_today_text(), reply_markup=_v29_live_today_keyboard())
        return
    if data == 'mainmenu|results':
        await q.answer()
        try:
            await q.edit_message_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())
        except Exception:
            await q.message.reply_text("Ш§Ш®ШӘШұ ШӘШ§ШұЩҠШ® Ш§Щ„ЩҶШӘШ§ШҰШ¬:", reply_markup=_v28_previous_results_keyboard())
        return
    try:
        if callable(_PATCH11_OLD_PUBLIC_MENU_CALLBACK):
            return await _PATCH11_OLD_PUBLIC_MENU_CALLBACK(update, context)
    except Exception:
        pass

