# ==================== PATCH16: FIX DATE CALLBACKS + AUTHORITATIVE RESULTS TABLE ====================
# ЩҮШҜЩҒЩҮ ЩҒЩӮШ·:
# - ШІШұ Ш§Щ„ШӘШ§ШұЩҠШ® ЩҠШұШіЩ„ Ш§Щ„ШӘШ§ШұЩҠШ® ЩҶЩҒШіЩҮ ШЁШҙЩғЩ„ ШўЩ…ЩҶШҢ Щ„Ш§ index ЩҲЩ„Ш§ ЩғЩҲШҜ Щ…ШІШ§Шӯ.
# - Ш№ШұШ¶ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӘШ§ШұЩҠШ® Щ…ЩҶ Ш¬ШҜЩҲЩ„ЩҶШ§ Ш§Щ„ШөШӯЩҠШӯ ШҜШ§ШҰЩ…ЩӢШ§.
# - Ш§Щ„ШӘШӯШҜЩҠШ« ЩҒЩӮШ· ЩҮЩҲ Ш§Щ„Ш°ЩҠ ЩҠШЁШӯШ« ЩҒЩҠ ESPN ЩҲШ§Щ„Щ…ШөШ§ШҜШұ Ш§Щ„Ш§ШӯШӘЩҠШ§Ш·ЩҠШ©.
# - ШҘШөЩ„Ш§Шӯ live/result callbacks ШЁШҜЩҲЩҶ Щ„Щ…Ші Ш§Щ„ШӘШөШ§Щ…ЩҠЩ… ШЈЩҲ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ.
V46_PATCH_NAME = "PATCH16_DATE_CALLBACK_FIX"


def _v46_date_code(d):
    d = _normalize_date_arg(d)
    m = re.match(r'(\d{2})/(\d{2})/(\d{4})', d or '')
    if not m:
        return str(d or '').replace('/', '-')
    dd, mm, yy = m.groups()
    return f"{yy}{mm}{dd}"


def _v46_date_from_code(code):
    s = str(code or '').strip()
    m = re.fullmatch(r'(\d{4})(\d{2})(\d{2})', s)
    if m:
        yy, mm, dd = m.groups()
        return f"{dd}/{mm}/{yy}"
    return _normalize_date_arg(s)


