# ==================== PATCH17: BULK HIGHLIGHTS 60 + LIVE GOALS CAPTION FIX ====================
# Ш§Щ„Щ…Ш·Щ„ЩҲШЁ ЩӮШЁЩ„ ШӘШҜШҙЩҠЩҶ Ш§Щ„ШЁЩҲШӘ:
# 1) /Ш§Ш¶Ш§ЩҒШ©_Щ…Щ„Ш®ШөШ§ШӘ ШӯШӘЩү 60 ШіШ·ШұЩӢШ§ ШҜЩҒШ№Ш© ЩҲШ§ШӯШҜШ©.
# 2) /ШӯШ°ЩҒ_Щ…Щ„Ш®Шө ЩҲ /ШӯШ°ЩҒ_Щ…Щ„Ш®ШөШ§ШӘ + ШІШұ ШӯШ°ЩҒ Щ„Щ„Щ…ШҙШұЩҒ Ш№ЩҶШҜ Ш№ШұШ¶ Ш§Щ„Щ…Щ„Ш®Шө.
# 3) ШӘШӯШіЩҠЩҶ Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ: ЩҶЩҒШі ШҜШ§Щ„Ш© Ш§Щ„ЩҶШӘШ§ШҰШ¬ Щ„ШҘЩғЩ…Ш§Щ„ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Ш«Щ… Ш№ШұШ¶ЩҮЩ… ЩҒЩҠ Ш§Щ„ЩғЩ„Ш§Щ… ШӘШӯШӘ Ш§Щ„ШөЩҲШұШ©.

V47_PATCH_NAME = "PATCH17_SUMMARIES60_LIVE_GOALS"
V47_HIGHLIGHTS_BULK_LIMIT = 60


def _v47_url_ok(url):
    url = normalize_name(url or '') if 'normalize_name' in globals() else str(url or '').strip()
    return bool(re.search(r"https?://|youtu\.be|youtube\.com|t\.me|x\.com|twitter\.com|fifa\.com|bein|ssc|shahid", url, re.I))


def _v47_split_highlight_line(line, require_url=True):
    """ЩҠШұШ¬Ш№ team1, team2, url, error."""
    raw = normalize_name(line or '') if 'normalize_name' in globals() else str(line or '').strip()
    raw = raw.strip()
    if not raw:
        return '', '', '', 'ЩҒШ§ШұШә'
    if '|' in raw:
        pair, url = raw.split('|', 1)
        url = url.strip()
    else:
        pair, url = raw, ''
    team1, team2, _ = _parse_match_pair(pair) if '_parse_match_pair' in globals() else ('', '', '')
    if not team1 or not team2:
        return '', '', url, 'ШөЩҠШәШ© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ШәЩҠШұ ШөШӯЩҠШӯШ©'
    if require_url and not _v47_url_ok(url):
        return team1, team2, url, 'Ш§Щ„ШұШ§ШЁШ· ЩҶШ§ЩӮШө ШЈЩҲ ШәЩҠШұ ШөШӯЩҠШӯ'
    return team1, team2, url, ''


def _v47_delete_match_highlight(team1, team2):
    team1 = canonical_team_name(team1) or normalize_name(team1)
    team2 = canonical_team_name(team2) or normalize_name(team2)
    data = _load_highlights() if '_load_highlights' in globals() else {}
    removed = 0
    keys_to_delete = set()
    try:
        keys_to_delete.add(_match_hash_key(team1, team2))
        keys_to_delete.add(_match_hash_key(team2, team1))
    except Exception:
        pass
    for k, item in list((data or {}).items()):
        a = canonical_team_name(item.get('team1')) or normalize_name(item.get('team1') or '')
        b = canonical_team_name(item.get('team2')) or normalize_name(item.get('team2') or '')
        if k in keys_to_delete or {simple_key(a), simple_key(b)} == {simple_key(team1), simple_key(team2)}:
            data.pop(k, None)
            removed += 1
    try:
        _save_highlights(data)
    except Exception:
        pass
    # Ш§Щ…ШіШӯ Ш§Щ„ШұШ§ШЁШ· Ш§Щ„ЩҠШҜЩҲЩҠ Щ…ЩҶ ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ ШҘШ°Ш§ Щ…ЩҲШ¬ЩҲШҜ
    try:
        manual = _load_manual_match_data()
        changed = False
        for k, item in list((manual or {}).items()):
            a = canonical_team_name(item.get('team1')) or normalize_name(item.get('team1') or '')
            b = canonical_team_name(item.get('team2')) or normalize_name(item.get('team2') or '')
            if {simple_key(a), simple_key(b)} == {simple_key(team1), simple_key(team2)}:
                if item.pop('summary_url', None) is not None:
                    changed = True
                if item.pop('summary_url_manual', None) is not None:
                    changed = True
        if changed:
            _save_manual_match_data(manual)
    except Exception:
        pass
    return removed


async def add_highlights_bulk_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ''
    body = re.sub(r"^/\S+", "", text, count=1).strip()
    lines = [ln.strip() for ln in body.splitlines() if ln.strip()]
    if not lines:
        await update.message.reply_text(
            "Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n"
            "/Ш§Ш¶Ш§ЩҒШ©_Щ…Щ„Ш®ШөШ§ШӘ\n"
            "Ш§Щ„ШҘЩғЩҲШ§ШҜЩҲШұ * ЩғЩҲШұШ§ШіШ§ЩҲ | https://youtube.com/...\n"
            "ЩҮЩҲЩ„ЩҶШҜШ§ * Ш§Щ„ШіЩҲЩҠШҜ | https://youtube.com/...\n\n"
            "Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү 60 Щ…Щ„Ш®Шө ШЁШ§Щ„ШұШіШ§Щ„Ш© Ш§Щ„ЩҲШ§ШӯШҜШ©."
        )
        return
    if len(lines) > V47_HIGHLIGHTS_BULK_LIMIT:
        await update.message.reply_text(f"вҡ пёҸ ШЈШұШіЩ„ШӘ {len(lines)} ШіШ·Шұ. Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү {V47_HIGHLIGHTS_BULK_LIMIT}.\nЩӮШіЩ…ЩҮШ§ Ш№Щ„Щү ШұШіШ§Щ„ШӘЩҠЩҶ.")
        return
    saved = updated = failed = 0
    errors = []
    data_before = _load_highlights() if '_load_highlights' in globals() else {}
    before_keys = set((data_before or {}).keys())
    for i, line in enumerate(lines, start=1):
        team1, team2, url, err = _v47_split_highlight_line(line, require_url=True)
        if err:
            failed += 1
            errors.append(f"Ш§Щ„ШіШ·Шұ {i}: {err} вҖ” {line[:70]}")
            continue
        try:
            key = _match_hash_key(team1, team2)
            existed = key in before_keys
            _save_match_highlight(team1, team2, url)
            if existed:
                updated += 1
            else:
                saved += 1
                before_keys.add(key)
        except Exception as e:
            failed += 1
            errors.append(f"Ш§Щ„ШіШ·Шұ {i}: Ш®Ш·ШЈ {str(e)[:50]}")
    msg = [
        "рҹҺһпёҸ ШӘЩӮШұЩҠШұ ШҘШ¶Ш§ЩҒШ© Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ",
        f"вң… ШӘЩ… ШӯЩҒШё: {saved}",
        f"рҹ”Ғ ШӘЩ… ШӘШӯШҜЩҠШ«: {updated}",
        f"вҡ пёҸ ЩҒШҙЩ„: {failed}",
    ]
    if errors:
        msg += ["", "Ш§Щ„ШЈШіШ·Шұ Ш§Щ„ШӘЩҠ Щ„Щ… ШӘЩҸШӯЩҒШё:"] + [f"- {x}" for x in errors[:12]]
        if len(errors) > 12:
            msg.append(f"... ЩҲШЁШ§ЩӮЩҠ {len(errors)-12} ШіШ·Шұ")
    await update.message.reply_text("\n".join(msg))


async def delete_highlight_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = re.sub(r"^/\S+", "", update.message.text or "", count=1).strip()
    team1, team2, _ = _parse_match_pair(body) if '_parse_match_pair' in globals() else ('', '', '')
    if not team1 or not team2:
        await update.message.reply_text("Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӯШ°ЩҒ_Щ…Щ„Ш®Шө Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * ШҘШіШЁШ§ЩҶЩҠШ§")
        return
    removed = _v47_delete_match_highlight(team1, team2)
    if removed:
        await update.message.reply_text(f"рҹ—‘пёҸ ШӘЩ… ШӯШ°ЩҒ Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}")
    else:
        await update.message.reply_text(f"Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„Ш®Шө Щ…ШӯЩҒЩҲШё Щ„Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}")


async def delete_highlights_bulk_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ''
    body = re.sub(r"^/\S+", "", text, count=1).strip()
    lines = [ln.strip() for ln in body.splitlines() if ln.strip()]
    if not lines:
        await update.message.reply_text(
            "Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n"
            "/ШӯШ°ЩҒ_Щ…Щ„Ш®ШөШ§ШӘ\n"
            "Ш§Щ„ШҘЩғЩҲШ§ШҜЩҲШұ * ЩғЩҲШұШ§ШіШ§ЩҲ\n"
            "ЩҮЩҲЩ„ЩҶШҜШ§ * Ш§Щ„ШіЩҲЩҠШҜ\n\n"
            "Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү 60 Щ…ШЁШ§ШұШ§Ш© ШЁШ§Щ„ШұШіШ§Щ„Ш© Ш§Щ„ЩҲШ§ШӯШҜШ©."
        )
        return
    if len(lines) > V47_HIGHLIGHTS_BULK_LIMIT:
        await update.message.reply_text(f"вҡ пёҸ ШЈШұШіЩ„ШӘ {len(lines)} ШіШ·Шұ. Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү {V47_HIGHLIGHTS_BULK_LIMIT}.\nЩӮШіЩ…ЩҮШ§ Ш№Щ„Щү ШұШіШ§Щ„ШӘЩҠЩҶ.")
        return
    deleted = failed = 0
    errors = []
    for i, line in enumerate(lines, start=1):
        team1, team2, _url, err = _v47_split_highlight_line(line, require_url=False)
        if err and err != 'Ш§Щ„ШұШ§ШЁШ· ЩҶШ§ЩӮШө ШЈЩҲ ШәЩҠШұ ШөШӯЩҠШӯ':
            failed += 1
            errors.append(f"Ш§Щ„ШіШ·Шұ {i}: {err} вҖ” {line[:70]}")
            continue
        try:
            n = _v47_delete_match_highlight(team1, team2)
            if n:
                deleted += 1
            else:
                failed += 1
                errors.append(f"Ш§Щ„ШіШ·Шұ {i}: ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ вҖ” {team1} Г— {team2}")
        except Exception as e:
            failed += 1
            errors.append(f"Ш§Щ„ШіШ·Шұ {i}: Ш®Ш·ШЈ {str(e)[:50]}")
    msg = ["рҹ—‘пёҸ ШӘЩӮШұЩҠШұ ШӯШ°ЩҒ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ", f"вң… ШӘЩ… ШӯШ°ЩҒ: {deleted}", f"вҡ пёҸ Щ„Щ… ЩҠЩҸШӯШ°ЩҒ: {failed}"]
    if errors:
        msg += ["", "Ш§Щ„ШӘЩҒШ§ШөЩҠЩ„:"] + [f"- {x}" for x in errors[:12]]
        if len(errors) > 12:
            msg.append(f"... ЩҲШЁШ§ЩӮЩҠ {len(errors)-12} ШіШ·Шұ")
    await update.message.reply_text("\n".join(msg))


def _highlights_keyboard():
    data = _load_highlights()
    rows = []
    for key, item in sorted((data or {}).items(), key=lambda kv: (kv[1].get('team1', ''), kv[1].get('team2', ''))):
        label = f"{item.get('team1','')} Г— {item.get('team2','')}".strip()
        if label and item.get('url'):
            rows.append([InlineKeyboardButton(label[:58], callback_data=f"hls|show|{key}")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


async def highlights_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    try:
        await q.answer()
    except Exception:
        pass
    parts = (q.data or '').split('|')
    if len(parts) >= 3 and parts[1] == 'show':
        key = parts[2]
        item = (_load_highlights() or {}).get(key)
        if not item:
            await q.message.reply_text("Ш§Щ„Щ…Щ„Ш®Шө ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ ШЈЩҲ ШӘЩ… ШӯШ°ЩҒЩҮ.")
            return
        kb = None
        try:
            if '_is_admin' in globals() and _is_admin(q.from_user.id):
                kb = InlineKeyboardMarkup([[InlineKeyboardButton("рҹ—‘пёҸ ШӯШ°ЩҒ ЩҮШ°Ш§ Ш§Щ„Щ…Щ„Ш®Шө", callback_data=f"hls|del|{key}")]])
        except Exception:
            kb = None
        await q.message.reply_text(
            f"рҹҺһпёҸ Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {item.get('team1')} Г— {item.get('team2')}\n{item.get('url')}",
            reply_markup=kb,
        )
        return
    if len(parts) >= 3 and parts[1] == 'del':
        if '_is_admin' in globals() and not _is_admin(q.from_user.id):
            await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
            return
        key = parts[2]
        data = _load_highlights() or {}
        item = data.get(key)
        if not item:
            await q.message.reply_text("Ш§Щ„Щ…Щ„Ш®Шө Щ…ШӯШ°ЩҲЩҒ ШЈЩҲ ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ.", reply_markup=_highlights_keyboard())
            return
        data.pop(key, None)
        _save_highlights(data)
        try:
            _v47_delete_match_highlight(item.get('team1'), item.get('team2'))
        except Exception:
            pass
        await q.message.reply_text(f"рҹ—‘пёҸ ШӘЩ… ШӯШ°ЩҒ Щ…Щ„Ш®Шө {item.get('team1')} Г— {item.get('team2')}", reply_markup=_highlights_keyboard())
        return


# Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ: Ш§ШіШӘШ®ШҜЩ… ЩҶЩҒШі Щ…ЩҶШ·ЩӮ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ШҘЩғЩ…Ш§Щ„ Ш§Щ„ШЈЩҮШҜШ§ЩҒШҢ ЩҲЩ„Ш§ ШӘШұШ¬Ш№ ЩғШ§Шҙ ЩҶШ§ЩӮШө ШҘШ°Ш§ Ш¶ШәШ· Ш§Щ„Щ…ШіШӘШ®ШҜЩ… ШӘШӯШҜЩҠШ«.
def _v47_live_goal_ready(obj):
    try:
        return isinstance(obj, dict) and _patch6_numeric_score(obj) and _v43_goals_complete(obj)
    except Exception:
        return False


def _v40_fetch_live_for_fixture(m, force=False):
    d = _normalize_date_arg((m or {}).get('date')) or _normalize_date_arg(_v41_active_live_date())
    if not force:
        for getter in [globals().get('_v34_get_fast_live_cache_for_fixture'), globals().get('_v43_get_cached_match_result')]:
            try:
                if callable(getter):
                    cached = getter(m)
                    if _v47_live_goal_ready(cached):
                        return cached
            except Exception:
                pass
    # force=True ШЈЩҲ ЩғШ§Шҙ ЩҶШ§ЩӮШө: ЩҶЩҒШі Щ…ШіШ§Шұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ШҢ Щ…Ш№ Ш§Щ„ШіЩ…Ш§Шӯ ШЁШ§Щ„Ш§ШӯШӘЩҠШ§Ш· ЩҲШ§Щ„ШЁШӯШ« Ш§Щ„Ш®Ш§ШұШ¬ЩҠ.
    try:
        obj = _v41_fetch_result_for_fixture(m, d, force=True if force else False, allow_seed=True)
    except Exception:
        obj = None
    if isinstance(obj, dict) and _patch6_numeric_score(obj):
        try:
            if not _v43_goals_complete(obj):
                dbg = []
                obj = _v43_complete_goals_multi(obj, m, d, force=True, debug=dbg)
        except Exception:
            pass
        try:
            _v43_put_cached_match_result(m, obj, obj.get('actual_source') or obj.get('source') or 'ESPN')
        except Exception:
            pass
        try:
            _save_fast_live_cache(m.get('team1'), m.get('team2'), d, obj)
        except Exception:
            pass
        return obj
    return obj


# Ш§Щ„ЩғЩ„Ш§Щ… ШӘШӯШӘ ШөЩҲШұШ© Ш§Щ„Щ…ШЁШ§ШҙШұ: Ш§ШіШӘШ®ШҜЩ… _patch6_goal_lines Ш№ШҙШ§ЩҶ Щ„Ш§ ЩҠЩғШӘШЁ Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈЩҮШҜШ§ЩҒ ШҘЩ„Ш§ ШҘШ°Ш§ Ш§Щ„ЩҶШӘЩҠШ¬Ш© 0-0.
def build_live_caption(match, mode_label="ШӘЩ„ЩӮШ§ШҰЩҠ"):
    match = match or {}
    lines = [f"{match.get('team1','')} {match.get('score1','-')} - {match.get('score2','-')} {match.get('team2','')}"]
    st = match.get('status') or match.get('minute') or ''
    if st:
        lines.append(str(st))
    lines.append('')
    try:
        lines.extend(_patch6_goal_lines(match))
    except Exception:
        sc = match.get('scorers') or []
        if sc:
            lines.append('вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ:')
            lines.extend([f"- {x}" for x in sc[:10]])
        else:
            lines.append('вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«')
    actual = match.get('actual_source') or match.get('source') or match.get('goals_source') or mode_label
    lines += ['', f"Ш§Щ„Щ…ШөШҜШұ: {actual}"]
    link = match.get('summary_url_manual') or match.get('highlight_url') or match.get('summary_url') or ''
    if link:
        lines.append(f"рҹҺһпёҸ Щ…Щ„Ш®Шө Ш§Щ„Щ…ШЁШ§ШұШ§Ш©: {link}")
    return "\n".join([str(x) for x in lines if x is not None]).strip()

# ==================== END PATCH17 ====================


# ==================== PATCH18: FAST HIGHLIGHTS SAVE + LIVE GOALS USE RESULTS PATH ====================
# ШҘШөЩ„Ш§ШӯШ§ЩҶ ЩҒЩӮШ·:
# 1) Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ: ШӯЩҒШё Щ…ШЁШ§ШҙШұ ШЁШҜЩҲЩҶ ЩҒШӯШө ШұЩҲШ§ШЁШ·/ШЁШҜЩҲЩҶ ШӘШ№Щ„ЩҠЩӮШҢ ЩҲШӯЩҒШё Щ…Щ„ЩҒ JSON Щ…ШұШ© ЩҲШ§ШӯШҜШ© Щ„Щ„ШҜЩҒШ№Ш§ШӘ ШӯШӘЩү 60.
# 2) Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ: ШҘШ°Ш§ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ЩҒЩҠЩҮШ§ ШЈЩҮШҜШ§ЩҒШҢ ЩҠШіШӘШ®ШҜЩ… ЩҶЩҒШі Щ…ШіШ§Шұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Щ„ШҘЩғЩ…Ш§Щ„ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ ЩӮШЁЩ„ ШҘШұШіШ§Щ„ Ш§Щ„ШөЩҲШұШ©/Ш§Щ„ЩғЩ„Ш§Щ….

V48_PATCH_NAME = "PATCH18_FAST_SUMMARIES_LIVE_GOALS_FIX"
V48_HIGHLIGHTS_BULK_LIMIT = 60


def _v48_norm_txt(x):
    try:
        return normalize_name(x)
    except Exception:
        return str(x or '').strip()


def _v48_is_url(url):
    s = str(url or '').strip()
    return bool(re.search(r'^(?:https?://|www\.)\S+', s, re.I) or re.search(r'(?:youtube\.com|youtu\.be|t\.me|x\.com|twitter\.com|fifa\.com)', s, re.I))


def _v48_pair_from_text(pair):
    raw = _v48_norm_txt(pair)
    # Щ„Ш§ ЩҶШіШӘШҜШ№ЩҠ _parse_match_pair ЩҮЩҶШ§ Ш№ШҙШ§ЩҶ Щ…Ш§ ЩҠШӘШЈШ«Шұ ШЁЩҖ | ШЈЩҲ ШЈЩ…Шұ Ш§Щ„ШіЩ„Ш§Шҙ.
    for sep in ['*', 'Г—', ' x ', ' X ', ' - ', 'вҖ“', 'вҖ”']:
        if sep in raw:
            a, b = raw.split(sep, 1)
            a = canonical_team_name(a) or _v48_norm_txt(a)
            b = canonical_team_name(b) or _v48_norm_txt(b)
            if a and b:
                return a, b
    return '', ''


def _v48_parse_highlight_line(line, require_url=True):
    raw = _v48_norm_txt(line)
    if not raw:
        return '', '', '', 'ЩҒШ§ШұШә'
    if '|' in raw:
        pair, url = raw.split('|', 1)
        url = url.strip()
    else:
        pair, url = raw, ''
    a, b = _v48_pair_from_text(pair)
    if not a or not b:
        return '', '', url, 'ШөЩҠШәШ© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ШәЩҠШұ ШөШӯЩҠШӯШ©'
    if require_url and not _v48_is_url(url):
        return a, b, url, 'Ш§Щ„ШұШ§ШЁШ· ЩҶШ§ЩӮШө ШЈЩҲ ШәЩҠШұ ШөШӯЩҠШӯ'
    return a, b, url, ''


def _v48_highlight_key(team1, team2):
    try:
        return _match_hash_key(team1, team2)
    except Exception:
        a = simple_key(team1) if 'simple_key' in globals() else re.sub(r'\W+', '', str(team1))
        b = simple_key(team2) if 'simple_key' in globals() else re.sub(r'\W+', '', str(team2))
        return 'hl_' + '_'.join(sorted([a, b]))


def _v48_direct_save_highlight(team1, team2, url, data=None):
    team1 = canonical_team_name(team1) or _v48_norm_txt(team1)
    team2 = canonical_team_name(team2) or _v48_norm_txt(team2)
    url = str(url or '').strip()
    if data is None:
        data = _load_highlights() if '_load_highlights' in globals() else {}
    key = _v48_highlight_key(team1, team2)
    existed = key in (data or {})
    try:
        now_txt = _now_riyadh_text()
    except Exception:
        now_txt = ''
    data[key] = {'team1': team1, 'team2': team2, 'url': url, 'updated_at': now_txt}
    return key, existed


def _v48_direct_delete_highlight(team1, team2, data=None):
    team1 = canonical_team_name(team1) or _v48_norm_txt(team1)
    team2 = canonical_team_name(team2) or _v48_norm_txt(team2)
    if data is None:
        data = _load_highlights() if '_load_highlights' in globals() else {}
    removed = 0
    keys = {_v48_highlight_key(team1, team2), _v48_highlight_key(team2, team1)}
    for k, item in list((data or {}).items()):
        a = canonical_team_name((item or {}).get('team1')) or _v48_norm_txt((item or {}).get('team1'))
        b = canonical_team_name((item or {}).get('team2')) or _v48_norm_txt((item or {}).get('team2'))
        try:
            same_pair = {simple_key(a), simple_key(b)} == {simple_key(team1), simple_key(team2)}
        except Exception:
            same_pair = {a, b} == {team1, team2}
        if k in keys or same_pair:
            data.pop(k, None)
            removed += 1
    return removed


async def add_highlights_bulk_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    # ШұШҜ ЩҒЩҲШұЩҠ Ш№ШҙШ§ЩҶ Ш§Щ„Щ…ШіШӘШ®ШҜЩ… ЩҠШ№ШұЩҒ ШЈЩҶ Ш§Щ„ШЁЩҲШӘ Ш§ШіШӘЩ„Щ… Ш§Щ„Ш·Щ„ШЁ.
    text = update.message.text or ''
    body = re.sub(r'^/\S+', '', text, count=1).strip()
    lines = [ln.strip() for ln in body.splitlines() if ln.strip()]
    if not lines:
        await update.message.reply_text(
            'Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n'
            '/Ш§Ш¶Ш§ЩҒШ©_Щ…Щ„Ш®ШөШ§ШӘ\n'
            'Ш§Щ„ШҘЩғЩҲШ§ШҜЩҲШұ * ЩғЩҲШұШ§ШіШ§ЩҲ | https://youtube.com/...\n'
            'ЩҮЩҲЩ„ЩҶШҜШ§ * Ш§Щ„ШіЩҲЩҠШҜ | https://youtube.com/...\n\n'
            'Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү 60 Щ…Щ„Ш®Шө ШЁШ§Щ„ШұШіШ§Щ„Ш© Ш§Щ„ЩҲШ§ШӯШҜШ©.'
        )
        return
    if len(lines) > V48_HIGHLIGHTS_BULK_LIMIT:
        await update.message.reply_text(f'вҡ пёҸ ШЈШұШіЩ„ШӘ {len(lines)} ШіШ·Шұ. Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү {V48_HIGHLIGHTS_BULK_LIMIT}.\nЩӮШіЩ…ЩҮШ§ Ш№Щ„Щү ШұШіШ§Щ„ШӘЩҠЩҶ.')
        return

    wait = await update.message.reply_text(f'вҸі Ш¬Ш§ШұЩҠ ШӯЩҒШё {len(lines)} Щ…Щ„Ш®Шө...')
    saved = updated = failed = 0
    errors = []
    data = _load_highlights() if '_load_highlights' in globals() else {}
    if not isinstance(data, dict):
        data = {}
    for i, line in enumerate(lines, start=1):
        team1, team2, url, err = _v48_parse_highlight_line(line, require_url=True)
        if err:
            failed += 1
            errors.append(f'Ш§Щ„ШіШ·Шұ {i}: {err}')
            continue
        try:
            _key, existed = _v48_direct_save_highlight(team1, team2, url, data=data)
            if existed:
                updated += 1
            else:
                saved += 1
        except Exception as e:
            failed += 1
            errors.append(f'Ш§Щ„ШіШ·Шұ {i}: Ш®Ш·ШЈ {str(e)[:60]}')
    try:
        _save_highlights(data)
    except Exception as e:
        await wait.edit_text(f'вқҢ ШӘШ№Ш°Шұ ШӯЩҒШё Щ…Щ„ЩҒ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ: {str(e)[:160]}')
        return
    msg = [
        'рҹҺһпёҸ ШӘЩӮШұЩҠШұ ШҘШ¶Ш§ЩҒШ© Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ',
        f'вң… ШӘЩ… ШӯЩҒШё: {saved}',
        f'рҹ”Ғ ШӘЩ… ШӘШӯШҜЩҠШ«: {updated}',
        f'вҡ пёҸ ЩҒШҙЩ„: {failed}',
        '',
        'ШӘЩ… Ш§Щ„ШӯЩҒШё Щ…ШЁШ§ШҙШұШ© ШЁШҜЩҲЩҶ ЩҒШӯШө ШұЩҲШ§ШЁШ· Ш№ШҙШ§ЩҶ Щ…Ш§ ЩҠШ№Щ„ЩӮ Ш§Щ„ШЁЩҲШӘ.'
    ]
    if errors:
        msg += ['', 'Ш§Щ„ШЈШіШ·Шұ Ш§Щ„ШӘЩҠ Щ„Щ… ШӘЩҸШӯЩҒШё:'] + [f'- {x}' for x in errors[:10]]
        if len(errors) > 10:
            msg.append(f'... ЩҲШЁШ§ЩӮЩҠ {len(errors)-10} ШіШ·Шұ')
    await wait.edit_text('\n'.join(msg))


async def add_highlight_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = re.sub(r'^/\S+', '', update.message.text or '', count=1).strip()
    team1, team2, url, err = _v48_parse_highlight_line(body, require_url=False)
    if not team1 or not team2:
        await update.message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/Ш§Ш¶Ш§ЩҒШ©_Щ…Щ„Ш®Шө Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * ШҘШіШЁШ§ЩҶЩҠШ§ | https://youtube.com/...\nШЈЩҲ:\n/Ш§Ш¶Ш§ЩҒШ©_Щ…Щ„Ш®Шө Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * ШҘШіШЁШ§ЩҶЩҠШ§\nШ«Щ… Ш§ШұШіЩ„ Ш§Щ„ШұШ§ШЁШ·')
        return
    if url and _v48_is_url(url):
        data = _load_highlights() if '_load_highlights' in globals() else {}
        _key, existed = _v48_direct_save_highlight(team1, team2, url, data=data)
        _save_highlights(data)
        await update.message.reply_text(('рҹ”Ғ ШӘЩ… ШӘШӯШҜЩҠШ«' if existed else 'вң… ШӘЩ… ШӯЩҒШё') + f' Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}')
        return
    context.user_data['pending_highlight_add'] = {'team1': team1, 'team2': team2}
    await update.message.reply_text(f'Ш§ШұШіЩ„ ШұШ§ШЁШ· Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2} Ш§Щ„ШўЩҶ:')


async def _pending_highlight_input(update: Update, context: ContextTypes.DEFAULT_TYPE):
    pending = context.user_data.get('pending_highlight_add')
    if not isinstance(pending, dict):
        return False
    url = str(update.message.text or '').strip()
    if not _v48_is_url(url):
        await update.message.reply_text('Ш§ШұШіЩ„ ШұШ§ШЁШ· Ш§Щ„Щ…Щ„Ш®Шө ЩғШ§Щ…Щ„ЩӢШ§.')
        return True
    team1, team2 = pending.get('team1'), pending.get('team2')
    data = _load_highlights() if '_load_highlights' in globals() else {}
    _key, existed = _v48_direct_save_highlight(team1, team2, url, data=data)
    _save_highlights(data)
    context.user_data.pop('pending_highlight_add', None)
    await update.message.reply_text(('рҹ”Ғ ШӘЩ… ШӘШӯШҜЩҠШ«' if existed else 'вң… ШӘЩ… ШӯЩҒШё') + f' Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}')
    return True


async def delete_highlight_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    body = re.sub(r'^/\S+', '', update.message.text or '', count=1).strip()
    team1, team2, _url, err = _v48_parse_highlight_line(body, require_url=False)
    if not team1 or not team2:
        await update.message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӯШ°ЩҒ_Щ…Щ„Ш®Шө Ш§Щ„ШіШ№ЩҲШҜЩҠШ© * ШҘШіШЁШ§ЩҶЩҠШ§')
        return
    data = _load_highlights() if '_load_highlights' in globals() else {}
    n = _v48_direct_delete_highlight(team1, team2, data=data)
    _save_highlights(data)
    if n:
        await update.message.reply_text(f'рҹ—‘пёҸ ШӘЩ… ШӯШ°ЩҒ Щ…Щ„Ш®Шө Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}')
    else:
        await update.message.reply_text(f'Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„Ш®Шө Щ…ШӯЩҒЩҲШё Щ„Щ…ШЁШ§ШұШ§Ш© {team1} Г— {team2}')


async def delete_highlights_bulk_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text or ''
    body = re.sub(r'^/\S+', '', text, count=1).strip()
    lines = [ln.strip() for ln in body.splitlines() if ln.strip()]
    if not lines:
        await update.message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШӯШ°ЩҒ_Щ…Щ„Ш®ШөШ§ШӘ\nШ§Щ„ШҘЩғЩҲШ§ШҜЩҲШұ * ЩғЩҲШұШ§ШіШ§ЩҲ\nЩҮЩҲЩ„ЩҶШҜШ§ * Ш§Щ„ШіЩҲЩҠШҜ')
        return
    if len(lines) > V48_HIGHLIGHTS_BULK_LIMIT:
        await update.message.reply_text(f'вҡ пёҸ ШЈШұШіЩ„ШӘ {len(lines)} ШіШ·Шұ. Ш§Щ„ШӯШҜ Ш§Щ„ШЈЩӮШөЩү {V48_HIGHLIGHTS_BULK_LIMIT}.')
        return
    wait = await update.message.reply_text(f'вҸі Ш¬Ш§ШұЩҠ ШӯШ°ЩҒ {len(lines)} Щ…Щ„Ш®Шө...')
    data = _load_highlights() if '_load_highlights' in globals() else {}
    deleted = failed = 0
    errors = []
    for i, line in enumerate(lines, start=1):
        team1, team2, _url, err = _v48_parse_highlight_line(line, require_url=False)
        if not team1 or not team2:
            failed += 1; errors.append(f'Ш§Щ„ШіШ·Шұ {i}: ШөЩҠШәШ© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© ШәЩҠШұ ШөШӯЩҠШӯШ©'); continue
        n = _v48_direct_delete_highlight(team1, team2, data=data)
        if n:
            deleted += 1
        else:
            failed += 1; errors.append(f'Ш§Щ„ШіШ·Шұ {i}: ШәЩҠШұ Щ…ЩҲШ¬ЩҲШҜ')
    _save_highlights(data)
    msg = ['рҹ—‘пёҸ ШӘЩӮШұЩҠШұ ШӯШ°ЩҒ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ', f'вң… ШӘЩ… ШӯШ°ЩҒ: {deleted}', f'вҡ пёҸ Щ„Щ… ЩҠЩҸШӯШ°ЩҒ: {failed}']
    if errors:
        msg += ['', 'Ш§Щ„ШӘЩҒШ§ШөЩҠЩ„:'] + [f'- {x}' for x in errors[:10]]
    await wait.edit_text('\n'.join(msg))


# ШӘШӯШіЩҠЩҶ Ш§ШіШӘШ®ШұШ§Ш¬ ШЈШіЩ…Ш§ШЎ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ ESPN Summary ШЁШҙЩғЩ„ ШЈЩҲШіШ№ Щ„Щ„Щ…ШЁШ§ШҙШұ ЩҲШ§Щ„ЩҶШӘШ§ШҰШ¬.
def _v48_extract_scorers_from_summary_json(data, debug=None):
    debug = debug if debug is not None else []
    out = []

    def add(name, minute='', own=False, pen=False):
        try:
            _v43_add_goal(out, name, minute, own=own, pen=pen)
        except Exception:
            line = str(name or '').strip()
            if line and line not in out:
                out.append(line)

    def get_name_from_any(x):
        if not isinstance(x, dict):
            return ''
        # Щ…ШЁШ§ШҙШұ Щ…ЩҶ dict Ш§Щ„Щ„Ш§Ш№ШЁ
        for path in [('athlete',), ('player',), ('scorer',), ('participant',)]:
            v = x.get(path[0])
            if isinstance(v, dict):
                nm = v.get('displayName') or v.get('shortName') or v.get('name') or v.get('fullName')
                nm = _v43_clean_person_name(nm) if '_v43_clean_person_name' in globals() else str(nm or '').strip()
                if nm: return nm
        # ЩӮЩҲШ§ШҰЩ… Ш§Щ„Щ…ШҙШ§ШұЩғЩҠЩҶШҢ Ш§Щ„ШЈЩҮЩ… ШЈЩҲЩ„ Ш§ШіЩ… ЩҒЩҠ ШӯШҜШ« goal
        for k in ['athletes','players','participants','competitors']:
            arr = x.get(k)
            if isinstance(arr, list):
                for it in arr:
                    if isinstance(it, dict):
                        a = it.get('athlete') if isinstance(it.get('athlete'), dict) else it
                        nm = a.get('displayName') or a.get('shortName') or a.get('name') or a.get('fullName')
                        nm = _v43_clean_person_name(nm) if '_v43_clean_person_name' in globals() else str(nm or '').strip()
                        if nm: return nm
        return ''

    def node_blob(x):
        try:
            return _v43_node_text_blob(x)
        except Exception:
            vals=[]
            if isinstance(x, dict):
                for k,v in x.items():
                    if k.lower() in ['text','description','displaytext','shorttext','headline','summary','name','type','playtype']:
                        vals.append(str(v))
            return ' '.join(vals)

    def minute_from(x, blob=''):
        try:
            return _v43_minute_from_node(x, blob)
        except Exception:
            m = re.search(r"([1-9][0-9]{0,2}(?:\+[0-9]{1,2})?)\s*['вҖҷ]", str(blob or ''))
            return m.group(1) if m else ''

    def is_goal_node(x, blob):
        if not isinstance(x, dict):
            return False
        b = str(blob or '')
        # ESPN ЩғШ«ЩҠШұ ЩҠШіШӘШ®ШҜЩ… type.id=70/scoreValue ШЈЩҲ scoringPlay
        typ = x.get('type')
        tblob = ''
        if isinstance(typ, dict):
            tblob = ' '.join(str(typ.get(k,'')) for k in ['text','description','displayName','name','abbreviation','id'])
        elif typ is not None:
            tblob = str(typ)
        if x.get('scoringPlay') is True or x.get('scoreValue') in (1, '1'):
            return True
        if re.search(r'\b(goal|penalty goal|own goal|scored|scores)\b', b + ' ' + tblob, re.I):
            if not re.search(r'goals against|goals for|expected goals|goal difference|shots on goal|total goals|standings|highlight|preview', b, re.I):
                return True
        return False

    def walk(x):
        if isinstance(x, dict):
            blob = node_blob(x)
            if is_goal_node(x, blob):
                own = bool(re.search(r'own goal', blob, re.I))
                pen = bool(re.search(r'penalty', blob, re.I))
                name = get_name_from_any(x)
                if not name:
                    try:
                        name = _v43_extract_goal_name_from_text(blob)
                    except Exception:
                        name = ''
                add(name, minute_from(x, blob), own=own, pen=pen)
            for v in x.values():
                walk(v)
        elif isinstance(x, list):
            for it in x:
                walk(it)

    # ШЁШ№Ш¶ ESPN dumps ЩҒЩҠЩҮШ§ ШөЩҠШә ЩҲШөЩҒЩҠШ© ЩҒЩӮШ·
    try:
        dump = json.dumps(data, ensure_ascii=False)
        patterns = [
            r'Goal!.*?\.\s*([A-ZГҖ-Г–Гҳ-Г¶Гё-Гҝ][A-Za-zГҖ-Г–Гҳ-Г¶Гё-Гҝ\'вҖҷ\.\- ]{2,55})\s*\(',
            r'([A-ZГҖ-Г–Гҳ-Г¶Гё-Гҝ][A-Za-zГҖ-Г–Гҳ-Г¶Гё-Гҝ\'вҖҷ\.\- ]{2,55})\s+(?:Penalty Goal|Own Goal|Goal)\b',
        ]
        for pat in patterns:
            for mm in re.finditer(pat, dump, re.I):
                add(mm.group(1), '')
    except Exception:
        pass
    walk(data)
    # ШӘЩҶШёЩҠЩҒ ЩҲШӘЩғШұШ§Шұ
    seen, clean = set(), []
    for x in out:
        s = str(x or '').strip()
        if not s: continue
        key = re.sub(r'\s+', ' ', s.lower())
        if key not in seen:
            seen.add(key); clean.append(s)
    debug.append(f'PATCH18 ESPN Summary parser: {len(clean)}')
    return clean[:12]


# Override parser Ш§Щ„Щ…ШіШӘШ®ШҜЩ… ШҜШ§Ш®Щ„ _v43_fetch_espn_summary_scorers
_v43_extract_scorers_from_summary_json = _v48_extract_scorers_from_summary_json


def _v48_event_id_from_obj(obj):
    eid = str((obj or {}).get('event_id') or '').replace('espn_', '').strip()
    if eid:
        return eid
    for k in ['summary_url','highlight_url','url']:
        s = str((obj or {}).get(k) or '')
        m = re.search(r'(?:gameId|event)[=/](\d{5,})|gameId/(\d{5,})', s)
        if m:
            return next(g for g in m.groups() if g)
    return ''


def _v48_complete_live_goals(obj, m, d=None, force=True):
    if not isinstance(obj, dict) or not _patch6_numeric_score(obj):
        return obj
    total = _v41_total_goals(obj) if '_v41_total_goals' in globals() else 0
    if total <= 0:
        obj['scorers'] = []
        obj['goals_source'] = 'Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈЩҮШҜШ§ЩҒ'
        return obj
    debug = []
    eid = _v48_event_id_from_obj(obj) or str((m or {}).get('event_id') or '').replace('espn_', '')
    if eid:
        obj['event_id'] = eid
    try:
        # ЩҮШ°Ш§ ЩҶЩҒШі Щ…ШіШ§Шұ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Щ…ШӘШ№ШҜШҜ Ш§Щ„Щ…ШөШ§ШҜШұ
        obj = _v43_complete_goals_multi(obj, m, d or (m or {}).get('date'), force=True, debug=debug)
    except Exception as e:
        debug.append(f'complete_goals_multi error: {str(e)[:70]}')
    # ШҘШ°Ш§ Щ„ШіЩҮ ЩҶШ§ЩӮШөШҢ ЩҶШ¶ШұШЁ ESPN Summary Щ…ШЁШ§ШҙШұШ© Щ…ШұШ© Ш«Ш§ЩҶЩҠШ© ШЁШ§Щ„ЩҖ event_id
    try:
        if not _v43_goals_complete(obj) and eid:
            sc = _v43_fetch_espn_summary_scorers(eid, debug=debug)
            merged = _v43_merge_scorers(obj.get('scorers') or [], sc, total=total)
            obj['scorers'] = merged[:total]
            if sc:
                obj['goals_source'] = 'ESPN Summary'
    except Exception as e:
        debug.append(f'ESPN direct goals error: {str(e)[:70]}')
    # Щ„Ш§ ШӘЩғШӘШЁ Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈЩҮШҜШ§ЩҒ ШҘШ°Ш§ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ЩҒЩҠЩҮШ§ ШЈЩҮШҜШ§ЩҒ.
    if not (obj.get('scorers') or []):
        obj['goals_source'] = 'ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«'
    obj['goal_debug'] = list(debug)[-12:]
    try:
        _v43_cache_goal_debug(m, debug)
    except Exception:
        pass
    return obj


# Override Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ: Щ„Ш§ ЩҠШұШ¬Ш№ Щ„Щ„Щ…ШіШӘШ®ШҜЩ… ЩӮШЁЩ„ Щ…ШӯШ§ЩҲЩ„Ш© ШҘЩғЩ…Ш§Щ„ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ШЁЩҶЩҒШі ШҜЩҲШ§Щ„ Ш§Щ„ЩҶШӘШ§ШҰШ¬.
def _v40_fetch_live_for_fixture(m, force=False):
    d = _normalize_date_arg((m or {}).get('date')) or _normalize_date_arg(_v41_active_live_date())
    if not force:
        try:
            cached = _v43_get_cached_match_result(m)
            if isinstance(cached, dict) and _patch6_numeric_score(cached) and _v43_goals_complete(cached):
                return cached
        except Exception:
            pass
    try:
        obj = _v41_fetch_result_for_fixture(m, d, force=True, allow_seed=True)
    except Exception:
        obj = None
    if isinstance(obj, dict) and _patch6_numeric_score(obj):
        obj = _v48_complete_live_goals(obj, m, d, force=True)
        try:
            _v43_put_cached_match_result(m, obj, obj.get('actual_source') or obj.get('source') or 'ESPN')
        except Exception:
            pass
        try:
            _save_fast_live_cache(m.get('team1'), m.get('team2'), d, obj)
        except Exception:
            pass
        return obj
    return obj


# Ш§Щ„ЩғШ§ШЁШҙЩҶ: ЩҶЩҒШі Ш§Щ„ЩҶШӘШ§ШҰШ¬ШҢ Щ„Ш§ ЩҠЩғШӘШЁ Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈЩҮШҜШ§ЩҒ ШҘЩ„Ш§ ШҘШ°Ш§ 0-0.
def build_live_caption(match, mode_label='ESPN'):
    match = match or {}
    lines = [f"{match.get('team1','')} {match.get('score1','-')} - {match.get('score2','-')} {match.get('team2','')}"]
    st = match.get('status') or match.get('minute') or ''
    if st:
        lines.append(str(st))
    lines.append('')
    total = 0
    try:
        total = _v41_total_goals(match)
    except Exception:
        pass
    scorers = match.get('scorers') or []
    if total <= 0:
        lines.append('вҡҪ Щ„Ш§ ЩҠЩҲШ¬ШҜ ШЈЩҮШҜШ§ЩҒ')
    elif scorers:
        lines.append('вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ:')
        for s in scorers[:total]:
            lines.append(f'- {s}')
        if len(scorers) < total:
            for i in range(len(scorers)+1, total+1):
                lines.append(f'- Ш§Щ„ЩҮШҜЩҒ ШұЩӮЩ… {i} ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«')
    else:
        lines.append('вҡҪ Ш§Щ„ЩҮШҜШ§ЩҒЩҲЩҶ ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«')
        for i in range(1, total+1):
            lines.append(f'- Ш§Щ„ЩҮШҜЩҒ ШұЩӮЩ… {i} ЩӮЩҠШҜ Ш§Щ„ШӘШӯШҜЩҠШ«')
    src = match.get('actual_source') or match.get('source') or mode_label
    gsrc = match.get('goals_source') or ''
    lines += ['', f'Ш§Щ„Щ…ШөШҜШұ: {src}' + (f' | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {gsrc}' if gsrc else '')]
    link = match.get('summary_url_manual') or match.get('highlight_url') or match.get('summary_url') or ''
    if link:
        lines.append(f'рҹҺһпёҸ Щ…Щ„Ш®Шө Ш§Щ„Щ…ШЁШ§ШұШ§Ш©: {link}')
    return '\n'.join([str(x) for x in lines if x is not None]).strip()

# ==================== END PATCH18 ====================


