async def _send_status_board_to_message(update, kind):
    msg = update.message if getattr(update, 'message', None) else update.callback_query.message
    if kind == 'qualified':
        teams = _v32_calculated_qualified()
        if teams:
            try:
                path = render_qualified32_board(teams)
                await send_photo_path(msg, path, "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ вҖ” Ш§Щ„Щ…ШөШҜШұ: ШӯШіШЁШ© ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„")
                return
            except Exception:
                await msg.reply_text("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§:\n" + "\n".join([f"- {x}" for x in teams])); return
        await msg.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ШұШіЩ…ЩҠЩҠЩҶ ШӯШіШЁ Ш§Щ„ШӯШіШЁШ© ШӯШӘЩү Ш§Щ„ШўЩҶ."); return
    teams = _v32_calculated_eliminated()
    if teams:
        try:
            path = render_eliminated_board(teams)
            await send_photo_path(msg, path, "вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ вҖ” Ш§Щ„Щ…ШөШҜШұ: ШӯШіШЁШ© ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„")
            return
        except Exception:
            await msg.reply_text("вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§:\n" + "\n".join([f"- {x}" for x in teams])); return
    await msg.reply_text("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШіШӘШЁШ№ШҜЩҠЩҶ ШұШіЩ…ЩҠЩҠЩҶ ШӯШіШЁ Ш§Щ„ШӯШіШЁШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.")


async def public_status_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    await q.answer()
    action = (q.data or '').split('|')[1] if '|' in (q.data or '') else 'qualified'
    if action == 'qualified':
        class Dummy: pass
        dummy = Dummy(); dummy.callback_query = q; dummy.message = None
        await _send_status_board_to_message(dummy, 'qualified')
        return
    if action == 'eliminated':
        class Dummy: pass
        dummy = Dummy(); dummy.callback_query = q; dummy.message = None
        await _send_status_board_to_message(dummy, 'eliminated')
        return
    if _V32_OLD_PUBLIC_STATUS_CALLBACK:
        return await _V32_OLD_PUBLIC_STATUS_CALLBACK(update, context)


