def _v32_group_remaining_count(g):
    try:
        return max(0, 6 - len(g.get('results') or []))
    except Exception:
        return int((g or {}).get('remaining') or 0)


def _v32_team_status_for_row(team, row, idx, bounds, complete=False):
    """ШӯШ§Щ„Ш© Щ…ШӯШ§ЩҒШёШ© ШӯШіШЁ Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ: Ш§Щ„ШұШіЩ…ЩҠ 100ЩӘ ЩҒЩӮШ·.
    ЩӮШЁЩ„ Ш§ЩғШӘЩ…Ш§Щ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Щ„Ш§ ЩҶШ№Щ„ЩҶ Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ШҘЩ„Ш§ ШҘШ°Ш§ Щ„ШҜЩҠЩҮ 6 ЩҶЩӮШ§Ш· ЩҲШЈШіЩҲШ§ШЎ Ш§ШӯШӘЩ…Ш§Щ„ Щ„Ш§ ЩҠЩҶШІЩ„ЩҮ Ш№ЩҶ ШЈЩҲЩ„/Ш«Ш§ЩҶЩҠ.
    ЩҮШ°Ш§ ЩҠЩ…ЩҶШ№ Ш§Ш№ШӘШЁШ§Шұ ЩҒШұЩӮ 4 ЩҶЩӮШ§Ш· Щ…Ш«Щ„ ЩғЩҶШҜШ§/ШіЩҲЩҠШіШұШ§/ЩҮЩҲЩ„ЩҶШҜШ§ Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§ ШЁШҜШұЩҠ.
    """
    pts = int((row or {}).get('Pts') or 0)
    best_pos = int((bounds or {}).get('best') or (idx + 1))
    worst_pos = int((bounds or {}).get('worst') or (idx + 1))
    if complete:
        if idx <= 1:
            return "вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§"
        if idx == 2:
            return "рҹҘү ЩҒЩҠ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«"
        return "вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§"
    if pts >= 6 and worst_pos <= 2:
        return "вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§"
    if best_pos >= 4:
        return "вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§"
    if best_pos <= 3 and idx >= 2:
        return "рҹҘү ЩҒЩҠ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«"
    if idx <= 1:
        return "рҹ”Ҙ ЩӮШұЩҠШЁ Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„" if pts >= 4 else "вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі"
    if idx == 2:
        return "рҹҘү ЩҒЩҠ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«"
    return "вҡ пёҸ ЩҲШ¶Ш№ЩҮ ШөШ№ШЁ"


def _v32_build_snapshot(force=False):
    cache = _v32_load_json(V32_TOURNAMENT_CACHE_FILE, {})
    now = _v32_now_ts()
    if not force and isinstance(cache, dict) and cache.get("data") and now - float(cache.get("ts", 0) or 0) < V32_SNAPSHOT_TTL:
        return cache.get("data")

    fixtures = _v32_all_group_fixtures()
    groups = {code: {"fixtures": [], "results": [], "rows": [], "remaining": 0} for code, _ in WORLD_CUP_GROUPS}
    finished_results = []

    for m in fixtures:
        code = _v32_fixture_group_code(m)
        if code not in groups:
            continue
        groups[code]["fixtures"].append(m)
        obj = _v32_result_for_fixture(m, force=force)
        s1 = _v32_score_num((obj or {}).get("score1"))
        s2 = _v32_score_num((obj or {}).get("score2"))
        st = (obj or {}).get("status") or ""
        finished = s1 is not None and s2 is not None and _v32_is_finished_status(st)
        try:
            if s1 is not None and s2 is not None and _date_key(m.get("date")) < _v32_today_key():
                finished = True
        except Exception:
            pass
        if finished:
            r = {"group": code, "date": m.get("date"), "team1": canonical_team_name(m.get("team1")) or m.get("team1"), "team2": canonical_team_name(m.get("team2")) or m.get("team2"), "score1": s1, "score2": s2, "status": st}
            groups[code]["results"].append(r)
            finished_results.append(r)

    for code, teams in WORLD_CUP_GROUPS:
        # Щ…ЩҶШ№ Ш§Щ„Ш°ЩҮШ§ШЁ ЩҲШ§Щ„ШҘЩҠШ§ШЁ: Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© 6 Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩӮШ·ШҢ ЩҲЩғЩ„ Щ…ЩҶШӘШ®ШЁ 3 Щ…ШЁШ§ШұЩҠШ§ШӘ.
        groups[code]["results"] = groups[code]["results"][:6]
        groups[code]["remaining"] = max(0, 6 - len(groups[code]["results"]))
        stats = {t: _v32_blank_stats(t) for t in teams}
        for r in groups[code]["results"]:
            _v32_add_match_stats(stats, r["team1"], r["team2"], int(r["score1"]), int(r["score2"]))
        rows = list(stats.values())
        groups[code]["rows"] = _v32_sort_group_rows(rows, groups[code]["results"])

    for code, g in groups.items():
        try:
            g["position_bounds"] = _v32_group_position_bounds(code, g)
        except Exception:
            g["position_bounds"] = {}

    thirds = []
    for code in groups:
        rows = groups[code].get("rows") or []
        if len(rows) >= 3:
            r = dict(rows[2]); r["group"] = code; thirds.append(r)
    thirds = sorted(thirds, key=lambda r: (-r.get("Pts",0), -r.get("GD",0), -r.get("GF",0), r.get("team","")))

    status = {t: "вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі" for t in WORLD_CUP_TEAMS}
    qualified = []
    eliminated = []
    for code, g in groups.items():
        rows = g.get("rows") or []
        complete = int(g.get("remaining") or 0) == 0 and len(g.get("results") or []) >= 6
        bounds = g.get("position_bounds") or {}
        for idx, r in enumerate(rows):
            team = r.get('team')
            st = _v32_team_status_for_row(team, r, idx, bounds.get(team, {}), complete=complete)
            status[team] = st
            if st == "вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§" and team not in qualified:
                qualified.append(team)
            if st == "вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§" and team not in eliminated:
                eliminated.append(team)

    all_groups_complete = all(int(g.get("remaining") or 0) == 0 and len(g.get("results") or []) >= 6 for g in groups.values())
    for i, r in enumerate(thirds):
        if i < 8:
            r["third_status"] = "вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§"
            if all_groups_complete:
                r["third_status"] = "вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§"
                if r["team"] not in qualified:
                    qualified.append(r["team"])
                status[r["team"]] = "вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ Ш№ШЁШұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«"
        else:
            r["third_status"] = "вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§"
            if all_groups_complete:
                r["third_status"] = "вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§"
                if r["team"] not in eliminated:
                    eliminated.append(r["team"])
                status[r["team"]] = "вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§"

    goals = sum(int(r.get("score1") or 0) + int(r.get("score2") or 0) for r in finished_results)
    attacks = Counter(); defenses = defaultdict(int); played = Counter()
    biggest = None
    for r in finished_results:
        t1,t2 = r["team1"], r["team2"]
        s1,s2 = int(r["score1"]), int(r["score2"])
        attacks[t1] += s1; attacks[t2] += s2
        defenses[t1] += s2; defenses[t2] += s1
        played[t1] += 1; played[t2] += 1
        diff = abs(s1-s2)
        if biggest is None or diff > biggest["diff"] or (diff == biggest["diff"] and s1+s2 > biggest["total"]):
            biggest = {"team1":t1,"team2":t2,"score1":s1,"score2":s2,"diff":diff,"total":s1+s2}

    data = {
        "updated_at": _now_riyadh_text() if '_now_riyadh_text' in globals() else datetime.utcnow().isoformat(),
        "groups": groups,
        "thirds": thirds,
        "qualified": _unique_teams(qualified, 32) if '_unique_teams' in globals() else qualified[:32],
        "eliminated": _unique_teams(eliminated) if '_unique_teams' in globals() else eliminated,
        "status": status,
        "finished_count": len(finished_results),
        "total_group_matches": 72,
        "total_tournament_matches": 104,
        "goals": goals,
        "biggest": biggest,
        "best_attack": attacks.most_common(1)[0] if attacks else ("-", 0),
        "best_defense": sorted([(t, ga) for t, ga in defenses.items() if played[t] > 0], key=lambda x: (x[1], x[0]))[0] if defenses else ("-", 0),
        "all_groups_complete": all_groups_complete,
    }
    _v32_save_json(V32_TOURNAMENT_CACHE_FILE, {"ts": now, "data": data})
    return data


def _v32_groups_keyboard(prefix="race"):
    rows=[]; row=[]
    for code, _teams in WORLD_CUP_GROUPS:
        row.append(InlineKeyboardButton(_v32_group_name(code), callback_data=f"v32|{prefix}_group|{code}"))
        if len(row)==3:
            rows.append(row); row=[]
    if row: rows.append(row)
    if prefix == "race":
        rows.append([InlineKeyboardButton("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§", callback_data="v32|qualified"), InlineKeyboardButton("вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§", callback_data="v32|eliminated")])
        rows.append([InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…", callback_data="v32|decisive")])
        rows.append([InlineKeyboardButton("рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғШҹ", callback_data="v32|needs_pick")])
        rows.append([InlineKeyboardButton("рҹ“„ ЩғЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ PDF", callback_data="v32|race_pdf")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="v32|board")])
    return InlineKeyboardMarkup(rows)


def _v32_board_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹҸҒ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|race")],
        [InlineKeyboardButton("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ", callback_data="v32|qualified"), InlineKeyboardButton("вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҠЩҶ", callback_data="v32|eliminated")],
        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…", callback_data="v32|decisive")],
        [InlineKeyboardButton("рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғШҹ", callback_data="v32|needs_pick")],
        [InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Ш§Щ„ШўЩҶ", callback_data="v32|board_force")],
    ])


def _v32_format_group_table(code, snap=None):
    snap = snap or _v32_snapshot(False)
    g = (snap.get("groups") or {}).get(code, {})
    lines = [f"рҹҸҒ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„ - {_v32_group_name(code)}", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}", ""]
    rows = g.get("rows") or []
    if not rows:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© Щ„ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.")
    for idx, r in enumerate(rows, start=1):
        st = (snap.get("status") or {}).get(r["team"], "вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі")
        lines.append(f"{idx}. {r['team']} вҖ” {r['Pts']} ЩҶЩӮШ·Ш©")
        lines.append(f"   Щ„Ш№ШЁ: {r['P']}/3")
        lines.append(f"   Ш§Щ„Щ…ШӘШЁЩӮЩҠ Щ„Щ„Щ…ЩҶШӘШ®ШЁ: {_v32_group_team_remaining_matches(r)}")
        lines.append(f"   ЩҒЩҲШІ: {r['W']} вҖ” ШӘШ№Ш§ШҜЩ„: {r['D']} вҖ” Ш®ШіШ§ШұШ©: {r['L']}")
        lines.append(f"   Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF', 0)}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {st}")
        lines.append("")
    rem = _v32_group_remaining_count(g)
    if rem:
        lines.append(f"Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: {rem}")
        rems = _v32_group_remaining_fixtures_for_sim(code, g)[:3]
        for m in rems:
            lines.append(f"- {m.get('team1')} Г— {m.get('team2')} вҖ” {m.get('date','')} {m.get('time','')}")
    return "\n".join(lines).strip()


def _v32_best_thirds_text(force=False):
    snap = _v32_snapshot(force)
    thirds = snap.get("thirds") or []
    lines = ["рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}", ""]
    if not thirds:
        return "рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ."
    inside = list(enumerate(thirds[:8], start=1))
    outside = list(enumerate(thirds[8:], start=9))
    lines.append("вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
    if not inside: lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ.")
    for i, r in inside:
        lines.append(f"{i}. {r.get('team')} вҖ” {_v32_group_name(r.get('group'))}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')}")
        lines.append(f"   Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d}")
        lines.append(f"   Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {r.get('third_status','вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§')}")
        lines.append("")
    lines.append("вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
    if not outside: lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ.")
    for i, r in outside:
        lines.append(f"{i}. {r.get('team')} вҖ” {_v32_group_name(r.get('group'))}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')}")
        lines.append(f"   Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d}")
        lines.append(f"   Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {r.get('third_status','вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§')}")
        lines.append("")
    lines.append("ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« ЩҠШӘШЈЩҮЩ„ЩҲЩҶ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32. ЩӮШЁЩ„ ЩҶЩҮШ§ЩҠШ© ЩғЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШӘШёЩҮШұ Ш§Щ„ШӯШ§Щ„Ш© ЩғЩҖ ШҜШ§Ш®Щ„/Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§ ЩҒЩӮШ·.")
    return "\n".join(lines).strip()


def _v32_decisive_rows(force=False):
    snap = _v32_snapshot(force)
    rows=[]
    for code, g in (snap.get("groups") or {}).items():
        for m in g.get("fixtures") or []:
            pair = frozenset([canonical_team_name(m.get('team1')) or m.get('team1'), canonical_team_name(m.get('team2')) or m.get('team2')])
            finished = any(pair == frozenset([r.get('team1'), r.get('team2')]) for r in g.get('results') or [])
            if finished:
                continue
            t1 = canonical_team_name(m.get('team1')) or m.get('team1')
            t2 = canonical_team_name(m.get('team2')) or m.get('team2')
            s1 = (snap.get('status') or {}).get(t1, '')
            s2 = (snap.get('status') or {}).get(t2, '')
            note = []
            for t, st in [(t1,s1),(t2,s2)]:
                if 'Щ…ШӘШЈЩҮЩ„' in st: note.append(f"{t} ЩҠШұЩҠШҜ ШӘШ«ШЁЩҠШӘ Ш§Щ„ШөШҜШ§ШұШ©")
                elif 'ЩӮШұЩҠШЁ' in st: note.append(f"{t} ЩӮШұЩҠШЁ Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„")
                elif 'Ш«ЩҲШ§Щ„Ш«' in st: note.append(f"{t} ЩҒЩҠ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«")
                elif 'ШөШ№ШЁ' in st: note.append(f"{t} ЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш©")
                elif 'ЩҠЩҶШ§ЩҒШі' in st: note.append(f"{t} Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі")
            if note or len(g.get('results') or []) >= 4:
                rows.append((m.get('date'), m.get('time',''), code, t1, t2, 'ШҢ '.join(note[:2]) or 'ШӘШӨШ«Шұ Ш№Щ„Щү ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©'))
    return sorted(rows, key=lambda x: (_date_key(x[0]), x[1]))[:12]


def _v32_decisive_matches_text(force=False):
    snap = _v32_snapshot(force)
    rows = _v32_decisive_rows(force=False)
    lines = ["рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ… Ш§Щ„ЩӮШ§ШҜЩ…Ш©", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}", ""]
    if not rows:
        lines.append("Щ…Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұЩҠШ§ШӘ ШӯШіЩ… ЩҲШ§Ш¶ШӯШ© ШӯШ§Щ„ЩҠЩӢШ§.")
    for idx, (d,t,code,a,b,note) in enumerate(rows, start=1):
        lines.append(f"{idx}. {a} Г— {b}")
        lines.append(f"   рҹ“… {d}")
        lines.append(f"   вҸ° {t or '-'}")
        lines.append(f"   рҹ“Ҡ {_v32_group_name(code)}")
        lines.append(f"   рҹҺҜ Ш§Щ„ШӘШЈШ«ЩҠШұ: {note}")
        lines.append("")
    lines.append("Щ…Щ„Ш§ШӯШёШ©: Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ… ШӘШӘШәЩҠШұ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§ ШӯШіШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    return "\n".join(lines).strip()


def _v32_tournament_board_text(force=False):
    snap = _v32_snapshot(force)
    biggest = snap.get('biggest') or {}
    big = '-' if not biggest else f"{biggest.get('team1')} {biggest.get('score1')}-{biggest.get('score2')} {biggest.get('team2')}"
    ba = snap.get('best_attack') or ('-',0)
    bd = snap.get('best_defense') or ('-',0)
    last_q = (snap.get('qualified') or ['-'])[-1]
    last_e = (snap.get('eliminated') or ['-'])[-1]
    decisive_count = len(_v32_decisive_rows(False))
    lines = [
        "рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©",
        f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}",
        "",
        f"Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Ш§Щ„Щ…ЩғШӘЩ…Щ„Ш©: {snap.get('finished_count',0)} / {snap.get('total_tournament_matches',104)}",
        f"Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ: {snap.get('finished_count',0)} / {snap.get('total_group_matches',72)}",
        f"ШҘШ¬Щ…Ш§Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {snap.get('goals',0)}",
        f"ШЈЩғШЁШұ ЩҶШӘЩҠШ¬Ш©: {big}",
        f"ШЈЩӮЩҲЩү ЩҮШ¬ЩҲЩ…: {ba[0]} вҖ” {ba[1]} ШЈЩҮШҜШ§ЩҒ",
        f"ШЈЩӮЩҲЩү ШҜЩҒШ§Ш№: {bd[0]} вҖ” Ш§ШіШӘЩӮШЁЩ„ {bd[1]}",
        f"ШўШ®Шұ Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§: {last_q}",
        f"ШўШ®Шұ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§: {last_e}",
        f"Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ… Ш§Щ„ЩӮШ§ШҜЩ…Ш©: {decisive_count}",
    ]
    return "\n".join(lines)


def _v32_needs_scenario_lines(team, snap, code, row, status_txt):
    pts = int((row or {}).get('Pts') or 0)
    rem = _v32_group_team_remaining_matches(row or {})
    lines = []
    if "Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§" in status_txt:
        return ["вң… Щ„Ш§ ЩҠШӯШӘШ§Ш¬ ШҙЩҠШЎШҢ ШӯШіЩ… Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§."]
    if "Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§" in status_txt:
        return ["вқҢ Ш§ЩҶШӘЩҮШӘ ЩҒШұШөЩҮ ШӯШіШ§ШЁЩҠЩӢШ§."]
    up = _v32_upcoming_matches_for_team(team, snap)
    if not up:
        return ["ШЁШ§ЩҶШӘШёШ§Шұ Ш§ЩғШӘЩ…Ш§Щ„ ШӯШіШ§ШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШЁШ§ЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ."]
    m = up[0]
    opp = m.get('team2') if (canonical_team_name(m.get('team1')) or m.get('team1')) == team else m.get('team1')
    lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш©: {m.get('team1')} Г— {m.get('team2')} вҖ” {m.get('date')} {m.get('time','')}")
    lines.append("")
    lines.append("вң… ЩҠШӘШЈЩҮЩ„ ШҘШ°Ш§:")
    if pts >= 4:
        lines.append(f"- Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp} ЩҠШ¬Ш№Щ„ЩҮ ЩӮШұЩҠШЁ Ш¬ШҜЩӢШ§ Щ…ЩҶ Ш§Щ„ШӯШіЩ…ШҢ ЩҲЩӮШҜ ЩҠШ¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү.")
        lines.append("- Ш§Щ„ШӘШ№Ш§ШҜЩ„ ШәШ§Щ„ШЁЩӢШ§ ЩҠШЁЩӮЩҠЩҮ ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁШ§ШӘ Ш§Щ„ЩӮЩҲЩҠШ©ШҢ ЩҲЩӮШҜ ЩҠШҜШ®Щ„ЩҮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘШ°Ш§ Щ„Щ… ЩҠШӯШіЩ… ШЈЩҲЩ„/Ш«Ш§ЩҶЩҠ.")
    elif pts >= 2:
        lines.append(f"- Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp} ЩҠШұЩҒШ№ ШӯШёЩҲШёЩҮ ШЁЩӮЩҲШ©ШҢ ЩҲЩӮШҜ ЩҠШҜШ®Щ„ЩҮ ШЈЩҲЩ„/Ш«Ш§ЩҶЩҠ ШЈЩҲ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.")
    else:
        lines.append(f"- ЩҠШӯШӘШ§Ш¬ Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp} ШЈЩҲЩ„ЩӢШ§ШҢ Ш«Щ… ЩҠЩҶШӘШёШұ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҠЩҶ ШҜШ§Ш®Щ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    lines.append("вҡ пёҸ ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШҘШ°Ш§:")
    lines.append("- ШӘШ№Ш§ШҜЩ„ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш©Шӣ ЩҲЩӮШӘЩҮШ§ ЩӮШҜ ЩҠШ№ШӘЩ…ШҜ Ш№Щ„Щү Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„Щ…ШЁШ§ШҙШұШ© ШЈЩҲ ЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ШЈЩҲ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    lines.append("вқҢ ЩҠШ®ШұШ¬ ШҘШ°Ш§:")
    lines.append("- Ш®ШіШұ ЩҲЩғШ§ЩҶШӘ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҠЩҶ Ш¶ШҜЩҮШҢ ШЈЩҲ ШөШ§Шұ ШЈЩҒШ¶Щ„ Щ…ШұЩғШІ Щ…Щ…ЩғЩҶ Щ„ЩҮ Ш§Щ„ШұШ§ШЁШ№.")
    return lines


def _v32_team_needs_text(team, force=False):
    team = _v32_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Щ…Ш«Щ„ЩӢШ§: Ш§Щ„ШіШ№ЩҲШҜЩҠШ©"
    snap = _v32_snapshot(force)
    code, row = _v32_team_row(team, snap)
    status_txt = (snap.get("status") or {}).get(team, "вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі")
    lines = [f"рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ {team}Шҹ", f"{_v32_group_name(code)}", f"Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„ШӯШ§Щ„ЩҠШ©: {status_txt}", ""]
    if not row:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.")
        return "\n".join(lines)
    lines.append(f"Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„Щ…ШӘШЁЩӮЩҠ: {_v32_group_team_remaining_matches(row)}")
    lines.append(f"Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {row.get('GF')}")
    lines.append("")
    lines += _v32_needs_scenario_lines(team, snap, code, row, status_txt)
    lines.append("\nЩ…Щ„Ш§ШӯШёШ©: Ш№ЩҶШҜ ШӘШіШ§ЩҲЩҠ Ш§Щ„ЩҶЩӮШ§Ш·ШҢ Ш§Щ„ШЁЩҲШӘ ЩҠШұШ¬Ш№ Щ„Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„Щ…ШЁШ§ШҙШұШ© ШЈЩҲЩ„ЩӢШ§ШҢ ЩҲЩ„ЩҲ 3 Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…ШӘШіШ§ЩҲЩҠЩҶ ЩҠШіЩҲЩҠ Ш¬ШҜЩҲЩ„ Щ…ШөШәШұ ШЁЩҠЩҶЩҮЩ….")
    return "\n".join(lines).strip()


def _v32_team_summary_text(team, force=False):
    team = _v32_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Ш§Щ„ЩҠШ§ШЁШ§ЩҶ ШЈЩҲ Japan"
    snap = _v32_snapshot(force)
    code, row = _v32_team_row(team, snap)
    status_txt = (snap.get("status") or {}).get(team, "вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі")
    lines = [f"вҡЎ {team}", f"{_v32_group_name(code)}", f"Ш§Щ„ШӯШ§Щ„Ш©: {status_txt}", ""]
    if row:
        pos = 1 + [x.get('team') for x in (snap.get('groups') or {}).get(code, {}).get('rows', [])].index(team)
        lines.append(f"Ш§Щ„ШӘШұШӘЩҠШЁ: {pos}")
        lines.append(f"Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„Щ…ШӘШЁЩӮЩҠ: {_v32_group_team_remaining_matches(row)}")
        lines.append(f"Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {row.get('GF')}")
    last = _v32_finished_matches_for_team(team, snap)
    if last:
        r = last[-1]
        lines.append(f"ШўШ®Шұ ЩҶШӘЩҠШ¬Ш©: {r.get('team1')} {r.get('score1')} - {r.get('score2')} {r.get('team2')}")
    nxt = _v32_upcoming_matches_for_team(team, snap)
    if nxt:
        m = nxt[0]
        lines.append(f"Ш§Щ„ЩӮШ§ШҜЩ…: {m.get('team1')} Г— {m.get('team2')} вҖ” {m.get('date')} вҖ” {m.get('time','')}")
    hls = _v32_highlights_for_team(team)
    if hls:
        lines.append(f"Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШӘЩҲЩҒШұШ©: {len(hls)}")
    if row:
        lines.append("")
        lines.append("Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ")
        lines += _v32_needs_scenario_lines(team, snap, code, row, status_txt)[:6]
    lines.append(f"\nШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}")
    return "\n".join(lines).strip()


def _v32_pdf_draw_line(draw, text, x, y, font, fill="white", max_width=1060):
    lines = wrap_text(draw, str(text or ""), font, max_width)
    line_h = int(font_size(font, 24) * 1.36)
    for ln in lines:
        draw_text(draw, (x, y), ln, font, fill=fill, anchor="ra", align="right")
        y += line_h
    return y


def _v32_create_race_pdf(force=False):
    snap = _v32_snapshot(force)
    ensure_generated_dir()
    pages = []
    width, height = 1240, 1754
    margin = 72
    subtitle = f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')} - ESPN + ШӯШіШЁШ© Ш§Щ„Щ…ШөЩҠЩҒ Ш§Щ„ШұШіЩ…ЩҠШ©"
    group_title_font = get_font(31)
    row_font = get_font(23)
    small_font = get_font(19)

    # ШөЩҒШӯШ© 1: Щ…Щ„Ш®Шө ШіШұЩҠШ№
    img, draw, y = _v32_pdf_new_page("Щ…Щ„Ш®Шө ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", subtitle)
    q = snap.get('qualified') or []
    e = snap.get('eliminated') or []
    y = _v32_pdf_draw_line(draw, f"Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Ш§Щ„Щ…ЩғШӘЩ…Щ„Ш©: {snap.get('finished_count',0)} / 104", width-margin, y, get_font(28), fill="#FFFFFF")
    y = _v32_pdf_draw_line(draw, f"Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ: {snap.get('finished_count',0)} / 72", width-margin, y, get_font(28), fill="#FFFFFF")
    y = _v32_pdf_draw_line(draw, f"Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§: {len(q)}", width-margin, y, get_font(28), fill="#A7F3D0")
    if q:
        y = _v32_pdf_draw_line(draw, "ШҢ ".join(q[:12]), width-margin, y, small_font, fill="#D1FAE5")
    y += 10
    y = _v32_pdf_draw_line(draw, f"Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§: {len(e)}", width-margin, y, get_font(28), fill="#FCA5A5")
    if e:
        y = _v32_pdf_draw_line(draw, "ШҢ ".join(e[:12]), width-margin, y, small_font, fill="#FEE2E2")
    y += 14
    y = _v32_pdf_draw_line(draw, f"ШҘШ¬Щ…Ш§Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {snap.get('goals',0)}", width-margin, y, get_font(26), fill="#FFFFFF")
    y = _v32_pdf_draw_line(draw, f"Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ… Ш§Щ„ЩӮШ§ШҜЩ…Ш©: {len(_v32_decisive_rows(False))}", width-margin, y, get_font(26), fill="#FDE68A")
    y += 20
    y = _v32_pdf_draw_line(draw, "Щ…Щ„Ш§ШӯШёШ©: Ш§Щ„Щ…ШӘШЈЩҮЩ„/Ш§Щ„Щ…ШіШӘШЁШ№ШҜ Ш§Щ„ШұШіЩ…ЩҠ Щ„Ш§ ЩҠШёЩҮШұ ШҘЩ„Ш§ ШҘШ°Ш§ ШӯЩҸШіЩ… ШӯШіШ§ШЁЩҠЩӢШ§ 100ЩӘ.", width-margin, y, small_font, fill="#CBD5E1")
    pages.append(img)

    # ШөЩҒШӯШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ: 3 Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҒЩҠ Ш§Щ„ШөЩҒШӯШ©
    groups_per_page = 3
    current = None
    for idx_code, (code, _teams) in enumerate(WORLD_CUP_GROUPS):
        if idx_code % groups_per_page == 0:
            if current is not None:
                pages.append(current[0])
            current = _v32_pdf_new_page("Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", subtitle)
        img, draw, y = current
        g = (snap.get("groups") or {}).get(code, {})
        y = _v32_pdf_draw_line(draw, f"рҹҸҒ {_v32_group_name(code)}", width-margin, y, group_title_font, fill="#F2B705")
        for idx, r in enumerate(g.get('rows') or [], start=1):
            st = _v32_plain_status((snap.get('status') or {}).get(r.get('team'), 'Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі'))
            y = _v32_pdf_draw_line(draw, f"{idx}. {r.get('team')} вҖ” {r.get('Pts')} ЩҶЩӮШ·Ш©", width-margin, y, row_font, fill="#FFFFFF")
            y = _v32_pdf_draw_line(draw, f"   Щ„Ш№ШЁ: {r.get('P')}/3 вҖ” Ш§Щ„Щ…ШӘШЁЩӮЩҠ: {_v32_group_team_remaining_matches(r)} вҖ” ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}", width-margin, y, small_font, fill="#CBD5E1")
            color = "#A7F3D0" if 'Щ…ШӘШЈЩҮЩ„' in st else ("#FCA5A5" if 'Щ…ШіШӘШЁШ№ШҜ' in st else "#FDE68A")
            y = _v32_pdf_draw_line(draw, f"   Ш§Щ„ШӯШ§Щ„Ш©: {st}", width-margin, y, small_font, fill=color)
        rem = _v32_group_remaining_count(g)
        if rem:
            y = _v32_pdf_draw_line(draw, f"Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: {rem}", width-margin, y, small_font, fill="#FDE68A")
            for m in _v32_group_remaining_fixtures_for_sim(code, g)[:2]:
                y = _v32_pdf_draw_line(draw, f"- {m.get('team1')} Г— {m.get('team2')}", width-margin, y, small_font, fill="#E5E7EB")
        y += 22
        current = (img, draw, y)
    if current is not None:
        pages.append(current[0])

    # ШөЩҒШӯШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«
    img, draw, y = _v32_pdf_new_page("ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", subtitle)
    y = _v32_pdf_draw_line(draw, "ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« ЩҠШӘШЈЩҮЩ„ЩҲЩҶ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32", width-margin, y, group_title_font, fill="#F2B705")
    thirds = snap.get('thirds') or []
    y = _v32_pdf_draw_line(draw, "вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§", width-margin, y, get_font(30), fill="#86EFAC")
    for i, r in enumerate(thirds[:8], start=1):
        y = _v32_pdf_draw_line(draw, f"{i}. {r.get('team')} вҖ” {_v32_group_name(r.get('group'))}", width-margin, y, row_font, fill="#FFFFFF")
        y = _v32_pdf_draw_line(draw, f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}", width-margin, y, small_font, fill="#CBD5E1")
    y += 18
    y = _v32_pdf_draw_line(draw, "вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§", width-margin, y, get_font(30), fill="#FCA5A5")
    for i, r in enumerate(thirds[8:], start=9):
        y = _v32_pdf_draw_line(draw, f"{i}. {r.get('team')} вҖ” {_v32_group_name(r.get('group'))}", width-margin, y, row_font, fill="#FFFFFF")
        y = _v32_pdf_draw_line(draw, f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}", width-margin, y, small_font, fill="#CBD5E1")
    pages.append(img)

    # ШөЩҒШӯШ© Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…
    img, draw, y = _v32_pdf_new_page("Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…", subtitle)
    rows = _v32_decisive_rows(False)
    if not rows:
        y = _v32_pdf_draw_line(draw, "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ШӯШіЩ… ЩҲШ§Ш¶ШӯШ© ШӯШ§Щ„ЩҠЩӢШ§.", width-margin, y, get_font(28), fill="#FFFFFF")
    for idx, (d,t,code,a,b,note) in enumerate(rows[:10], start=1):
        y = _v32_pdf_draw_line(draw, f"{idx}. {a} Г— {b}", width-margin, y, row_font, fill="#FFFFFF")
        y = _v32_pdf_draw_line(draw, f"   рҹ“… {d} вҖ” вҸ° {t or '-'} вҖ” рҹ“Ҡ {_v32_group_name(code)}", width-margin, y, small_font, fill="#CBD5E1")
        y = _v32_pdf_draw_line(draw, f"   рҹҺҜ {note}", width-margin, y, small_font, fill="#FDE68A")
        y += 8
    pages.append(img)

    label = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    out_path = os.path.join(GENERATED_DIR, f"qualification_race_{label}.pdf")
    rgb_pages = [p.convert("RGB") for p in pages]
    rgb_pages[0].save(out_path, "PDF", resolution=120.0, save_all=True, append_images=rgb_pages[1:])
    return out_path


async def _v32_show_qualified_message(message):
    teams = _v32_calculated_qualified()
    txt = "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§\n" + ("\n".join([f"- {x}" for x in teams]) if teams else "Щ„Ш§ ЩҠЩҲШ¬ШҜ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
    await message.reply_text(txt)


async def _v32_show_eliminated_message(message):
    teams = _v32_calculated_eliminated()
    txt = "вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§\n" + ("\n".join([f"- {x}" for x in teams]) if teams else "Щ„Ш§ ЩҠЩҲШ¬ШҜ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
    await message.reply_text(txt)


async def _v32_show_fantasy_gate(update, context):
    context.user_data['v32_pending_fantasy_password'] = True
    await update.effective_message.reply_text(_v32_fantasy_gate_text())


async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    _v32_track_user(update)
    txt = normalize_name(update.message.text or '')
    if txt in ("рҹҺ¬ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", "рҹҺһпёҸ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ"):
        await update.message.reply_text("рҹҺҘ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", reply_markup=_v32_hls_home_keyboard()); return
    if txt in ("рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© Ш§Щ„ШўЩҶ"):
        await update.message.reply_text(_v32_tournament_board_text(), reply_markup=_v32_board_keyboard()); return
    if txt == "рҹҸҒ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„":
        await update.message.reply_text("рҹҸҒ Ш§Ш®ШӘШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Щ„Ш№ШұШ¶ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„:", reply_markup=_v32_groups_keyboard()); return
    if txt == "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§":
        await _v32_show_qualified_message(update.message); return
    if txt == "вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§":
        await _v32_show_eliminated_message(update.message); return
    if txt == "рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«":
        await update.message.reply_text(_v32_best_thirds_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ«", callback_data="v32|thirds_force")]])); return
    if txt == "рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…":
        await update.message.reply_text(_v32_decisive_matches_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ«", callback_data="v32|decisive_force")]])); return
    if txt == "вҸұпёҸ Ш¬ШҜЩҲЩ„ Щ…Ш®ШӘШөШұ Ш§Щ„ЩҠЩҲЩ…":
        await update.message.reply_text(_v32_short_today_text()); return
    if txt == "вӯҗ Щ…ЩҶШӘШ®ШЁЩҠ Ш§Щ„Щ…ЩҒШ¶Щ„":
        uid = _v32_user_id(update); team = _v32_load_favorites().get(uid)
        if team:
            await update.message.reply_text(_v32_team_summary_text(team), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("ШӘШәЩҠЩҠШұ Ш§Щ„Щ…ЩҶШӘШ®ШЁ", callback_data="v32|fav_home")]]))
        else:
            await update.message.reply_text("Ш§Ш®ШӘШұ Щ…ЩҶШӘШ®ШЁЩғ Ш§Щ„Щ…ЩҒШ¶Щ„ вӯҗ", reply_markup=_v32_favorite_team_keyboard())
        return
    if txt == "рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ":
        if _v32_user_is_fantasy_allowed(update):
            await _v32_open_fantasy_menu_for(update, context)
        else:
            await _v32_show_fantasy_gate(update, context)
        return
    if txt in ("рҹ§‘вҖҚрҹ’» Щ„ЩҲШӯШ© Ш§Щ„ШҘШҜШ§ШұШ©", "рҹ§‘вҖҚрҹ’» Щ„ЩҲШӯШ© Ш§Щ„Щ…ШҙШұЩҒ"):
        if not is_admin_user(update):
            await update.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’"); return
        await v32_admin_panel_command(update, context); return
    return await _V32_OLD_PUBLIC_REPLY_MENU_ROUTER(update, context)


# ЩҶШӯЩҒШё ЩғЩҲЩ„ШЁШ§Щғ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„ЩӮШҜЩҠЩ…ШҢ Ш«Щ… ЩҶШ¶Ш№ ШЁЩҲШ§ШЁШ© Ш§Щ„ШұЩӮЩ… Ш§Щ„ШіШұЩҠ ЩӮШЁЩ„ЩҮ.
try:
    _V32_FULLPATCH_PREV_FANTASY_CALLBACK = fantasy_menu_callback
except Exception:
    _V32_FULLPATCH_PREV_FANTASY_CALLBACK = None

async def fantasy_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if q:
        await q.answer()
        if not _v32_user_is_fantasy_allowed(q.from_user):
            context.user_data['v32_pending_fantasy_password'] = True
            await q.message.reply_text(_v32_fantasy_gate_text())
            return
    if callable(_V32_FULLPATCH_PREV_FANTASY_CALLBACK):
        return await _V32_FULLPATCH_PREV_FANTASY_CALLBACK(update, context)


async def text_state_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    # ШұЩ…ШІ ШҜШ®ЩҲЩ„ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ Щ„Щ„Ш¬Щ…ЩҠШ№
    if context.user_data.get('v32_pending_fantasy_password'):
        context.user_data.pop('v32_pending_fantasy_password', None)
        entered = normalize_name(update.message.text or '').strip()
        if entered == _v32_get_fantasy_password():
            _v32_grant_fantasy_access(update)
            await update.message.reply_text("вң… ШӘЩ… ЩҒШӘШӯ ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ Щ„Щғ.")
            await _v32_open_fantasy_menu_for(update, context)
        else:
            await update.message.reply_text("вқҢ Ш§Щ„ШұЩ…ШІ ШәЩҠШұ ШөШӯЩҠШӯ.\nШ§Ш¶ШәШ· рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ ЩҲШӯШ§ЩҲЩ„ Щ…ШұШ© Ш«Ш§ЩҶЩҠШ©.")
        return
    if context.user_data.get('v32_pending_needs'):
        context.user_data.pop('v32_pending_needs', None)
        query = normalize_name(update.message.text or '')
        team = _v32_find_team(query)
        if not team:
            suggestions = _v32_team_suggestions(query)
            if suggestions:
                await update.message.reply_text("Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ШЁШ§Щ„Ш¶ШЁШ·. ЩҠЩ…ЩғЩҶ ШӘЩӮШөШҜ:\n" + "\n".join([f"- {x}" for x in suggestions[:6]]) + "\n\nШ§ЩғШӘШЁ Ш§ШіЩ… Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ…ШұШ© Ш«Ш§ЩҶЩҠШ©.")
            else:
                await update.message.reply_text("Щ…Ш§ Щ„ЩӮЩҠШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Щ…Ш«Щ„ЩӢШ§: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Ш§Щ„ЩҠШ§ШЁШ§ЩҶ ШЈЩҲ Japan")
            return
        await update.message.reply_text(_v32_team_needs_text(team), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("в¬…пёҸ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")]]))
        return
    if context.user_data.get('v32_pending_broadcast'):
        if not is_admin_user(update):
            context.user_data.pop('v32_pending_broadcast', None)
            await update.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
            return
        context.user_data.pop('v32_pending_broadcast', None)
        text = normalize_name(update.message.text or '')
        token = f"bc_{int(_v32_now_ts()*1000)}"
        context.bot_data.setdefault('v32_broadcasts', {})[token] = text
        kb = InlineKeyboardMarkup([[InlineKeyboardButton("вң… ШҘШұШіШ§Щ„", callback_data=f"v32adm|sendbc|{token}"), InlineKeyboardButton("вқҢ ШҘЩ„ШәШ§ШЎ", callback_data="v32adm|cancelbc")]])
        await update.message.reply_text(f"рҹ“ў ШӘШЈЩғЩҠШҜ Ш§Щ„ШҘШұШіШ§Щ„\n\n{text}\n\nЩҮЩ„ ШӘШұЩҠШҜ ШҘШұШіШ§Щ„ЩҮШ§ Щ„Щ„Ш¬Щ…ЩҠШ№Шҹ", reply_markup=kb)
        return
    # Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШіШұЩҠШ№Ш© ШЁШҜЩҲЩҶ ШЈЩ…Шұ: Ш§ЩғШӘШЁ Ш§ШіЩ… Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩӮШ·
    raw = normalize_name(update.message.text or '').strip()
    team = _v32_find_team(raw)
    if team:
        await update.message.reply_text(_v32_team_summary_text(team), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ", callback_data=f"v32|needs_team|{simple_key(team)}"), InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds")]]))
        return
    # Ш§Щ„ШӯШ§Щ„Ш§ШӘ Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШӘШЁЩӮЩү Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ·
    if is_admin_user(update):
        return await _V32_OLD_TEXT_STATE_ROUTER(update, context)
    return


async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    if data == 'mainmenu|home':
        await q.answer(); await q.edit_message_text("Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ©:", reply_markup=_public_main_keyboard()); return
    if data == 'mainmenu|fantasy':
        await q.answer()
        if _v32_user_is_fantasy_allowed(q.from_user):
            await q.message.reply_text("рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ", reply_markup=_fantasy_public_keyboard())
        else:
            context.user_data['v32_pending_fantasy_password'] = True
            await q.message.reply_text(_v32_fantasy_gate_text())
        return
    if data == 'mainmenu|highlights':
        await q.answer(); await q.edit_message_text("рҹҺҘ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", reply_markup=_v32_hls_home_keyboard()); return
    if _V32_OLD_PUBLIC_MENU_CALLBACK:
        return await _V32_OLD_PUBLIC_MENU_CALLBACK(update, context)


# ЩҶШ№ЩҠШҜ ШӘШ№ШұЩҠЩҒ v32_callback Щ„ШҘШ¶Ш§ЩҒШ© ШЁЩҲШ§ШЁШ© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ ЩҲШӘШӯШіЩҠЩҶ ЩҶШөЩҲШө Ш§Щ„ШұШ¬ЩҲШ№.
_V32_FULLPATCH_PREV_V32_CALLBACK = v32_callback
async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q: return
    _v32_track_user(update)
    data = q.data or ''
    parts = data.split('|')
    action = parts[1] if len(parts)>1 else ''
    if action == 'fantasy_gate':
        await q.answer()
        if _v32_user_is_fantasy_allowed(q.from_user):
            await q.message.reply_text("рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„Щ…ШөЩҠЩҒ", reply_markup=_fantasy_public_keyboard())
        else:
            context.user_data['v32_pending_fantasy_password'] = True
            await q.message.reply_text(_v32_fantasy_gate_text())
        return
    if action == 'board':
        await q.answer(); await q.edit_message_text(_v32_tournament_board_text(), reply_markup=_v32_board_keyboard()); return
    if action == 'race':
        await q.answer(); await q.edit_message_text("рҹҸҒ Ш§Ш®ШӘШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Щ„Ш№ШұШ¶ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„:", reply_markup=_v32_groups_keyboard()); return
    if action == 'qualified':
        await q.answer(); teams = _v32_calculated_qualified(); txt = "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§\n" + ("\n".join([f"- {x}" for x in teams]) if teams else "Щ„Ш§ ЩҠЩҲШ¬ШҜ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
        await q.edit_message_text(txt, reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|race"), InlineKeyboardButton("рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")]])); return
    if action == 'eliminated':
        await q.answer(); teams = _v32_calculated_eliminated(); txt = "вқҢ Ш§Щ„Щ…ШіШӘШЁШ№ШҜЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§\n" + ("\n".join([f"- {x}" for x in teams]) if teams else "Щ„Ш§ ЩҠЩҲШ¬ШҜ ШӯШӘЩү Ш§Щ„ШўЩҶ.")
        await q.edit_message_text(txt, reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|race"), InlineKeyboardButton("рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")]])); return
    # Ш§Щ„ШЁШ§ЩӮЩҠ Щ„Щ„ЩғЩҲЩ„ШЁШ§Щғ Ш§Щ„ШіШ§ШЁЩӮ ШЁШ№ШҜ ШҘШ№Ш§ШҜШ© ШӘШ№ШұЩҠЩҒ Ш§Щ„ШҜЩҲШ§Щ„ ШЈШ№Щ„Ш§ЩҮ
    return await _V32_FULLPATCH_PREV_V32_CALLBACK(update, context)


def _v32_admin_keyboard():
    auth = _v32_load_fantasy_access()
    auth_count = len((auth.get('users') or {}))
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹ‘Ҙ Ш№ШҜШҜ Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ", callback_data="v32adm|count"), InlineKeyboardButton("рҹ“ў ШұШіШ§Щ„Ш© Ш¬Щ…Ш§Ш№ЩҠШ©", callback_data="v32adm|broadcast")],
        [InlineKeyboardButton("рҹҶ• ШўШ®Шұ Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ", callback_data="v32adm|last_users"), InlineKeyboardButton("вҡ пёҸ Щ…ШұЩғШІ Ш§Щ„ШӘЩҶШЁЩҠЩҮШ§ШӘ", callback_data="v32adm|alerts")],
        [InlineKeyboardButton(f"рҹ”җ Щ…ШөШұШӯЩҠЩҶ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ: {auth_count}", callback_data="v32adm|fantasy_auth_count"), InlineKeyboardButton("рҹ”‘ ШұЩ…ШІ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ", callback_data="v32adm|fantasy_code")],
        [InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32adm|refresh")],
    ])


async def v32_admin_panel_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    data = _v32_load_json(V32_USERS_FILE, {"users": {}})
    count = len((data.get('users') or {}))
    txt = f"рҹ§‘вҖҚрҹ’» Щ„ЩҲШӯШ© Ш§Щ„Щ…ШҙШұЩҒ\n\nрҹ‘Ҙ Ш№ШҜШҜ Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ: {count}\nрҹ”җ ШұЩ…ШІ Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„ШӯШ§Щ„ЩҠ: {_v32_get_fantasy_password()}\n\nШ§Ш®ШӘШұ Ш§Щ„Ш№Щ…Щ„ЩҠШ©:"
    await update.message.reply_text(txt, reply_markup=_v32_admin_keyboard())




