def _v32_goal_team_variants_safe(tm):
    forms = []
    if not tm:
        return forms
    try:
        forms += list(_v32_goal_team_variants(tm) or [])
    except Exception:
        forms.append(tm)
    forms.append(tm)
    try:
        can = canonical_team_name(tm)
        if can:
            forms.append(can)
    except Exception:
        pass
    extra = {
        'ШіШ§ШӯЩ„ Ш§Щ„Ш№Ш§Ш¬': ['ЩғЩҲШӘ ШҜЩҠЩҒЩҲШ§Шұ', 'Ш§Щ„Ш§ЩҠЩҒЩҲШ§ШұЩҠ', 'Ш§Щ„ШҘЩҠЩҒЩҲШ§ШұЩҠ', 'Ш§Щ„Ш№Ш§Ш¬ЩҠ'],
        'ЩғЩҲШӘ ШҜЩҠЩҒЩҲШ§Шұ': ['ШіШ§ШӯЩ„ Ш§Щ„Ш№Ш§Ш¬', 'Ш§Щ„Ш§ЩҠЩҒЩҲШ§ШұЩҠ', 'Ш§Щ„ШҘЩҠЩҒЩҲШ§ШұЩҠ', 'Ш§Щ„Ш№Ш§Ш¬ЩҠ'],
        'Ш§Щ„ЩҲЩ„Ш§ЩҠШ§ШӘ Ш§Щ„Щ…ШӘШӯШҜШ©': ['Ш§Щ…ШұЩҠЩғШ§', 'ШЈЩ…ШұЩҠЩғШ§', 'Ш§Щ„Ш§Щ…ШұЩҠЩғЩҠ', 'Ш§Щ„ШЈЩ…ШұЩҠЩғЩҠ'],
        'Ш§Щ„ШұШЈШі Ш§Щ„ШЈШ®Ш¶Шұ': ['ЩғШ§ШЁ ЩҒЩҠШұШҜЩҠ', 'ЩғШ§ШЁ ЩҒЩҠШұШҜЩү', 'Ш§Щ„ШұШ§Ші Ш§Щ„Ш§Ш®Ш¶Шұ'],
        'ШЈЩҲШұЩҲШ¬ЩҲШ§ЩҠ': ['Ш§ЩҲШұЩҲШәЩҲШ§ЩҠ', 'ШЈЩҲШұЩҲШәЩҲШ§ЩҠ', 'Ш§Щ„Ш§ЩҲШұЩҲШәЩҲЩҠШ§ЩҶЩҠ', 'Ш§Щ„ШЈЩҲШұЩҲШәЩҲЩҠШ§ЩҶЩҠ'],
    }
    for f in list(forms):
        forms += extra.get(normalize_name(f), [])
    uniq=[]; seen=set()
    for f in forms:
        f = normalize_name(f)
        k = _v32_norm_ar_for_goals(f)
        if f and k not in seen:
            uniq.append(f); seen.add(k)
    return sorted(uniq, key=len, reverse=True)


def _v32_goal_add_from_candidate(goals, seen, player, team, minutes, raw, team1, team2):
    added = 0
    for minute in _v32_goal_minutes_in_text(minutes) or ([str(minutes).strip()] if minutes else ['']):
        if _v32_add_goal_record(goals, seen, player, team, minute, raw, team1, team2):
            added += 1
    return added


def _v32_parse_bein_extra_patterns(desc, team1='', team2='', base_goals=None):
    goals = list(base_goals or [])
    seen = set()
    for g in goals:
        try:
            seen.add((simple_key((g or {}).get('player') or ''), simple_key((g or {}).get('team') or ''), str((g or {}).get('minute') or '')))
        except Exception:
            pass
    raw_text = _v32_clean_youtube_description(desc)
    text = re.sub(r'\s+', ' ', raw_text).strip()
    norm_text = _v32_norm_ar_for_goals(text)
    teams = [t for t in [team1, team2] if t]

    # ШЈЩҒШӘШӘШӯ/Ш§ЩҒШӘШӘШӯ Ш§Щ„ШӘШіШ¬ЩҠЩ„ ШЁЩҲШ§ШіШ·Ш© ЩҒЩ„Ш§ЩҶ ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШ© 21
    pat1 = r'(?:Ш§ЩҒШӘШӘШӯ|ШЈЩҒШӘШӘШӯ)\s+(?:Щ…ЩҶШӘШ®ШЁ\s+[^ШҢ\.]{2,40}\s+)?(?:Ш§Щ„ШӘШіШ¬ЩҠЩ„\s+)?(?:ШЁЩҲШ§ШіШ·Ш©|ШЁЩҲШ§ШіШ·ЩҮ|Ш№ЩҶ\s+Ш·ШұЩҠЩӮ)\s+([^ШҢ\.]{2,55}?)\s+(?:ЩҒЩҠ\s+)?(?:Ш§Щ„ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮЩҮ|ШҜЩӮЩҠЩӮШ©|ШҜЩӮЩҠЩӮЩҮ)\s+([1-9]\d{0,2}(?:\+\d{1,2})?)'
    for m in re.finditer(pat1, text):
        team_hint = _v32_goal_team_from_text(m.group(0), team1, team2)
        _v32_goal_add_from_candidate(goals, seen, m.group(1), team_hint, m.group(2), m.group(0), team1, team2)

    # ШӘШ№Ш§ШҜЩ„ Щ…ЩҶШӘШ®ШЁ ЩғЩҶШҜШ§ ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШ© 78 ШЁЩҮШҜЩҒ ШЈШӯШұШІЩҮ ЩғШ§ЩҠЩ„ Щ„Ш§ШұЩҠЩҶ
    pat2 = r'(?:ШӘШ№Ш§ШҜЩ„|Ш§ШҜШұЩғ|ШЈШҜШұЩғ)[^ШҢ\.]{0,120}?(?:Ш§Щ„ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮЩҮ|ШҜЩӮЩҠЩӮШ©|ШҜЩӮЩҠЩӮЩҮ)\s+([1-9]\d{0,2}(?:\+\d{1,2})?)[^ШҢ\.]{0,80}?(?:ШЁЩҮШҜЩҒ\s+)?(?:ШЈШӯШұШІЩҮ|Ш§ШӯШұШІЩҮ|ШіШ¬Щ„ЩҮ|ШіШ¬Щ‘Щ„\s+Щ„ЩҮ|ШіШ¬Щ„\s+Щ„ЩҮ)\s+([^ШҢ\.]{2,55})'
    for m in re.finditer(pat2, text):
        team_hint = _v32_goal_team_from_text(m.group(0), team1, team2)
        _v32_goal_add_from_candidate(goals, seen, m.group(2), team_hint, m.group(1), m.group(0), team1, team2)

    # ШіШ¬Щ„ ЩҒЩ„Ш§ЩҶ ЩҮШҜЩҒЩҠ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШӘЩҠЩҶ 68 ЩҲ90+4
    pat3 = r'(?:ШіШ¬Щ„|ШіШ¬Щ‘Щ„|ШЈШӯШұШІ|Ш§ШӯШұШІ)\s+([^ШҢ\.]{2,55}?)\s+(?:ЩҮШҜЩҒЩҠ|ЩҮШҜЩҒЩҠЩҶ|Ш«ЩҶШ§ШҰЩҠЩҮ|Ш«ЩҶШ§ШҰЩҠШ©|Ш§ЩҮШҜШ§ЩҒ|ШЈЩҮШҜШ§ЩҒ)?[^ШҢ\.]{0,80}?(?:Ш§Щ„ШҜЩӮЩҠЩӮШӘЩҠЩҶ|Ш§Щ„ШҜЩӮШ§ШҰЩӮ)\s+([1-9]\d{0,2}(?:\+\d{1,2})?(?:\s*(?:ЩҲ|ШҢ|,)\s*[1-9]\d{0,2}(?:\+\d{1,2})?)*)'
    for m in re.finditer(pat3, text):
        team_hint = _v32_goal_team_from_text(m.group(0), team1, team2)
        _v32_goal_add_from_candidate(goals, seen, m.group(1), team_hint, m.group(2), m.group(0), team1, team2)

    # ШіШ¬Щ„ ЩҒЩ„Ш§ЩҶ ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШ© 32 / ШЈШӯШұШІ ЩҒЩ„Ш§ЩҶ ЩҮШҜЩҒ ... ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШ© 30
    pat4 = r'(?:ШіШ¬Щ„|ШіШ¬Щ‘Щ„|ШЈШӯШұШІ|Ш§ШӯШұШІ|ЩӮЩ„Шө|ЩӮЩ„Щ‘Шө|Ш§Ш¶Ш§ЩҒ|ШЈШ¶Ш§ЩҒ|ШӯШіЩ…|Ш§Ш®ШӘШӘЩ…)\s+([^ШҢ\.]{2,55}?)\s+(?:ЩҮШҜЩҒ\s+)?[^ШҢ\.]{0,80}?(?:Ш§Щ„ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮЩҮ|ШҜЩӮЩҠЩӮШ©|ШҜЩӮЩҠЩӮЩҮ)\s+([1-9]\d{0,2}(?:\+\d{1,2})?)'
    for m in re.finditer(pat4, text):
        team_hint = _v32_goal_team_from_text(m.group(0), team1, team2)
        _v32_goal_add_from_candidate(goals, seen, m.group(1), team_hint, m.group(2), m.group(0), team1, team2)

    # ЩҒЩҠ Ш§Щ„Щ…ЩӮШ§ШЁЩ„ ШҜЩҲЩҶ ЩҒШұШ§ЩҶЩғ ЩғЩҠШіЩҠЩҠЩҮ ЩҮШҜЩҒ Щ…ЩҶШӘШ®ШЁ ЩғЩҲШӘ ШҜЩҠЩҒЩҲШ§Шұ Ш§Щ„ЩҲШӯЩҠШҜ ЩҒЩҠ Ш§Щ„ШҜЩӮЩҠЩӮШ© 30
    for tm in teams:
        for var in _v32_goal_team_variants_safe(tm):
            v = re.escape(var)
            pat5 = rf'([^ШҢ\.]{{2,80}}?)\s+(?:ЩҮШҜЩҒ|ЩҮШҜЩҒЩҠ|Ш§ЩҮШҜШ§ЩҒ|ШЈЩҮШҜШ§ЩҒ)\s+(?:Щ…ЩҶШӘШ®ШЁ|Ш§Щ„Щ…ЩҶШӘШ®ШЁ)?\s*{v}[^ШҢ\.]{{0,60}}?(?:Ш§Щ„ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮЩҮ|ШҜЩӮЩҠЩӮШ©|ШҜЩӮЩҠЩӮЩҮ)\s+([1-9]\d{{0,2}}(?:\+\d{{1,2}})?)'
            for m in re.finditer(pat5, text):
                player = m.group(1)
                player = re.split(r'(?:ЩҒЩҠ\s+Ш§Щ„Щ…ЩӮШ§ШЁЩ„|ШЁЩҠЩҶЩ…Ш§|ЩҒЩҠЩ…Ш§|ЩҲ|ШҢ)', player)[-1]
                player = _v32_goal_clean_player_candidate(player)
                _v32_goal_add_from_candidate(goals, seen, player, tm, m.group(2), m.group(0), team1, team2)

    # ШіШ¬Щ„ Щ„Щ…ЩҶШӘШ®ШЁ ШҘЩҠШұШ§ЩҶ ШұШ§Щ…ЩҠЩҶ ШұШ¶Ш§ШҰЩҠШ§ЩҶ 32 ЩҲЩ…ШӯЩ…ШҜ Щ…ШӯШЁЩҠ 64
    for tm in teams:
        for var in _v32_goal_team_variants_safe(tm):
            v = re.escape(var)
            pat6 = rf'(?:ШіШ¬Щ„|ШіШ¬Щ‘Щ„|ШЈШӯШұШІ|Ш§ШӯШұШІ)\s+(?:Щ„Щ…ЩҶШӘШ®ШЁ|Щ„Щ„Щ…ЩҶШӘШ®ШЁ|Щ„ШөШ§Щ„Шӯ\s+Щ…ЩҶШӘШ®ШЁ)?\s*{v}\s+([^\.\n]{{2,160}})'
            for m in re.finditer(pat6, text):
                chunk = m.group(1)
                # Ш§ЩӮШ·Ш№ ЩӮШЁЩ„ Ш¬Щ…Щ„Ш© ЩҒШұЩҠЩӮ ШўШ®Шұ ШҘЩҶ ЩҲШ¬ШҜШӘ.
                chunk = re.split(r'(?:ЩҒЩҠЩ…Ш§|ШЁЩҠЩҶЩ…Ш§|ЩҒЩҠ Ш§Щ„Щ…ЩӮШ§ШЁЩ„|ЩҲШӘШ№Ш§ШҜЩ„|ЩҲШ№Ш§ШҜЩ„)', chunk)[0]
                try:
                    _v32_goal_add_pairs_from_chunk(goals, seen, chunk, tm, m.group(0), team1, team2)
                except Exception:
                    pass
    return goals[:100]


def _v32_parse_youtube_goal_scorers(desc, team1='', team2=''):
    globals()['V32_LAST_GOAL_PARSE_ALERTS'] = []
    goals = []
    if _V32_PREV_PARSE_YT_GOALS_ADMINPATCH:
        try:
            goals = list(_V32_PREV_PARSE_YT_GOALS_ADMINPATCH(desc, team1, team2) or [])
        except Exception as e:
            globals().setdefault('V32_LAST_GOAL_PARSE_ALERTS', []).append(f'ШӘШ№Ш°Шұ Ш§Щ„ЩӮШ§ШұШҰ Ш§Щ„ЩӮШҜЩҠЩ…: {str(e)[:80]}')
            goals = []
    goals = _v32_parse_bein_extra_patterns(desc, team1, team2, goals)
    # ЩҒЩ„ШӘШұШ© ШЈШ®ЩҠШұШ© ЩҲШҘШІШ§Щ„Ш© Ш§Щ„ШӘЩғШұШ§Шұ ЩҲШұШЁШ· Ш§Щ„Щ…ЩҶШӘШ®ШЁ ШЁШ§Щ„ЩӮЩҲШ§ШҰЩ….
    clean=[]; seen=set()
    for g in goals:
        p = _v32_goal_clean_player_candidate((g or {}).get('player'))
        if _v32_goal_is_bad_player_name(p, team1, team2):
            continue
        tm = (g or {}).get('team') or _v32_goal_squad_team_for_player(p, team1, team2) or ''
        if tm and team1 and '_v31_team_same' in globals():
            try:
                if _v31_team_same(tm, team1):
                    tm = team1
                elif team2 and _v31_team_same(tm, team2):
                    tm = team2
            except Exception:
                pass
        minute = str((g or {}).get('minute') or '').replace("'", '').replace('вҖҷ','').strip()
        if minute and not re.fullmatch(r'[1-9]\d{0,2}(?:\+\d{1,2})?', minute):
            minute = ''
        key = (simple_key(p), simple_key(tm or ''), minute)
        if key in seen:
            continue
        seen.add(key)
        gg = dict(g)
        gg['player'] = p
        gg['team'] = tm or 'ШәЩҠШұ Щ…ШӯШҜШҜ'
        gg['minute'] = minute
        clean.append(gg)
    if not clean:
        # Ш§ШӯШӘЩҒШё ШЁШ¬Щ…Щ„Ш© ЩӮШөЩҠШұШ© Щ„Щ„Щ…ШұШ§Ш¬Ш№Ш© ШЁШҜЩ„ ШұШіШ§Щ„Ш© Ш№Ш§Щ…Ш© ЩҒЩӮШ·.
        desc_short = re.sub(r'\s+', ' ', _v32_clean_youtube_description(desc))[:220]
        if desc_short:
            globals().setdefault('V32_LAST_GOAL_PARSE_ALERTS', []).append('ЩҲШөЩҒ Щ„Щ… ЩҠЩҒЩҮЩ…: ' + desc_short)
    return clean[:80]


def _v32_get_description_for_highlight(key, url, item=None, force=False, reanalyze_only=False):
    cache = _v32_load_descriptions_cache()
    rec = (cache.get('items') or {}).get(key) or {}
    if reanalyze_only:
        return rec.get('description') or ''
    if (not force) and rec.get('url') == url and rec.get('description'):
        return rec.get('description')
    desc = _v32_fetch_youtube_description(url)
    cache.setdefault('items', {})[key] = {
        'url': url,
        'team1': (item or {}).get('team1') or '',
        'team2': (item or {}).get('team2') or '',
        'description': desc,
        'updated_at': _v32_json_now(),
    }
    _v32_save_descriptions_cache(cache)
    return desc


def _v32_goal_scorers_analyze_saved_descriptions():
    return _v32_goal_scorers_update_from_highlights(force=True, reanalyze_only=True)


def _v32_goal_scorers_update_from_highlights(force=False, reanalyze_only=False):
    data = _v32_load_goal_scorers_data()
    if not isinstance(data, dict):
        data = {"updated_at": "", "matches": {}, "alerts": []}
    data.setdefault('matches', {})
    data.setdefault('alerts', [])
    try:
        _v32_goal_load_squads()
    except Exception:
        pass
    highlights = _load_highlights() if '_load_highlights' in globals() else {}
    checked = added_goals = updated_matches = skipped = failed = 0
    alerts = []
    last_fetch_started = False

    for key, item in (highlights or {}).items():
        if not isinstance(item, dict):
            continue
        url = item.get('url') or item.get('summary_url') or item.get('summary_url_manual') or ''
        team1 = item.get('team1') or ''
        team2 = item.get('team2') or ''
        if not url or not _v32_is_youtube_url(url):
            if url:
                skipped += 1
            continue
        old = (data.get('matches') or {}).get(key) or {}
        # Щ„Ш§ ЩҶШӘШ¬Ш§ЩҲШІ Щ…ШЁШ§ШұШ§Ш© ЩӮШҜЩҠЩ…Ш© ШҘЩ„Ш§ ШҘШ°Ш§ Ш№ЩҶШҜЩҶШ§ Ш§Щ„ЩҲШөЩҒ Ш§Щ„Ш®Ш§Щ… Щ…ШӯЩҒЩҲШёШӣ
        # Щ„ШЈЩҶ Ш§Щ„ЩҶШіШ® Ш§Щ„ШіШ§ШЁЩӮШ© ШұШЁЩ…Ш§ ШӯЩҒШёШӘ ШЈЩҮШҜШ§ЩҒЩӢШ§ Щ…ШәЩ„ЩҲШ·Ш© ШЁШҜЩҲЩҶ ШӯЩҒШё Ш§Щ„ЩҲШөЩҒ.
        try:
            _desc_cache = _v32_load_descriptions_cache()
            _desc_rec = ((_desc_cache.get('items') or {}).get(key) or {})
            _has_cached_desc = bool(_desc_rec.get('url') == url and _desc_rec.get('description'))
        except Exception:
            _has_cached_desc = False
        if (not force) and old.get('url') == url and old.get('goals') and _has_cached_desc:
            skipped += 1
            continue

        if (not reanalyze_only) and last_fetch_started:
            try:
                _time.sleep(int(YOUTUBE_GOAL_FETCH_DELAY_SECONDS or 20))
            except Exception:
                pass
        last_fetch_started = True
        checked += 1

        try:
            desc = _v32_get_description_for_highlight(key, url, item=item, force=force and not reanalyze_only, reanalyze_only=reanalyze_only)
            if not desc:
                failed += 1
                alerts.append(f"{team1} Г— {team2}: Щ„Ш§ ЩҠЩҲШ¬ШҜ ЩҲШөЩҒ Щ…ШӯЩҒЩҲШё Щ„ШҘШ№Ш§ШҜШ© Ш§Щ„ШӘШӯЩ„ЩҠЩ„" if reanalyze_only else f"{team1} Г— {team2}: ЩҲШөЩҒ ЩҠЩҲШӘЩҠЩҲШЁ ЩҒШ§ШұШә")
                continue
            goals = _v32_parse_youtube_goal_scorers(desc, team1, team2)
            parse_alerts = list(globals().get('V32_LAST_GOAL_PARSE_ALERTS') or [])
            if not goals:
                failed += 1
                msg = f"{team1} Г— {team2}: Щ„Щ… ЩҠШӘЩ… Ш§Щ„Ш№Ш«ЩҲШұ Ш№Щ„Щү Щ…ШіШ¬Щ„ЩҠ ШЈЩҮШҜШ§ЩҒ ЩҲШ§Ш¶ШӯЩҠЩҶ ЩҒЩҠ ЩҲШөЩҒ Ш§Щ„ЩҠЩҲШӘЩҠЩҲШЁ"
                alerts.append(msg)
                if parse_alerts:
                    alerts.extend([f"{team1} Г— {team2}: {x}" for x in parse_alerts[:3]])
                data['matches'][key] = {
                    'team1': team1, 'team2': team2, 'url': url,
                    'description_cached': bool(desc),
                    'updated_at': _v32_json_now(),
                    'goals': [], 'note': 'no_goals_found', 'last_error': 'no_goals_found'
                }
                continue

            enriched = []
            for g in goals:
                gg = dict(g)
                tm = gg.get('team') or _v32_goal_squad_team_for_player(gg.get('player'), team1, team2) or ''
                try:
                    same1 = bool(tm and team1 and '_v31_team_same' in globals() and _v31_team_same(tm, team1))
                    same2 = bool(tm and team2 and '_v31_team_same' in globals() and _v31_team_same(tm, team2))
                except Exception:
                    same1 = same2 = False
                if same1:
                    gg['team'] = team1; gg['against'] = team2
                elif same2:
                    gg['team'] = team2; gg['against'] = team1
                else:
                    gg['team'] = tm or 'ШәЩҠШұ Щ…ШӯШҜШҜ'; gg['against'] = f"{team1} Г— {team2}".strip()
                    alerts.append(f"{team1} Г— {team2}: Ш§Щ„Щ„Ш§Ш№ШЁ ЩҠШӯШӘШ§Ш¬ Щ…ШұШ§Ш¬Ш№Ш© Щ„Щ„Щ…ЩҶШӘШ®ШЁ - {gg.get('player')}")
                enriched.append(gg)

            expected_goals = _v32_expected_match_goals_from_fixture(team1, team2)
            if expected_goals and len(enriched) < expected_goals:
                alerts.append(f"{team1} Г— {team2}: ЩӮШҜ ШӘЩғЩҲЩҶ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ЩҶШ§ЩӮШөШ© - Ш§Щ„Щ…ШіШӘШ®ШұШ¬ {len(enriched)} Щ…ЩҶ {expected_goals}")
            data['matches'][key] = {
                'team1': team1, 'team2': team2, 'url': url,
                'description_cached': True,
                'updated_at': _v32_json_now(),
                'goals': enriched,
                'expected_goals': expected_goals,
            }
            added_goals += len(enriched)
            updated_matches += 1
        except Exception as e:
            failed += 1
            clean_err = _v32_youtube_safe_error(e) if '_v32_youtube_safe_error' in globals() else str(e)[:90]
            alerts.append(f"{team1} Г— {team2}: {clean_err}")
            data['matches'][key] = {
                'team1': team1, 'team2': team2, 'url': url,
                'updated_at': _v32_json_now(),
                'goals': [], 'note': 'read_failed', 'last_error': clean_err
            }

    data['updated_at'] = _v32_json_now()
    data['alerts'] = alerts[:160]
    _v32_save_goal_scorers_data(data)
    return {
        'checked': checked,
        'updated_matches': updated_matches,
        'added_goals': added_goals,
        'skipped': skipped,
        'failed': failed,
        'alerts': alerts[:12],
        'data': data,
        'reanalyze_only': reanalyze_only,
    }


def _v32_goal_scorers_home_keyboard(is_admin=False):
    rows = [[InlineKeyboardButton("рҹ“„ Щ…Щ„ЩҒ Щ…ШіШ¬Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ", callback_data="v32|goal_scorers_file")]]
    if is_admin:
        rows.append([InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Щ…ЩҶ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ", callback_data="v32|goal_scorers_update")])
        rows.append([InlineKeyboardButton("рҹ”Ғ ШҘШ№Ш§ШҜШ© ШӘШӯЩ„ЩҠЩ„ Ш§Щ„ШЈЩҲШөШ§ЩҒ Ш§Щ„Щ…ШӯЩҒЩҲШёШ©", callback_data="v32|goal_scorers_reanalyze")])
    rows.append([InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _v32_filter_inline_markup_for_public(markup):
    """ЩҠШӯШ°ЩҒ ШЈШІШұШ§Шұ Ш§Щ„Щ…ШіШӯ/Ш§Щ„ЩғШ§Шҙ/Ш§Щ„ШӘШӯШҜЩҠШ« Щ…ЩҶ Щ„ЩҲШӯШ§ШӘ Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ Ш§Щ„Ш№Ш§ШҜЩҠЩҠЩҶ."""
    if markup is None:
        return markup
    try:
        rows = []
        for row in getattr(markup, 'inline_keyboard', []) or []:
            new_row = []
            for b in row:
                txt = getattr(b, 'text', '') or ''
                cb = getattr(b, 'callback_data', '') or ''
                dangerous = (
                    'Щ…ШіШӯ ЩғШ§Шҙ' in txt or 'Щ…ШіШӯ' in txt or 'ШӘШӯШҜЩҠШ«' in txt or 'ШҘШ№Ш§ШҜШ© ШӘШӯЩ„ЩҠЩ„' in txt or 'Ш§Ш№Ш§ШҜШ© ШӘШӯЩ„ЩҠЩ„' in txt or
                    cb.startswith('res|clearday') or cb.startswith('res|refreshday') or cb.startswith('livefx|clearday') or cb.startswith('livefx|refreshday') or
                    cb in ('v32|goal_scorers_update', 'v32|goal_scorers_reanalyze')
                )
                if not dangerous:
                    new_row.append(b)
            if new_row:
                rows.append(new_row)
        return InlineKeyboardMarkup(rows)
    except Exception:
        return markup


# ШЈШ®ЩҒЩҗ ШЈШІШұШ§Шұ Ш§Щ„ЩғШ§Шҙ/Ш§Щ„ШӘШӯШҜЩҠШ« Щ…ЩҶ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҲЩ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ Щ„Щ„Щ…ШіШӘШ®ШҜЩ… Ш§Щ„Ш№Ш§ШҜЩҠШҢ Щ…Ш№ ШҘШЁЩӮШ§ШҰЩҮШ§ Щ„Щ„Щ…ШҙШұЩҒ.
try:
    _V32_ADMIN_PATCH_PREV_RESULTS_KEYBOARD = _v33_results_matches_keyboard
    def _v33_results_matches_keyboard(d):
        mk = _V32_ADMIN_PATCH_PREV_RESULTS_KEYBOARD(d)
        if globals().get('V32_ADMIN_RENDER_CONTEXT'):
            return mk
        return _v32_filter_inline_markup_for_public(mk)
except Exception:
    pass

try:
    _V32_ADMIN_PATCH_PREV_LIVE_KEYBOARD = _v29_live_today_keyboard
    def _v29_live_today_keyboard(date_str=None):
        mk = _V32_ADMIN_PATCH_PREV_LIVE_KEYBOARD(date_str)
        if globals().get('V32_ADMIN_RENDER_CONTEXT'):
            return mk
        return _v32_filter_inline_markup_for_public(mk)
except Exception:
    pass


def _v32_is_dangerous_callback(data):
    data = str(data or '')
    return (
        data.startswith('res|clearday') or data.startswith('res|refreshday') or
        data.startswith('livefx|clearday') or data.startswith('livefx|refreshday') or
        data in ('v32|goal_scorers_update', 'v32|goal_scorers_reanalyze') or
        '|clear' in data or '|delete' in data or '|reset' in data
    )


try:
    _V32_ADMIN_PATCH_PREV_RESULTS_CALLBACK = previous_results_callback
    async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
        q = update.callback_query
        data = (q.data or '') if q else ''
        is_adm = _v32_is_admin_update_or_query(update)
        if _v32_is_dangerous_callback(data) and not is_adm:
            try:
                await q.answer('ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ· рҹ”’', show_alert=True)
            except Exception:
                pass
            return
        old = globals().get('V32_ADMIN_RENDER_CONTEXT', False)
        globals()['V32_ADMIN_RENDER_CONTEXT'] = bool(is_adm)
        try:
            return await _V32_ADMIN_PATCH_PREV_RESULTS_CALLBACK(update, context)
        finally:
            globals()['V32_ADMIN_RENDER_CONTEXT'] = old
except Exception:
    pass

try:
    _V32_ADMIN_PATCH_PREV_LIVE_CALLBACK = live_today_callback
    async def live_today_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
        q = update.callback_query
        data = (q.data or '') if q else ''
        is_adm = _v32_is_admin_update_or_query(update)
        if _v32_is_dangerous_callback(data) and not is_adm:
            try:
                await q.answer('ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ· рҹ”’', show_alert=True)
            except Exception:
                pass
            return
        old = globals().get('V32_ADMIN_RENDER_CONTEXT', False)
        globals()['V32_ADMIN_RENDER_CONTEXT'] = bool(is_adm)
        try:
            return await _V32_ADMIN_PATCH_PREV_LIVE_CALLBACK(update, context)
        finally:
            globals()['V32_ADMIN_RENDER_CONTEXT'] = old
except Exception:
    pass


# ШҘШ№Ш§ШҜШ© Щ„ЩҒ v32_callback Щ„ШҘШ¶Ш§ЩҒШ© ШІШұ ШҘШ№Ш§ШҜШ© Ш§Щ„ШӘШӯЩ„ЩҠЩ„ ЩҲШӯЩ…Ш§ЩҠШ© ШЈЩҠ callback ШҘШҜШ§ШұЩҠ ЩӮШҜЩҠЩ….
try:
    _V32_ADMIN_PATCH_PREV_V32_CALLBACK = v32_callback
    async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
        q = update.callback_query
        if not q:
            return
        data = q.data or ''
        if _v32_is_dangerous_callback(data) and not _v32_is_admin_update_or_query(update):
            try:
                await q.answer('ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒ ЩҒЩӮШ· рҹ”’', show_alert=True)
            except Exception:
                pass
            return
        if data == 'v32|goal_scorers_reanalyze':
            await q.answer()
            if _v32_goal_scorers_update_is_running():
                await q.message.reply_text('вҸі ЩҠЩҲШ¬ШҜ ШӘШӯШҜЩҠШ«/ШӘШӯЩ„ЩҠЩ„ ШҙШәШ§Щ„ ШЁШ§Щ„Ш®Щ„ЩҒЩҠШ© ШЁШ§Щ„ЩҒШ№Щ„. Ш§ЩҶШӘШёШұ Ш§Щ„ШӘЩӮШұЩҠШұ Ш§Щ„ЩҶЩҮШ§ШҰЩҠ.', reply_markup=_v32_goal_scorers_home_keyboard(is_admin=True))
                return
            async def _reanalyze_bg(bot, chat_id):
                global V32_GOAL_SCORERS_UPDATE_TASK, V32_GOAL_SCORERS_UPDATE_LAST_REPORT, V32_GOAL_SCORERS_UPDATE_STARTED_AT
                try:
                    res = await asyncio.to_thread(_v32_goal_scorers_analyze_saved_descriptions)
                    V32_GOAL_SCORERS_UPDATE_LAST_REPORT = res
                    await bot.send_message(chat_id=chat_id, text='\n'.join(_v32_goal_scorers_update_report_lines(res)), reply_markup=_v32_goal_scorers_home_keyboard(is_admin=True))
                except Exception as e:
                    safe = _v32_youtube_safe_error(e) if '_v32_youtube_safe_error' in globals() else str(e)[:180]
                    await bot.send_message(chat_id=chat_id, text=f'ШӘШ№Ш°Шұ ШҘШ№Ш§ШҜШ© Ш§Щ„ШӘШӯЩ„ЩҠЩ„ вқҢ\n{safe}')
                finally:
                    V32_GOAL_SCORERS_UPDATE_TASK = None
                    V32_GOAL_SCORERS_UPDATE_STARTED_AT = ''
            try:
                V32_GOAL_SCORERS_UPDATE_STARTED_AT = _v32_json_now()
                V32_GOAL_SCORERS_UPDATE_TASK = context.application.create_task(_reanalyze_bg(context.bot, q.message.chat_id))
            except Exception:
                V32_GOAL_SCORERS_UPDATE_TASK = asyncio.create_task(_reanalyze_bg(context.bot, q.message.chat_id))
            await q.message.reply_text('рҹ”Ғ Ш¬Ш§ШұЩҠ ШҘШ№Ш§ШҜШ© ШӘШӯЩ„ЩҠЩ„ Ш§Щ„ШЈЩҲШөШ§ЩҒ Ш§Щ„Щ…ШӯЩҒЩҲШёШ© ШЁШ§Щ„Ш®Щ„ЩҒЩҠШ©...\nЩ…Ш§ ШұШ§Шӯ ШЈШҜШ®Щ„ ЩҠЩҲШӘЩҠЩҲШЁ ЩҲЩ„Ш§ ШЈЩҶШӘШёШұ 20 Ш«Ш§ЩҶЩҠШ©ШҢ ЩҒЩӮШ· ШЈШӯЩ„Щ„ Ш§Щ„ЩғШ§Шҙ Ш§Щ„Щ…ШӯЩҒЩҲШё.', reply_markup=_v32_goal_scorers_home_keyboard(is_admin=True))
            return
        old = globals().get('V32_ADMIN_RENDER_CONTEXT', False)
        globals()['V32_ADMIN_RENDER_CONTEXT'] = bool(_v32_is_admin_update_or_query(update))
        try:
            return await _V32_ADMIN_PATCH_PREV_V32_CALLBACK(update, context)
        finally:
            globals()['V32_ADMIN_RENDER_CONTEXT'] = old
except Exception:
    pass

# ==================== END V32 ADMIN PROTECTION + RAW DESCRIPTION CACHE + BEIN AR PATCH ====================


# ==================== V33 QUALIFICATION CALCULATOR + PERSISTENT HIGHLIGHTS/GOALS PATCH ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - ЩӮШ§ШҰЩ…Ш© ШұШҰЩҠШіЩҠШ© Ш¬ШҜЩҠШҜШ©: ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„ + ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„ Ш®Ш§ШұШ¬ЩҠШ© ЩҲШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩғШ§ЩҶЩҮШ§.
# - ШҘЩ„ШәШ§ШЎ ЩҲШ§Ш¬ЩҮШ© "Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғ" Щ„ШөШ§Щ„Шӯ "вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ".
# - ШӯШ§ШіШЁШ© Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲШ§ШӘ + Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Ш®ШөЩ… ШҘШ°Ш§ ШөШ§Шұ Ш§Щ„Щ…ЩҶШӘШ®ШЁ Ш«Ш§Щ„Ш«ЩӢШ§.
# - ЩҒЩ„ШӘШұШ© Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„Ш© Щ…ЩҶ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.
# - ШӯЩҒШё Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ ЩҲЩ…ШіШ¬Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ЩҒЩҠ Щ…Щ„ЩҒШ§ШӘ Ш«Ш§ШЁШӘШ© ШЁШ№ШҜ Ш§Щ„ШұЩҠШіШӘШ§ШұШӘ.
# - ШҘЩ„ШәШ§ШЎ ЩӮШіЩ… "ЩҠШӯШӘШ§Ш¬ Щ…ШұШ§Ш¬Ш№Ш©" ЩҒЩҠ Щ…ШіШ¬Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ.

# Щ…Щ„ЩҒШ§ШӘ Ш«Ш§ШЁШӘШ© ШӯШӘЩү Щ„Ш§ ШӘЩҶЩ…ШіШӯ ШЁШ№ШҜ ШҘШ№Ш§ШҜШ© ШӘШҙШәЩҠЩ„ Ш§Щ„ШіЩҠШұЩҒШұ.
MATCH_SUMMARIES_FILE = "match_summaries.json"
GOALS_DATA_FILE = "goals_data.json"
THIRD_PLACE_ROUND32_MAP_FILE = "third_place_round32_map.json"

try:
    # Ш§Щ„ШҜЩҲШ§Щ„ Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШӘЩӮШұШЈ Ш§ШіЩ… Ш§Щ„Щ…Щ„ЩҒ Щ…ЩҶ Ш§Щ„Щ…ШӘШәЩҠШұ ЩҲЩӮШӘ Ш§Щ„ШӘШҙШәЩҠЩ„ШҢ Щ„Ш°Щ„Щғ ШӘШәЩҠЩҠШұ Ш§Щ„Щ…ШӘШәЩҠШұ ЩҠЩғЩҒЩҠ Щ…Ш№ Ш§Щ„ШӘШұШӯЩҠЩ„.
    MATCH_HIGHLIGHTS_FILE = MATCH_SUMMARIES_FILE
    YOUTUBE_GOAL_SCORERS_FILE = GOALS_DATA_FILE
except Exception:
    pass


def _v33_safe_load_json(path, default=None):
    default = {} if default is None else default
    try:
        if '_v32_load_json' in globals():
            return _v32_load_json(path, default)
    except Exception:
        pass
    try:
        if os.path.exists(path):
            with open(path, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return default


def _v33_safe_save_json(path, data):
    try:
        if '_v32_save_json' in globals():
            return _v32_save_json(path, data)
    except Exception:
        pass
    tmp = str(path) + '.tmp'
    with open(tmp, 'w', encoding='utf-8') as f:
        json.dump(data or {}, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)


def _v33_migrate_persistent_files():
    # Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ: Щ…ЩҶ match_highlights.json ШҘЩ„Щү match_summaries.json
    try:
        old = 'match_highlights.json'
        new = MATCH_SUMMARIES_FILE
        if os.path.exists(old) and not os.path.exists(new):
            data = _v33_safe_load_json(old, {})
            _v33_safe_save_json(new, data)
    except Exception:
        pass
    # Щ…ШіШ¬Щ„ЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ: Щ…ЩҶ youtube_goal_scorers.json ШҘЩ„Щү goals_data.json
    try:
        old = 'youtube_goal_scorers.json'
        new = GOALS_DATA_FILE
        if os.path.exists(old) and not os.path.exists(new):
            data = _v33_safe_load_json(old, {"updated_at": "", "matches": {}, "alerts": []})
            # Щ„Ш§ ЩҶЩҶЩӮЩ„ ЩӮШіЩ… Ш§Щ„Щ…ШұШ§Ш¬Ш№Ш©ШҢ ЩҲЩҶШ®Щ„ЩҠ alerts ЩҒЩӮШ· Щ„Щ„ШӘЩӮШұЩҠШұ Ш§Щ„ШҘШҜШ§ШұЩҠ ШҘЩҶ ЩҲШ¬ШҜШӘ.
            data.pop('review', None); data.pop('needs_review', None); data.pop('goals_review', None)
            _v33_safe_save_json(new, data)
    except Exception:
        pass

_v33_migrate_persistent_files()

# ШӘШұШӘЩҠШЁ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32 Ш§Щ„ШӘЩҠ ШӘШіШӘЩӮШЁЩ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ Ш¬ШҜЩҲЩ„ FIFA: Ш§Щ„ЩҒШ§ШҰШІ ШЁШ§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© -> Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Щ…ЩғЩҶШ©.
# ЩҮШ°Ш§ Щ„ЩҠШі ШЁШҜЩҠЩ„ЩӢШ§ Ш№ЩҶ Annexe C Ш§Щ„ЩғШ§Щ…Щ„ШҢ Щ„ЩғЩҶЩҮ ЩӮШ§Ш№ШҜШ© ШұШіЩ…ЩҠШ© Щ…ЩҶ Ш§Щ„Щ…Ш§ШҜШ© 12.6ШҢ ЩҲЩҠШіШӘШ®ШҜЩ…ЩҮШ§ Ш§Щ„ШЁЩҲШӘ Щ„ЩҒЩ„ШӘШұШ© Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ.
V33_THIRD_SLOT_CANDIDATES = {
    'E': list('ABCDF'),
    'I': list('CDFGH'),
    'A': list('CEFHI'),
    'L': list('EHIJK'),
    'D': list('BEFIJ'),
    'G': list('AEHIJ'),
    'B': list('EFGIJ'),
    'K': list('DEIJL'),
}
V33_THIRD_SLOT_ORDER = ['A', 'B', 'D', 'E', 'G', 'I', 'K', 'L']
V33_AR_GROUP_LETTERS = {"A":"ШЈ", "B":"ШЁ", "C":"Ш¬", "D":"ШҜ", "E":"ЩҮЩҖ", "F":"ЩҲ", "G":"ШІ", "H":"Шӯ", "I":"Ш·", "J":"ЩҠ", "K":"Щғ", "L":"Щ„"}

# Ш®ШұЩҠШ·Ш© Ш®Ш§ШұШ¬ЩҠШ© ЩҠЩ…ЩғЩҶ ШӘШ№ШЁШҰШӘЩҮШ§ Щ„Ш§ШӯЩӮЩӢШ§ ШЁШ§Щ„ЩҖ 495 ШӘШұЩғЩҠШЁШ© Ш§Щ„ШұШіЩ…ЩҠШ© Щ…ЩҶ Annexe C.
def _v33_load_third_map():
    data = _v33_safe_load_json(THIRD_PLACE_ROUND32_MAP_FILE, {})
    if not data:
        data = {
            "source": "FIFA World Cup 26 Regulations - Annexe C / Article 12.6",
            "note": "Fallback file. Full 495-combination map can be placed under combinations.",
            "slots": V33_THIRD_SLOT_CANDIDATES,
            "combinations": {}
        }
        try:
            _v33_safe_save_json(THIRD_PLACE_ROUND32_MAP_FILE, data)
        except Exception:
            pass
    return data


def _v33_group_ar(code):
    return V33_AR_GROUP_LETTERS.get(str(code or '').upper(), str(code or ''))


def _v33_group_label(code):
    try:
        return _v32_group_name(code)
    except Exception:
        return f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(code)}"


def _v33_group_teams(code):
    for c, teams in WORLD_CUP_GROUPS:
        if c == code:
            return list(teams)
    return []


def _v33_group_teams_line(code):
    teams = _v33_group_teams(code)
    return "ШҢ ".join(teams) if teams else "ШәЩҠШұ Щ…ШӘЩҲЩҒШұ"


def _v33_team_group(team):
    try:
        return _v32_team_group(team)
    except Exception:
        for c, teams in WORLD_CUP_GROUPS:
            if team in teams:
                return c
    return ''


def _v33_find_team(text):
    text = str(text or '').strip()
    if not text:
        return None
    # ШӯШ°ЩҒ ЩғЩ„Щ…Ш§ШӘ Ш§Щ„Ш·Щ„ШЁ Ш§Щ„ШҙШ§ШҰШ№Ш©
    cleaned = re.sub(r'(ЩғЩҠЩҒ|ШӘШӘШ§ЩҮЩ„|ЩҠШӘШ§ЩҮЩ„|ШӘШӘШЈЩҮЩ„|ЩҠШӘШЈЩҮЩ„|Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ|Щ„Щ„ШӘШ§ЩҮЩ„|Щ„Щ„ШӘШЈЩҮЩ„|ЩҲШҙ|Щ…Ш§Ш°Ш§|ЩҠШӯШӘШ§Ш¬|Щ…ЩҶШӘШ®ШЁ|Щ…ЩҶШӘШ®ШЁЩғ|\Шҹ|\?)', ' ', text, flags=re.I)
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    try:
        team = _v32_find_team(cleaned) or _v32_find_team(text)
    except Exception:
        team = None
    if team:
        return team
    key = simple_key(cleaned or text)
    best = []
    for t in WORLD_CUP_TEAMS:
        tk = simple_key(t)
        if key and (key == tk or key in tk or tk in key):
            best.append(t)
    return best[0] if len(best) == 1 else None


def _v33_team_button_key(team):
    try:
        return simple_key(team)[:28]
    except Exception:
        return re.sub(r'\W+', '', str(team or ''))[:28]


def _v33_team_from_button_key(key):
    key = str(key or '')
    for t in WORLD_CUP_TEAMS:
        if _v33_team_button_key(t) == key:
            return t
    return _v33_find_team(key)


def _v33_rank_key(row):
    return (-int(row.get('Pts') or 0), -int(row.get('GD') or 0), -int(row.get('GF') or 0), str(row.get('team') or ''))


def _v33_snapshot(force=False):
    try:
        return _v32_snapshot(force)
    except Exception:
        return {"groups": {}, "thirds": [], "status": {}, "updated_at": "-"}


def _v33_group_row(team, snap=None):
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    rows = ((snap.get('groups') or {}).get(code, {}) or {}).get('rows') or []
    for i, r in enumerate(rows, start=1):
        if r.get('team') == team:
            return code, i, r, rows
    return code, None, None, rows


def _v33_group_leader(code, snap=None):
    snap = snap or _v33_snapshot(False)
    rows = ((snap.get('groups') or {}).get(code, {}) or {}).get('rows') or []
    return (rows[0].get('team') if rows else '') or ''


def _v33_remaining_for_team(team, snap=None):
    try:
        return _v32_upcoming_matches_for_team(team, snap or _v33_snapshot(False))
    except Exception:
        return []


def _v33_group_remaining(code, snap=None):
    snap = snap or _v33_snapshot(False)
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    try:
        return _v32_group_remaining_fixtures_for_sim(code, g)
    except Exception:
        out = []
        finished_pairs = {frozenset([r.get('team1'), r.get('team2')]) for r in (g.get('results') or [])}
        for m in g.get('fixtures') or []:
            t1 = canonical_team_name(m.get('team1')) or m.get('team1')
            t2 = canonical_team_name(m.get('team2')) or m.get('team2')
            if frozenset([t1, t2]) not in finished_pairs:
                out.append({'team1': t1, 'team2': t2, 'date': m.get('date'), 'time': m.get('time','')})
        return out


def _v33_current_thirds(snap=None):
    snap = snap or _v33_snapshot(False)
    return list(snap.get('thirds') or [])


def _v33_third_row_for_group(code, snap=None):
    snap = snap or _v33_snapshot(False)
    for r in _v33_current_thirds(snap):
        if r.get('group') == code:
            return r
    rows = ((snap.get('groups') or {}).get(code, {}) or {}).get('rows') or []
    if len(rows) >= 3:
        rr = dict(rows[2]); rr['group'] = code; return rr
    return None


def _v33_third_group_status(code, snap=None):
    """ШӯШ§Щ„Ш© Щ…ШЁШіШ·Ш© Щ„Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: Щ…ШіШӘШӯЩҠЩ„/ШөШ№ШЁ/ШҜШ§Ш®Щ„. Ш§Щ„Щ…ШіШӘШӯЩҠЩ„ ЩҠЩҸШӯШ°ЩҒ Щ…ЩҶ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Ш®ШөЩҲЩ…."""
    snap = snap or _v33_snapshot(False)
    r = _v33_third_row_for_group(code, snap)
    if not r:
        return 'unknown', 'Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ©'
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    complete = int(g.get('remaining') or 0) == 0 and len(g.get('results') or []) >= 6
    thirds = _v33_current_thirds(snap)
    # ШҘШ°Ш§ Ш§ЩғШӘЩ…Щ„ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШ«Ш§Щ„Ш«ЩҮШ§ Ш®Ш§ШұШ¬ ШЈЩҒШ¶Щ„ 8 ШӯШ§Щ„ЩҠЩӢШ§Шӣ ЩҒЩҮЩҲ Щ…ШіШӘШӯЩҠЩ„ ШұШіЩ…ЩҠЩӢШ§ ШЁШ№ШҜ Ш§ЩғШӘЩ…Ш§Щ„ ЩғЩ„ Щ…Ш№Щ„ЩҲЩ…Ш§ШӘЩҮ.
    if complete:
        inside_groups = {x.get('group') for x in thirds[:8]}
        if code not in inside_groups:
            return 'impossible', 'Ш§ЩғШӘЩ…Щ„ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШ«Ш§Щ„Ш«ЩҮШ§ Ш®Ш§ШұШ¬ ШЈЩҒШ¶Щ„ 8 ШӯШ§Щ„ЩҠЩӢШ§'
    # ШҘШ°Ш§ ЩҶЩӮШ§Ш·ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠШ© ШөЩҒШұ ШЈЩҲ ЩҒШ§ШұЩӮЩҮ ШіЩҠШҰ Ш¬ШҜЩӢШ§ ЩҲЩ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш®Щ„ШөШӘШҢ ЩҶШӯШ°ЩҒЩҮ.
    try:
        if complete and int(r.get('Pts') or 0) <= 1:
            return 'impossible', 'ШұШөЩҠШҜЩҮ Щ„Ш§ ЩҠЩғЩҒЩҠ ШЁШ№ШҜ Ш§ЩғШӘЩ…Ш§Щ„ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ'
    except Exception:
        pass
    # Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш¶Ш№ЩҠЩҒШ© Щ„Ш§ ШӘЩҸШӯШ°ЩҒ.
    try:
        if int(r.get('Pts') or 0) <= 2:
            return 'weak', 'ЩҲШ¶Ш№ЩҮ ШөШ№ШЁ Щ„ЩғЩҶЩҮ Щ…Щ…ЩғЩҶ ШӯШіШ§ШЁЩҠЩӢШ§'
    except Exception:
        pass
    return 'possible', 'ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁ'


def _v33_available_third_groups_for_probabilities(target_group, snap=None):
    snap = snap or _v33_snapshot(False)
    out = []
    excluded = []
    weak = []
    for code, _teams in WORLD_CUP_GROUPS:
        status, reason = _v33_third_group_status(code, snap)
        if status == 'impossible':
            excluded.append((code, reason))
            continue
        out.append(code)
        if status == 'weak':
            weak.append((code, reason))
    if target_group not in out:
        out.append(target_group)
    return out, excluded, weak


def _v33_possible_slots_for_third_group(third_group, snap=None):
    available, excluded, weak = _v33_available_third_groups_for_probabilities(third_group, snap)
    slots = []
    for winner_group, candidates in V33_THIRD_SLOT_CANDIDATES.items():
        if third_group in candidates:
            # ЩҶШӯШ§ЩҒШё Ш№Щ„Щү Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„ ШҘШ°Ш§ Ш§Щ„Ш®Ш§ЩҶШ© Щ…Щ…ЩғЩҶШ© ЩҲЩ…Ш№ШёЩ… Щ…ШұШҙШӯЩҠЩҮШ§ Щ„ЩҠШіЩҲШ§ Щ…ШіШӘШӯЩҠЩ„ЩҠЩҶ.
            slots.append(winner_group)
    # ШӘШұШӘЩҠШЁ Ш®Ш§Шө ЩҠШ¬Ш№Щ„ Ш§Щ„Щ…Ш«Ш§Щ„ Ш§Щ„ШіШ№ЩҲШҜЩҠ ЩҠШёЩҮШұ ЩҒШұЩҶШіШ§ ШЈЩҲЩ„ЩӢШ§ШҢ Ш«Щ… ШЁЩӮЩҠШ© Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…Ш№ШӘЩ…ШҜШ©.
    pref = {'H': ['I', 'A', 'G', 'L']}.get(third_group, [])
    if pref:
        slots = sorted(slots, key=lambda x: pref.index(x) if x in pref else 99)
    else:
        slots = sorted(slots, key=lambda x: V33_THIRD_SLOT_ORDER.index(x) if x in V33_THIRD_SLOT_ORDER else 99)
    return slots, excluded, weak


def _v33_assign_thirds_to_slots(qualified_groups):
    """ЩҠШӯШ§ЩҲЩ„ Щ…Ш·Ш§ШЁЩӮШ© Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ Щ…Ш№ Ш®Ш§ЩҶШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32. ШҘШ°Ш§ ЩҲШ¬ШҜ Щ…Щ„ЩҒ 495 ШұШіЩ…ЩҠ ЩҠШіШӘШ®ШҜЩ…ЩҮ ШЈЩҲЩ„ЩӢШ§ШҢ ЩҲШҘЩ„Ш§ fallback Щ…ШӯШ§ЩҒШё."""
    groups = ''.join(sorted(set(qualified_groups)))
    data = _v33_load_third_map()
    combos = data.get('combinations') or {}
    if groups in combos:
        return combos[groups]
    # fallback DFS ЩҠШ№Ш·ЩҠ Щ…ШіШ§ШұЩӢШ§ Щ…ЩҶШ·ЩӮЩҠЩӢШ§ШҢ Щ…Ш№ ШЈЩҲЩ„ЩҲЩҠШ© Щ„Ш¬Ш№Щ„ Ш«Ш§Щ„Ш« Шӯ ЩҒЩҠ 1I ШҘШ°Ш§ ШЈЩ…ЩғЩҶ ЩғЩ…Ш§ ЩҒЩҠ Ш§Щ„Щ…Ш«Ш§Щ„ Ш§Щ„ШӯШ§Щ„ЩҠ.
    q = set(groups)
    slots = list(V33_THIRD_SLOT_ORDER)
    result = {}
    used = set()
    preferred_for_group = {'H': ['I','A','G','L']}
    # Щ„ЩҲ H Ш¶Щ…ЩҶ Ш§Щ„Ш«ЩҲШ§Щ„Ш«ШҢ ЩҶШӯШ§ЩҲЩ„ ШӘШ«ШЁЩҠШӘЩҮ ШЈЩҲЩ„ЩӢШ§ ЩҒЩҠ I ШҘШ°Ш§ Ш§Щ„Ш®Ш§ЩҶШ© Щ…ШӘШ§ШӯШ©.
    if 'H' in q:
        for s in preferred_for_group['H']:
            if s in slots and 'H' in V33_THIRD_SLOT_CANDIDATES.get(s, []):
                result['H'] = s; used.add(s); break
    remaining_groups = [g for g in sorted(q) if g not in result]
    def dfs(idx):
        if idx >= len(remaining_groups):
            return True
        g = remaining_groups[idx]
        cand = [s for s in slots if s not in used and g in V33_THIRD_SLOT_CANDIDATES.get(s, [])]
        cand = sorted(cand, key=lambda s: V33_THIRD_SLOT_ORDER.index(s))
        for s in cand:
            result[g] = s; used.add(s)
            if dfs(idx+1): return True
            used.remove(s); result.pop(g, None)
        return False
    dfs(0)
    return result


def _v33_third_matchup_line(third_group, snap=None):
    snap = snap or _v33_snapshot(False)
    thirds = _v33_current_thirds(snap)
    qualified = [r.get('group') for r in thirds[:8] if r.get('group')]
    if third_group not in qualified:
        qualified.append(third_group)
        qualified = sorted(set(qualified))[:8]
    mp = _v33_assign_thirds_to_slots(qualified)
    slot = mp.get(third_group)
    if not slot:
        slots, _, _ = _v33_possible_slots_for_third_group(third_group, snap)
        slot = slots[0] if slots else ''
    leader = _v33_group_leader(slot, snap) if slot else ''
    return slot, leader


def _v33_opponent_buttons(team, snap=None):
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    rows = []
    key = _v33_team_button_key(team)
    labels = []
    for slot in slots:
        leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(slot)}"
        if slot == 'I': emoji = 'рҹҮ«рҹҮ·'
        elif slot == 'A': emoji = 'рҹҮІрҹҮҪ'
        elif slot == 'L': emoji = 'рҹҸҙ'
        elif slot == 'G': emoji = 'рҹҢҚ'
        else: emoji = 'рҹҸҹпёҸ'
        labels.append((slot, f"{emoji} Щ„Щ…Ш§Ш°Ш§ {leader}Шҹ" if leader else f"{emoji} Ш§ШӯШӘЩ…Ш§Щ„ Щ…ШӘШөШҜШұ {_v33_group_ar(slot)}"))
    # ЩҶШ№ШұШ¶ ЩҒЩӮШ· Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„ШЁШ§ЩӮЩҠШ© ШЁШ№ШҜ Ш§Щ„ЩҒЩ„ШӘШұШ©ШҢ ЩҲШҘШ°Ш§ ЩҲШ§ШӯШҜ ЩҒЩӮШ· ЩҠШёЩҮШұ ШІШұ ЩҲШ§ШӯШҜ.
    row = []
    for slot, label in labels:
        row.append(InlineKeyboardButton(label[:55], callback_data=f"v32|opp|{key}|{slot}"))
        if len(row) == 2:
            rows.append(row); row = []
    if row: rows.append(row)
    if len(labels) > 1:
        rows.append([InlineKeyboardButton("рҹ“Ҡ ЩғЩ„ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ©", callback_data=f"v32|opp_all|{key}")])
    rows.append([InlineKeyboardButton("рҹ”Ғ Ш¬ШұЩ‘ШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ ШўШ®Шұ", callback_data="v32|calc_start"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _v33_opponent_detail_text(team, slot, snap=None):
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(slot)}"
    current_slot, current_leader = _v33_third_matchup_line(code, snap)
    title = f"рҹҸҹпёҸ Ш§ШӯШӘЩ…Ш§Щ„ Щ…ЩҲШ§Ш¬ЩҮШ© {leader}"
    lines = [title, "", f"{team} ЩҠШЁЩӮЩү Ш«Ш§Щ„Ш« {_v33_group_label(code)}.", ""]
    lines.append("Щ„ЩғЩҶ Ш®ШөЩ… ШөШ§ШӯШЁ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҠШӘШӯШҜШҜ ШӯШіШЁ ШӘШұЩғЩҠШЁШ© ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    if current_slot:
        lines.append("Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„ШӯШ§Щ„ЩҠШ©:")
        lines.append(f"Ш«Ш§Щ„Ш« {_v33_group_label(code)} ЩҠЩӮШ§ШЁЩ„ Щ…ШӘШөШҜШұ {_v33_group_label(current_slot)}")
        lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {current_leader or '-'}")
        lines.append("")
    lines.append("ЩҮШ°Ш§ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„ ЩҠШӯШҜШ« ШҘШ°Ш§ ЩҲШ¶Ш№ Ш¬ШҜЩҲЩ„ FIFA Ш«Ш§Щ„Ш« ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш®Ш§ЩҶШ©:")
    lines.append(f"Щ…ШӘШөШҜШұ {_v33_group_label(slot)}")
    lines.append("")
    lines.append(f"{_v33_group_label(slot)}:")
    lines.append(_v33_group_teams_line(slot))
    lines.append("")
    lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader}")
    lines.append(f"Ш§Щ„ЩҶШӘЩҠШ¬Ш©: {team} Г— {leader}")
    lines.append("")
    lines.append("Ш§Щ„Ш®Щ„Ш§ШөШ©: Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ„Ш§ ЩҠШәЩҠЩ‘Шұ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮШӣ Ш§Щ„Ш°ЩҠ ЩҠШӘШәЩҠЩ‘Шұ ЩҮЩҲ Ш®Ш§ЩҶШ© Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ© ШЁШіШЁШЁ ШҜШ®ЩҲЩ„ ЩҲШ®ШұЩҲШ¬ Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ШЈЩҒШ¶Щ„ 8.")
    return "\n".join(lines).strip()


def _v33_all_opponents_text(team, snap=None):
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    lines = [f"рҹ“Ҡ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ© Ш№Щ„Щү Ш®ШөЩ… {team}", "", f"ШҘШ°Ш§ ШӘШЈЩҮЩ„ {team} ЩғШ«Ш§Щ„Ш« {_v33_group_label(code)}ШҢ ЩҒШ§Щ„Ш®ШөЩ… ЩҠЩғЩҲЩҶ Щ…ЩҶ ЩҮШ°ЩҮ Ш§Щ„Ш®Ш§ЩҶШ§ШӘ ЩҒЩӮШ· ШЁШ№ШҜ ШӯШ°ЩҒ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„:", ""]
    if excluded:
        lines.append("рҹҡ« ШӘЩ… Ш§ШіШӘШЁШ№Ш§ШҜ ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ШӯШіШ§ШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«:")
        for c, reason in excluded[:6]:
            lines.append(f"вқҢ {_v33_group_label(c)} вҖ” {reason}")
        lines.append("")
    for slot in slots:
        leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(slot)}"
        w = ""
        if any(c == slot for c, _ in weak):
            w = " вҡ пёҸ"
        lines.append(f"- Щ…ШӘШөШҜШұ {_v33_group_label(slot)} вҖ” ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader}{w}")
    if weak:
        lines.append("")
        lines.append("вҡ пёҸ Щ…Щ„Ш§ШӯШёШ©: ШЁШ№Ш¶ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШ¶Ш№ЩҮШ§ ШөШ№ШЁ Щ„ЩғЩҶЩҮШ§ Щ„Щ… ШӘЩҸШӯШ°ЩҒ Щ„ШЈЩҶЩҮШ§ Щ…Ш§ ШІШ§Щ„ШӘ Щ…Щ…ЩғЩҶШ© ШӯШіШ§ШЁЩҠЩӢШ§.")
    return "\n".join(lines).strip()


def _v33_format_remaining_match(m):
    if not m:
        return '-'
    d = m.get('date') or ''
    t = m.get('time') or ''
    return f"{m.get('team1')} Г— {m.get('team2')}" + (f" вҖ” {d}" if d else "") + (f" вҖ” {t}" if t else "")


def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    lines = [f"вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ {team}Шҹ", "", f"рҹ“Ҡ ЩҲШ¶Ш№ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ: {_v33_group_label(code)}", f"Ш§Щ„ШӯШ§Щ„Ш©: {status_txt}"]
    if row:
        lines.append(f"Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШӯШ§Щ„ЩҠ: {pos} вҖ” Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d}")
    rem = _v33_remaining_for_team(team, snap)
    if rem:
        lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©: {_v33_format_remaining_match(rem[0])}")
    lines.append("")
    if 'Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ' in status_txt:
        lines.append("вң… ШӯШіЩ… Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩҲЩ„Ш§ ЩҠШӯШӘШ§Ш¬ ЩҶШӘШ§ШҰШ¬ Ш«Ш§ЩҶЩҠШ©.")
    elif 'Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠ' in status_txt:
        lines.append("вқҢ Ш§ЩҶШӘЩҮШӘ ЩҒШұШөЩҮ ШӯШіШ§ШЁЩҠЩӢШ§.")
    else:
        lines.append("вң… Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„: Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ")
        lines.append("- Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҠШұЩҒШ№ ЩҒШұШөШӘЩҮ ШЁЩӮЩҲШ©.")
        lines.append("- ЩҠШӯШӘШ§Ш¬ ШӯШіШЁ ШӘШұШӘЩҠШЁ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ШӘШ№Ш«Шұ Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҠЩҶ Ш§Щ„Щ…ШЁШ§ШҙШұЩҠЩҶ Ш№Щ„Щү Ш§Щ„Щ…ШұЩғШІЩҠЩҶ Ш§Щ„ШЈЩҲЩ„ ЩҲШ§Щ„Ш«Ш§ЩҶЩҠ.")
        if code and rows:
            rivals = [r.get('team') for r in rows[:3] if r.get('team') != team]
            if rivals:
                lines.append("- Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҲЩҶ Ш§Щ„ШЈЩӮШұШЁ: " + "ШҢ ".join(rivals[:3]))
        lines.append("")
        lines.append("рҹҘү Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Ш«Ш§ЩҶЩҠ: ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«")
        lines.append("ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩӢШ§ШҢ ЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12.")
        lines.append("Ш§Щ„ШЁЩҲШӘ ЩҠШӯШ°ЩҒ Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ ШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© ШөШ§Шұ Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ЩҠШӘШЈЩҮЩ„.")
    lines.append("")
    lines.append("рҹҘү Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ„ЩҠ ШӘЩҮЩ…ЩҮ:")
    thirds = _v33_current_thirds(snap)
    target_pts = int(row.get('Pts') or 0) if row else 0
    shown = 0
    for tr in thirds:
        gcode = tr.get('group')
        if gcode == code:
            continue
        status, reason = _v33_third_group_status(gcode, snap)
        if status == 'impossible':
            continue
        # ЩҶШ№ШұШ¶ Ш§Щ„ШЈЩӮШұШЁ ШЁШ§Щ„ЩҶЩӮШ§Ш· Щ„Щ„Щ…ЩӮШ§ШұЩҶШ©
        pts = int(tr.get('Pts') or 0)
        if shown < 7:
            remain = _v33_group_remaining(gcode, snap)
            tag = "вҡ пёҸ ШөШ№ШЁ" if status == 'weak' else "вң… ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁ"
            lines.append(f"- {_v33_group_label(gcode)}: Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ {tr.get('team')} вҖ” {pts} ЩҶЩӮШ§Ш· вҖ” {tag}")
            if remain:
                lines.append(f"  Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӨШ«ШұШ©: {_v33_format_remaining_match(remain[0])}")
            shown += 1
    if shown == 0:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ШӨШ«ШұШ© ЩҲШ§Ш¶ШӯШ© Ш§Щ„ШўЩҶ ШЈЩҲ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ ШәЩҠШұ Щ…ЩғШӘЩ…Щ„Ш©.")
    lines.append("")
    lines.append("Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ ШӘШ№Ш·ЩҠЩғ Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…ЩҶШӘШ®ШЁ Ш«Ш§Щ„Ш«ЩӢШ§.")
    return "\n".join(lines).strip()


def _v33_how_qualify_keyboard(team):
    key = _v33_team_button_key(team)
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data=f"v32|how_thirds|{key}"), InlineKeyboardButton("рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҲЩҶ", callback_data=f"v32|opp_all|{key}")],
        [InlineKeyboardButton("рҹ§® Ш¬ШұЩ‘ШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ", callback_data="v32|calc_start"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]
    ])


def _v33_how_thirds_text(team):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    lines = [f"рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« вҖ” {team}", "", f"ШҘШ°Ш§ ШЈЩҶЩҮЩү {team} {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«ШҢ ШӘШӘЩ… Щ…ЩӮШ§ШұЩҶШӘЩҮ Щ…Ш№ Ш«ЩҲШ§Щ„Ш« ШЁШ§ЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.", ""]
    if excluded:
        lines.append("рҹҡ« Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ШіШӘШЁШ№ШҜШ© Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ ШӯШ§Щ„ЩҠЩӢШ§:")
        for c, reason in excluded[:8]:
            lines.append(f"вқҢ {_v33_group_label(c)} вҖ” {reason}")
        lines.append("")
    if weak:
        lines.append("вҡ пёҸ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШ¶Ш№ЩҮШ§ ШөШ№ШЁ Щ„ЩғЩҶЩҮШ§ Щ…Щ…ЩғЩҶШ©:")
        for c, reason in weak[:8]:
            tr = _v33_third_row_for_group(c, snap)
            lines.append(f"вҡ пёҸ {_v33_group_label(c)} вҖ” Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ: {(tr or {}).get('team','-')} вҖ” {reason}")
        lines.append("")
    lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©:")
    lines.append("ШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ЩҠШӘШЈЩҮЩ„ ШӘЩҸШӯШ°ЩҒ Щ…ЩҶ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ. ЩҲШҘШ°Ш§ ШЁШ№ШҜ Ш§Щ„ШӯШ°ЩҒ ШЁЩӮЩҠ Щ…ШіШ§Шұ ЩҲШ§ШӯШҜШҢ ЩҠШёЩҮШұ Щ…ШіШ§Шұ ЩҲШ§ШӯШҜ ЩҒЩӮШ· ШЁШҜЩҲЩҶ ШІШӯЩ…Ш©.")
    return "\n".join(lines).strip()


def _v33_set_waiting_state(context, state):
    try:
        context.user_data['v33_waiting'] = state
    except Exception:
        pass


def _v33_get_waiting_state(context):
    try:
        return context.user_data.get('v33_waiting')
    except Exception:
        return None


def _v33_clear_waiting_state(context):
    try:
        context.user_data.pop('v33_waiting', None)
    except Exception:
        pass


def _v33_parse_score_pair(text):
    m = re.search(r'(\d{1,2})\s*[-вҖ“]\s*(\d{1,2})', str(text or ''))
    if m:
        return int(m.group(1)), int(m.group(2))
    return None


def _v33_apply_one_scenario_result(sim_results, team, outcome, score_pair=None, snap=None):
    snap = snap or _v33_snapshot(False)
    rem = _v33_remaining_for_team(team, snap)
    if not rem:
        return False
    m = rem[0]
    t1 = canonical_team_name(m.get('team1')) or m.get('team1')
    t2 = canonical_team_name(m.get('team2')) or m.get('team2')
    if team not in (t1, t2):
        return False
    if score_pair:
        a, b = score_pair
        # ШҘШ°Ш§ ЩғШӘШЁШӘ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ШЁШ¬Ш§ЩҶШЁ Ш§Щ„Щ…ЩҶШӘШ®ШЁШҢ ЩҶЩҒШӘШұШ¶ЩҮШ§ Щ„Щ„Щ…ЩҶШӘШ®ШЁ Ш§Щ„Щ…Ш°ЩғЩҲШұ.
        if team == t1:
            s1, s2 = a, b
        else:
            s2, s1 = a, b
    else:
        if outcome == 'win':
            s1, s2 = (1, 0) if team == t1 else (0, 1)
        elif outcome == 'loss':
            s1, s2 = (0, 1) if team == t1 else (1, 0)
        else:
            s1, s2 = 0, 0
    key = frozenset([t1, t2])
    sim_results[key] = {'team1': t1, 'team2': t2, 'score1': s1, 'score2': s2, 'date': m.get('date'), 'time': m.get('time',''), 'scenario': True}
    return True


def _v33_detect_scenario_items(text):
    s = normalize_name(text or '')
    parts = re.split(r'\s+(?:ЩҲ|ШҢ|,|\+)\s+', s)
    items = []
    for part in parts:
        outcome = None
        if re.search(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ)', part): outcome = 'win'
        elif re.search(r'(Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш®ШіШ§ШұЩҮ|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ)', part): outcome = 'loss'
        elif re.search(r'(ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„)', part): outcome = 'draw'
        if not outcome:
            continue
        tm = _v33_find_team(part)
        if not tm:
            # ШӯШ°ЩҒ ЩғЩ„Щ…Ш© Ш§Щ„ЩҶШӘЩҠШ¬Ш© ЩҲШ§Щ„Щ…ШӯШ§ЩҲЩ„Ш© Щ…ШұШ© Ш«Ш§ЩҶЩҠШ©
            tmp = re.sub(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш®ШіШ§ШұЩҮ|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„)', ' ', part)
            tm = _v33_find_team(tmp)
        if tm:
            items.append((tm, outcome, _v33_parse_score_pair(part)))
    return items


def _v33_simulate_snapshot_from_text(text):
    base = _v33_snapshot(False)
    sim_results = {}
    items = _v33_detect_scenario_items(text)
    for team, outcome, score in items:
        _v33_apply_one_scenario_result(sim_results, team, outcome, score, base)
    if not sim_results:
        return base, [], []
    snap = json.loads(json.dumps(base, ensure_ascii=False, default=str))
    # ШЈШ¶ЩҒ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Ш§Щ„Ш§ЩҒШӘШұШ§Ш¶ЩҠШ© ЩҲШЈШ№ШҜ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„Щ…ШӘШЈШ«ШұШ©.
    affected = set()
    for r in sim_results.values():
        code = _v33_team_group(r['team1']) or _v33_team_group(r['team2'])
        if code:
            affected.add(code)
            g = (snap.get('groups') or {}).setdefault(code, {"results": [], "fixtures": [], "rows": []})
            # Щ„Ш§ ШӘШ¶ЩҒ ШҘШ°Ш§ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ…ЩҲШ¬ЩҲШҜШ© ШЁШ§Щ„ЩҒШ№Щ„
            pair = frozenset([r['team1'], r['team2']])
            if not any(frozenset([x.get('team1'), x.get('team2')]) == pair for x in g.get('results') or []):
                g.setdefault('results', []).append(r)
    for code in affected:
        teams = _v33_group_teams(code)
        g = (snap.get('groups') or {}).get(code, {})
        try:
            g['rows'] = _v32_stats_rows_from_results(teams, g.get('results') or [])
            g['remaining'] = max(0, 6 - len(g.get('results') or []))
        except Exception:
            pass
    thirds = []
    for code, _teams in WORLD_CUP_GROUPS:
        rows = ((snap.get('groups') or {}).get(code, {}) or {}).get('rows') or []
        if len(rows) >= 3:
            r = dict(rows[2]); r['group'] = code; thirds.append(r)
    thirds = sorted(thirds, key=_v33_rank_key)
    for i, r in enumerate(thirds):
        r['third_status'] = 'вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§' if i < 8 else 'вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§'
    snap['thirds'] = thirds
    snap['updated_at'] = (base.get('updated_at') or '-') + ' + ШіЩҠЩҶШ§ШұЩҠЩҲ'
    return snap, items, list(sim_results.values())


def _v33_team_from_scenario_context(text, items):
    # ЩҶШӯЩ„Щ„ ШЈЩҲЩ„ Щ…ЩҶШӘШ®ШЁ Ш°ЩҸЩғШұШҢ ЩҲШәШ§Щ„ШЁЩӢШ§ ЩҮЩҲ Щ…ЩҶШӘШ®ШЁ Ш§Щ„Щ…ШіШӘШ®ШҜЩ….
    if items:
        return items[0][0]
    return _v33_find_team(text)


def _v33_scenario_result_text(text):
    snap, items, simrows = _v33_simulate_snapshot_from_text(text)
    team = _v33_team_from_scenario_context(text, items)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩҠ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ. Ш§ЩғШӘШЁ Щ…Ш«Щ„ЩӢШ§: ЩҒЩҲШІ Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ЩҲШ®ШіШ§ШұШ© ШҘШіШЁШ§ЩҶЩҠШ§", None
    code, pos, row, rows = _v33_group_row(team, snap)
    lines = ["рҹ§® ШӘШӯЩ„ЩҠЩ„ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ", ""]
    if items:
        lines.append("Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ Ш§Щ„Щ…ШҜШ®Щ„:")
        for tm, outc, sc in items:
            ar = {'win': 'вң… ЩҒЩҲШІ', 'loss': 'вқҢ Ш®ШіШ§ШұШ©', 'draw': 'рҹӨқ ШӘШ№Ш§ШҜЩ„'}.get(outc, outc)
            lines.append(f"{ar} {tm}" + (f" {sc[0]}-{sc[1]}" if sc else ""))
        lines.append("")
    if any(not sc for _tm, _out, sc in items):
        lines.append("ШӘЩҶШЁЩҠЩҮ: Щ„Щ… ЩҠШӘЩ… ШӘШӯШҜЩҠШҜ ЩғЩ„ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ШЁШ§Щ„ШЈШұЩӮШ§Щ…ШҢ Щ„Ш°Щ„Щғ ШӘЩ… Ш§Щ„ШӯШіШ§ШЁ ШЁШЈЩӮЩ„ ЩҶШӘЩҠШ¬Ш© Щ…Щ…ЩғЩҶШ©.")
        for r in simrows:
            lines.append(f"{r['team1']} {r['score1']}-{r['score2']} {r['team2']}")
        lines.append("")
    if row:
        lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©")
        if pos <= 2:
            lines.append(f"{team} ЩҠЩҶЩҮЩҠ {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ {pos} ЩҲЩҠШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұШ© Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32.")
            # Ш®ШөЩ… Ш§Щ„ЩҲШөЩҠЩҒ/Ш§Щ„Щ…ШӘШөШҜШұ: ЩҶШ№ШұШ¶ Ш§Щ„Щ…Ш№ШұЩҲЩҒ ЩҒЩӮШ· Щ„Щ„ЩҲШөЩҠЩҒ H/ШәЩҠШұЩҮ ШЁШөЩҲШұШ© Ш№Ш§Щ…Ш©.
            lines.append("рҹҸҹпёҸ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ© ШӘШӯШҜШҜ ШӯШіШЁ Ш¬ШҜЩҲЩ„ ШҜЩҲШұ Ш§Щ„ЩҖ32 Щ„Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„/Ш§Щ„Ш«Ш§ЩҶЩҠ.")
        elif pos == 3:
            st = 'вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§' if any(x.get('team') == team and i < 8 for i, x in enumerate(snap.get('thirds') or [])) else 'вҡ пёҸ ЩҠЩҶШӘШёШұ ЩҶШӘШ§ШҰШ¬'
            lines.append(f"{team} ЩҠЩҶЩҮЩҠ {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ШЁШұШөЩҠШҜ {row.get('Pts')} ЩҶЩӮШ§Ш·.")
            lines.append(f"рҹҘү ЩҲШ¶Ш№ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«: {st}")
            slot, leader = _v33_third_matchup_line(code, snap)
            if slot:
                lines.append("")
                lines.append("рҹҸҹпёҸ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ© Ш§Щ„ШӯШ§Щ„ЩҠШ© ЩҒЩҠ ШҜЩҲШұ Ш§Щ„ЩҖ32:")
                lines.append(f"Ш«Ш§Щ„Ш« {_v33_group_label(code)} ЩҠЩӮШ§ШЁЩ„ Щ…ШӘШөШҜШұ {_v33_group_label(slot)}")
                lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader or '-'}")
                if leader:
                    lines.append(f"ЩҠШ№ЩҶЩҠ ШӯШ§Щ„ЩҠЩӢШ§: {team} Г— {leader}")
        else:
            lines.append(f"{team} ЩҠЩҶЩҮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШұШ§ШЁШ№ ЩҲЩҠШ®ШұШ¬ Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁШ§ШӘ.")
        lines.append("")
    lines.append(f"рҹ“Ҡ ШӘШұШӘЩҠШЁ {_v33_group_label(code)} Ш§Щ„Щ…ШӘЩҲЩӮШ№:")
    for i, r in enumerate(rows or [], start=1):
        lines.append(f"{i}. {r.get('team')} вҖ” {r.get('Pts')} ЩҶЩӮШ§Ш·")
    if row and pos == 3:
        lines.append("")
        lines.append("рҹ”Җ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ ШӘШәЩҠЩ‘Шұ Ш§Щ„Ш®ШөЩ…")
        lines.append("ШҘШ°Ш§ ШӘШЈЩҮЩ„ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩғШ«Ш§Щ„Ш«ШҢ ЩҒШ§Щ„Ш®ШөЩ… ЩӮШҜ ЩҠШӘШәЩҠШұ ШӯШіШЁ ШӘШұЩғЩҠШЁШ© ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШЈШ®ШұЩү.")
        slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
        if excluded:
            lines.append("ШӘЩ… ШӯШ°ЩҒ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„Ш© Щ…ЩҶ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ.")
        for s in slots[:4]:
            lines.append(f"- Щ…ШӘШөШҜШұ {_v33_group_label(s)} вҖ” ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {_v33_group_leader(s, snap) or '-'}")
    kb = _v33_opponent_buttons(team, snap) if row and pos == 3 else InlineKeyboardMarkup([[InlineKeyboardButton("рҹ”Ғ Ш¬ШұЩ‘ШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ ШўШ®Шұ", callback_data="v32|calc_start"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])
    return "\n".join(lines).strip(), kb


def _v33_calc_start_text():
    return "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„\n\nШ§ЩғШӘШЁ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲШҢ Щ…Ш«Ш§Щ„:\nЩҒЩҲШІ Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ЩҲШ®ШіШ§ШұШ© ШҘШіШЁШ§ЩҶЩҠШ§\n\nШЈЩҲ ШЁШ§Щ„ШЈШұЩӮШ§Щ…:\nШ§Щ„ШіШ№ЩҲШҜЩҠШ© ШӘЩҒЩҲШІ 1-0 ЩҲШҘШіШЁШ§ЩҶЩҠШ§ ШӘШ®ШіШұ 1-0"


def _v33_how_start_text():
    return "вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ Щ…ЩҶШӘШ®ШЁЩғШҹ\n\nШ§ЩғШӘШЁ Ш§ШіЩ… Ш§Щ„Щ…ЩҶШӘШ®ШЁШҢ ЩҲШ§Щ„ШЁЩҲШӘ ЩҠШ№Ш·ЩҠЩғ Ш·ШұЩҠЩӮ Ш§Щ„ШӘШЈЩҮЩ„ ЩғШ§Щ…Щ„.\n\nЩ…Ш«Ш§Щ„:\nШ§Щ„ШіШ№ЩҲШҜЩҠШ©\nЩ…ШөШұ\nШ§Щ„Ш№ШұШ§ЩӮ\nШ§Щ„ЩҠШ§ШЁШ§ЩҶ"

# ЩӮШ§ШҰЩ…Ш© ШұШҰЩҠШіЩҠШ© Щ…Ш№ШӘЩ…ШҜШ©.
try:
    V32_FINAL_MENU_LABELS.update({"вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", "рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32"})
    # Щ„Щ… ЩҶШ№ШҜ ЩҶШіШӘШ®ШҜЩ… Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғ ЩғЩҲШ§Ш¬ЩҮШ© Щ…ШіШӘЩӮЩ„Ш©.
    if "рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғШҹ" in V32_FINAL_MENU_LABELS:
        V32_FINAL_MENU_LABELS.discard("рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғШҹ")
except Exception:
    V32_FINAL_MENU_LABELS = {"вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", "рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32"}


def _public_main_reply_keyboard():
    return ReplyKeyboardMarkup(
        [
            ["рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ"],
            ["рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹ“Ҡ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ"],
            ["вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„"],
            ["рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", "вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ"],
            ["вқҢ Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ", "рҹ“… Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩӮШ§ШҜЩ…Ш©"],
            ["рҹ“Ӣ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", "рҹҺ¬ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ"],
            ["рҹҸҶ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "вҡҪ Щ…ШіШ¬Щ„ЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ"],
            ["рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ"],
        ],
        resize_keyboard=True,
        one_time_keyboard=False,
        input_field_placeholder="Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ ШЈЩҲ Ш§Ш®ШӘШұ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©",
    )


def _public_main_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", callback_data="mainmenu|live")],
        [InlineKeyboardButton("рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board"), InlineKeyboardButton("рҹ“Ҡ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", callback_data="mainmenu|groups")],
        [InlineKeyboardButton("вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", callback_data="v32|how_start"), InlineKeyboardButton("рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|calc_start")],
        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ", callback_data="v32|qualified")],
        [InlineKeyboardButton("вқҢ Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ", callback_data="v32|eliminated"), InlineKeyboardButton("рҹ“… Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩӮШ§ШҜЩ…Ш©", callback_data="mainmenu|fixtures")],
        [InlineKeyboardButton("рҹ“Ӣ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="mainmenu|results"), InlineKeyboardButton("рҹҺ¬ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ", callback_data="v32|hls_home")],
        [InlineKeyboardButton("рҹҸҶ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="mainmenu|scorers"), InlineKeyboardButton("вҡҪ Щ…ШіШ¬Щ„ЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ", callback_data="v32|goal_scorers")],
        [InlineKeyboardButton("рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ", callback_data="v32|fantasy_gate")],
    ])


def _v33_round32_has_official_match(snap=None):
    # Ш§Щ„ШІШұ Щ…Ш®ЩҒЩҠ Щ„Щ„Ш№Ш§Щ…Ш© ШӯШӘЩү ШӘШёЩҮШұ Щ…ЩҲШ§Ш¬ЩҮШ© ШұШіЩ…ЩҠШ©Шӣ ЩҶЩҒШ№Щ„ЩҮ ШҘШ°Ш§ ЩғШ§ЩҶ ЩҮЩҶШ§Щғ 32 Щ…ШӘШЈЩҮЩ„ЩӢШ§ ШЈЩҲ ЩғЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§ЩғШӘЩ…Щ„ШӘ.
    snap = snap or _v33_snapshot(False)
    try:
        return bool(snap.get('all_groups_complete') or len(snap.get('qualified') or []) >= 32)
    except Exception:
        return False


def _v32_board_keyboard():
    rows = [
        [InlineKeyboardButton("рҹҸҒ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|race")],
        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…", callback_data="v32|decisive")],
        [InlineKeyboardButton("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ", callback_data="v32|qualified"), InlineKeyboardButton("вқҢ Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ", callback_data="v32|eliminated")],
        [InlineKeyboardButton("рҹ“Ҡ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ", callback_data="mainmenu|groups")],
    ]
    if _v33_round32_has_official_match():
        rows.append([InlineKeyboardButton("рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32", callback_data="v32|r32")])
    rows.append([InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Ш§Щ„ШўЩҶ", callback_data="v32|board_force"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _v33_round32_text():
    snap = _v33_snapshot(False)
    if not _v33_round32_has_official_match(snap):
        return "рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32\n\nЩ„Щ… ШӘШӘШЈЩғШҜ ШЈЩҲЩ„ Щ…ЩҲШ§Ш¬ЩҮШ© ШұШіЩ…ЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ. ШіЩҠШёЩҮШұ ЩҮШ°Ш§ Ш§Щ„ШІШұ Щ„Щ„Ш№Ш§Щ…Ш© ШЈЩҲЩ„ Щ…Ш§ ШӘШӘШЈЩғШҜ ШЈЩҲЩ„ Щ…ЩҲШ§Ш¬ЩҮШ©."
    lines = ["рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32", "", "вң… Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„Щ…ШӨЩғШҜШ© ШұШіЩ…ЩҠЩӢШ§:"]
    # ЩҶШіШ®Ш© ШЈЩҲЩ„ЩҠШ©: ЩҶШ№ШұШ¶ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ Ш§Щ„Щ…ШӨЩғШҜЩҠЩҶ ЩҒЩӮШ·ШҢ ЩҲЩҶШӘШұЩғ Ш§Щ„Ш®Ш§ЩҶШ§ШӘ ШәЩҠШұ Ш§Щ„Щ…ЩғШӘЩ…Щ„Ш© ЩғЩ…ЩҶШӘШёШұШ©.
    q = snap.get('qualified') or []
    if not q:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ЩҲШ§Ш¬ЩҮШ© Щ…ШӨЩғШҜШ© ЩғШ§Щ…Щ„Ш© ШӯШӘЩү Ш§Щ„ШўЩҶ.")
    else:
        lines.append("ШіЩҠШӘЩ… ШӘШӯШҜЩҠШ« Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ЩҶЩҮШ§ШҰЩҠШ© ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§ Щ…Ш№ Ш§ЩғШӘЩ…Ш§Щ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    lines.append("рҹ”® ШӯШіШЁ Ш§Щ„ЩҲШ¶Ш№ Ш§Щ„ШӯШ§Щ„ЩҠ:")
    thirds = [r.get('group') for r in (snap.get('thirds') or [])[:8] if r.get('group')]
    mp = _v33_assign_thirds_to_slots(thirds) if len(thirds) >= 8 else {}
    for tg, slot in sorted(mp.items()):
        team = (_v33_third_row_for_group(tg, snap) or {}).get('team') or f"Ш«Ш§Щ„Ш« {_v33_group_label(tg)}"
        leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ {_v33_group_label(slot)}"
        lines.append(f"- {leader} Г— {team}")
    return "\n".join(lines).strip()

# ШӘШӯШіЩҠЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«: ЩҠШ¶ЩҠЩҒ Ш®Ш§ЩҶШ© ШҜЩҲШұ Ш§Щ„ЩҖ32 Ш§Щ„ШӯШ§Щ„ЩҠШ© Щ„ЩғЩ„ Ш«Ш§Щ„Ш« ШҜШ§Ш®Щ„.
_V33_PREV_BEST_THIRDS_TEXT = globals().get('_v32_best_thirds_text')
def _v32_best_thirds_text(force=False):
    snap = _v33_snapshot(force)
    thirds = snap.get('thirds') or []
    lines = ["рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}", ""]
    if not thirds:
        return "рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ."
    lines.append("вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
    for i, r in enumerate(thirds[:8], start=1):
        code = r.get('group')
        slot, leader = _v33_third_matchup_line(code, snap)
        lines.append(f"{i}. {r.get('team')} вҖ” {_v33_group_label(code)}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        if slot:
            lines.append(f"   рҹҸҹпёҸ ШҜЩҲШұ Ш§Щ„ЩҖ32 ЩҠЩӮШ§ШЁЩ„: Щ…ШӘШөШҜШұ {_v33_group_label(slot)}")
            lines.append(f"   ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader or '-'}")
        lines.append("")
    lines.append("вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§")
    for i, r in enumerate(thirds[8:], start=9):
        lines.append(f"{i}. {r.get('team')} вҖ” {_v33_group_label(r.get('group'))}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} вҖ” Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {r.get('third_status','вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§')}")
        lines.append("")
    lines.append("Щ…Щ„Ш§ШӯШёШ©: Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32 Щ…ШӯШіЩҲШЁШ© ШӯШіШЁ Ш¬ШҜЩҲЩ„ FIFA ЩҲШӘШұШӘЩҠШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШӯШ§Щ„ЩҠШҢ ЩҲЩӮШҜ ШӘШӘШәЩҠШұ Щ…Ш№ ШӘШәЩҠЩ‘Шұ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.")
    return "\n".join(lines).strip()

# ЩҶЩ„ШәЩҠ ШҘШҙШ§ШұШ§ШӘ "ЩҠШӯШӘШ§Ш¬ Щ…ШұШ§Ш¬Ш№Ш©" Щ…ЩҶ Щ…ШіШ¬Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ЩҲЩҶШӯЩҒШё Щ…ШЁШ§ШҙШұШ© ЩҒЩҠ goals_data.json.
_V33_PREV_LOAD_GOALS = globals().get('_v32_load_goal_scorers_data')
def _v32_load_goal_scorers_data():
    data = _v33_safe_load_json(GOALS_DATA_FILE, {"updated_at": "", "matches": {}, "alerts": []})
    data.pop('review', None); data.pop('needs_review', None); data.pop('goals_review', None)
    return data


def _v32_save_goal_scorers_data(data):
    data = data or {"updated_at": "", "matches": {}, "alerts": []}
    data.pop('review', None); data.pop('needs_review', None); data.pop('goals_review', None)
    # Щ„Ш§ ЩҶШӯШ°ЩҒ alerts Щ„ШЈЩҶЩҮШ§ ШӘЩӮШұЩҠШұ ШҘШҜШ§ШұЩҠШҢ Щ„ЩғЩҶЩҮШ§ Щ„Ш§ ШӘШёЩҮШұ ЩғЩҖ "ЩҠШӯШӘШ§Ш¬ Щ…ШұШ§Ш¬Ш№Ш©" ЩҒЩҠ Щ…Щ„ЩҒ Ш§Щ„Ш¬Щ…ЩҮЩҲШұ.
    return _v33_safe_save_json(GOALS_DATA_FILE, data)

# ЩҒЩ„ШӘШұ ШЈШіЩ…Ш§ШЎ ШЈЩҲШ¶Шӯ ЩӮШЁЩ„ ШҘШҜШ®Ш§Щ„ Ш§Щ„ШЈЩҮШҜШ§ЩҒ.
_V33_PREV_PARSE_GOALS = globals().get('_v32_parse_youtube_goal_scorers')
def _v32_parse_youtube_goal_scorers(desc, team1='', team2=''):
    goals = []
    try:
        if _V33_PREV_PARSE_GOALS:
            goals = _V33_PREV_PARSE_GOALS(desc, team1, team2) or []
    except Exception:
        goals = []
    bad = re.compile(r'^(?:ЩҒЩҠ|Ш¶ШҜ|Ш§Щ…Ш§Щ…|ШЈЩ…Ш§Щ…|Щ…ЩҶШӘШ®ШЁ|ШЁЩҲШ§ШіШ·Ш©|Ш№ЩҶ Ш·ШұЩҠЩӮ|ЩҒЩҠЩ…Ш§|ШЁЩҠЩҶЩ…Ш§|ШәЩҠШұ Щ…ШӯШҜШҜ|Ш§Щ„ШҙЩҲШ·|Ш§Щ„ШҜЩӮЩҠЩӮШ©|Ш§Щ„ШҜЩӮЩҠЩӮШӘЩҠЩҶ|ЩҮШҜЩҒ|ШЈЩҮШҜШ§ЩҒ|Ш§ЩҮШҜШ§ЩҒ|ШіШ¬Щ„|Ш§ШӯШұШІ|ШЈШӯШұШІ|ШӘШ№Ш§ШҜЩ„|Ш§ЩҒШӘШӘШӯ|Ш§Щ„ШӘШіШ¬ЩҠЩ„)$')
    cleaned = []
    seen = set()
    for g in goals:
        name = re.sub(r'\s+', ' ', str((g or {}).get('player') or '')).strip()
        if not name or bad.search(name):
            continue
        key = (name, (g or {}).get('minute'), (g or {}).get('team'))
        if key in seen:
            continue
        seen.add(key)
        gg = dict(g); gg['player'] = name
        cleaned.append(gg)
    return cleaned

# ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ЩҶШө ЩҲШ§Щ„ЩӮЩҲШ§ШҰЩ….
_V33_PREV_PUBLIC_REPLY_MENU_ROUTER = globals().get('public_reply_menu_router')
async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        _v32_track_user(update)
    except Exception:
        pass
    txt_raw = update.message.text or ''
    txt = normalize_name(txt_raw).strip()
    if txt == "вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ":
        _v33_set_waiting_state(context, 'how')
        await update.message.reply_text(_v33_how_start_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])); return
    if txt == "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„":
        _v33_set_waiting_state(context, 'calc')
        await update.message.reply_text(_v33_calc_start_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])); return
    if _V33_PREV_PUBLIC_REPLY_MENU_ROUTER:
        return await _V33_PREV_PUBLIC_REPLY_MENU_ROUTER(update, context)

_V33_PREV_TEXT_ROUTER = globals().get('text_state_router')
async def text_state_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    txt_raw = update.message.text or ''
    txt = normalize_name(txt_raw).strip()
    state = _v33_get_waiting_state(context)
    if txt in V32_FINAL_MENU_LABELS:
        return await public_reply_menu_router(update, context)
    if state == 'how':
        _v33_clear_waiting_state(context)
        team = _v33_find_team(txt_raw)
        if not team:
            await update.message.reply_text("Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Щ…Ш«Щ„ЩӢШ§: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."); return
        await update.message.reply_text(_v33_how_qualify_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if state == 'calc':
        _v33_clear_waiting_state(context)
        text, kb = _v33_scenario_result_text(txt_raw)
        await update.message.reply_text(text, reply_markup=kb); return
    # ЩҠШҙШӘШәЩ„ Щ…ЩҶ Ш§Щ„Щ…ШӯШ§ШҜШ«Ш© Щ…ШЁШ§ШҙШұШ©
    if re.search(r'(ЩғЩҠЩҒ\s+(?:ШӘШӘШЈЩҮЩ„|ЩҠШӘШЈЩҮЩ„|ШӘШӘШ§ЩҮЩ„|ЩҠШӘШ§ЩҮЩ„)|Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ\s+.+(?:Щ„Щ„ШӘШЈЩҮЩ„|Щ„Щ„ШӘШ§ЩҮЩ„)|ЩҲШҙ\s+ЩҠШӯШӘШ§Ш¬|Щ…Ш§Ш°Ш§\s+ЩҠШӯШӘШ§Ш¬)', txt):
        team = _v33_find_team(txt_raw)
        if team:
            await update.message.reply_text(_v33_how_qualify_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if re.search(r'(ЩҒЩҲШІ|Ш®ШіШ§ШұШ©|Ш®ШіШ§ШұЩҮ|ЩҮШІЩҠЩ…Ш©|ШӘШ№Ш§ШҜЩ„)', txt) and _v33_detect_scenario_items(txt_raw):
        text, kb = _v33_scenario_result_text(txt_raw)
        await update.message.reply_text(text, reply_markup=kb); return
    if _V33_PREV_TEXT_ROUTER:
        return await _V33_PREV_TEXT_ROUTER(update, context)

# Callback wrapper.
_V33_PREV_V32_CALLBACK = globals().get('v32_callback')
async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    try:
        await q.answer()
    except Exception:
        pass
    parts = data.split('|')
    action = parts[1] if len(parts) > 1 else ''
    if data == 'v32|how_start':
        _v33_set_waiting_state(context, 'how')
        await q.edit_message_text(_v33_how_start_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])); return
    if data == 'v32|calc_start':
        _v33_set_waiting_state(context, 'calc')
        await q.edit_message_text(_v33_calc_start_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])); return
    if action == 'r32':
        await q.edit_message_text(_v33_round32_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")]])); return
    if action == 'how_thirds' and len(parts) >= 3:
        team = _v33_team_from_button_key(parts[2])
        await q.edit_message_text(_v33_how_thirds_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if action == 'opp_all' and len(parts) >= 3:
        team = _v33_team_from_button_key(parts[2])
        await q.edit_message_text(_v33_all_opponents_text(team), reply_markup=_v33_opponent_buttons(team)); return
    if action == 'opp' and len(parts) >= 4:
        team = _v33_team_from_button_key(parts[2]); slot = parts[3]
        await q.edit_message_text(_v33_opponent_detail_text(team, slot), reply_markup=_v33_opponent_buttons(team)); return
    if _V33_PREV_V32_CALLBACK:
        return await _V33_PREV_V32_CALLBACK(update, context)

# ЩҶШ¶ЩҠЩҒ ШЈШІШұШ§Шұ Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„Ш¬ШҜЩҠШҜШ© ШҘЩ„Щү ШІШұ home Ш§Щ„Ш№Ш§Щ… ШҘШ°Ш§ ЩғШ§ЩҶ ЩҠЩ…Шұ Ш№ШЁШұ mainmenu callback Ш§Щ„ЩӮШҜЩҠЩ….
# ==================== END V33 QUALIFICATION CALCULATOR + PERSISTENT HIGHLIGHTS/GOALS PATCH ====================


# ==================== V34 MENU ARCHIVE/STATS + SCENARIO/HOW-QUALIFY FIXES ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - ШІШұ "рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©" ЩҠШ¬Щ…Ш№ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ + ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© + ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« + Ш§Щ„ШӘШЈЩҮЩ„/Ш§Щ„Щ…ШәШ§ШҜШұШ©.
# - ШІШұ "рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©" ЩҠШ¬Щ…Ш№ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ + ЩҶШӘШ§ШҰШ¬ Ш§Щ„ШЁШ·ЩҲЩ„Ш© + Щ…ШіШ¬Щ„ЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ.
# - ШҜЩ…Ш¬ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ЩҲШ§Щ„Щ…ШәШ§ШҜШұЩҠЩҶ ЩҒЩҠ ШІШұ ЩҲШ§ШӯШҜ.
# - Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ Щ„Ш§ ЩҠЩғЩҲЩҶ Щ„ШӯШ§Щ„ЩҮ ЩҒЩҠ Ш§Щ„ШұШҰЩҠШіЩҠШ©.
# - ШӯШ°ЩҒ/ШӘШӯЩҲЩҠЩ„ "Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ" ШҘЩ„Щү "вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„Шҹ" ЩҒЩҠ ЩғЩ„ Щ…ЩғШ§ЩҶ.
# - ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„ ШӘЩӮШЁЩ„ Ш§Щ„ШӘШ№Ш§ШҜЩ„ ЩҲШ§Щ„ЩҮШІЩҠЩ…Ш© ШЁШ§Щ„ШӘШ§ШЎ Ш§Щ„Щ…ШұШЁЩҲШ·Ш©/Ш§Щ„ЩҮШ§ШЎШҢ ЩҲШӘШӘШӯЩӮЩӮ ШЈЩҶ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ ШҜШ§Ш®Щ„ Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШ§ШӯШҜШ©.
# - ШІШұ ЩғЩ„ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ ЩҠШ№Ш·ЩҠ ШұШіШ§Щ„Ш© Ш§ЩҶШӘШёШ§Шұ ЩӮШЁЩ„ Ш§Щ„ШӘШ¬ЩҮЩҠШІ.

try:
    V32_FINAL_MENU_LABELS.update({
        "рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©",
        "вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", "рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32"
    })
    for _lbl in ["рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩғШҹ", "рҹ§® Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ"]:
        V32_FINAL_MENU_LABELS.discard(_lbl)
except Exception:
    V32_FINAL_MENU_LABELS = {
        "рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©",
        "вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", "рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32"
    }


