        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©", callback_data="v34|status_home")],
