def _v34_archive_text():
    return "рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©\n\nЩҮЩҶШ§ ШӘЩ„ЩӮЩү ЩғЩ„ Ш§Щ„ШіШ¬Щ„Ш§ШӘ Ш§Щ„Щ…ШӯЩҒЩҲШёШ© Щ„Щ„ШЁШ·ЩҲЩ„Ш©:"


def _v34_status_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ", callback_data="v32|qualified"), InlineKeyboardButton("вқҢ Ш§Щ„Щ…ШәШ§ШҜШұЩҲЩҶ", callback_data="v32|eliminated")],
        [InlineKeyboardButton("в¬…пёҸ Ш§Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ", callback_data="v34|stats"), InlineKeyboardButton("в¬…пёҸ Ш§Щ„ШұШҰЩҠШіЩҠШ©", callback_data="mainmenu|home")],
    ])


def _v34_status_text():
    return "вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©\n\nШ§Ш®ШӘШұ Ш§Щ„Щ„ЩҠ ШӘШЁЩҠ ШӘШҙЩҲЩҒЩҮ:"


# Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ© Ш§Щ„Щ…Ш№ШӘЩ…ШҜШ© ШЁШ№ШҜ ЩҶЩӮЩ„ Ш§Щ„ШҘШӯШөШ§ШҰЩҠШ§ШӘ ЩҲШ§Щ„ШЈШұШҙЩҠЩҒ.
def _public_main_reply_keyboard():
    return ReplyKeyboardMarkup(
        [
            ["рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", "рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©"],
            ["вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„"],
            ["рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹ“… Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩӮШ§ШҜЩ…Ш©"],
            ["рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", "рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ"],
        ],
        resize_keyboard=True,
        one_time_keyboard=False,
        input_field_placeholder="Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ ШЈЩҲ Ш§Ш®ШӘШұ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©",
    )


def _public_main_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹ“ә Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ", callback_data="mainmenu|live"), InlineKeyboardButton("рҹҸҶ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")],
        [InlineKeyboardButton("вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", callback_data="v32|how_start"), InlineKeyboardButton("рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|calc_start")],
        [InlineKeyboardButton("рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v34|stats"), InlineKeyboardButton("рҹ“… Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ЩӮШ§ШҜЩ…Ш©", callback_data="mainmenu|fixtures")],
        [InlineKeyboardButton("рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v34|archive"), InlineKeyboardButton("рҹҺ® ЩҒШ§ЩҶШӘШІЩҠ", callback_data="v32|fantasy_gate")],
    ])


# Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©: ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„ ШЈЩҲЩ„ЩӢШ§ШҢ ЩҲШҜЩҲШұ Ш§Щ„ЩҖ32 Щ…Ш®ЩҒЩҠ ШӯШӘЩү ШӘШӘШЈЩғШҜ ШЈЩҲЩ„ Щ…ЩҲШ§Ш¬ЩҮШ©.
def _v32_board_keyboard():
    rows = [
        [InlineKeyboardButton("рҹҸҒ ШіШЁШ§ЩӮ Ш§Щ„ШӘШЈЩҮЩ„", callback_data="v32|race")],
        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", callback_data="v32|thirds"), InlineKeyboardButton("рҹ”Ҙ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„ШӯШіЩ…", callback_data="v32|decisive")],
        [InlineKeyboardButton("вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©", callback_data="v34|status_home"), InlineKeyboardButton("рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v34|stats")],
    ]
    if _v33_round32_has_official_match():
        rows.append([InlineKeyboardButton("рҹҸҹпёҸ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32", callback_data="v32|r32")])
    rows.append([InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Ш§Щ„ШўЩҶ", callback_data="v32|board_force"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")])
    return InlineKeyboardMarkup(rows)


def _v34_direct_third_match(team, gcode, snap):
    """ЩҠШұШ¬Ш№ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© Ш§Щ„ШӘЩҠ ЩҠЩғЩҲЩҶ Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„ШӯШ§Щ„ЩҠ Ш·ШұЩҒЩӢШ§ ЩҒЩҠЩҮШ§ ШҘЩҶ ЩҲШ¬ШҜШӘ."""
    tr = _v33_third_row_for_group(gcode, snap)
    third_team = (tr or {}).get('team')
    rem = _v33_group_remaining(gcode, snap)
    if third_team:
        for m in rem:
            t1 = canonical_team_name(m.get('team1')) or m.get('team1')
            t2 = canonical_team_name(m.get('team2')) or m.get('team2')
            if third_team in (t1, t2):
                return m
    return rem[0] if rem else None


def _v34_why_third_group_matters(target_team, target_pts_if_third, gcode, tr, status, snap):
    pts = int((tr or {}).get('Pts') or 0)
    third_team = (tr or {}).get('team') or 'Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©'
    if status == 'weak':
        return f"Щ„ШЈЩҶ {third_team} Щ…Ш§ ШІШ§Щ„ Щ…Щ…ЩғЩҶ ЩҠШҜШ®Щ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘШ°Ш§ ШӘШӯШіЩҶШӘ ЩҶШӘЩҠШ¬ШӘЩҮШҢ ЩҲШӘШ№Ш«ШұЩҮ ЩҠШЁЩӮЩҠЩҮ Ш®Щ„ЩҒ {target_team}."
    if pts >= target_pts_if_third:
        return f"Щ„ШЈЩҶ {third_team} ЩӮШұЩҠШЁ ШЈЩҲ Щ…ШӘЩӮШҜЩ… Ш№Щ„Щү ШұШөЩҠШҜ {target_team} Ш§Щ„Щ…ШӘЩҲЩӮШ№ШҢ ЩҲЩҶШӘЩҠШ¬ШӘЩҮ ЩӮШҜ ШӘШӨШ«Шұ Ш№Щ„Щү ШӘШұШӘЩҠШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«."
    return f"Щ„ШЈЩҶ {third_team} ЩҠШіШӘШ·ЩҠШ№ Ш§Щ„Ш§ЩӮШӘШұШ§ШЁ Щ…ЩҶ {target_team} ШЈЩҲ ШӘШ¬Ш§ЩҲШІЩҮ ШҘШ°Ш§ ЩҒШ§ШІШҢ ЩҲШӘШ№Ш«ШұЩҮ ЩҠШіШ§Ш№ШҜ {target_team}."


def _v34_relevant_thirds_lines(team, snap, target_pts_if_third=None, limit=7):
    code, pos, row, rows = _v33_group_row(team, snap)
    if target_pts_if_third is None:
        target_pts_if_third = int((row or {}).get('Pts') or 0)
        rem = _v33_remaining_for_team(team, snap)
        if rem:
            # ШәШ§Щ„ШЁЩӢШ§ ШІШұ ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„ ЩҠШӯШіШЁ Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„ШЈЩҒШ¶Щ„ ШЁШ§Щ„ЩҒЩҲШІ Ш§Щ„ЩӮШ§ШҜЩ…ШҢ Щ„Ш°Щ„Щғ ЩҶШұЩҒШ№ Ш§Щ„ШұШөЩҠШҜ Ш§Щ„Щ…ШӘЩҲЩӮШ№ 3 ЩҶЩӮШ§Ш·.
            target_pts_if_third += 3
    lines = []
    shown = 0
    thirds = _v33_current_thirds(snap)
    for tr in thirds:
        gcode = tr.get('group')
        if not gcode or gcode == code:
            continue
        status, reason = _v33_third_group_status(gcode, snap)
        if status == 'impossible':
            continue
        third_team = tr.get('team') or '-'
        pts = int(tr.get('Pts') or 0)
        gd = int(tr.get('GD') or 0)
        tag = "вҡ пёҸ ШөШ№ШЁ" if status == 'weak' else "вң… ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁ"
        m = _v34_direct_third_match(third_team, gcode, snap)
        lines.append(f"- {_v33_group_label(gcode)}: Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ {third_team} вҖ” {pts} ЩҶЩӮШ§Ш· вҖ” Ш§Щ„ЩҒШ§ШұЩӮ {gd:+d} вҖ” {tag}")
        if m:
            lines.append(f"  Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӨШ«ШұШ©: {_v33_format_remaining_match(m)}")
        lines.append(f"  Щ„ЩҠЩҮ ШӘЩҮЩ… {team}Шҹ {_v34_why_third_group_matters(team, target_pts_if_third, gcode, tr, status, snap)}")
        shown += 1
        if shown >= limit:
            break
    if not lines:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ШӨШ«ШұШ© ЩҲШ§Ш¶ШӯШ© Ш§Щ„ШўЩҶ ШЈЩҲ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ ШәЩҠШұ Щ…ЩғШӘЩ…Щ„Ш©.")
    return lines


def _v34_direct_path_lines(team, code, row, rows, snap):
    lines = []
    rem = _v33_remaining_for_team(team, snap)
    if not rem:
        return ["Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© Щ…ШӘШЁЩӮЩҠШ© Щ„ЩҮШ°Ш§ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."]
    m = rem[0]
    t1 = canonical_team_name(m.get('team1')) or m.get('team1')
    t2 = canonical_team_name(m.get('team2')) or m.get('team2')
    opp = t2 if team == t1 else t1
    lines.append(f"ШЈЩҲЩ„ ШҙШұШ· Щ…ЩҮЩ…: ЩҶШӘЩҠШ¬Ш© Щ…ШЁШ§ШұШ§Ш© {team} Ш§Щ„ЩӮШ§ШҜЩ…Ш© Ш¶ШҜ {opp}.")
    lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш©: {_v33_format_remaining_match(m)}")
    lines.append("")
    lines.append("ШЁШҙЩғЩ„ Ш№Ш§Щ…:")
    lines.append(f"- Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp} ЩҠЩҒШӘШӯ Ш·ШұЩҠЩӮ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЈЩҲ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.")
    lines.append("- Ш§Щ„ШӘШ№Ш§ШҜЩ„ ЩҠШЁЩӮЩҠ Ш§Щ„ШӯШіШ§ШЁШ§ШӘ Щ…Щ…ЩғЩҶШ© ШҘШ°Ш§ ЩғШ§ЩҶ Ш§Щ„ШұШөЩҠШҜ ЩҠШіЩ…ШӯШҢ Щ„ЩғЩҶЩҮ ШәШ§Щ„ШЁЩӢШ§ ЩҠШ№Щ„Щ‘ЩӮ Ш§Щ„ШӘШЈЩҮЩ„ Ш№Щ„Щү ЩҶШӘШ§ШҰШ¬ ЩғШ«ЩҠШұШ©.")
    lines.append("- Ш§Щ„Ш®ШіШ§ШұШ© ЩӮШҜ ШӘШ®ШұШ¬ЩҮ ШЈЩҲ ШӘШөШ№Щ‘ШЁ ЩҲШ¶Ш№ЩҮ Ш¬ШҜЩӢШ§ ШӯШіШЁ ШӘШұШӘЩҠШЁЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ.")
    # ШӘЩҲШ¶ЩҠШӯ Ш®Ш§Шө Ш№ЩҶШҜЩ…Ш§ ЩҠЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү ЩҒЩҠ ЩҶЩҒШі Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.
    other = []
    for gm in _v33_group_remaining(code, snap):
        a = canonical_team_name(gm.get('team1')) or gm.get('team1')
        b = canonical_team_name(gm.get('team2')) or gm.get('team2')
        if team not in (a, b):
            other.append(gm)
    if other:
        lines.append("")
        lines.append("Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„ШӘЩҠ ШӘШӨШ«Шұ Ш№Щ„ЩҠЩҮ:")
        lines.append(f"- {_v33_format_remaining_match(other[0])}")
    return lines


def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    # ШөЩҠШәШ© Ш§Щ„Ш№ЩҶЩҲШ§ЩҶ: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© Щ…ШӨЩҶШ«Ш© Ш§ШіШӘШ®ШҜШ§Щ…ЩӢШ§ШҢ ЩҲШ§Щ„ШЁШ§ЩӮЩҠ Щ…ЩҶШӘШ®ШЁ X.
    title = f"вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„ {team}Шҹ" if team == "Ш§Щ„ШіШ№ЩҲШҜЩҠШ©" else f"вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ {team}Шҹ"
    lines = [title, "", f"рҹ“Ҡ ЩҲШ¶Ш№ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ: {_v33_group_label(code)}", f"Ш§Щ„ШӯШ§Щ„Ш©: {status_txt}"]
    if row:
        lines.append(f"Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШӯШ§Щ„ЩҠ: {pos} вҖ” Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d}")
    rem = _v33_remaining_for_team(team, snap)
    if rem:
        lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©: {_v33_format_remaining_match(rem[0])}")
    lines.append("")
    if 'Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ' in status_txt:
        lines.append("вң… ШӯШіЩ… Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩҲЩ„Ш§ ЩҠШӯШӘШ§Ш¬ ЩҶШӘШ§ШҰШ¬ Ш«Ш§ЩҶЩҠШ©.")
    elif 'Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠ' in status_txt:
        lines.append("вқҢ Ш§ЩҶШӘЩҮШӘ ЩҒШұШөЩҮ ШӯШіШ§ШЁЩҠЩӢШ§.")
    else:
        lines.append("вң… Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„ШЈЩҲЩ„: Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ")
        lines += _v34_direct_path_lines(team, code, row, rows, snap)
        lines.append("")
        lines.append("рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«")
        lines.append("ШЈЩҲЩ„ЩӢШ§: ЩғЩҠЩҒ ЩҠШҜШ®Щ„ Щ…ШіШ§Шұ Ш§Щ„Ш«Ш§Щ„Ш«Шҹ")
        lines.append("ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«ШҢ ЩҠШЁШҜШЈ ШЁШ№ШҜЩҮШ§ ШӯШіШ§ШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
        lines.append("Щ…Ш«Ш§Щ„ Ш№Щ…Щ„ЩҠ: ШҘШ°Ш§ ЩҒШ§ШІ ЩҒЩҠ Щ…ШЁШ§ШұШ§ШӘЩҮ Ш§Щ„ЩӮШ§ШҜЩ…Ш© Щ„ЩғЩҶ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҠЩҶ Ш¬Ш№Щ„ШӘЩҮ Ш«Ш§Щ„Ш«ЩӢШ§ШҢ ЩҠЩҶШӘЩӮЩ„ Щ„ШӯШіШЁШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
        lines.append("")
        lines.append("ШЁШ№ШҜ Щ…Ш§ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ШҢ Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ")
        lines.append("ЩҠШӘШЈЩҮЩ„ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12ШҢ Щ„Ш°Щ„Щғ ЩҠШӯШӘШ§Ш¬ ШЈЩҶ ЩҠЩғЩҲЩҶ ШЈЩҒШ¶Щ„ Щ…ЩҶ 4 Ш«ЩҲШ§Щ„Ш« Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
        lines.append("Ш§Щ„ШЁЩҲШӘ ЩҠШӯШ°ЩҒ Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ ШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© ШөШ§Шұ Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ЩҠШӘШЈЩҮЩ„.")
    lines.append("")
    lines.append(f"рҹҘү Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ„ЩҠ ШӘЩҮЩ… {team}:")
    if row:
        lines += _v34_relevant_thirds_lines(team, snap)
    else:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.")
    lines.append("")
    lines.append("Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ ШӘШ№Ш·ЩҠЩғ Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…ЩҶШӘШ®ШЁ Ш«Ш§Щ„Ш«ЩӢШ§.")
    return "\n".join(lines).strip()


def _v33_how_thirds_text(team):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = _v33_snapshot(False)
    code, pos, row, rows = _v33_group_row(team, snap)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    lines = [f"рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« вҖ” {team}", ""]
    lines.append("ЩғЩҠЩҒ ЩҠШҜШ®Щ„ Щ…ШіШ§Шұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«Шҹ")
    lines.append("Щ„Ш§ШІЩ… ЩҠЩҶЩҮЩҠ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«ШҢ ШЁШ№ШҜЩҮШ§ ШӘШӘЩ… Щ…ЩӮШ§ШұЩҶШӘЩҮ Щ…Ш№ Ш«ЩҲШ§Щ„Ш« ШЁШ§ЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.")
    lines.append("")
    lines.append("ШЁШ№ШҜ Щ…Ш§ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ШҢ Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ")
    lines.append("ЩҠШӘШЈЩҮЩ„ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12ШҢ ЩҠШ№ЩҶЩҠ ЩҠШӯШӘШ§Ш¬ ЩҠЩғЩҲЩҶ ШЈЩҒШ¶Щ„ Щ…ЩҶ 4 Ш«ЩҲШ§Щ„Ш« Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
    lines.append("")
    lines.append(f"рҹҘү Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ„ЩҠ ШӘЩҮЩ… {team}:")
    lines += _v34_relevant_thirds_lines(team, snap)
    lines.append("")
    if excluded:
        lines.append("рҹҡ« Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ШіШӘШЁШ№ШҜШ© Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ ШӯШ§Щ„ЩҠЩӢШ§:")
        for c, reason in excluded[:8]:
            lines.append(f"вқҢ {_v33_group_label(c)} вҖ” {reason}")
        lines.append("")
    if weak:
        lines.append("вҡ пёҸ Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШ¶Ш№ЩҮШ§ ШөШ№ШЁ Щ„ЩғЩҶЩҮШ§ Щ…Щ…ЩғЩҶШ©:")
        for c, reason in weak[:8]:
            tr = _v33_third_row_for_group(c, snap)
            lines.append(f"вҡ пёҸ {_v33_group_label(c)} вҖ” Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ: {(tr or {}).get('team','-')} вҖ” {reason}")
        lines.append("")
    lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©:")
    lines.append("ШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ЩҠШӘШЈЩҮЩ„ ШӘЩҸШӯШ°ЩҒ Щ…ЩҶ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ. ЩҲШ§Щ„ШөШ№ШЁ ЩҠШЁЩӮЩү ШЁШ№Щ„Ш§Щ…Ш© ШӘШӯШ°ЩҠШұ Щ„ШЈЩҶЩҮ Щ„Ш§ ЩҠШІШ§Щ„ Щ…Щ…ЩғЩҶЩӢШ§.")
    return "\n".join(lines).strip()


# ШҘШІШ§Щ„Ш© Ш№ШЁШ§ШұШ© "Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬" Щ…ЩҶ Щ…Щ„Ш®Шө Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҲШ§ШіШӘШЁШҜШ§Щ„ЩҮШ§ ШЁШҘШҙШ§ШұШ© ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„.
_V34_PREV_TEAM_SUMMARY_TEXT = globals().get('_v32_team_summary_text')
def _v32_team_summary_text(team, force=False):
    txt = _V34_PREV_TEAM_SUMMARY_TEXT(team, force) if _V34_PREV_TEAM_SUMMARY_TEXT else ""
    txt = str(txt or '').replace("Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ", "вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„Шҹ")
    return txt


def _v34_normalize_scenario_text(text):
    s = normalize_name(text or '')
    s = s.replace('ЩҮШІЩҠЩ…ЩҮ', 'ЩҮШІЩҠЩ…Ш©').replace('Ш®ШіШ§ШұЩҮ', 'Ш®ШіШ§ШұШ©')
    s = s.replace('Ш§Щ„ШӘШ№Ш§ШҜЩ„', 'ШӘШ№Ш§ШҜЩ„').replace('ШӘШ№Ш§ШҜЩҸЩ„', 'ШӘШ№Ш§ШҜЩ„')
    return s


def _v33_detect_scenario_items(text):
    s = _v34_normalize_scenario_text(text or '')
    # ЩҠЩӮШіЩ… Ш№Щ„Щү Ш§Щ„ЩҲШ§ЩҲ/Ш§Щ„ЩҒЩҲШ§ШөЩ„/Ш№Щ„Ш§Щ…Ш© +ШҢ Щ…Ш№ ШҘШЁЩӮШ§ШЎ Ш§Щ„ЩҶШө Ш§Щ„ШЁШіЩҠШ· Щ…Ш«Щ„ "ШӘШ№Ш§ШҜЩ„ Ш§ШіШЁШ§ЩҶЩҠШ§ ЩҲШӘШ№Ш§ШҜЩ„ Ш§Щ„ШіШ№ЩҲШҜЩҠШ©".
    parts = re.split(r'\s+(?:ЩҲ|ШҢ|,|\+)\s+', s)
    items = []
    for part in parts:
        part = part.strip()
        if not part:
            continue
        outcome = None
        if re.search(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|ЩҠЩҶШӘШөШұ|Ш§ЩҶШӘШөШ§Шұ)', part):
            outcome = 'win'
        elif re.search(r'(Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|Ш§ЩҶЩҮШІЩ…|ЩҠЩҶЩҮШІЩ…)', part):
            outcome = 'loss'
        elif re.search(r'(ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„|ШӘШ№Ш§ШҜЩ„ШӘ|ЩҠШӘШ№Ш§ШҜЩ„ЩҲЩҶ)', part):
            outcome = 'draw'
        if not outcome:
            continue
        tm = _v33_find_team(part)
        if not tm:
            tmp = re.sub(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|ЩҠЩҶШӘШөШұ|Ш§ЩҶШӘШөШ§Шұ|Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|Ш§ЩҶЩҮШІЩ…|ЩҠЩҶЩҮШІЩ…|ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„|ШӘШ№Ш§ШҜЩ„ШӘ)', ' ', part)
            tm = _v33_find_team(tmp)
        if tm:
            items.append((tm, outcome, _v33_parse_score_pair(part)))
    return items


def _v34_validate_scenario_groups(items):
    groups = {}
    for tm, _out, _sc in items:
        g = _v33_team_group(tm)
        if g:
            groups.setdefault(g, []).append(tm)
    return groups


def _v34_scenario_group_error_text(groups):
    lines = ["вҡ пёҸ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ ШәЩҠШұ ЩҲШ§Ш¶Шӯ", "", "Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„Щ…Ш°ЩғЩҲШұШ© Щ„ЩҠШіШӘ ЩҒЩҠ ЩҶЩҒШі Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.", ""]
    for g, teams in groups.items():
        lines.append(f"{', '.join(teams)} вҖ” {_v33_group_label(g)}")
    lines.append("")
    lines.append("Ш§ЩғШӘШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…ЩҶ ЩҶЩҒШі Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©ШҢ ШЈЩҲ Ш§ШіШӘШ®ШҜЩ… ШІШұ вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ Щ„Щ…Ш№ШұЩҒШ© ШӘШЈШ«ЩҠШұ ШЁШ§ЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    return "\n".join(lines)


_V34_PREV_SIMULATE = globals().get('_v33_simulate_snapshot_from_text')
def _v33_simulate_snapshot_from_text(text):
    base = _v33_snapshot(False)
    items = _v33_detect_scenario_items(text)
    groups = _v34_validate_scenario_groups(items)
    # ЩҶШ®ШІЩҶ Ш®Ш·ШЈ Ш§Щ„ШӘШӯЩӮЩӮ ЩҒЩҠ ЩҶШӘЩҠШ¬Ш© Ш®Ш§ШөШ© ШӘЩӮШұШЈЩҮШ§ ШҜШ§Щ„Ш© Ш§Щ„ЩҶШө.
    if len(groups) > 1:
        return base, items, [{'scenario_error': 'different_groups', 'groups': groups}]
    sim_results = {}
    for team, outcome, score in items:
        _v33_apply_one_scenario_result(sim_results, team, outcome, score, base)
    if not sim_results:
        return base, [], []
    snap = json.loads(json.dumps(base, ensure_ascii=False, default=str))
    affected = set()
    for r in sim_results.values():
        code = _v33_team_group(r['team1']) or _v33_team_group(r['team2'])
        if code:
            affected.add(code)
            g = (snap.get('groups') or {}).setdefault(code, {"results": [], "fixtures": [], "rows": []})
            pair = frozenset([r['team1'], r['team2']])
            if not any(frozenset([x.get('team1'), x.get('team2')]) == pair for x in g.get('results') or []):
                g.setdefault('results', []).append(r)
    for code in affected:
        teams = _v33_group_teams(code)
        g = (snap.get('groups') or {}).get(code, {})
        try:
            g['rows'] = _v32_stats_rows_from_results(teams, g.get('results') or [])
            g['remaining'] = max(0, 6 - len(g.get('results') or []))
        except Exception:
            pass
    thirds = []
    for code, _teams in WORLD_CUP_GROUPS:
        rows = ((snap.get('groups') or {}).get(code, {}) or {}).get('rows') or []
        if len(rows) >= 3:
            r = dict(rows[2]); r['group'] = code; thirds.append(r)
    thirds = sorted(thirds, key=_v33_rank_key)
    for i, r in enumerate(thirds):
        r['third_status'] = 'вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§' if i < 8 else 'вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§'
    snap['thirds'] = thirds
    snap['updated_at'] = (base.get('updated_at') or '-') + ' + ШіЩҠЩҶШ§ШұЩҠЩҲ'
    return snap, items, list(sim_results.values())


_V34_PREV_SCENARIO_RESULT_TEXT = globals().get('_v33_scenario_result_text')
def _v33_scenario_result_text(text):
    snap, items, simrows = _v33_simulate_snapshot_from_text(text)
    if simrows and isinstance(simrows[0], dict) and simrows[0].get('scenario_error') == 'different_groups':
        return _v34_scenario_group_error_text(simrows[0].get('groups') or {}), InlineKeyboardMarkup([[InlineKeyboardButton("вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ", callback_data="v32|how_start"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")]])
    # ЩҶШіШӘШ®ШҜЩ… Ш§Щ„ЩҶШө Ш§Щ„ЩӮШҜЩҠЩ… ШЁШ№ШҜ ШӘШӯШіЩҠЩҶ Ш§Щ„ШЁШ§ШұШіШұ ЩҲШ§Щ„ШӘШӯЩӮЩӮ.
    return _V34_PREV_SCENARIO_RESULT_TEXT(text) if _V34_PREV_SCENARIO_RESULT_TEXT else ("ШӘШ№Ш°Шұ ШӘШӯЩ„ЩҠЩ„ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ.", None)


_V34_PREV_PUBLIC_REPLY_MENU_ROUTER = globals().get('public_reply_menu_router')
async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        _v32_track_user(update)
    except Exception:
        pass
    txt_raw = update.message.text or ''
    txt = normalize_name(txt_raw).strip()
    if txt == "рҹ“Ҡ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш©":
        await update.message.reply_text(_v34_stats_text(), reply_markup=_v34_stats_keyboard()); return
    if txt == "рҹ—ӮпёҸ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©":
        await update.message.reply_text(_v34_archive_text(), reply_markup=_v34_archive_keyboard()); return
    if txt == "вң…вқҢ Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ©":
        await update.message.reply_text(_v34_status_text(), reply_markup=_v34_status_keyboard()); return
    if txt == "вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„Шҹ":
        _v33_set_waiting_state(context, 'how')
        await update.message.reply_text(_v33_how_start_text(), reply_markup=_v34_back_home_kb()); return
    if txt == "рҹ§® ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„":
        _v33_set_waiting_state(context, 'calc')
        await update.message.reply_text(_v33_calc_start_text(), reply_markup=_v34_back_home_kb()); return
    if _V34_PREV_PUBLIC_REPLY_MENU_ROUTER:
        return await _V34_PREV_PUBLIC_REPLY_MENU_ROUTER(update, context)


_V34_PREV_TEXT_STATE_ROUTER = globals().get('text_state_router')
async def text_state_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    txt_raw = update.message.text or ''
    txt = normalize_name(txt_raw).strip()
    state = _v33_get_waiting_state(context)
    if txt in V32_FINAL_MENU_LABELS:
        return await public_reply_menu_router(update, context)
    if state == 'how':
        _v33_clear_waiting_state(context)
        team = _v33_find_team(txt_raw)
        if not team:
            await update.message.reply_text("Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Щ…Ш«Щ„ЩӢШ§: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."); return
        await update.message.reply_text(_v33_how_qualify_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if state == 'calc':
        _v33_clear_waiting_state(context)
        text, kb = _v33_scenario_result_text(txt_raw)
        await update.message.reply_text(text, reply_markup=kb); return
    if re.search(r'(ЩғЩҠЩҒ\s+(?:ШӘШӘШЈЩҮЩ„|ЩҠШӘШЈЩҮЩ„|ШӘШӘШ§ЩҮЩ„|ЩҠШӘШ§ЩҮЩ„)|Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ\s+.+(?:Щ„Щ„ШӘШЈЩҮЩ„|Щ„Щ„ШӘШ§ЩҮЩ„)|ЩҲШҙ\s+ЩҠШӯШӘШ§Ш¬|Щ…Ш§Ш°Ш§\s+ЩҠШӯШӘШ§Ш¬)', txt):
        team = _v33_find_team(txt_raw)
        if team:
            await update.message.reply_text(_v33_how_qualify_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if re.search(r'(ЩҒЩҲШІ|Ш®ШіШ§ШұШ©|Ш®ШіШ§ШұЩҮ|ЩҮШІЩҠЩ…Ш©|ЩҮШІЩҠЩ…ЩҮ|ШӘШ№Ш§ШҜЩ„)', txt) and _v33_detect_scenario_items(txt_raw):
        text, kb = _v33_scenario_result_text(txt_raw)
        await update.message.reply_text(text, reply_markup=kb); return
    if _V34_PREV_TEXT_STATE_ROUTER:
        return await _V34_PREV_TEXT_STATE_ROUTER(update, context)


_V34_PREV_V32_CALLBACK = globals().get('v32_callback')
async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    try:
        await q.answer()
    except Exception:
        pass
    parts = data.split('|')
    action = parts[1] if len(parts) > 1 else ''
    if data == 'v34|stats':
        await q.edit_message_text(_v34_stats_text(), reply_markup=_v34_stats_keyboard()); return
    if data == 'v34|archive':
        await q.edit_message_text(_v34_archive_text(), reply_markup=_v34_archive_keyboard()); return
    if data == 'v34|status_home':
        await q.edit_message_text(_v34_status_text(), reply_markup=_v34_status_keyboard()); return
    # Ш§Щ„ЩӮШҜЩҠЩ…: Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ -> Ш§Щ„Ш¬ШҜЩҠШҜ: ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„.
    if action == 'needs_pick':
        _v33_set_waiting_state(context, 'how')
        await q.edit_message_text(_v33_how_start_text(), reply_markup=_v34_back_home_kb()); return
    if action == 'needs_team' and len(parts) >= 3:
        team = _v33_team_from_button_key(parts[2]) or _v33_find_team(parts[2])
        await q.edit_message_text(_v33_how_qualify_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if data == 'v32|how_start':
        _v33_set_waiting_state(context, 'how')
        await q.edit_message_text(_v33_how_start_text(), reply_markup=_v34_back_home_kb()); return
    if data == 'v32|calc_start':
        _v33_set_waiting_state(context, 'calc')
        await q.edit_message_text(_v33_calc_start_text(), reply_markup=_v34_back_home_kb()); return
    if action == 'how_thirds' and len(parts) >= 3:
        team = _v33_team_from_button_key(parts[2])
        await q.edit_message_text(_v33_how_thirds_text(team), reply_markup=_v33_how_qualify_keyboard(team)); return
    if action == 'opp_all' and len(parts) >= 3:
        team = _v33_team_from_button_key(parts[2])
        try:
            await q.edit_message_text("вҸі Ш¬Ш§ШұЩҠ ШӘШ¬ЩҮЩҠШІ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ...\n\nЩҠШӘЩ… Ш§Щ„ШўЩҶ ШӯШіШ§ШЁ Ш§Щ„ШӘШұЩғЩҠШЁШ§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ© ЩҒЩӮШ· ШӯШіШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ¬ШҜЩҲЩ„ FIFA.")
        except Exception:
            pass
        await q.edit_message_text(_v33_all_opponents_text(team), reply_markup=_v33_opponent_buttons(team)); return
    if action == 'opp' and len(parts) >= 4:
        team = _v33_team_from_button_key(parts[2]); slot = parts[3]
        await q.edit_message_text(_v33_opponent_detail_text(team, slot), reply_markup=_v33_opponent_buttons(team)); return
    if action == 'r32':
        await q.edit_message_text(_v33_round32_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data="v32|board")]])); return
    if _V34_PREV_V32_CALLBACK:
        return await _V34_PREV_V32_CALLBACK(update, context)

# ==================== END V34 MENU ARCHIVE/STATS + SCENARIO/HOW-QUALIFY FIXES ====================

# ==================== V35 HOW-QUALIFY FORMAT + SCENARIO PARSER FINAL PATCH ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - ШӯШ§ШіШЁШ© Ш§Щ„ШӘШЈЩҮЩ„ ШӘЩҒЩҮЩ… Ш§Щ„ЩҲШ§ЩҲ Ш§Щ„Щ…Щ„ШөЩӮШ©: ЩҲЩҒЩҲШІ/ЩҲШӘШ№Ш§ШҜЩ„/ЩҲЩҮШІЩҠЩ…Ш©.
# - ШұШҜ "ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„" ЩҠЩғЩҲЩҶ Ш№Щ…Щ„ЩҠ: Ш§Щ„Ш®Щ„Ш§ШөШ©ШҢ Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЁШ§Щ„ШЈШұЩӮШ§Щ…ШҢ ЩғЩҠЩҒ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ШҢ Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬ ШЁШ№ШҜЩҮШ§.
# - Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…ШӨШ«ШұШ© ШӘЩҸШ№ШұШ¶ ШЁШӘЩҶШіЩҠЩӮ ШЈЩҒШ®Щ…: Ш§ШіЩ… Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© + Щ…ЩҶШӘШ®ШЁШ§ШӘЩҮШ§ + Ш«Ш§Щ„Ш«ЩҮШ§ + Щ…ШЁШ§ШұШ§ШӘЩҮ + Щ„Щ…Ш§Ш°Ш§ ШӘЩҮЩ…ЩҮ.


def _v35_group_teams_pretty(code):
    teams = _v33_group_teams(code)
    return " вҖў ".join(teams) if teams else "ШәЩҠШұ Щ…ШӘЩҲЩҒШұ"


def _v35_group_card_header(code, prefix="вҡ пёҸ"):
    return f"{prefix} {_v33_group_label(code)}\n({_v35_group_teams_pretty(code)})"


def _v35_team_title(team):
    feminine = {"Ш§Щ„ШіШ№ЩҲШҜЩҠШ©", "Щ…ШөШұ", "ШӘЩҲЩҶШі", "Ш§Щ„Ш¬ШІШ§ШҰШұ", "Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ", "Ш§Щ„ШЁЩҲШіЩҶШ© ЩҲШ§Щ„ЩҮШұШіЩғ", "ШіЩҲЩҠШіШұШ§", "ЩҮШ§ЩҠШӘЩҠ", "ЩғШұЩҲШ§ШӘЩҠШ§", "ЩғЩҲЩ„ЩҲЩ…ШЁЩҠШ§", "Ш§Щ„ЩҶШұЩҲЩҠШ¬"}
    if team in feminine:
        return f"вң… ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„ {team}Шҹ"
    return f"вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ {team}Шҹ"


def _v35_match_pair_key(m):
    try:
        t1 = canonical_team_name(m.get('team1')) or m.get('team1')
        t2 = canonical_team_name(m.get('team2')) or m.get('team2')
        return frozenset([t1, t2])
    except Exception:
        return frozenset()


def _v35_make_match_result(m, mode, team=None):
    t1 = canonical_team_name(m.get('team1')) or m.get('team1')
    t2 = canonical_team_name(m.get('team2')) or m.get('team2')
    if mode in ('win', 'loss', 'draw') and team:
        if mode == 'draw':
            s1, s2 = 0, 0
        elif mode == 'win':
            s1, s2 = (1, 0) if team == t1 else (0, 1)
        else:
            s1, s2 = (0, 1) if team == t1 else (1, 0)
    elif mode == 't1_win':
        s1, s2 = 1, 0
    elif mode == 't2_win':
        s1, s2 = 0, 1
    else:
        s1, s2 = 0, 0
    return {'team1': t1, 'team2': t2, 'score1': s1, 'score2': s2, 'date': m.get('date'), 'time': m.get('time', ''), 'scenario': True}


def _v35_result_sentence(r):
    t1, t2 = r.get('team1'), r.get('team2')
    s1, s2 = int(r.get('score1') or 0), int(r.get('score2') or 0)
    if s1 > s2:
        return f"ЩҒЩҲШІ {t1} Ш№Щ„Щү {t2}"
    if s2 > s1:
        return f"ЩҒЩҲШІ {t2} Ш№Щ„Щү {t1}"
    return f"ШӘШ№Ш§ШҜЩ„ {t1} ЩҲ{t2}"


def _v35_position_in_rows(team, rows):
    for i, r in enumerate(rows or [], start=1):
        if r.get('team') == team:
            return i, r
    return None, None


def _v35_rows_with_sim_results(code, sim_results, snap=None):
    snap = snap or _v33_snapshot(False)
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    pairs = {_v35_match_pair_key(x) for x in sim_results}
    base_results = []
    for r in (g.get('results') or []):
        if _v35_match_pair_key(r) not in pairs:
            base_results.append(r)
    try:
        return _v32_stats_rows_from_results(_v33_group_teams(code), base_results + list(sim_results or []))
    except Exception:
        return g.get('rows') or []


def _v35_group_other_remaining_matches(code, team, snap=None):
    snap = snap or _v33_snapshot(False)
    team_rem = _v33_remaining_for_team(team, snap)
    team_pair = _v35_match_pair_key(team_rem[0]) if team_rem else None
    out = []
    for m in _v33_group_remaining(code, snap):
        if team_pair and _v35_match_pair_key(m) == team_pair:
            continue
        out.append(m)
    return out


def _v35_evaluate_team_outcome(team, outcome, snap=None):
    """ЩҠШұШ¬Ш№ ЩҶШӘШ§ШҰШ¬ ЩғЩ„ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү ШҜШ§Ш®Щ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЁШ№ШҜ ЩҶШӘЩҠШ¬Ш© Щ…ЩҶШӘШ®ШЁ Щ…ШӯШҜШҜШ©."""
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    rem = _v33_remaining_for_team(team, snap)
    if not code or not rem:
        return {'available': False, 'cases': []}
    target_match = rem[0]
    target_result = _v35_make_match_result(target_match, outcome, team=team)
    other_matches = _v35_group_other_remaining_matches(code, team, snap)
    modes = ['t1_win', 'draw', 't2_win']
    try:
        from itertools import product
        combos = list(product(modes, repeat=len(other_matches))) if other_matches else [()]
    except Exception:
        combos = [()]
    cases = []
    for combo in combos[:81]:
        other_results = [_v35_make_match_result(m, mode) for m, mode in zip(other_matches, combo)]
        sim_results = [target_result] + other_results
        rows = _v35_rows_with_sim_results(code, sim_results, snap)
        pos, row = _v35_position_in_rows(team, rows)
        other_txt = "ШҢ ".join(_v35_result_sentence(r) for r in other_results) if other_results else "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү Щ…ШӨШ«ШұШ©"
        cases.append({'pos': pos or 99, 'row': row or {}, 'rows': rows, 'other': other_txt, 'target_result': target_result, 'other_results': other_results})
    pts_after = None
    if cases:
        try:
            pts_after = int((cases[0].get('row') or {}).get('Pts') or 0)
        except Exception:
            pts_after = None
    return {'available': True, 'cases': cases, 'pts_after': pts_after, 'target_match': target_match, 'target_result': target_result}


def _v35_outcome_status_line(team, outcome, snap=None):
    ev = _v35_evaluate_team_outcome(team, outcome, snap)
    if not ev.get('available'):
        return None, ev
    cases = ev.get('cases') or []
    pts = ev.get('pts_after')
    positions = [int(c.get('pos') or 99) for c in cases]
    m = ev.get('target_match') or {}
    opp = (m.get('team2') if (canonical_team_name(m.get('team1')) or m.get('team1')) == team else m.get('team1')) or "Ш§Щ„Щ…ЩҶШ§ЩҒШі"
    ar_out = {'win': 'Ш§Щ„ЩҒЩҲШІ', 'draw': 'Ш§Щ„ШӘШ№Ш§ШҜЩ„', 'loss': 'Ш§Щ„Ш®ШіШ§ШұШ©'}.get(outcome, outcome)
    if positions and max(positions) <= 2:
        status = "ШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұ ШұШіЩ…ЩҠ"
    elif positions and any(p <= 2 for p in positions) and any(p == 3 for p in positions):
        status = "ЩӮШҜ ЩҠШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұЩӢШ§ ШЈЩҲ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү"
    elif positions and any(p <= 2 for p in positions):
        status = "ЩҠШЁЩӮЩҠ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ Щ…Щ…ЩғЩҶЩӢШ§ ШЁШҙШұШ· ЩҶШӘШ§ШҰШ¬ ШЈШ®ШұЩү"
    elif positions and any(p == 3 for p in positions):
        status = "ЩҠШҜШ®Щ„ЩҮ Щ…ШіШ§Шұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«"
    else:
        status = "ЩҠШ®ШұШ¬ЩҮ ШЈЩҲ ЩҠШөШ№Щ‘ШЁ ЩҲШ¶Ш№ЩҮ Ш¬ШҜЩӢШ§"
    pts_txt = f"{pts} ЩҶЩӮШ§Ш·" if pts is not None else "ШұШөЩҠШҜ Ш¬ШҜЩҠШҜ"
    return f"- {ar_out} Ш№Щ„Щү/ШЈЩ…Ш§Щ… {opp} вһң {pts_txt} вһң {status}", ev


def _v35_third_path_examples(team, snap=None):
    snap = snap or _v33_snapshot(False)
    examples = []
    for outcome in ['win', 'draw', 'loss']:
        ev = _v35_evaluate_team_outcome(team, outcome, snap)
        if not ev.get('available'):
            continue
        for c in ev.get('cases') or []:
            if int(c.get('pos') or 99) == 3:
                tr = c.get('target_result') or {}
                examples.append((outcome, _v35_result_sentence(tr), c.get('other') or '', int((c.get('row') or {}).get('Pts') or 0)))
                break
    return examples


def _v35_current_third_direct_match(gcode, third_team, snap=None):
    snap = snap or _v33_snapshot(False)
    rem = _v33_remaining_for_team(third_team, snap) if third_team else []
    if rem:
        return rem[0]
    for m in _v33_group_remaining(gcode, snap):
        t1 = canonical_team_name(m.get('team1')) or m.get('team1')
        t2 = canonical_team_name(m.get('team2')) or m.get('team2')
        if third_team in (t1, t2):
            return m
    gr = _v33_group_remaining(gcode, snap)
    return gr[0] if gr else None


def _v35_related_thirds_lines(team, snap=None, target_pts=None, limit=7):
    snap = snap or _v33_snapshot(False)
    code = _v33_team_group(team)
    lines = []
    shown = 0
    for tr in _v33_current_thirds(snap):
        gcode = tr.get('group')
        if not gcode or gcode == code:
            continue
        status, reason = _v33_third_group_status(gcode, snap)
        if status == 'impossible':
            continue
        third_team = tr.get('team') or '-'
        pts = int(tr.get('Pts') or 0)
        gd = int(tr.get('GD') or 0)
        tag = "вҡ пёҸ ШөШ№ШЁ" if status == 'weak' else "вң… ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁ"
        match = _v35_current_third_direct_match(gcode, third_team, snap)
        match_txt = _v33_format_remaining_match(match) if match else "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© Щ…ШӘШЁЩӮЩҠШ© Щ…ШЁШ§ШҙШұШ©"
        max_pts = pts + (3 if match else 0)
        base_target = target_pts if target_pts is not None else int((_v33_group_row(team, snap)[2] or {}).get('Pts') or 0)
        lines.append(_v35_group_card_header(gcode, "вҡ пёҸ" if status == 'weak' else "рҹҘү"))
        lines.append(f"Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ: {third_team} вҖ” {pts} ЩҶЩӮШ§Ш· вҖ” Ш§Щ„ЩҒШ§ШұЩӮ {gd:+d} вҖ” {tag}")
        lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӨШ«ШұШ©: {match_txt}")
        lines.append(f"Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШӘЩҠ ШӘШіШ§Ш№ШҜ {team}: ШӘШ№Ш«Шұ {third_team} ШЈЩҲ ШЁЩӮШ§ШӨЩҮ Ш®Щ„ЩҒ {team} ШЁШ§Щ„ЩҶЩӮШ§Ш·/Ш§Щ„ЩҒШ§ШұЩӮ.")
        if max_pts > base_target:
            lines.append(f"Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШӘЩҠ ШӘШ¶Шұ {team}: ЩҒЩҲШІ {third_team} ЩӮШҜ ЩҠШұЩҒШ№ЩҮ ШҘЩ„Щү {max_pts} ЩҶЩӮШ§Ш· ЩҲЩҠШӘЩӮШҜЩ… ЩҒЩҠ ШӘШұШӘЩҠШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
        else:
            lines.append(f"Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШӘЩҠ ШӘШ¶Шұ {team}: ШӘШӯШіЩҶ ЩҒШ§ШұЩӮ {third_team} ШҘШ°Ш§ ШЁЩӮЩҠ ЩӮШұЩҠШЁЩӢШ§ ШЁШ§Щ„ЩҶЩӮШ§Ш·.")
        lines.append(f"Щ„ЩҠЩҮ ШӘЩҮЩ… {team}Шҹ Щ„ШЈЩҶЩҮШ§ ЩӮШҜ ШӘШ№Ш·ЩҠ Ш«Ш§Щ„Ш«ЩӢШ§ ЩҠЩҶШ§ЩҒШіЩҮ Ш№Щ„Щү ШЈШӯШҜ Щ…ЩӮШ§Ш№ШҜ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«ШҢ ЩҲШӘШ№Ш«ШұЩҮШ§ ЩҠЩӮЩҲЩ‘ЩҠ Щ…ЩҲЩӮЩҒ {team}.")
        lines.append("")
        shown += 1
        if shown >= limit:
            break
    if not lines:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ Ш«ЩҲШ§Щ„Ш« Щ…ШӨШ«ШұШ© ЩҲШ§Ш¶ШӯШ© Ш§Щ„ШўЩҶ ШЈЩҲ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ ШәЩҠШұ Щ…ЩғШӘЩ…Щ„Ш©.")
    return lines


def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    rem = _v33_remaining_for_team(team, snap)
    title = _v35_team_title(team)
    lines = [title, ""]

    # 1) Ш§Щ„Ш®Щ„Ш§ШөШ© ШЈЩҲЩ„ЩӢШ§
    if 'Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ' in status_txt:
        lines += ["вң… Ш§Щ„Ш®Щ„Ш§ШөШ©", "ШӯШіЩ… Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩҲЩ„Ш§ ЩҠШӯШӘШ§Ш¬ ЩҶШӘШ§ШҰШ¬ ШЈШ®ШұЩү.", ""]
    elif 'Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠ' in status_txt:
        lines += ["вқҢ Ш§Щ„Ш®Щ„Ш§ШөШ©", "Ш§ЩҶШӘЩҮШӘ ЩҒШұШөЩҮ ШӯШіШ§ШЁЩҠЩӢШ§.", ""]
    else:
        win_line, win_ev = _v35_outcome_status_line(team, 'win', snap)
        draw_line, draw_ev = _v35_outcome_status_line(team, 'draw', snap)
        loss_line, loss_ev = _v35_outcome_status_line(team, 'loss', snap)
        lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©")
        if win_line:
            # ШЈЩҲЩ„ЩҲЩҠШ©: ШҘШ°Ш§ Ш§Щ„ЩҒЩҲШІ ЩҠШ¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ЩҶШЁШҜШЈ ШЁЩҮШ§.
            if win_ev.get('cases') and max(int(c.get('pos') or 99) for c in win_ev.get('cases')) <= 2:
                lines.append("Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҠШӨЩҮЩ„ЩҮ ШұШіЩ…ЩҠЩӢШ§ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32.")
            else:
                lines.append("Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҠШұЩҒШ№ ЩҒШұШөЩҮ ШЁЩӮЩҲШ©ШҢ ЩҲЩӮШҜ ЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү ШҜШ§Ш®Щ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.")
        if draw_line and draw_ev.get('cases') and max(int(c.get('pos') or 99) for c in draw_ev.get('cases')) <= 2:
            lines.append("Ш§Щ„ШӘШ№Ш§ШҜЩ„ ЩҠЩғЩҒЩҠЩҮ Щ„Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ ШӯШіШЁ Ш§Щ„ШӯШіШЁШ© Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
        lines.append("")

    # 2) Ш§Щ„ЩҲШ¶Ш№ Ш§Щ„ШӯШ§Щ„ЩҠ
    lines.append("рҹ“Ҡ ЩҲШ¶Ш№ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ")
    lines.append(f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: {_v33_group_label(code)}")
    if code:
        lines.append(f"({_v35_group_teams_pretty(code)})")
    lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: {status_txt}")
    if row:
        lines.append(f"Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШӯШ§Щ„ЩҠ: {pos} вҖ” Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„ЩҒШ§ШұЩӮ {int(row.get('GD') or 0):+d}")
    if rem:
        lines.append(f"Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©: {_v33_format_remaining_match(rem[0])}")
    lines.append("")

    if 'Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ' in status_txt or 'Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠ' in status_txt:
        return "\n".join(lines).strip()

    # 3) Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЁШ§Щ„ШЈШұЩӮШ§Щ…
    lines.append("вң… Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЁШ§Щ„ШЈШұЩӮШ§Щ…")
    any_out = False
    outcome_evals = {}
    for outcome in ['win', 'draw', 'loss']:
        line, ev = _v35_outcome_status_line(team, outcome, snap)
        outcome_evals[outcome] = ev
        if line:
            lines.append(line)
            any_out = True
    if not any_out:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© Щ…ШӘШЁЩӮЩҠШ© ЩҲШ§Ш¶ШӯШ© Щ„ЩҮШ°Ш§ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩҠ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    lines.append("")

    # 4) ЩғЩҠЩҒ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§Шҹ
    third_examples = _v35_third_path_examples(team, snap)
    lines.append("рҹҘү ЩғЩҠЩҒ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§Шҹ")
    if third_examples:
        lines.append(f"ЩӮШҜ ЩҠШөШЁШӯ {team} Ш«Ш§Щ„Ш« Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ЩҒЩҠ ЩҮШ°ЩҮ Ш§Щ„ШӯШ§Щ„Ш§ШӘ:")
        for _outcome, target_txt, other_txt, pts_after in third_examples[:4]:
            lines.append(f"- {target_txt}" + (f" + {other_txt}" if other_txt and other_txt != "Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү Щ…ШӨШ«ШұШ©" else "") + f" вһң ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҖ{pts_after} ЩҶЩӮШ§Ш·")
    else:
        lines.append("ШӯШіШЁ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© Ш§Щ„ШўЩҶШҢ Ш·ШұЩҠЩӮЩҮ Ш§Щ„ШЈЩӮШұШЁ ЩҠЩғЩҲЩҶ Ш№ШЁШұ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЈЩҲ Ш§Щ„Ш®ШұЩҲШ¬ШҢ ЩҲЩ„Ш§ ЩҠШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш« ЩҲШ§Ш¶Шӯ Щ…ЩҶ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    lines.append("")

    # 5) ШҘШ°Ш§ ШөШ§Шұ Ш«Ш§Щ„Ш« ЩҲШҙ ЩҠШӯШӘШ§Ш¬Шҹ
    target_third_pts = None
    if third_examples:
        target_third_pts = max(x[3] for x in third_examples if len(x) >= 4)
    elif row:
        try:
            target_third_pts = int(row.get('Pts') or 0)
        except Exception:
            target_third_pts = None
    lines.append("ШЁШ№ШҜ Щ…Ш§ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ШҢ Щ…Ш§Ш°Ш§ ЩҠШӯШӘШ§Ш¬Шҹ")
    lines.append("ЩҠШӘШЈЩҮЩ„ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12ШҢ Щ„Ш°Щ„Щғ ЩҠШӯШӘШ§Ш¬ ШЈЩҶ ЩҠЩғЩҲЩҶ ШЈЩҒШ¶Щ„ Щ…ЩҶ 4 Ш«ЩҲШ§Щ„Ш« Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„.")
    lines.append("Ш§Щ„ШЁЩҲШӘ ЩҠШӯШ°ЩҒ ШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© ШөШ§Шұ Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ЩҠШӘШЈЩҮЩ„ШҢ ЩҲЩҠШЁЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШөШ№ШЁШ© ШЁШ№Щ„Ш§Щ…Ш© ШӘШӯШ°ЩҠШұ ЩҒЩӮШ·.")
    lines.append("")

    # 6) Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…ШӨШ«ШұШ© ШЁШӘЩҶШіЩҠЩӮ ШЈЩҒШ®Щ…
    lines.append(f"рҹҘү Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ„ЩҠ ШӘЩҮЩ… {team}")
    lines.extend(_v35_related_thirds_lines(team, snap, target_pts=target_third_pts, limit=7))
    lines.append("Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ ШӘШ№Ш·ЩҠЩғ Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…ЩҶШӘШ®ШЁ Ш«Ш§Щ„Ш«ЩӢШ§.")
    return "\n".join(lines).strip()


def _v33_how_thirds_text(team):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    lines = [f"рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« вҖ” {team}", ""]
    lines.append(f"ШҘШ°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)}ШҢ ШӘШӘЩ… Щ…ЩӮШ§ШұЩҶШӘЩҮ Щ…Ш№ Ш«ЩҲШ§Щ„Ш« ШЁШ§ЩӮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.")
    lines.append("ЩҠШӘШЈЩҮЩ„ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12ШҢ ЩҲШЈЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩҮШ§ Щ…ШіШӘШӯЩҠЩ„ ШӘЩҸШӯШ°ЩҒ Щ…ЩҶ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ.")
    lines.append("")
    lines.append(f"{_v33_group_label(code)}")
    lines.append(f"({_v35_group_teams_pretty(code)})")
    lines.append("")
    lines.append(f"рҹҘү Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ„ЩҠ ШӘЩҮЩ… {team}")
    lines.extend(_v35_related_thirds_lines(team, snap, target_pts=None, limit=10))
    return "\n".join(lines).strip()


# ШӘШӯШіЩҠЩҶ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Ш®ШөЩ… ШЁШҘШёЩҮШ§Шұ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ ШӘШӯШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШЁШөЩҠШ§ШәШ© ШЈШЁШіШ·.
def _v33_opponent_detail_text(team, slot, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code = _v33_team_group(team)
    leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(slot)}"
    current_slot, current_leader = _v33_third_matchup_line(code, snap)
    lines = [f"рҹҸҹпёҸ Ш§ШӯШӘЩ…Ш§Щ„ Щ…ЩҲШ§Ш¬ЩҮШ© {leader}", ""]
    lines.append(f"{team} ЩҠШЁЩӮЩү Ш«Ш§Щ„Ш« {_v33_group_label(code)}.")
    lines.append(f"({_v35_group_teams_pretty(code)})")
    lines.append("")
    if current_slot:
        lines.append("Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„ШӯШ§Щ„ЩҠШ©:")
        lines.append(f"Ш«Ш§Щ„Ш« {_v33_group_label(code)} ЩҠЩӮШ§ШЁЩ„ Щ…ШӘШөШҜШұ {_v33_group_label(current_slot)}")
        lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {current_leader or '-'}")
        lines.append("")
    lines.append("ЩҮШ°Ш§ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„ ЩҠШёЩҮШұ ШҘШ°Ш§ ШӘШәЩҠЩ‘ШұШӘ ШӘШұЩғЩҠШЁШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«ШҢ ЩҒЩҲШ¶Ш№ Ш¬ШҜЩҲЩ„ FIFA Ш«Ш§Щ„Ш« ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш®Ш§ЩҶШ©:")
    lines.append(f"Щ…ШӘШөШҜШұ {_v33_group_label(slot)}")
    lines.append(f"({_v35_group_teams_pretty(slot)})")
    lines.append("")
    lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader}")
    lines.append(f"Ш§Щ„ЩҶШӘЩҠШ¬Ш©: {team} Г— {leader}")
    lines.append("")
    lines.append("Ш§Щ„Ш®Щ„Ш§ШөШ©: Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ„Ш§ ЩҠШәЩҠЩ‘Шұ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮШӣ Ш§Щ„Ш°ЩҠ ЩҠШӘШәЩҠЩ‘Шұ ЩҮЩҲ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ ШҜЩҲШұ Ш§Щ„ЩҖ32 ШЁШіШЁШЁ ШҜШ®ЩҲЩ„ ЩҲШ®ШұЩҲШ¬ Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Щ…ЩҶ ШЈЩҒШ¶Щ„ 8.")
    return "\n".join(lines).strip()


def _v33_all_opponents_text(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code = _v33_team_group(team)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    lines = [f"рҹ“Ҡ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ© Ш№Щ„Щү Ш®ШөЩ… {team}", ""]
    lines.append(f"ШҘШ°Ш§ ШӘШЈЩҮЩ„ {team} ЩғШ«Ш§Щ„Ш« {_v33_group_label(code)}ШҢ ЩҒШ§Щ„Ш®ШөЩ… ЩҠЩғЩҲЩҶ Щ…ЩҶ Ш§Щ„Ш®Ш§ЩҶШ§ШӘ Ш§Щ„ШӘШ§Щ„ЩҠШ© ШЁШ№ШҜ ШӯШ°ЩҒ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„:")
    lines.append(f"({_v35_group_teams_pretty(code)})")
    lines.append("")
    if excluded:
        lines.append("рҹҡ« Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШӯЩҸШ°ЩҒШӘ Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ:")
        for c, reason in excluded[:8]:
            tr = _v33_third_row_for_group(c, snap) or {}
            lines.append(_v35_group_card_header(c, "вқҢ"))
            lines.append(f"Ш«Ш§Щ„Ш«ЩҮШ§ Ш§Щ„ШӯШ§Щ„ЩҠ: {tr.get('team','-')}")
            lines.append(f"Ш§Щ„ШіШЁШЁ: {reason}")
            lines.append("")
    for slot in slots:
        leader = _v33_group_leader(slot, snap) or f"Щ…ШӘШөШҜШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {_v33_group_ar(slot)}"
        lines.append(_v35_group_card_header(slot, "рҹҸҹпёҸ"))
        lines.append(f"Ш§Щ„Ш®ШөЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„: Щ…ШӘШөШҜШұ {_v33_group_label(slot)}")
        lines.append(f"ШӯШіШЁ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader}")
        lines.append("")
    if weak:
        lines.append("вҡ пёҸ Щ…Щ„Ш§ШӯШёШ©: ШЁШ№Ш¶ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШ¶Ш№ЩҮШ§ ШөШ№ШЁ Щ„ЩғЩҶЩҮШ§ Щ„Щ… ШӘЩҸШӯШ°ЩҒ Щ„ШЈЩҶЩҮШ§ Щ…Ш§ ШІШ§Щ„ШӘ Щ…Щ…ЩғЩҶШ© ШӯШіШ§ШЁЩҠЩӢШ§.")
    return "\n".join(lines).strip()


# ШЁШ§ШұШіШұ ШіЩҠЩҶШ§ШұЩҠЩҲШ§ШӘ ШЈЩҲШ¶Шӯ: ЩҠЩӮШЁЩ„ Ш§Щ„ЩҲШ§ЩҲ Ш§Щ„Щ…Щ„ШөЩӮШ© Щ…Ш«Щ„ ЩҲЩҒЩҲШІ/ЩҲШӘШ№Ш§ШҜЩ„/ЩҲЩҮШІЩҠЩ…Ш©.
def _v33_detect_scenario_items(text):
    s = _v34_normalize_scenario_text(text or '') if '_v34_normalize_scenario_text' in globals() else normalize_name(text or '')
    s = re.sub(r'\s+ЩҲ(?=(?:ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|ЩҠЩҶШӘШөШұ|Ш§ЩҶШӘШөШ§Шұ|Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|Ш§ЩҶЩҮШІЩ…|ЩҠЩҶЩҮШІЩ…|ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„|ШӘШ№Ш§ШҜЩ„ШӘ))', '\n', s)
    raw_parts = []
    for chunk in re.split(r'[\nШҢ,\+]+', s):
        chunk = chunk.strip()
        if not chunk:
            continue
        # Ш§ШӯШӘЩҠШ§Ш· Щ„ЩҲ ШЁЩӮЩҠШӘ ЩҲШ§ЩҲ Щ…ЩҶЩҒШөЩ„Ш©
        raw_parts.extend([p.strip() for p in re.split(r'\s+ЩҲ\s+', chunk) if p.strip()])
    items = []
    for part in raw_parts:
        outcome = None
        if re.search(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|ЩҠЩҶШӘШөШұ|Ш§ЩҶШӘШөШ§Шұ)', part):
            outcome = 'win'
        elif re.search(r'(Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|Ш§ЩҶЩҮШІЩ…|ЩҠЩҶЩҮШІЩ…)', part):
            outcome = 'loss'
        elif re.search(r'(ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„|ШӘШ№Ш§ШҜЩ„ШӘ)', part):
            outcome = 'draw'
        if not outcome:
            continue
        tm = _v33_find_team(part)
        if not tm:
            tmp = re.sub(r'(ЩҒЩҲШІ|ЩҠЩҒЩҲШІ|ШӘЩҒЩҲШІ|ЩҒШ§ШІШӘ|ЩҠЩҶШӘШөШұ|Ш§ЩҶШӘШөШ§Шұ|Ш®ШіШ§ШұШ©|ЩҮШІЩҠЩ…Ш©|Ш§ЩҶЩҮШІШ§Щ…|ЩҠШ®ШіШұ|ШӘШ®ШіШұ|Ш®ШіШұ|Ш§ЩҶЩҮШІЩ…|ЩҠЩҶЩҮШІЩ…|ШӘШ№Ш§ШҜЩ„|ЩҠШӘШ№Ш§ШҜЩ„|ШӘШӘШ№Ш§ШҜЩ„|ШӘШ№Ш§ШҜЩ„ШӘ)', ' ', part)
            tm = _v33_find_team(tmp)
        if tm:
            items.append((tm, outcome, _v33_parse_score_pair(part)))
    return items

# ==================== END V35 HOW-QUALIFY FORMAT + SCENARIO PARSER FINAL PATCH ====================

# ==================== V36 FULL AGREEMENTS PATCH ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - ШІШұ ШҘШӯШөШ§ШҰЩҠШ§ШӘ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШҜШ§Ш®Щ„ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ЩҠЩҒШӘШӯ ЩҒШ№Щ„ЩҠЩӢШ§ (callback v32 ЩҲЩ„ЩҠШі v34).
# - Ш№ЩҶШҜ Ш§Ш®ШӘЩҠШ§Шұ/ЩғШӘШ§ШЁШ© Щ…ЩҶШӘШ®ШЁ ЩҠШёЩҮШұ: Ш¬Ш§ШұЩҠ Ш¬Щ…Ш№ Щ…Ш№Щ„ЩҲЩ…Ш§ШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁШҢ ЩҲЩ„Ш§ ЩҠШ№Щ„ЩӮ ШЁШөЩ…ШӘ.
# - ШЁШӯШ« Ш§Щ„Щ…Щ„Ш®Шө ШЁШ§Щ„ШІШұ: ЩҠШ·Щ„ШЁ Ш§ШіЩ… Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҒЩӮШ· ШЁШҜЩҲЩҶ ШЈЩ…Шұ.
# - ШҘШұШіШ§Щ„ Щ…Щ„ЩҒ Excel ЩҠШ№Ш·ЩҠ ШЈШІШұШ§Шұ: Ш§ШіШӘЩҠШұШ§ШҜ Ш§Щ„Щ…Щ„ЩҒ Ш«Щ… Ш§Ш№ШӘЩ…Ш§ШҜ/ШҘЩ„ШәШ§ШЎ.
# - ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӘШ№ШұШ¶ Щ„Ш№ШЁ: X/3.
# - ЩҶШӘШ§ШҰШ¬ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ЩҒЩҠЩҮШ§ ШІШұ ШіШӯШЁ ЩғЩ„ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҶШөЩӢШ§ ШЁШҜЩҲЩҶ ЩҮШҜШ§ЩҒЩҠЩҶ.
# - Ш§Щ„ШӘШЈЩҮЩ„ ЩҲШ§Щ„Щ…ШәШ§ШҜШұШ© ШІШұ ЩҲШ§ШӯШҜ ЩҠШ№ШұШ¶ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ ЩҲШ§Щ„Щ…ШәШ§ШҜШұЩҠЩҶ Щ…Ш№ЩӢШ§: 32 ЩҲ16.
# - ШӯЩҒШё Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ ЩҲШ§Щ„Щ…Щ„Ш®ШөШ§ШӘ ЩҲШ§Щ„ШЈЩҮШҜШ§ЩҒ ЩҒЩҠ Щ…Ш¬Щ„ШҜ Ш«Ш§ШЁШӘ ЩӮШҜШұ Ш§Щ„ШҘЩ…ЩғШ§ЩҶ.
# - Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ© ШӘШӘШӯШҜШ« Щ…Ш№ ШЈЩҠ ШӘЩҒШ§Ш№Щ„ ЩҶШөЩҠ ШЁШҜЩҲЩҶ /start.

import shutil as _v36_shutil

V36_PERSISTENT_BASENAMES = {
    "users.json",
    "users_backup.json",
    "match_summaries.json",
    "match_highlights.json",
    "goals_data.json",
    "youtube_goal_scorers.json",
    "youtube_descriptions_cache.json",
    "fantasy_access_users.json",
}


def _v36_data_dir():
    candidates = []
    env_dir = os.environ.get("BOT_DATA_DIR") or os.environ.get("DATA_DIR")
    if env_dir:
        candidates.append(env_dir)
    candidates.append("/data")
    candidates.append(".")
    for d in candidates:
        try:
            os.makedirs(d, exist_ok=True)
            test = os.path.join(d, ".write_test")
            with open(test, "w", encoding="utf-8") as f:
                f.write("ok")
            try:
                os.remove(test)
            except Exception:
                pass
            return d
        except Exception:
            continue
    return "."


V36_DATA_DIR = _v36_data_dir()


def _v36_persistent_path(path):
    base = os.path.basename(str(path or ""))
    if base in V36_PERSISTENT_BASENAMES:
        return os.path.join(V36_DATA_DIR, base)
    return str(path)


_V36_PREV_LOAD_JSON = globals().get("_v32_load_json")
_V36_PREV_SAVE_JSON = globals().get("_v32_save_json")


def _v36_migrate_file(base):
    try:
        dst = os.path.join(V36_DATA_DIR, base)
        src = base
        if V36_DATA_DIR != "." and os.path.exists(src) and not os.path.exists(dst):
            _v36_shutil.copy2(src, dst)
    except Exception:
        pass


for _v36_base in list(V36_PERSISTENT_BASENAMES):
    _v36_migrate_file(_v36_base)


# Ш«ШЁЩ‘ШӘ ШЈШіЩ…Ш§ШЎ Ш§Щ„Щ…Щ„ЩҒШ§ШӘ Ш№Щ„Щү Ш§Щ„Щ…ШіШ§Шұ Ш§Щ„ШҜШ§ШҰЩ….
try:
    V32_USERS_FILE = _v36_persistent_path("users.json")
    MATCH_SUMMARIES_FILE = _v36_persistent_path("match_summaries.json")
    MATCH_HIGHLIGHTS_FILE = MATCH_SUMMARIES_FILE
    GOALS_DATA_FILE = _v36_persistent_path("goals_data.json")
    YOUTUBE_GOAL_SCORERS_FILE = GOALS_DATA_FILE
except Exception:
    pass


def _v32_load_json(path, default=None):
    default = {} if default is None else default
    real = _v36_persistent_path(path)
    try:
        if os.path.exists(real):
            with open(real, "r", encoding="utf-8") as f:
                obj = json.load(f)
            return obj if isinstance(obj, type(default)) else default
    except Exception:
        pass
    try:
        if real != str(path) and os.path.exists(str(path)):
            with open(str(path), "r", encoding="utf-8") as f:
                obj = json.load(f)
            return obj if isinstance(obj, type(default)) else default
    except Exception:
        pass
    if _V36_PREV_LOAD_JSON and real == str(path):
        try:
            return _V36_PREV_LOAD_JSON(path, default)
        except Exception:
            pass
    return default


def _v32_save_json(path, data):
    real = _v36_persistent_path(path)
    try:
        os.makedirs(os.path.dirname(real) or ".", exist_ok=True)
        tmp = real + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data or {}, f, ensure_ascii=False, indent=2)
        os.replace(tmp, real)
        if os.path.basename(real) == "users.json":
            try:
                _v36_shutil.copy2(real, os.path.join(os.path.dirname(real) or ".", "users_backup.json"))
            except Exception:
                pass
        return
    except Exception:
        pass
    try:
        if _V36_PREV_SAVE_JSON:
            return _V36_PREV_SAVE_JSON(path, data)
    except Exception:
        pass


# ЩӮЩҲШ§ШҰЩ… ЩҶЩҮШ§ШҰЩҠШ© Щ…Ш№ callback ЩҠШ№Щ…Щ„ Ш¶Щ…ЩҶ Handler v32.
