_V36_PREV_HOW_QUALIFY_TEXT_FINAL = globals().get('_v33_how_qualify_text')
def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    is_out = ('Щ…ШіШӘШЁШ№ШҜ' in str(status_txt) or 'ШәШ§ШҜШұ' in str(status_txt)) and ('ШұШіЩ…ЩҠ' in str(status_txt) or 'ШәШ§ШҜШұ' in str(status_txt))
    is_qualified = ('Щ…ШӘШЈЩҮЩ„' in str(status_txt)) and ('ШұШіЩ…ЩҠ' in str(status_txt))
    if is_out or is_qualified:
        icon = 'вқҢ' if is_out else 'вң…'
        title = f"{icon} Щ…ЩҶШӘШ®ШЁ {team} ШәШ§ШҜШұ Ш§Щ„ШЁШ·ЩҲЩ„Ш©" if is_out else f"{icon} Щ…ЩҶШӘШ®ШЁ {team} ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§"
        lines = [title, ""]
        lines.append(f"Ш§Щ„Щ…ЩҶШӘШ®ШЁ: {team}")
        lines.append(f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: {_v33_group_label(code)}")
        if code:
            lines.append(f"({_v35_group_teams_pretty(code)})")
        lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: {status_txt}")
        if row:
            lines.append(f"Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШӯШ§Щ„ЩҠ: {pos} вҖ” Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')} вҖ” Щ„Ш№ШЁ: {row.get('P')}/3 вҖ” Ш§Щ„ЩҒШ§ШұЩӮ {int(row.get('GD') or 0):+d}")
        lines.append("")
        if is_out:
            lines.append("вқҢ Щ„Ш§ ШӘЩҲШ¬ШҜ Ш·ШұЩҠЩӮШ© Щ„Щ„ШӘШЈЩҮЩ„")
            lines.append("Ш§Щ„Щ…ЩҶШӘШ®ШЁ ШәШ§ШҜШұ ШұШіЩ…ЩҠЩӢШ§ШҢ ЩҲЩ„Ш§ ШӘЩҲШ¬ШҜ ШіЩҠЩҶШ§ШұЩҠЩҲЩҮШ§ШӘ ШӘШ№ЩҠШҜЩҮ Щ„Щ„Щ…ЩҶШ§ЩҒШіШ©.")
        else:
            lines.append("вң… Щ„Ш§ ЩҠШӯШӘШ§Ш¬ ШӯШіШ§ШЁШ§ШӘ ШҘШ¶Ш§ЩҒЩҠШ©")
            lines.append("Ш§Щ„Щ…ЩҶШӘШ®ШЁ Ш¶Щ…ЩҶ Щ…ЩӮШ№ШҜЩҮ ЩҒЩҠ ШҜЩҲШұ Ш§Щ„ЩҖ32 ШұШіЩ…ЩҠЩӢШ§.")
        try:
            finished = _v32_finished_matches_for_team(team, snap)
        except Exception:
            finished = []
        if finished:
            last = finished[-1]
            lines.append("")
            lines.append("ШўШ®Шұ ЩҶШӘЩҠШ¬Ш©:")
            lines.append(f"{last.get('team1')} {last.get('score1')} - {last.get('score2')} {last.get('team2')}")
        try:
            rem = _v33_remaining_for_team(team, snap)
        except Exception:
            rem = []
        if rem:
            lines.append("")
            lines.append("Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш©:")
            lines.append(_v33_format_remaining_match(rem[0]))
            if is_out:
                lines.append("Щ…Щ„Ш§ШӯШёШ©: Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Щ„Ш§ ШӘШәЩҠЩ‘Шұ ШӯШ§Щ„Ш© Ш§Щ„ШӘШЈЩҮЩ„ШҢ Щ„ЩғЩҶЩҮШ§ ШӘЩҸШӯШӘШіШЁ ЩҒЩҠ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„ЩҶЩҮШ§ШҰЩҠ.")
        return "\n".join(lines).strip()
    if _V36_PREV_HOW_QUALIFY_TEXT_FINAL:
        return _V36_PREV_HOW_QUALIFY_TEXT_FINAL(team, force)
    return f"вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ {team}Шҹ\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ©."


def _v36_split_text(text, limit=3800):
    text = str(text or '')
    if len(text) <= limit:
        return [text]
    chunks, cur = [], ''
    for line in text.splitlines():
        if len(cur) + len(line) + 1 > limit:
            chunks.append(cur.rstrip())
            cur = ''
        cur += line + '\n'
    if cur.strip():
        chunks.append(cur.rstrip())
    return chunks or [text[:limit]]


_V36_PREV_PREVIOUS_RESULTS_CALLBACK_FINAL = globals().get('previous_results_callback')
async def previous_results_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    try:
        await q.answer()
    except Exception:
        pass
    if data == 'res|all_text':
        chunks = _v36_split_text(_v36_all_results_text())
        try:
            await q.edit_message_text(chunks[0], reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№ Щ„Щ„ШӘЩҲШ§ШұЩҠШ®", callback_data="res|dates")]] if len(chunks) == 1 else []))
        except Exception:
            await q.message.reply_text(chunks[0])
        for ch in chunks[1:]:
            await q.message.reply_text(ch)
        if len(chunks) > 1:
            await q.message.reply_text("в¬…пёҸ Ш§ЩҶШӘЩҮЩү ШіШӯШЁ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Ш§Щ„ЩҶШөЩҠШ©", reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№ Щ„Щ„ШӘЩҲШ§ШұЩҠШ®", callback_data="res|dates")]]))
        return
    if data == 'res|dates':
        txt = "рҹ“Ӣ ЩҶШӘШ§ШҰШ¬ Ш§Щ„ШЁШ·ЩҲЩ„Ш©\n\nШ§Ш®ШӘШұ Ш§Щ„ШӘШ§ШұЩҠШ®ШҢ ШЈЩҲ Ш§ШіШӯШЁ Ш¬Щ…ЩҠШ№ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҶШөЩӢШ§ ШЁШҜЩҲЩҶ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ."
        try:
            await q.edit_message_text(txt, reply_markup=_v28_previous_results_keyboard())
        except Exception:
            await q.message.reply_text(txt, reply_markup=_v28_previous_results_keyboard())
        return
    if _V36_PREV_PREVIOUS_RESULTS_CALLBACK_FINAL:
        return await _V36_PREV_PREVIOUS_RESULTS_CALLBACK_FINAL(update, context)

# ==================== END V36B SMALL COMPLETION PATCH ====================


# ==================== V37 LIGHT THIRD-PATH + OFFICIAL BEST-THIRDS LINK PATCH ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - ШұШіШ§Щ„Ш© ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ ШӘШЁЩӮЩү Щ…Ш®ШӘШөШұШ© ЩҲЩҲШ§Ш¶ШӯШ©.
# - ШІШұ Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҠЩӮШіЩ… Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘЩ„Щү: Щ…Щ…ЩғЩҶ ЩҠШӘШ¬Ш§ЩҲШІ / Щ…ЩӮШ§ШұЩҶШ© ЩҒШ§ШұЩӮ / Ш®Щ„ЩҒ Щ…Ш¶Щ…ЩҲЩҶ.
# - Ш№ШҜШҜ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¶Щ…ЩҲЩҶ Ш®Щ„ЩҒ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҠШёЩҮШұ X/4.
# - ШҘШ°Ш§ ШөШ§Шұ Ш®Щ„ЩҒЩҮ 4/4 Ш«ЩҲШ§Щ„Ш« Щ…Ш¶Щ…ЩҲЩҶЩҠЩҶ = ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ Ш¶Щ…ЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲЩҠШұШӘШЁШ· ШЁЩ„ЩҲШӯШ© Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ.


def _v37_group_is_complete(code, snap=None):
    snap = snap or _v33_snapshot(False)
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    try:
        return int(g.get('remaining') or 0) == 0 and len(g.get('results') or []) >= 6
    except Exception:
        return False


def _v37_group_teams(code):
    try:
        return list(_v33_group_teams(code) or [])
    except Exception:
        for c, teams in WORLD_CUP_GROUPS:
            if c == code:
                return list(teams)
    return []


def _v37_safe_int(v, default=0):
    try:
        return int(v)
    except Exception:
        return default


def _v37_team_max_from_row(row):
    try:
        return int(row.get('Pts') or 0) + max(0, 3 - int(row.get('P') or 0)) * 3
    except Exception:
        return int((row or {}).get('Pts') or 0)


def _v37_max_third_points_for_group(code, snap=None):
    """ШЈШ№Щ„Щү ШұШөЩҠШҜ Щ…Щ…ЩғЩҶ Щ„Ш«Ш§Щ„Ш« ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЁШ№ШҜ ЩғЩ„ Ш§Щ„Щ…ШӘШЁЩӮЩҠ.
    ЩҶШіШӘШ®ШҜЩ…ЩҮШ§ Щ„Щ„ШӯШіЩ… Ш§Щ„ШұШіЩ…ЩҠ: ШҘШ°Ш§ ШЈШ№Щ„Щү Ш«Ш§Щ„Ш« Щ…Щ…ЩғЩҶ ЩҒЩҠ Щ…Ш¬Щ…ЩҲШ№Ш© ШЈЩӮЩ„ Щ…ЩҶ Щ…ЩҶШӘШ®ШЁЩғШҢ ЩҒЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш®Щ„ЩҒЩғ Щ…Ш¶Щ…ЩҲЩҶШ©.
    """
    snap = snap or _v33_snapshot(False)
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    rows = g.get('rows') or []
    if len(rows) < 3:
        return 0
    try:
        remaining = _v32_group_remaining_fixtures_for_sim(code, g)
    except Exception:
        remaining = []
    if not remaining:
        return _v37_safe_int(rows[2].get('Pts'))
    teams = _v37_group_teams(code) or [r.get('team') for r in rows if r.get('team')]
    base_results = list(g.get('results') or [])
    # ШӯШҜ ШЈЩ…Ш§ЩҶШҢ ЩҲШ§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш·ШЁЩҠШ№ЩҠЩӢШ§ Щ„Ш§ ЩҠШӘШ¬Ш§ЩҲШІ Щ…ШӘШЁЩӮЩҠЩҮШ§ 6 Щ…ШЁШ§ШұЩҠШ§ШӘ.
    if len(remaining) > 6:
        return _v37_team_max_from_row(rows[2])
    from itertools import product
    max_pts = -1
    for combo in product([(1,0), (0,0), (0,1)], repeat=len(remaining)):
        sim_results = list(base_results)
        for m, (s1, s2) in zip(remaining, combo):
            sim_results.append({'group': code, 'team1': m.get('team1'), 'team2': m.get('team2'), 'score1': s1, 'score2': s2, 'status': 'SIM'})
        try:
            sim_rows = _v32_stats_rows_from_results(teams, sim_results)
            if len(sim_rows) >= 3:
                max_pts = max(max_pts, _v37_safe_int(sim_rows[2].get('Pts')))
        except Exception:
            continue
    return max_pts if max_pts >= 0 else _v37_team_max_from_row(rows[2])


def _v37_guaranteed_behind_groups(team, target_pts, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    my_code = _v33_team_group(team)
    out = []
    for code, _teams in WORLD_CUP_GROUPS:
        if code == my_code:
            continue
        tr = _v33_third_row_for_group(code, snap)
        if not tr:
            continue
        try:
            max_third = _v37_max_third_points_for_group(code, snap)
            if max_third < int(target_pts):
                out.append((code, tr, max_third))
        except Exception:
            pass
    return out


def _v37_apply_official_best_thirds(snap):
    if not isinstance(snap, dict):
        return snap
    status = snap.setdefault('status', {})
    qualified = list(snap.get('qualified') or [])
    for tr in list(snap.get('thirds') or []):
        code = tr.get('group')
        team = tr.get('team')
        if not code or not team:
            continue
        # Щ„Ш§ ЩҶШ№ШӘЩ…ШҜ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„ШұШіЩ…ЩҠ Щ…ЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘЩ„Ш§ ШЁШ№ШҜ Ш§ЩғШӘЩ…Ш§Щ„ Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Щ…ЩҶШӘШ®ШЁ ЩҶЩҒШіЩҮ ЩҲЩҮЩҲ Ш«Ш§Щ„Ш« ЩҒШ№Щ„ЩҠЩӢШ§.
        if not _v37_group_is_complete(code, snap):
            continue
        try:
            target_pts = int(tr.get('Pts') or 0)
        except Exception:
            continue
        behind = _v37_guaranteed_behind_groups(team, target_pts, snap)
        if len(behind) >= 4:
            tr['third_status'] = 'вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§'
            status[team] = 'вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ Ш№ШЁШұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«'
            if team not in qualified:
                qualified.append(team)
    # ШҘШІШ§Щ„Ш© Ш§Щ„ШӘЩғШұШ§Шұ Щ…Ш№ Ш§Щ„ШӯЩҒШ§Шё Ш№Щ„Щү Ш§Щ„ШӘШұШӘЩҠШЁ.
    clean = []
    for t in qualified:
        if t and t not in clean:
            clean.append(t)
    snap['qualified'] = clean[:32]
    return snap


_V37_PREV_V33_SNAPSHOT = globals().get('_v33_snapshot')
def _v33_snapshot(force=False):
    snap = _V37_PREV_V33_SNAPSHOT(force) if _V37_PREV_V33_SNAPSHOT else {}
    try:
        return _v37_apply_official_best_thirds(snap)
    except Exception:
        return snap


_V37_PREV_V32_CALCULATED_QUALIFIED = globals().get('_v32_calculated_qualified')
def _v32_calculated_qualified():
    try:
        q = list((_v33_snapshot(False) or {}).get('qualified') or [])
        if q:
            return q[:32]
    except Exception:
        pass
    return _V37_PREV_V32_CALCULATED_QUALIFIED() if _V37_PREV_V32_CALCULATED_QUALIFIED else []


_V37_PREV_STATUS_LISTS = globals().get('_v36_status_lists')
def _v36_status_lists():
    q, e = ([], [])
    if _V37_PREV_STATUS_LISTS:
        try:
            q, e = _V37_PREV_STATUS_LISTS()
        except Exception:
            q, e = [], []
    try:
        snap = _v33_snapshot(False)
        for t in (snap.get('qualified') or []):
            if t not in q:
                q.append(t)
        st = snap.get('status') or {}
        for t, s in st.items():
            if 'Щ…ШӘШЈЩҮЩ„' in str(s) and 'ШұШіЩ…ЩҠ' in str(s) and t not in q:
                q.append(t)
            if ('Щ…ШіШӘШЁШ№ШҜ' in str(s) or 'ШәШ§ШҜШұ' in str(s)) and 'ШұШіЩ…ЩҠ' in str(s) and t not in e:
                e.append(t)
    except Exception:
        pass
    return q[:32], e[:16]


def _v37_third_case_info(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    best = None
    # ЩҶЩҒШ¶Щ‘Щ„ Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„ШӘЩҠ ШӘШ№Ш·ЩҠЩҮ ШЈЩҒШ¶Щ„ ШұШөЩҠШҜ ЩҲЩҮЩҲ Ш«Ш§Щ„Ш«Шӣ ШәШ§Щ„ШЁЩӢШ§ ЩҮЩҠ ШЈЩҲШ¶Шӯ Щ…ШіШ§Шұ.
    for outcome in ['loss', 'draw', 'win']:
        ev = _v35_evaluate_team_outcome(team, outcome, snap)
        if not ev.get('available'):
            continue
        for c in ev.get('cases') or []:
            if int(c.get('pos') or 99) == 3:
                pts = _v37_safe_int((c.get('row') or {}).get('Pts'))
                item = {'outcome': outcome, 'case': c, 'pts': pts, 'target_result': c.get('target_result') or {}, 'other': c.get('other') or ''}
                if best is None or pts > best.get('pts', -1):
                    best = item
    return best


def _v37_target_third_points(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code, pos, row, rows = _v33_group_row(team, snap)
    case = _v37_third_case_info(team, snap)
    if case:
        return case.get('pts'), case
    if pos == 3 and row:
        return _v37_safe_int(row.get('Pts')), None
    if row:
        return _v37_safe_int(row.get('Pts')), None
    return None, None


def _v37_remaining_match_short_for_team(third_team, gcode, snap=None):
    snap = snap or _v33_snapshot(False)
    m = _v35_current_third_direct_match(gcode, third_team, snap)
    if not m:
        return ''
    try:
        t1 = canonical_team_name(m.get('team1')) or m.get('team1')
        t2 = canonical_team_name(m.get('team2')) or m.get('team2')
        return f"{t1} Г— {t2}"
    except Exception:
        return _v33_format_remaining_match(m)


def _v37_third_categories(team, target_pts, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    my_code = _v33_team_group(team)
    danger, compare, safe = [], [], []
    for code, _teams in WORLD_CUP_GROUPS:
        if code == my_code:
            continue
        tr = _v33_third_row_for_group(code, snap)
        if not tr:
            continue
        third_team = tr.get('team') or '-'
        pts = _v37_safe_int(tr.get('Pts'))
        played = _v37_safe_int(tr.get('P'))
        gd = _v37_safe_int(tr.get('GD'))
        current_max = _v37_team_max_from_row(tr)
        max_third = _v37_max_third_points_for_group(code, snap)
        obj = {
            'group': code, 'team': third_team, 'pts': pts, 'played': played, 'gd': gd,
            'current_max': current_max, 'max_third': max_third,
            'match': _v37_remaining_match_short_for_team(third_team, code, snap),
        }
        if max_third < target_pts:
            safe.append(obj)
        elif max_third == target_pts:
            compare.append(obj)
        else:
            danger.append(obj)
    danger.sort(key=lambda x: (-x['pts'], -x['current_max'], x['group']))
    compare.sort(key=lambda x: (-x['pts'], -x['gd'], x['group']))
    safe.sort(key=lambda x: (-x['pts'], -x['gd'], x['group']))
    return danger, compare, safe


def _v37_one_line_item(x, target_pts, team, mode):
    g = _v33_group_label(x['group'])
    base = f"- {x['team']} вҖ” {g} | Щ„Ш№ШЁ: {x['played']}/3 | {x['pts']} ЩҶЩӮШ§Ш· | ЩҒШ§ШұЩӮ {x['gd']:+d}"
    if mode == 'danger':
        if x['played'] <= 1:
            note = f"ЩҠЩ…Щ„Щғ ШЈЩғШ«Шұ Щ…ЩҶ Щ…ШЁШ§ШұШ§Ш© ЩҲЩӮШҜ ЩҠШӘШ¬Ш§ЩҲШІ {team} ШҘШ°Ш§ ЩҲШөЩ„ ЩҒЩҲЩӮ {target_pts} ЩҶЩӮШ§Ш·."
        elif x['current_max'] > target_pts:
            note = f"ЩҒЩҲШІЩҮ ЩҠШұЩҒШ№ЩҮ ЩҒЩҲЩӮ {team}."
        else:
            note = f"ЩӮШҜ ШӘЩҶШӘШ¬ ЩҮШ°ЩҮ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩӢШ§ ЩҠШӘШ¬Ш§ЩҲШІ {team}."
    elif mode == 'compare':
        note = f"ШҘШ°Ш§ ЩҲШөЩ„ ШҘЩ„Щү {target_pts} ЩҶЩӮШ§Ш· ЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ Щ…Ш№ {team}."
    else:
        note = f"ШЈЩӮШөЩү Ш«Ш§Щ„Ш« ЩҒЩҠ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ {x['max_third']} ЩҶЩӮШ§Ш·ШҢ Щ„Ш°Щ„Щғ ЩҠШЁЩӮЩү Ш®Щ„ЩҒ {team}."
    if x.get('match') and mode != 'safe':
        note += f" Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӨШ«ШұШ©: {x['match']}."
    return base + "\n  " + note


def _v37_third_path_summary_block(team, target_pts, snap=None):
    danger, compare, safe = _v37_third_categories(team, target_pts, snap)
    guaranteed = len(safe)
    lines = []
    lines.append(f"вң… Ш№ШҜШҜ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¶Щ…ЩҲЩҶ ЩҲШ¬ЩҲШҜЩҮЩ… Ш®Щ„ЩҒ {team}: {min(guaranteed,4)}/4")
    if guaranteed >= 4:
        lines.append("Ш§Щ„ШӯШ§Щ„Ш©: вң… ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ Ш¶Щ…ЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҮШ°Ш§ Ш§Щ„ШұШөЩҠШҜ.")
    elif guaranteed == 3:
        lines.append("Ш§Щ„ШӯШ§Щ„Ш©: ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩӢШ§ ШұШ§ШЁШ№ЩӢШ§ ЩҒЩӮШ· ЩҠШЁЩӮЩү Ш®Щ„ЩҒЩҮ Щ„Ш¶Щ…Ш§ЩҶ Ш§Щ„ШӘШЈЩҮЩ„.")
    elif guaranteed == 2:
        lines.append("Ш§Щ„ШӯШ§Щ„Ш©: ЩҠШӯШӘШ§Ш¬ Щ…ЩҶШӘШ®ШЁЩҠЩҶ ШҘШ¶Ш§ЩҒЩҠЩҠЩҶ ЩҠШЁЩӮЩҲЩҶ Ш®Щ„ЩҒЩҮ Щ„Ш¶Щ…Ш§ЩҶ Ш§Щ„ШӘШЈЩҮЩ„.")
    else:
        lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: ЩҠШӯШӘШ§Ш¬ {4-guaranteed} Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш«Ш§Щ„Ш«Ш© ШҘШ¶Ш§ЩҒЩҠШ© ШӘШЁЩӮЩү Ш®Щ„ЩҒЩҮ Щ„Ш¶Щ…Ш§ЩҶ Ш§Щ„ШӘШЈЩҮЩ„.")
    lines.append("")
    if danger:
        lines.append(f"рҹ”Ҙ Щ…Щ…ЩғЩҶ ЩҠШӘШ¬Ш§ЩҲШІ {team}:")
        for x in danger[:6]:
            lines.append(_v37_one_line_item(x, target_pts, team, 'danger'))
        lines.append("")
    if compare:
        lines.append("вҡ пёҸ ЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ:")
        for x in compare[:6]:
            lines.append(_v37_one_line_item(x, target_pts, team, 'compare'))
        lines.append("")
    if safe:
        lines.append(f"вң… Ш®Щ„ЩҒ {team} Щ…Ш¶Щ…ЩҲЩҶ:")
        for x in safe[:6]:
            lines.append(_v37_one_line_item(x, target_pts, team, 'safe'))
        lines.append("")
    return lines


def _v33_how_thirds_text(team):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    target_pts, case = _v37_target_third_points(team, snap)
    lines = [f"рҹҘү ЩҲШ¶Ш№ {team} ШЁЩҠЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«", ""]
    if target_pts is None:
        target_pts = 0
    lines.append(f"ШҘШ°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)} ШЁЩҖ{target_pts} ЩҶЩӮШ§Ш·ШҢ ЩҠШҜШ®Щ„ ШіШЁШ§ЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    lines.append("вң… Ш§Щ„Щ…Ш·Щ„ЩҲШЁ:")
    lines.append("ШЈЩҶ ЩҠЩғЩҲЩҶ Ш®Щ„ЩҒЩҮ 4 Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш«Ш§Щ„Ш«Ш© Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„ШҢ Щ„ШЈЩҶ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 ЩҠШӘШЈЩҮЩ„ЩҲЩҶ.")
    lines.append("")
    lines.append("рҹ“Ң ЩҲШ¶Ш№ЩҮ Ш§Щ„Щ…ШӯШӘЩ…Щ„:")
    lines.append(f"{team} вҖ” {_v33_group_label(code)}")
    lines.append(f"Ш§Щ„ЩҶЩӮШ§Ш·: {target_pts}")
    lines.append("Щ„Ш№ШЁ: 3/3" if case else "Щ„Ш№ШЁ: ШӯШіШЁ ЩҲШ¶Ш№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    lines.append("Ш§Щ„ЩҒШ§ШұЩӮ: ЩҠШӘШӯШҜШҜ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ")
    if case:
        reqs = []
        tr = case.get('target_result') or {}
        reqs.append(_v35_result_sentence(tr))
        other = case.get('other') or ''
        if other and other != 'Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү Щ…ШӨШ«ШұШ©':
            reqs.append(other)
        lines.append("")
        lines.append("рҹ“Қ Ш§Щ„Щ…ШіШ§Шұ Ш§Щ„Ш°ЩҠ ЩҠШ¬Ш№Щ„ЩҮ Ш«Ш§Щ„Ш«ЩӢШ§:")
        for r in reqs[:3]:
            lines.append(f"- {r}")
    lines.append("")
    lines.extend(_v37_third_path_summary_block(team, target_pts, snap))
    lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©:")
    lines.append(f"ШҘШ°Ш§ Ш§ЩғШӘЩ…Щ„ Ш®Щ„ЩҒ {team} ШЈШұШЁШ№Ш© Ш«ЩҲШ§Щ„Ш« Щ…Ш¶Щ…ЩҲЩҶЩҠЩҶШҢ ЩҠШөШЁШӯ Щ…ШӘШЈЩҮЩ„ЩӢШ§ ШұШіЩ…ЩҠЩӢШ§ Ш¶Щ…ЩҶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("ЩҲШҘШ°Ш§ Щ„Щ… ЩҠЩғШӘЩ…Щ„ Ш§Щ„Ш№ШҜШҜШҢ ЩҠШЁЩӮЩү ШҜШ§Ш®Щ„ Ш§Щ„ШӯШіШ§ШЁШ§ШӘ ШӯШіШЁ ЩҶШӘШ§ШҰШ¬ ШЁЩӮЩҠШ© Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ.")
    return "\n".join(lines).strip()


def _v37_outcome_simplified_line(team, outcome, snap=None):
    ev = _v35_evaluate_team_outcome(team, outcome, snap)
    if not ev.get('available'):
        return None, ev
    pts = ev.get('pts_after')
    pts_txt = f"{pts} ЩҶЩӮШ§Ш·" if pts is not None else "ШұШөЩҠШҜ Ш¬ШҜЩҠШҜ"
    m = ev.get('target_match') or {}
    t1 = canonical_team_name(m.get('team1')) or m.get('team1')
    t2 = canonical_team_name(m.get('team2')) or m.get('team2')
    opp = t2 if t1 == team else t1
    cases = ev.get('cases') or []
    positions = [int(c.get('pos') or 99) for c in cases]
    direct = positions and max(positions) <= 2
    third = positions and any(p == 3 for p in positions)
    if outcome == 'win':
        lead = f"Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp}"
    elif outcome == 'draw':
        lead = f"Ш§Щ„ШӘШ№Ш§ШҜЩ„ Щ…Ш№ {opp}"
    else:
        lead = f"Ш§Щ„Ш®ШіШ§ШұШ© ШЈЩ…Ш§Щ… {opp}"
    if direct:
        status = "ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ Щ…ШЁШ§ШҙШұ"
    elif third:
        status = "ЩӮШҜ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү"
    else:
        status = "ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШөШ№ШЁШ©"
    return f"- {lead} вһң {pts_txt} вһң {status}", ev


def _v37_how_summary_line(team, snap=None):
    win_line, win_ev = _v37_outcome_simplified_line(team, 'win', snap)
    draw_line, draw_ev = _v37_outcome_simplified_line(team, 'draw', snap)
    loss_line, loss_ev = _v37_outcome_simplified_line(team, 'loss', snap)
    m = (win_ev or {}).get('target_match') or {}
    t1 = canonical_team_name(m.get('team1')) or m.get('team1')
    t2 = canonical_team_name(m.get('team2')) or m.get('team2')
    opp = t2 if t1 == team else t1 or "Ш§Щ„Щ…ЩҶШ§ЩҒШі"
    win_direct = win_ev.get('cases') and max(int(c.get('pos') or 99) for c in win_ev.get('cases')) <= 2
    draw_direct = draw_ev.get('cases') and max(int(c.get('pos') or 99) for c in draw_ev.get('cases')) <= 2
    if win_direct and draw_direct:
        return f"Ш§Щ„ЩҒЩҲШІ ШЈЩҲ Ш§Щ„ШӘШ№Ш§ШҜЩ„ ШЈЩ…Ш§Щ… {opp} ЩҠШӨЩҮЩ„ {team} Щ…ШЁШ§ШҙШұШ© ШҘЩ„Щү ШҜЩҲШұ Ш§Щ„ЩҖ32."
    if win_direct:
        return f"Ш§Щ„ЩҒЩҲШІ ШЈЩ…Ш§Щ… {opp} ЩҠШӨЩҮЩ„ {team} Щ…ШЁШ§ШҙШұШ© ШҘЩ„Щү ШҜЩҲШұ Ш§Щ„ЩҖ32."
    if draw_direct:
        return f"Ш§Щ„ШӘШ№Ш§ШҜЩ„ ШЈЩ…Ш§Щ… {opp} ЩҠЩғЩҒЩҠ {team} Щ„Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ."
    return f"{team} ЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш© ШҘЩҠШ¬Ш§ШЁЩҠШ© ШЈЩ…Ш§Щ… {opp}ШҢ ЩҲЩӮШҜ ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү."


_V37_PREV_HOW_QUALIFY_TEXT = globals().get('_v33_how_qualify_text')
def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    # Ш§Щ„ШӯШ§Щ„Ш§ШӘ Ш§Щ„ШұШіЩ…ЩҠШ© Ш§Щ„Щ…Ш®ШӘШөШұШ© ШӘШЁЩӮЩү Щ…ЩҶ ЩҶШіШ®Ш© V36.
    if ('Щ…ШіШӘШЁШ№ШҜ' in str(status_txt) or 'ШәШ§ШҜШұ' in str(status_txt) or ('Щ…ШӘШЈЩҮЩ„' in str(status_txt) and 'ШұШіЩ…ЩҠ' in str(status_txt))):
        if _V37_PREV_HOW_QUALIFY_TEXT:
            return _V37_PREV_HOW_QUALIFY_TEXT(team, force)
    rem = _v33_remaining_for_team(team, snap)
    lines = [_v35_team_title(team), ""]
    lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©:")
    lines.append(_v37_how_summary_line(team, snap))
    lines.append("")
    lines.append("рҹ“Ҡ Ш§Щ„ЩҲШ¶Ш№ Ш§Щ„ШӯШ§Щ„ЩҠ:")
    lines.append(f"{_v33_group_label(code)}:")
    lines.append(_v35_group_teams_pretty(code))
    lines.append("")
    if row:
        lines.append(f"Ш§Щ„Щ…ШұЩғШІ: {pos}")
        lines.append(f"Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')}")
        lines.append(f"Щ„Ш№ШЁ: {row.get('P')}/3")
        lines.append(f"Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d}")
    if rem:
        lines.append("")
        lines.append("Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:")
        lines.append(_v33_format_remaining_match(rem[0]))
    lines.append("")
    lines.append("вң… ШӯШіШ§ШЁШ§ШӘ Ш§Щ„ШӘШЈЩҮЩ„:")
    for out in ['win', 'draw', 'loss']:
        ln, _ev = _v37_outcome_simplified_line(team, out, snap)
        if ln:
            lines.append(ln)
    lines.append("")
    case = _v37_third_case_info(team, snap)
    lines.append(f"рҹҘү ЩғЩҠЩҒ ЩҠШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§Шҹ")
    if case:
        reqs = []
        tr = case.get('target_result') or {}
        reqs.append(_v35_result_sentence(tr))
        other = case.get('other') or ''
        if other and other != 'Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү Щ…ШӨШ«ШұШ©':
            reqs.append(other)
        lines.append(f"ЩҠШөШЁШӯ {team} Ш«Ш§Щ„Ш« Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ШҘШ°Ш§ ШӯШҜШ« Ш§Щ„ШӘШ§Щ„ЩҠ:")
        for i, r in enumerate(reqs[:3], 1):
            lines.append(f"{i}. {r}")
        rows_case = (case.get('case') or {}).get('rows') or []
        if rows_case:
            lines.append("")
            lines.append("ЩҲЩӮШӘЩҮШ§ ЩӮШҜ ЩҠЩғЩҲЩҶ Ш§Щ„ШӘШұШӘЩҠШЁ ШЁЩҮШ°Ш§ Ш§Щ„ШҙЩғЩ„ ШӯШіШЁ Ш§Щ„ЩҶШӘЩҠШ¬Ш© ЩҲЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ:")
            for i, rr in enumerate(rows_case[:4], 1):
                lines.append(f"{i}. {rr.get('team')} вҖ” {rr.get('Pts')} ЩҶЩӮШ§Ш·")
    else:
        lines.append("Щ„Ш§ ЩҠШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш« ЩҲШ§Ш¶Шӯ Щ…ЩҶ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©Шӣ ЩҲШ¶Ш№ЩҮ Ш§Щ„ШЈЩӮШұШЁ ЩҠЩғЩҲЩҶ Ш№ШЁШұ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ ШЈЩҲ ШӘШ№Ш«ШұШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©.")
    lines.append("")
    target_pts, _case2 = _v37_target_third_points(team, snap)
    if target_pts is None and row:
        target_pts = _v37_safe_int(row.get('Pts'))
    lines.append(f"рҹҘү ШҘШ°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§:")
    lines.append("ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 Щ…Ш¬Щ…ЩҲШ№Ш©.")
    if target_pts is not None:
        danger, compare, safe = _v37_third_categories(team, target_pts, snap)
        candidates = (danger + compare)[:4]
        if candidates:
            lines.append("")
            lines.append("ШЈЩҮЩ… Ш§Щ„Щ…ЩҶШ§ЩҒШіЩҠЩҶ Ш№Щ„Щү Щ…ЩӮШ§Ш№ШҜ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШ§Щ„ЩҠЩӢШ§:")
            for x in candidates:
                lines.append(f"* {x['team']} вҖ” {_v33_group_label(x['group'])} вҖ” {x['pts']} ЩҶЩӮШ§Ш· вҖ” Щ„Ш№ШЁ {x['played']}/3")
        lines.append("")
        lines.append(f"Ш№ШҜШҜ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¶Щ…ЩҲЩҶ Ш®Щ„ЩҒ {team} ШӯШ§Щ„ЩҠЩӢШ§ ШҘШ°Ш§ ШЈШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҮШ°Ш§ Ш§Щ„ШұШөЩҠШҜ: {min(len(safe),4)}/4")
    lines.append("")
    lines.append("Щ…Щ„Ш§ШӯШёШ©:")
    lines.append("ШӘЩҒШ§ШөЩҠЩ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ ШӘШёЩҮШұ Щ…ЩҶ Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ ШЁШҜЩҲЩҶ ШҘШ·Ш§Щ„Ш© ЩҒЩҠ Ш§Щ„ШұШіШ§Щ„Ш© Ш§Щ„ШЈШіШ§ШіЩҠШ©.")
    lines.append("")
    lines.append("Ш§Ш¶ШәШ· Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ Щ„Щ…Ш№ШұЩҒШ©:")
    lines.append("рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«")
    lines.append("рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ")
    lines.append("рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    return "\n".join(lines).strip()

# ==================== END V37 LIGHT THIRD-PATH + OFFICIAL BEST-THIRDS LINK PATCH ====================


# ==================== V38 PRECISE QUALIFICATION ENGINE PATCH ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - Щ„Ш§ ЩҶШ№ШұШ¶ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩӮШЁЩ„ Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Щ…ШЁШ§ШҙШұ.
# - ЩҶШӯШіШЁ ЩғЩ„ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©ШҢ ЩҲЩ„ЩҠШі Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҒЩӮШ·.
# - Щ„Ш§ ЩҶЩғШӘШЁ "ЩӮШҜ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§" Щ„ШӯШ§Щ„Ш© 0 ЩҶЩӮШ§Ш· ШЈЩҲ Щ…ШіШ§Шұ ШәЩҠШұ Щ…ЩҒЩҠШҜ.
# - Ш§Щ„ЩҒЩҲШІ/Ш§Щ„ШӘШ№Ш§ШҜЩ„/Ш§Щ„Ш®ШіШ§ШұШ© ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҠШҙШұШӯ ШЈШ«ШұЩҮ ШЁШҜЩҲЩҶ Щ…ШЁШ§Щ„ШәШ©.
# - Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Щ„Ш§ ЩҠШёЩҮШұ ШҘЩ„Ш§ ШҘШ°Ш§ ЩғШ§ЩҶ ЩҮЩҶШ§Щғ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш« ЩҶЩҮШ§ШҰЩҠ ШЁШұШөЩҠШҜ Щ…ЩҶШ·ЩӮЩҠ.


def _v38_pair_key(m):
    try:
        t1 = canonical_team_name(m.get('team1')) or m.get('team1')
        t2 = canonical_team_name(m.get('team2')) or m.get('team2')
        return frozenset([t1, t2])
    except Exception:
        return frozenset()


def _v38_result_mode(r):
    try:
        s1 = int(r.get('score1') or 0); s2 = int(r.get('score2') or 0)
        if s1 > s2:
            return 't1_win'
        if s2 > s1:
            return 't2_win'
        return 'draw'
    except Exception:
        return 'draw'


def _v38_mode_words_for_match(m, mode):
    try:
        t1 = canonical_team_name(m.get('team1')) or m.get('team1')
        t2 = canonical_team_name(m.get('team2')) or m.get('team2')
        if mode == 'draw':
            return 'ШӘШ№Ш§ШҜЩ„'
        if mode == 't1_win':
            return f'ЩҒЩҲШІ {t1}'
        if mode == 't2_win':
            return f'ЩҒЩҲШІ {t2}'
    except Exception:
        pass
    return 'ЩҶШӘЩҠШ¬Ш© Щ…ШӨШ«ШұШ©'


def _v38_outcome_points(outcome):
    return 3 if outcome == 'win' else 1 if outcome == 'draw' else 0


def _v38_target_match_for_team(team, snap=None):
    try:
        rem = _v33_remaining_for_team(team, snap or _v33_snapshot(False))
        return rem[0] if rem else None
    except Exception:
        return None


def _v38_outcome_result_for_team_match(team, outcome, match):
    try:
        return _v35_make_match_result(match, outcome, team=team)
    except Exception:
        t1 = canonical_team_name(match.get('team1')) or match.get('team1')
        t2 = canonical_team_name(match.get('team2')) or match.get('team2')
        if outcome == 'draw':
            s1, s2 = 0, 0
        elif (outcome == 'win' and t1 == team) or (outcome == 'loss' and t2 == team):
            s1, s2 = 1, 0
        else:
            s1, s2 = 0, 1
        return {'group': match.get('group'), 'team1': t1, 'team2': t2, 'score1': s1, 'score2': s2, 'status': 'SIM'}


def _v38_all_group_scenarios(code, snap=None, forced_results=None, max_cases=729):
    """ЩҠШӯШ§ЩғЩҠ ЩғЩ„ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© Щ…Ш№ ШҘЩ…ЩғШ§ЩҶЩҠШ© ШӘШ«ШЁЩҠШӘ ЩҶШӘЩҠШ¬Ш©/ЩҶШӘШ§ШҰШ¬.
    Ш§Щ„ЩҶШӘЩҠШ¬Ш© Щ„Ш§ ШӘЩҒШӘШұШ¶ Щ…ШЁШ§ШұШ§Ш© ЩҲШ§ШӯШҜШ© ЩҒЩӮШ·Шӣ Щ„Ш°Щ„Щғ ШӘЩ…ЩҶШ№ ШЈШ®Ш·Ш§ШЎ Щ…Ш«Щ„ Ш§Щ„Ш№ШұШ§ЩӮ ЩҲШ§Щ„ШіШ№ЩҲШҜЩҠШ©.
    """
    snap = snap or _v33_snapshot(False)
    forced_results = list(forced_results or [])
    g = ((snap.get('groups') or {}).get(code, {}) or {})
    teams = _v37_group_teams(code) or [r.get('team') for r in (g.get('rows') or []) if r.get('team')]
    base_results = list(g.get('results') or [])
    try:
        remaining = list(_v32_group_remaining_fixtures_for_sim(code, g))
    except Exception:
        remaining = []
    if not remaining:
        try:
            rows = _v32_stats_rows_from_results(teams, base_results)
        except Exception:
            rows = list(g.get('rows') or [])
        return [{'rows': rows, 'results': base_results, 'forced': forced_results, 'remaining': []}]

    forced_by_pair = {}
    for fr in forced_results:
        forced_by_pair[_v38_pair_key(fr)] = fr

    free = []
    fixed = []
    for m in remaining:
        pk = _v38_pair_key(m)
        if pk in forced_by_pair:
            fixed.append(forced_by_pair[pk])
        else:
            free.append(m)

    if len(free) > 6:
        free = free[:6]
    from itertools import product
    outcomes = [(1,0), (0,0), (0,1)]
    scenarios = []
    for combo in product(outcomes, repeat=len(free)):
        sim_results = list(base_results) + list(fixed)
        for m, (s1, s2) in zip(free, combo):
            t1 = canonical_team_name(m.get('team1')) or m.get('team1')
            t2 = canonical_team_name(m.get('team2')) or m.get('team2')
            sim_results.append({'group': code, 'team1': t1, 'team2': t2, 'score1': s1, 'score2': s2, 'status': 'SIM'})
        try:
            rows = _v32_stats_rows_from_results(teams, sim_results)
        except Exception:
            rows = []
        scenarios.append({'rows': rows, 'results': sim_results, 'forced': list(fixed), 'remaining': list(free)})
        if len(scenarios) >= max_cases:
            break
    return scenarios


def _v38_position_row(team, rows):
    try:
        for i, r in enumerate(rows or [], start=1):
            if r.get('team') == team:
                return i, r
    except Exception:
        pass
    return 99, {}


def _v38_eval_next_outcome(team, outcome, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code = _v33_team_group(team)
    target = _v38_target_match_for_team(team, snap)
    if not code or not target:
        return {'available': False, 'cases': [], 'pts_after_next': None, 'target_match': target}
    forced = _v38_outcome_result_for_team_match(team, outcome, target)
    scenarios = _v38_all_group_scenarios(code, snap, [forced])
    cases = []
    for sc in scenarios:
        pos, row = _v38_position_row(team, sc.get('rows'))
        cases.append({'pos': pos, 'row': row, 'rows': sc.get('rows') or [], 'results': sc.get('results') or [], 'target_result': forced})
    code0, pos0, row0, rows0 = _v33_group_row(team, snap)
    cur_pts = _v37_safe_int((row0 or {}).get('Pts'))
    pts_after_next = cur_pts + _v38_outcome_points(outcome)
    return {'available': True, 'cases': cases, 'pts_after_next': pts_after_next, 'target_match': target, 'target_result': forced}


def _v38_case_final_pts(case):
    try:
        return int((case.get('row') or {}).get('Pts') or 0)
    except Exception:
        return 0


def _v38_classify_cases(cases):
    positions = [int(c.get('pos') or 99) for c in (cases or [])]
    if not positions:
        return {'direct_guaranteed': False, 'direct_possible': False, 'third_possible': False, 'viable_third_possible': False, 'third_cases': [], 'direct_cases': []}
    direct_cases = [c for c in cases if int(c.get('pos') or 99) <= 2]
    third_cases = [c for c in cases if int(c.get('pos') or 99) == 3]
    viable_third = [c for c in third_cases if _v38_case_final_pts(c) >= 3]
    return {
        'direct_guaranteed': len(direct_cases) == len(cases),
        'direct_possible': bool(direct_cases),
        'third_possible': bool(third_cases),
        'viable_third_possible': bool(viable_third),
        'third_cases': third_cases,
        'viable_third_cases': viable_third,
        'direct_cases': direct_cases,
    }


def _v38_next_outcome_label(team, outcome, snap=None):
    ev = _v38_eval_next_outcome(team, outcome, snap)
    if not ev.get('available'):
        return None, ev
    target = ev.get('target_match') or {}
    t1 = canonical_team_name(target.get('team1')) or target.get('team1')
    t2 = canonical_team_name(target.get('team2')) or target.get('team2')
    opp = t2 if t1 == team else t1
    if outcome == 'win':
        lead = f"Ш§Щ„ЩҒЩҲШІ Ш№Щ„Щү {opp}"
    elif outcome == 'draw':
        lead = f"Ш§Щ„ШӘШ№Ш§ШҜЩ„ Щ…Ш№ {opp}"
    else:
        lead = f"Ш§Щ„Ш®ШіШ§ШұШ© ШЈЩ…Ш§Щ… {opp}"
    return lead, ev


def _v37_outcome_simplified_line(team, outcome, snap=None):
    team = _v33_find_team(team) or team
    snap = snap or _v33_snapshot(False)
    lead, ev = _v38_next_outcome_label(team, outcome, snap)
    if not lead:
        return None, ev
    cls = _v38_classify_cases(ev.get('cases') or [])
    pts_txt = f"{ev.get('pts_after_next')} ЩҶЩӮШ§Ш·" if ev.get('pts_after_next') is not None else "ШұШөЩҠШҜ Ш¬ШҜЩҠШҜ"
    rem_count_after = 0
    try:
        row = _v33_group_row(team, snap)[2]
        rem_count_after = max(0, 3 - int((row or {}).get('P') or 0) - 1)
    except Exception:
        rem_count_after = 0

    if outcome == 'loss':
        if rem_count_after > 0:
            status = "Щ„Ш§ ШӘШӨЩҮЩ„ЩҮ Ш§Щ„ШўЩҶШҢ ЩҲЩҠШӯШӘШ§Ш¬ Ш§Щ„ЩҒЩҲШІ ЩҒЩҠЩ…Ш§ ШӘШЁЩӮЩү Щ…Ш№ ШӯШіШ§ШЁШ§ШӘ ШөШ№ШЁШ© Ш¬ШҜЩӢШ§"
        elif cls['direct_possible']:
            status = "ЩӮШҜ ЩҠШЁЩӮЩү ШҜШ§Ш®Щ„ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү"
        elif cls['viable_third_possible']:
            status = "ЩӮШҜ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ЩҲЩҠШҜШ®Щ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү"
        else:
            status = "Щ„Ш§ ШӘШӨЩҮЩ„ЩҮШҢ ЩҲШ®ШұЩҲШ¬ЩҮ ЩҠШөШЁШӯ ЩӮШұЩҠШЁЩӢШ§ Ш¬ШҜЩӢШ§"
    elif cls['direct_guaranteed']:
        status = "ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠ Щ…ШЁШ§ШҙШұ"
    elif cls['direct_possible'] and cls['viable_third_possible']:
        status = "ЩҠЩҒШӘШӯ Ш·ШұЩҠЩӮЩҠЩҶ: ШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұ ШЈЩҲ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ШЁЩӮЩҠШ© Ш§Щ„ЩҶШӘШ§ШҰШ¬"
    elif cls['direct_possible']:
        status = "ЩҠШЁЩӮЩҠ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„Щ…ШЁШ§ШҙШұ Щ…Щ…ЩғЩҶЩӢШ§ ШӯШіШЁ ШЁЩӮЩҠШ© Ш§Щ„ЩҶШӘШ§ШҰШ¬"
    elif cls['viable_third_possible']:
        status = "ЩҠШҜШ®Щ„ЩҮ Щ…ШіШ§Шұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШіШЁ ШЁЩӮЩҠШ© Ш§Щ„ЩҶШӘШ§ШҰШ¬"
    else:
        status = "Щ„Ш§ ЩҠЩғЩҒЩҠ ЩҲШӯШҜЩҮШҢ ЩҲЩҠШӯШӘШ§Ш¬ ЩҶШӘШ§ШҰШ¬ ШЈШ®ШұЩү ЩӮЩҲЩҠШ©"
    return f"- {lead} вһң {pts_txt} вһң {status}", ev


def _v38_scenario_required_lines(team, scenario, snap=None, max_lines=4):
    snap = snap or _v33_snapshot(False)
    g = _v33_team_group(team)
    base = list((((snap.get('groups') or {}).get(g, {}) or {}).get('results') or []))
    base_pairs = {_v38_pair_key(r) for r in base}
    out = []
    for r in scenario.get('results') or []:
        if _v38_pair_key(r) in base_pairs:
            continue
        try:
            out.append(_v35_result_sentence(r))
        except Exception:
            t1 = r.get('team1'); t2 = r.get('team2'); s1 = r.get('score1'); s2 = r.get('score2')
            out.append(f"{t1} {s1}-{s2} {t2}")
    return out[:max_lines]


def _v38_direct_path_lines(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    lines = []
    next_target = _v38_target_match_for_team(team, snap)
    if not next_target:
        return lines
    # Щ„Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШӘЩҠ ШЁЩӮЩҠ ЩҒЩҠЩҮШ§ Щ…ШЁШ§ШұШ§ШӘШ§ЩҶ ЩҒЩӮШ·ШҢ ЩҶШөЩҶШ№ ШіШ·ШұЩӢШ§ ШҜЩӮЩҠЩӮЩӢШ§ ЩҲЩ…Ш®ШӘШөШұЩӢШ§ ШӯШіШЁ ЩҶШӘЩҠШ¬Ш© Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈШ®ШұЩү.
    try:
        g = _v33_team_group(team)
        group_data = ((snap.get('groups') or {}).get(g, {}) or {})
        remaining = list(_v32_group_remaining_fixtures_for_sim(g, group_data))
    except Exception:
        remaining = []
    for outcome in ['win', 'draw', 'loss']:
        lead, ev = _v38_next_outcome_label(team, outcome, snap)
        if not lead:
            continue
        cls = _v38_classify_cases(ev.get('cases') or [])
        if not cls['direct_possible']:
            continue
        # ШҘШ°Ш§ Ш§Щ„ШӯШіЩ… Щ…Ш¶Щ…ЩҲЩҶ ШЁШ№ШҜ ЩҮШ°ЩҮ Ш§Щ„ЩҶШӘЩҠШ¬Ш©.
        if cls['direct_guaranteed']:
            lines.append(f"- {lead} вһң ЩҠШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұЩӢШ§.")
            continue
        # ШҘШ°Ш§ ЩҒЩҠЩҮ Щ…ШЁШ§ШұШ§Ш© ШЈШ®ШұЩү ЩҲШ§ШӯШҜШ© ЩҒЩӮШ·ШҢ ЩҶЩҲШ¶Шӯ Ш§Щ„ЩҶШӘШ§ШҰШ¬ Ш§Щ„ШӘЩҠ ШӘШіШ§Ш№ШҜЩҮ.
        other_matches = [m for m in remaining if _v38_pair_key(m) != _v38_pair_key(next_target)]
        if len(other_matches) == 1:
            m = other_matches[0]
            ok_modes = []
            for c in cls['direct_cases']:
                for r in c.get('results') or []:
                    if _v38_pair_key(r) == _v38_pair_key(m):
                        md = _v38_result_mode(r)
                        if md not in ok_modes:
                            ok_modes.append(md)
            if ok_modes:
                # ШӘШұШӘЩҠШЁ Щ…ЩҶШ·ЩӮЩҠ: ЩҒЩҲШІ ШөШ§ШӯШЁ Ш§Щ„ШЈШұШ¶ШҢ ШӘШ№Ш§ШҜЩ„ШҢ ЩҒЩҲШІ Ш§Щ„Ш¶ЩҠЩҒ.
                order = ['t1_win', 'draw', 't2_win']
                ok_modes = [x for x in order if x in ok_modes]
                modes_txt = " ШЈЩҲ ".join(_v38_mode_words_for_match(m, md) for md in ok_modes)
                t1 = canonical_team_name(m.get('team1')) or m.get('team1')
                t2 = canonical_team_name(m.get('team2')) or m.get('team2')
                lines.append(f"- {lead} + {t1} Г— {t2}: {modes_txt} вһң ЩҠШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұЩӢШ§.")
                continue
        # Щ„Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш§Щ„ШӘЩҠ ШЁЩӮЩҠ ЩҒЩҠЩҮШ§ ШЈЩғШ«Шұ Щ…ЩҶ Щ…ШЁШ§ШұШ§Ш©.
        best = cls['direct_cases'][0]
        reqs = _v38_scenario_required_lines(team, best, snap, max_lines=3)
        if reqs:
            lines.append(f"- {lead} + " + " + ".join(reqs[1:] if reqs and lead in reqs[0] else reqs[:3]) + " вһң Ш·ШұЩҠЩӮ Щ…ШЁШ§ШҙШұ Щ…Щ…ЩғЩҶ.")
        else:
            lines.append(f"- {lead} вһң Ш·ШұЩҠЩӮ Щ…ШЁШ§ШҙШұ Щ…Щ…ЩғЩҶ ШӯШіШЁ ШЁЩӮЩҠШ© Ш§Щ„ЩҶШӘШ§ШҰШ¬.")
    return lines[:4]


def _v37_third_case_info(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    g = _v33_team_group(team)
    best = None
    for sc in _v38_all_group_scenarios(g, snap):
        pos, row = _v38_position_row(team, sc.get('rows'))
        pts = _v37_safe_int((row or {}).get('Pts'))
        if pos == 3 and pts >= 3:
            item = {'case': {'pos': pos, 'row': row, 'rows': sc.get('rows') or [], 'results': sc.get('results') or []}, 'pts': pts, 'scenario': sc}
            if best is None or pts > best.get('pts', -1):
                best = item
    return best


def _v37_target_third_points(team, snap=None):
    snap = snap or _v33_snapshot(False)
    case = _v37_third_case_info(team, snap)
    if case:
        return case.get('pts'), case
    code, pos, row, rows = _v33_group_row(team, snap)
    if int(pos or 99) == 3 and row and _v37_safe_int(row.get('Pts')) >= 3:
        return _v37_safe_int(row.get('Pts')), None
    return None, None


def _v38_how_summary_line(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    rem = _v33_remaining_for_team(team, snap)
    direct_lines = _v38_direct_path_lines(team, snap)
    win_line, win_ev = _v37_outcome_simplified_line(team, 'win', snap)
    draw_line, draw_ev = _v37_outcome_simplified_line(team, 'draw', snap)
    loss_line, loss_ev = _v37_outcome_simplified_line(team, 'loss', snap)
    target = _v38_target_match_for_team(team, snap) or {}
    t1 = canonical_team_name(target.get('team1')) or target.get('team1')
    t2 = canonical_team_name(target.get('team2')) or target.get('team2')
    opp = t2 if t1 == team else t1 or 'Ш§Щ„Щ…ЩҶШ§ЩҒШі'
    if len(rem) > 1:
        if direct_lines:
            return f"{team} Щ„ШҜЩҠЩҮ {len(rem)} Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ШӘШЁЩӮЩҠШ©. Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„ШЈЩҒШ¶Щ„ ЩҠШЁШҜШЈ ШЁЩҶШӘЩҠШ¬Ш© ЩӮЩҲЩҠШ© ШЈЩ…Ш§Щ… {opp}ШҢ ЩҲШ§Щ„ШӯШіЩ… ЩҠШ№ШӘЩ…ШҜ Ш№Щ„Щү ШЁЩӮЩҠШ© Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."
        third = _v37_third_case_info(team, snap)
        if third:
            return f"{team} ЩҠШӯШӘШ§Ш¬ Ш¬Щ…Ш№ Ш§Щ„ЩҶЩӮШ§Ш· ЩҒЩҠ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© ШӯШӘЩү ЩҠШҜШ®Щ„ Щ…ШіШ§Шұ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«."
        return f"{team} ЩҠШӯШӘШ§Ш¬ ЩҶШӘШ§ШҰШ¬ ЩӮЩҲЩҠШ© ЩҒЩҠ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©Шӣ ШЈЩҠ ШӘШ№Ш«Шұ Ш¬ШҜЩҠШҜ ЩҠШөШ№Щ‘ШЁ Щ…ЩҲЩӮЩҒЩҮ ЩғШ«ЩҠШұЩӢШ§."
    # Щ…ШЁШ§ШұШ§Ш© ЩҲШ§ШӯШҜШ© Щ…ШӘШЁЩӮЩҠШ©
    for ev, label in [(win_ev, 'Ш§Щ„ЩҒЩҲШІ'), (draw_ev, 'Ш§Щ„ШӘШ№Ш§ШҜЩ„')]:
        cls = _v38_classify_cases((ev or {}).get('cases') or [])
        if cls.get('direct_guaranteed'):
            if label == 'Ш§Щ„ЩҒЩҲШІ' and _v38_classify_cases((draw_ev or {}).get('cases') or []).get('direct_guaranteed'):
                return f"Ш§Щ„ЩҒЩҲШІ ШЈЩҲ Ш§Щ„ШӘШ№Ш§ШҜЩ„ ШЈЩ…Ш§Щ… {opp} ЩҠШӨЩҮЩ„ {team} Щ…ШЁШ§ШҙШұШ© ШҘЩ„Щү ШҜЩҲШұ Ш§Щ„ЩҖ32."
            return f"{label} ШЈЩ…Ш§Щ… {opp} ЩҠШӨЩҮЩ„ {team} Щ…ШЁШ§ШҙШұШ© ШҘЩ„Щү ШҜЩҲШұ Ш§Щ„ЩҖ32."
    if direct_lines:
        return f"{team} ЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш© ШӘШ®ШҜЩ…ЩҮ ЩҒЩҠ Щ…ШЁШ§ШұШ§ШӘЩҮ ЩҲЩ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„ШЈШ®ШұЩү Щ„Щ„ЩҲШөЩҲЩ„ ШҘЩ„Щү Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠШҢ ЩҲШҘЩ„Ш§ ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«."
    third = _v37_third_case_info(team, snap)
    if third:
        return f"{team} ЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш© ШҘЩҠШ¬Ш§ШЁЩҠШ© ШЈЩ…Ш§Щ… {opp} ШӯШӘЩү ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«."
    return f"Щ…ЩҲЩӮЩҒ {team} ШөШ№ШЁШҢ ЩҲЩҠШӯШӘШ§Ш¬ ЩҶШӘЩҠШ¬Ш© ЩӮЩҲЩҠШ© ЩҲШӘШ№Ш«ШұШ§ШӘ ШЈШ®ШұЩү ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."


_V38_PREV_HOW_QUALIFY_TEXT = globals().get('_v33_how_qualify_text')
def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, 'вҡ”пёҸ Щ…Ш§ ШІШ§Щ„ ЩҠЩҶШ§ЩҒШі')
    if ('Щ…ШіШӘШЁШ№ШҜ' in str(status_txt) or 'ШәШ§ШҜШұ' in str(status_txt) or ('Щ…ШӘШЈЩҮЩ„' in str(status_txt) and 'ШұШіЩ…ЩҠ' in str(status_txt))):
        if _V38_PREV_HOW_QUALIFY_TEXT:
            return _V38_PREV_HOW_QUALIFY_TEXT(team, force)
    rem = _v33_remaining_for_team(team, snap)
    lines = [_v35_team_title(team), ""]
    lines.append("вң… Ш§Щ„Ш®Щ„Ш§ШөШ©:")
    lines.append(_v38_how_summary_line(team, snap))
    lines.append("")
    lines.append("рҹ“Ҡ Ш§Щ„ЩҲШ¶Ш№ Ш§Щ„ШӯШ§Щ„ЩҠ:")
    lines.append(f"{_v33_group_label(code)}:")
    lines.append(_v35_group_teams_pretty(code))
    lines.append("")
    if row:
        lines.append(f"Ш§Щ„Щ…ШұЩғШІ: {pos}")
        lines.append(f"Ш§Щ„ЩҶЩӮШ§Ш·: {row.get('Pts')}")
        lines.append(f"Щ„Ш№ШЁ: {row.get('P')}/3")
        lines.append(f"Ш§Щ„ЩҒШ§ШұЩӮ: {int(row.get('GD') or 0):+d}")
    if rem:
        lines.append("")
        lines.append("Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш©:" if len(rem) > 1 else "Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:")
        lines.append(_v33_format_remaining_match(rem[0]))
        if len(rem) > 1:
            lines.append(f"Щ…ШӘШЁЩӮЩҠ ШЁШ№ШҜ ЩҮШ°ЩҮ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©: {len(rem)-1} Щ…ШЁШ§ШұШ§Ш©")
    lines.append("")
    direct_lines = _v38_direct_path_lines(team, snap)
    if direct_lines:
        lines.append("рҹҸҶ Ш§Щ„Ш·ШұЩҠЩӮ Ш§Щ„Щ…ШЁШ§ШҙШұ:")
        lines.extend(direct_lines)
        lines.append("")
    lines.append("вң… ШӯШіШ§ШЁШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш©:")
    for out in ['win', 'draw', 'loss']:
        ln, _ev = _v37_outcome_simplified_line(team, out, snap)
        if ln:
            lines.append(ln)
    lines.append("")
    case = _v37_third_case_info(team, snap)
    lines.append(f"рҹҘү Щ…ШӘЩү ЩҠШҜШ®Щ„ {team} Щ…ШіШ§Шұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«Шҹ")
    if case:
        pts = case.get('pts')
        reqs = _v38_scenario_required_lines(team, case.get('scenario') or {}, snap, max_lines=4)
        lines.append(f"ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩӢШ§ ШЁШұШөЩҠШҜ {pts} ЩҶЩӮШ§Ш· ШЈЩҲ ШЈЩғШ«ШұШҢ ЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
        if reqs:
            lines.append("Щ…Ш«Ш§Щ„ Щ…ШіШ§Шұ ЩҠШ¬Ш№Щ„ЩҮ Ш«Ш§Щ„Ш«ЩӢШ§:")
            for i, r in enumerate(reqs, start=1):
                lines.append(f"{i}. {r}")
        rows_case = ((case.get('case') or {}).get('rows') or [])[:4]
        if rows_case:
            lines.append("")
            lines.append("ШӘШұШӘЩҠШЁ ЩҮШ°Ш§ Ш§Щ„Щ…Ш«Ш§Щ„:")
            for i, rr in enumerate(rows_case, start=1):
                lines.append(f"{i}. {rr.get('team')} вҖ” {rr.get('Pts')} ЩҶЩӮШ§Ш·")
    else:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ШЈЩҒШ¶Щ„ Ш«ЩҲШ§Щ„Ш« ЩҲШ§Ш¶Шӯ ЩҲЩ…ЩҒЩҠШҜ Щ…ЩҶ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©Шӣ Ш·ШұЩҠЩӮЩҮ ЩҠЩғЩҲЩҶ Щ…ШЁШ§ШҙШұЩӢШ§ ШЈЩҲ ЩҠШөШЁШӯ Щ…ЩҲЩӮЩҒЩҮ ШөШ№ШЁЩӢШ§ Ш¬ШҜЩӢШ§.")
    lines.append("")
    target_pts, _case2 = _v37_target_third_points(team, snap)
    if target_pts is not None:
        danger, compare, safe = _v37_third_categories(team, target_pts, snap)
        lines.append(f"Ш№ШҜШҜ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¶Щ…ЩҲЩҶ Ш®Щ„ЩҒ {team} ШҘШ°Ш§ ШЈШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҮШ°Ш§ Ш§Щ„ШұШөЩҠШҜ: {min(len(safe),4)}/4")
    lines.append("")
    lines.append("Ш§Ш¶ШәШ· Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ Щ„Щ…Ш№ШұЩҒШ©:")
    lines.append("рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«")
    lines.append("рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ")
    lines.append("рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    return "\n".join(lines).strip()


def _v33_how_thirds_text(team):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    target_pts, case = _v37_target_third_points(team, snap)
    lines = [f"рҹҘү Ш·ШұЩҠЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« вҖ” {team}", ""]
    if target_pts is None:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш« ЩҲШ§Ш¶Шӯ ЩҲЩ…ЩҒЩҠШҜ Щ…ЩҶ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
        lines.append("ШҘШ°Ш§ ШӘШәЩҠЩ‘ШұШӘ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш«ШҢ ШіЩҠШӯШіШЁЩҮ Ш§Щ„ШЁЩҲШӘ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§.")
        return "\n".join(lines).strip()
    lines.append(f"ШҘШ°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)} ШЁЩҖ{target_pts} ЩҶЩӮШ§Ш·ШҢ ЩҠШҜШ®Щ„ ШіШЁШ§ЩӮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
    lines.append("")
    lines.append("вң… Ш§Щ„Щ…Ш·Щ„ЩҲШЁ:")
    lines.append("ШЈЩҶ ЩҠЩғЩҲЩҶ Ш®Щ„ЩҒЩҮ 4 Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш«Ш§Щ„Ш«Ш© Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„ШҢ Щ„ШЈЩҶ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 ЩҠШӘШЈЩҮЩ„ЩҲЩҶ.")
    if case:
        reqs = _v38_scenario_required_lines(team, case.get('scenario') or {}, snap, max_lines=4)
        if reqs:
            lines.append("")
            lines.append("рҹ“Қ Щ…Ш«Ш§Щ„ Щ…ШіШ§Шұ ЩҠШ¬Ш№Щ„ЩҮ Ш«Ш§Щ„Ш«ЩӢШ§:")
            for i, r in enumerate(reqs, start=1):
                lines.append(f"{i}. {r}")
    lines.append("")
    lines.extend(_v37_third_path_summary_block(team, target_pts, snap))
    return "\n".join(lines).strip()

# ==================== END V38 PRECISE QUALIFICATION ENGINE PATCH ====================


# ==================== V38C ESPN TOP SCORERS LIVE FIX ====================
# Ш§Щ„ЩҮШҜЩҒ: ШІШұ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ„Ш§ ЩҠШ№ШұШ¶ ШЈЩҠ ШЁЩҠШ§ЩҶШ§ШӘ Щ…ШӯЩҒЩҲШёШ©.
# ЩғЩ„ Ш¶ШәШ·Ш© ШӘШіШӯШЁ Щ…ЩҶ ESPN Щ…ШЁШ§ШҙШұШ© Щ…Ш№ ЩғШіШұ Ш§Щ„ЩғШ§ШҙШҢ Ш«Щ… ШӘШұШіЩ… ШөЩҲШұШ© Ш¬ШҜЩҠШҜШ© ШЁШ§ШіЩ… Ш¬ШҜЩҠШҜ.

_V38_TOP_SCORERS_LAST_ERROR = ""


def _v38_now_stamp():
    try:
        return datetime.now().strftime("%Y%m%d_%H%M%S_%f")
    except Exception:
        return "now"


def _v38_espn_cache_buster(url):
    try:
        sep = "&" if "?" in url else "?"
        return f"{url}{sep}_={_v38_now_stamp()}"
    except Exception:
        return url


def _v38_http_get_espn_no_cache(url, timeout=18):
    headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36",
        "Accept": "application/json,text/html;q=0.9,*/*;q=0.8",
        "Cache-Control": "no-cache, no-store, max-age=0",
        "Pragma": "no-cache",
        "Expires": "0",
    }
    url = _v38_espn_cache_buster(url)
    if requests is not None:
        return requests.get(url, timeout=timeout, headers=headers)
    import urllib.request
    req = urllib.request.Request(url, headers=headers)
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        raw = resp.read()
        enc = resp.headers.get_content_charset() or "utf-8"
        txt = raw.decode(enc, errors="replace")
        return _SimpleHTTPResponse(txt, getattr(resp, "status", 200), dict(resp.headers))


def _v38_espn_top_scorers_urls():
    # ESPN ЩҒЩӮШ· вҖ” Щ„Ш§ ЩҶЩӮШұШЈ Щ…ЩҶ Щ…Щ„ЩҒШ§ШӘ Ш§Щ„ШЁЩҲШӘ ЩҲЩ„Ш§ Щ…ЩҶ ШЈШӯШҜШ§Ш« Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ.
    return [
        "https://site.web.api.espn.com/apis/common/v3/sports/soccer/fifa.world/statistics/byathlete?region=us&lang=en&contentorigin=espn&season=2026&limit=100&sort=goals:desc",
        "https://site.web.api.espn.com/apis/common/v3/sports/soccer/fifa.world/statistics/byathlete?region=us&lang=en&contentorigin=espn&limit=100&sort=goals:desc",
        "https://site.api.espn.com/apis/site/v2/sports/soccer/fifa.world/leaders?category=goals&limit=100",
        "https://site.api.espn.com/apis/site/v2/sports/soccer/fifa.world/statistics?season=2026",
        "https://www.espn.com/soccer/stats/_/league/FIFA.WORLD/season/2026",
        "https://www.espn.com/soccer/stats/_/league/FIFA.WORLD",
    ]


def _v38_walk_json(obj, limit=7000):
    stack = [obj]
    seen = 0
    while stack and seen < limit:
        cur = stack.pop()
        seen += 1
        yield cur
        if isinstance(cur, dict):
            stack.extend(cur.values())
        elif isinstance(cur, list):
            stack.extend(cur)


def _v38_int_stat(v):
    if isinstance(v, dict):
        for k in ("value", "displayValue", "display", "stat", "total"):
            if k in v:
                out = _v38_int_stat(v.get(k))
                if out is not None:
                    return out
        return None
    try:
        s = str(v).replace(",", "").strip()
        if s == "":
            return None
        return int(float(s))
    except Exception:
        return None


def _v38_pick_name_from_node(node):
    if not isinstance(node, dict):
        return ""
    for key in ("athlete", "player", "participant"):
        val = node.get(key)
        if isinstance(val, dict):
            name = val.get("displayName") or val.get("fullName") or val.get("shortName") or val.get("name") or ""
            if name:
                return normalize_name(name)
    name = node.get("displayName") or node.get("fullName") or node.get("shortName") or node.get("name") or ""
    # Щ„Ш§ ЩҶШ№ШӘШЁШұ ШЈШіЩ…Ш§ШЎ Ш§Щ„ШӘШөЩҶЩҠЩҒШ§ШӘ Щ…Ш«Щ„ Goals ШЈЩҲ Teams ШЈШіЩ…Ш§ШЎ Щ„Ш§Ш№ШЁЩҠЩҶ.
    if str(name).lower() in ("goals", "goal", "scoring", "stats", "statistics"):
        return ""
    return normalize_name(name)


def _v38_pick_team_from_node(node):
    if not isinstance(node, dict):
        return ""
    for key in ("team", "club", "competitor"):
        val = node.get(key)
        if isinstance(val, dict):
            tm = val.get("displayName") or val.get("shortDisplayName") or val.get("abbreviation") or val.get("name") or ""
            if tm:
                return canonical_team_name(tm) or normalize_name(tm)
    for key in ("athlete", "player", "participant"):
        val = node.get(key)
        if isinstance(val, dict):
            tm = _v38_pick_team_from_node(val)
            if tm:
                return tm
    return ""


def _v38_pick_stat_from_node(node, names):
    if not isinstance(node, dict):
        return None
    names_l = {str(x).lower() for x in names}

    # Щ…ЩҒШ§ШӘЩҠШӯ Щ…ШЁШ§ШҙШұШ© Щ…Ш«Щ„ goals / appearances.
    for k, v in node.items():
        lk = str(k).lower()
        if lk in names_l or any(n in lk for n in names_l if len(n) > 2):
            out = _v38_int_stat(v)
            if out is not None:
                return out

    # statistics/stats/categories ЩғЩӮЩҲШ§ШҰЩ….
    for list_key in ("statistics", "stats", "categories"):
        arr = node.get(list_key)
        if isinstance(arr, list):
            for item in arr:
                if not isinstance(item, dict):
                    continue
                nm = str(item.get("name") or item.get("displayName") or item.get("shortDisplayName") or item.get("abbreviation") or "").lower()
                if nm and (nm in names_l or any(n in nm for n in names_l if len(n) > 2)):
                    out = _v38_int_stat(item.get("value") or item.get("displayValue") or item.get("total") or item.get("stat"))
                    if out is not None:
                        return out
                nested = _v38_pick_stat_from_node(item, names)
                if nested is not None:
                    return nested
    return None


def _v38_extract_top_scorers_from_espn_json(data):
    collected = {}

    # ШЈЩҲЩ„ЩӢШ§ Ш¬ШұЩ‘ШЁ Щ…ШіШӘШ®ШұШ¬ Ш§Щ„ЩҶШіШ®Ш© Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШҘЩҶ ЩғШ§ЩҶ ESPN ШәЩҠЩ‘Шұ Ш§Щ„ШҙЩғЩ„ ЩӮЩ„ЩҠЩ„ЩӢШ§.
    try:
        old_items = _v29_extract_top_scorers_from_json(data) if '_v29_extract_top_scorers_from_json' in globals() else []
    except Exception:
        old_items = []
    for it in old_items or []:
        name = normalize_name(it.get('name'))
        goals = _v38_int_stat(it.get('goals')) or 0
        if name and goals > 0:
            team = canonical_team_name(it.get('team')) or normalize_name(it.get('team') or "")
            played = _v38_int_stat(it.get('played'))
            key = (name.lower(), team.lower())
            collected[key] = {"name": name, "team": team or "-", "played": played if played is not None else "", "goals": goals}

    # Ш«Щ… Ш§ШіШӘШ®ШұШ§Ш¬ Ш№Ш§Щ… Щ…ЩҶ JSON.
    for node in _v38_walk_json(data):
        if not isinstance(node, dict):
            continue
        has_person = any(isinstance(node.get(k), dict) for k in ("athlete", "player", "participant"))
        if not has_person:
            continue
        name = _v38_pick_name_from_node(node)
        if not name or len(name) > 70:
            continue
        goals = _v38_pick_stat_from_node(node, ("goals", "goal", "g"))
        # Endpoint leaders ЩҠШӯШ· ШЈШӯЩҠШ§ЩҶЩӢШ§ Ш§Щ„ШұЩӮЩ… ЩҒЩҠ value/displayValue ШҜШ§Ш®Щ„ ЩҶЩҒШі Ш№ЩҶШөШұ Ш§Щ„Щ„Ш§Ш№ШЁ.
        if goals is None:
            goals = _v38_int_stat(node.get("value") or node.get("displayValue") or node.get("total"))
        if goals is None or goals <= 0:
            continue
        played = _v38_pick_stat_from_node(node, ("appearances", "appearance", "gamesPlayed", "games", "played", "gp", "p"))
        team = _v38_pick_team_from_node(node) or "-"
        key = (name.lower(), team.lower())
        prev = collected.get(key)
        if not prev or int(goals) > int(prev.get("goals") or 0):
            collected[key] = {"name": name, "team": team, "played": played if played is not None else "", "goals": int(goals)}

    items = list(collected.values())
    items.sort(key=lambda x: (-int(x.get("goals") or 0), str(x.get("name") or "")))
    return items[:25]


def _v38_extract_top_scorers_from_espn_html(html):
    # ESPN ЩҒЩӮШ·: fallback Щ…ЩҶ ШөЩҒШӯШ© ESPN ШҘШ°Ш§ API Щ…Ш§ ШұШ¬Ш№ JSON ЩӮШ§ШЁЩ„ Щ„Щ„ЩӮШұШ§ШЎШ©.
    try:
        items = _v29_extract_top_scorers_from_html(html) if '_v29_extract_top_scorers_from_html' in globals() else []
        if items:
            return items
    except Exception:
        pass
    return []


def fetch_espn_top_scorers(force_refresh=True):
    """ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN ЩҒЩӮШ· вҖ” ШЁШҜЩҲЩҶ ЩғШ§Шҙ ЩҶЩҮШ§ШҰЩҠЩӢШ§."""
    global _V38_TOP_SCORERS_LAST_ERROR
    _V38_TOP_SCORERS_LAST_ERROR = ""

    # Ш§Щ…ШіШӯ ШЈЩҠ ЩғШ§Шҙ ЩӮШҜЩҠЩ… Щ„ЩҲ ЩғШ§ЩҶ Щ…Ш№ШұЩҒ ЩҒЩҠ ЩҶШіШ® ШіШ§ШЁЩӮШ©.
    for cache_name in ("TOP_SCORERS_CACHE", "_TOP_SCORERS_CACHE", "ESPN_TOP_SCORERS_CACHE"):
        try:
            obj = globals().get(cache_name)
            if hasattr(obj, "clear"):
                obj.clear()
        except Exception:
            pass

    errors = []
    for url in _v38_espn_top_scorers_urls():
        try:
            r = _v38_http_get_espn_no_cache(url, timeout=18)
            status = int(getattr(r, "status_code", 200) or 200)
            if status >= 400:
                errors.append(f"HTTP {status}")
                continue
            ctype = str((getattr(r, "headers", {}) or {}).get("content-type", "")).lower()
            items = []
            if "json" in ctype or "api" in url:
                try:
                    data = r.json()
                    items = _v38_extract_top_scorers_from_espn_json(data)
                except Exception as e:
                    errors.append(f"JSON {str(e)[:60]}")
            if not items:
                try:
                    items = _v38_extract_top_scorers_from_espn_html(getattr(r, "text", ""))
                except Exception as e:
                    errors.append(f"HTML {str(e)[:60]}")
            if items:
                return items
        except Exception as e:
            errors.append(str(e)[:80])
            continue
    _V38_TOP_SCORERS_LAST_ERROR = " | ".join([e for e in errors if e])[:300]
    return []


def _v38_unique_top_scorers_image(items):
    path = render_top_scorers_v29(items)
    try:
        base, ext = os.path.splitext(path)
        new_path = f"{base}_{_v38_now_stamp()}{ext or '.png'}"
        shutil.copy2(path, new_path)
        return new_path
    except Exception:
        return path


async def _v38_send_fresh_espn_top_scorers(message):
    wait = await message.reply_text("вҸі Ш¬Ш§ШұЩҠ ШіШӯШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN Щ…ШЁШ§ШҙШұШ©...")
    try:
        items = await asyncio.wait_for(asyncio.to_thread(fetch_espn_top_scorers, True), timeout=40)
        if not items:
            err = _V38_TOP_SCORERS_LAST_ERROR or "Щ„Щ… ЩҠШұШ¬Ш№ ESPN ШЁЩҠШ§ЩҶШ§ШӘ ЩҮШҜШ§ЩҒЩҠЩҶ ШөШ§Щ„ШӯШ© Ш§Щ„ШўЩҶ."
            await wait.edit_text(f"вҡ пёҸ ШӘШ№Ш°Шұ ШіШӯШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN ШӯШ§Щ„ЩҠЩӢШ§.\n{err}")
            return
        path = _v38_unique_top_scorers_image(items)
        caption = f"ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© вң…\nШ§Щ„Щ…ШөШҜШұ: ESPN вҖ” ШіШӯШЁ Щ…ШЁШ§ШҙШұ\nШўШ®Шұ ШіШӯШЁ: {_now_riyadh_text() if '_now_riyadh_text' in globals() else datetime.now().strftime('%H:%M')}"
        await send_photo_path(message, path, caption)
        try:
            await wait.delete()
        except Exception:
            pass
    except Exception as e:
        await wait.edit_text(f"ШӘШ№Ш°Шұ Ш¬Щ„ШЁ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ…ЩҶ ESPN вқҢ\n{str(e)[:250]}")


async def public_top_scorers_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await _v38_send_fresh_espn_top_scorers(update.message)


_V38C_PREV_PUBLIC_MENU_CALLBACK = globals().get('public_menu_callback')
async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ""
    if data == "mainmenu|scorers":
        try:
            await q.answer("рҹ”„ ШӘШӯШҜЩҠШ« ESPN...", show_alert=False)
        except Exception:
            pass
        await _v38_send_fresh_espn_top_scorers(q.message)
        return
    if _V38C_PREV_PUBLIC_MENU_CALLBACK:
        return await _V38C_PREV_PUBLIC_MENU_CALLBACK(update, context)


_V38C_PREV_PUBLIC_REPLY_MENU_ROUTER = globals().get('public_reply_menu_router')
async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    txt = normalize_name(update.message.text or "").strip()
    if txt == "рҹҸҶ ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш©":
        await _v38_send_fresh_espn_top_scorers(update.message)
        return
    if _V38C_PREV_PUBLIC_REPLY_MENU_ROUTER:
        return await _V38C_PREV_PUBLIC_REPLY_MENU_ROUTER(update, context)

