    return InlineKeyboardMarkup([
        [InlineKeyboardButton("рҹ”Һ ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ Щ…ЩҶШӘШ®ШЁЩғШҹ", callback_data="v32|how_start")],
        [InlineKeyboardButton("рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ", callback_data="v32|thirds"), InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="mainmenu|home")],
    ])

