try:
    _V38E_PREV_ADMIN_CALLBACK = v32_admin_callback
except Exception:
    _V38E_PREV_ADMIN_CALLBACK = None
async def v32_admin_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    _v38e_track_user(update)
    try:
        await q.answer()
    except Exception:
        pass
    if not is_admin_user(update):
        await q.message.reply_text("ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’")
        return
    parts = (q.data or '').split('|')
    action = parts[1] if len(parts) > 1 else ''
    if action == 'count':
        await q.edit_message_text(_v38e_users_count_text(), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("рҹҶ• ШўШ®Шұ Ш§Щ„Щ…ШіШӘШ®ШҜЩ…ЩҠЩҶ", callback_data="v32adm|last_users")], [InlineKeyboardButton("в¬…пёҸ ШұШ¬ЩҲШ№", callback_data="v32adm|panel")]]))
