# ---------- V39: official statuses for best thirds / eliminated ----------
def _v39_clean_team_list(items):
    out = []
    for t in items or []:
        t = canonical_team_name(t) or normalize_name(t)
        if t and t not in out:
            out.append(t)
    return out


def _v39_snap_with_auto_status(force=False):
    snap = _v33_snapshot(force) if '_v33_snapshot' in globals() else (_v32_snapshot(force) if '_v32_snapshot' in globals() else {})
    if not isinstance(snap, dict):
        snap = {}
    status = snap.setdefault('status', {})
    q = _v39_clean_team_list(snap.get('qualified') or [])
    e = _v39_clean_team_list(snap.get('eliminated') or [])
    # ШЈЩҠ Ш«Ш§Щ„Ш« Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш« ЩҠШҜШ®Щ„ Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҠЩҶ.
    for tr in list(snap.get('thirds') or []):
        team = canonical_team_name(tr.get('team')) or tr.get('team')
        st = str(tr.get('third_status') or status.get(team, '') or '')
        if team and ('Щ…ШӘШЈЩҮЩ„' in st and 'ШұШіЩ…ЩҠ' in st):
            status[team] = 'вң… Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
            if team not in q:
                q.append(team)
    for team, st in list(status.items()):
        s = str(st or '')
        if team and ('Щ…ШӘШЈЩҮЩ„' in s and 'ШұШіЩ…ЩҠ' in s):
            if team not in q:
                q.append(team)
        if team and (('Щ…ШіШӘШЁШ№ШҜ' in s or 'ШәШ§ШҜШұ' in s or 'Ш®Ш§ШұШ¬' in s) and 'ШұШіЩ…ЩҠ' in s):
            if team not in e:
                e.append(team)
    snap['qualified'] = q[:32]
    snap['eliminated'] = e[:32]
    return snap


_V39_PREV_V33_SNAPSHOT = globals().get('_v33_snapshot')
def _v33_snapshot(force=False):
    snap = _V39_PREV_V33_SNAPSHOT(force) if _V39_PREV_V33_SNAPSHOT else (_v32_snapshot(force) if '_v32_snapshot' in globals() else {})
    try:
        # Ш·ШЁЩ‘ЩӮ Ш§Щ„Щ…ЩҶШ·ЩӮ Ш§Щ„ЩӮШҜЩҠЩ… ШЈЩҲЩ„ЩӢШ§ ШҘЩҶ ЩҲШ¬ШҜ.
        if '_v37_apply_official_best_thirds' in globals():
            snap = _v37_apply_official_best_thirds(snap)
    except Exception:
        pass
    try:
        status = snap.setdefault('status', {})
        q = _v39_clean_team_list(snap.get('qualified') or [])
        e = _v39_clean_team_list(snap.get('eliminated') or [])
        for tr in list(snap.get('thirds') or []):
            team = canonical_team_name(tr.get('team')) or tr.get('team')
            st = str(tr.get('third_status') or status.get(team, '') or '')
            if team and ('Щ…ШӘШЈЩҮЩ„' in st and 'ШұШіЩ…ЩҠ' in st):
                tr['third_status'] = 'вң… Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
                status[team] = 'вң… Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
                if team not in q:
                    q.append(team)
        for team, st in list(status.items()):
            s = str(st or '')
            if team and ('Щ…ШӘШЈЩҮЩ„' in s and 'ШұШіЩ…ЩҠ' in s) and team not in q:
                q.append(team)
            if team and (('Щ…ШіШӘШЁШ№ШҜ' in s or 'ШәШ§ШҜШұ' in s or 'Ш®Ш§ШұШ¬' in s) and 'ШұШіЩ…ЩҠ' in s) and team not in e:
                e.append(team)
        snap['qualified'] = q[:32]
        snap['eliminated'] = e[:32]
    except Exception:
        pass
    return snap


def _v32_calculated_qualified():
    try:
        return list((_v33_snapshot(False) or {}).get('qualified') or [])[:32]
    except Exception:
        return []


def _v32_calculated_eliminated():
    try:
        return list((_v33_snapshot(False) or {}).get('eliminated') or [])[:32]
    except Exception:
        return []


def _v39_status_label_for_team(team):
    try:
        snap = _v33_snapshot(False)
        st = str((snap.get('status') or {}).get(team, '') or '')
        if 'ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«' in st or 'ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' in st or 'ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' in st:
            return 'вң… Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
        if 'Щ…ШӘШЈЩҮЩ„' in st and 'ШұШіЩ…ЩҠ' in st:
            return 'вң… Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§'
        if ('Щ…ШіШӘШЁШ№ШҜ' in st or 'ШәШ§ШҜШұ' in st) and 'ШұШіЩ…ЩҠ' in st:
            return 'вқҢ Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§'
    except Exception:
        pass
    return ''


def _v32_best_thirds_text(force=False):
    snap = _v33_snapshot(force)
    thirds = snap.get('thirds') or []
    lines = ['рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ', f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {snap.get('updated_at','-')}", '']
    if not thirds:
        return 'рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.'
    inside = list(enumerate(thirds[:8], start=1))
    outside = list(enumerate(thirds[8:], start=9))
    lines.append('вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§')
    if not inside:
        lines.append('Щ„Ш§ ЩҠЩҲШ¬ШҜ.')
    for i, r in inside:
        team = r.get('team') or '-'
        st = str(r.get('third_status') or (snap.get('status') or {}).get(team, '') or 'вң… ШҜШ§Ш®Щ„ ШӯШ§Щ„ЩҠЩӢШ§')
        if 'Щ…ШӘШЈЩҮЩ„' in st and 'ШұШіЩ…ЩҠ' in st:
            st = 'вң… Ш¶Щ…ЩҶ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
        lines.append(f"{i}. {team} вҖ” {_v32_group_name(r.get('group'))}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} | Щ„Ш№ШЁ: {r.get('P')}/3")
        lines.append(f"   Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {st}")
        lines.append('')
    lines.append('вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§')
    if not outside:
        lines.append('Щ„Ш§ ЩҠЩҲШ¬ШҜ.')
    for i, r in outside:
        team = r.get('team') or '-'
        st = str(r.get('third_status') or 'вқҢ Ш®Ш§ШұШ¬ ШӯШ§Щ„ЩҠЩӢШ§')
        lines.append(f"{i}. {team} вҖ” {_v32_group_name(r.get('group'))}")
        lines.append(f"   Ш§Щ„ЩҶЩӮШ§Ш·: {r.get('Pts')} | Щ„Ш№ШЁ: {r.get('P')}/3")
        lines.append(f"   Ш§Щ„ЩҒШ§ШұЩӮ: {int(r.get('GD') or 0):+d} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {r.get('GF')}")
        lines.append(f"   Ш§Щ„ШӯШ§Щ„Ш©: {st}")
        lines.append('')
    lines.append('ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« ЩҠШӘШЈЩҮЩ„ЩҲЩҶ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32. ЩӮШЁЩ„ ЩҶЩҮШ§ЩҠШ© ЩғЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШӘШёЩҮШұ Ш§Щ„ШӯШ§Щ„Ш© ШӯШіШЁ Ш§Щ„ШӯШіШЁШ© Ш§Щ„ШӯШ§Щ„ЩҠШ©ШҢ ЩҲЩ„Ш§ ЩҠЩҸШ¶Ш§ЩҒ Щ„Щ„Щ…ШәШ§ШҜШұЩҠЩҶ ШҘЩ„Ш§ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„ ШұШіЩ…ЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


# ---------- V39: official qualified text format ----------
def _v39_rank_word(pos):
    try:
        pos = int(pos)
    except Exception:
        return '-'
    return {1: 'ШЈЩҲЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', 2: 'Ш«Ш§ЩҶЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', 3: 'Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©'}.get(pos, f'Ш§Щ„Щ…ШұЩғШІ {pos}')


def _v39_next_group_match_line(team, snap=None):
    snap = snap or _v33_snapshot(False)
    rem = _v33_remaining_for_team(team, snap) if '_v33_remaining_for_team' in globals() else []
    if not rem:
        return 'Щ„Ш§ ШӘЩҲШ¬ШҜ вҖ” ШЈЩҶЩҮЩү Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ ЩҒЩҠ ШҜЩҲШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.'
    m = rem[0]
    t1 = canonical_team_name(m.get('team1')) or m.get('team1') or '-'
    t2 = canonical_team_name(m.get('team2')) or m.get('team2') or '-'
    when = ' '.join([str(m.get('day') or '').strip(), str(m.get('date') or '').strip()]).strip()
    tm = str(m.get('time') or '').strip()
    line = f'{t1} Г— {t2}'
    if when or tm:
        line += '\n' + (when + (f' вҖ” {tm}' if tm else '')).strip()
    return line


def _v39_official_qualified_text(team, snap=None):
    team = _v33_find_team(team) or team
    snap = snap or _v33_snapshot(False)
    code, pos, row, rows = _v33_group_row(team, snap)
    rank = _v39_rank_word(pos)
    status = str((snap.get('status') or {}).get(team, '') or '')
    if 'ШЈЩҒШ¶Щ„' in status and 'Ш«Ш§Щ„Ш«' in status:
        rank = 'ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
    pts = row.get('Pts') if row else '-'
    gd = int((row or {}).get('GD') or 0)
    played = (row or {}).get('P') or '-'
    info = _v38e_round32_fixture_info_for_team(team, snap) if '_v38e_round32_fixture_info_for_team' in globals() else {}
    note = info.get('note') or 'ЩҠШӘШӯШҜШҜ ШӯШіШЁ Ш¬ШҜЩҲЩ„ ШҜЩҲШұ Ш§Щ„ЩҖ32'
    opponent = info.get('opponent') or 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§'
    fixture = info.get('fixture') or {}
    date_line = _v38e_match_datetime_line(fixture) if '_v38e_match_datetime_line' in globals() else 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§'
    opp_group = info.get('opponent_group')
    lines = [
        f'вң… {team} Щ…ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ Щғ{rank}',
        '',
        f'рҹ“Ҡ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©: {_v33_group_label(code)}',
        f'рҹҸҶ Ш§Щ„ШӘШұШӘЩҠШЁ: {rank}',
        f'рҹ“Ң Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Ш§Щ„ЩҒШ§ШұЩӮ: {gd:+d}',
        f'рҹҺ® Щ„Ш№ШЁ: {played}/3',
        '',
        'рҹ“… Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ЩӮШ§ШҜЩ…Ш© ЩҒЩҠ ШҜЩҲШұ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ:',
        _v39_next_group_match_line(team, snap),
        '',
        'рҹҸҹпёҸ Ш§Щ„Ш®ШөЩ… Ш§Щ„ЩӮШ§ШҜЩ… ЩҒЩҠ ШҜЩҲШұ Ш§Щ„ЩҖ32 ШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„ШӯШ§Щ„ЩҠ:',
        str(note),
        f'      {team}      Г—      {opponent}',
        '',
        'рҹ—“пёҸ Щ…ЩҲШ№ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©:',
        date_line,
    ]
    if opp_group:
        lines += ['', f'вҡ пёҸ ЩӮШҜ ЩҠШӘШәЩҠШұ Ш§Щ„Ш®ШөЩ… ШҘШ°Ш§ ШӘШәЩҠЩ‘Шұ ШӘШұШӘЩҠШЁ {_v33_group_label(opp_group)}.']
    return '\n'.join(lines).strip()


# ---------- V39: third-place analysis before best-third opponent ----------
def _v39_why_third(team, rows_case):
    try:
        idx = next((i for i, r in enumerate(rows_case) if r.get('team') == team), None)
        if idx is None or idx != 2:
            return f'{team} ЩҠЩҶШӘЩҮЩҠ ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ШӯШіШЁ ШӘШұШӘЩҠШЁ Ш§Щ„ЩҶЩӮШ§Ш· ЩҲЩҒЩҲШ§ШөЩ„ Ш§Щ„ШӘШұШӘЩҠШЁ ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ.'
        me = rows_case[idx]
        second = rows_case[idx-1]
        pts_me = int(me.get('Pts') or 0)
        pts_sec = int(second.get('Pts') or 0)
        if pts_me == pts_sec:
            return f'{team} ЩҠШӘШіШ§ЩҲЩү Щ…Ш№ {second.get("team")} ШЁШ§Щ„ЩҶЩӮШ§Ш·ШҢ Щ„ЩғЩҶ {second.get("team")} ЩҠШӘЩӮШҜЩ… Ш№Щ„ЩҠЩҮ ШЁЩғШіШұ Ш§Щ„ШӘШ№Ш§ШҜЩ„ Щ…Ш«Щ„ ЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ШЈЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ Ш§Щ„Щ…ШіШ¬Щ„Ш©.'
        return f'{team} ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ Щ„ШЈЩҶЩҮ ЩҠШЁЩӮЩү Ш®Щ„ЩҒ {second.get("team")} ШЁЩҒШ§ШұЩӮ Ш§Щ„ЩҶЩӮШ§Ш· ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ.'
    except Exception:
        return f'{team} ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШӯШіШЁ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ.'


def _v33_how_thirds_text(team):
    team = _v33_find_team(team) or team
    if not team:
        return 'Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ.'
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    case = _v37_third_case_info(team, snap) if '_v37_third_case_info' in globals() else None
    target_pts = None
    if case:
        target_pts = case.get('pts')
    else:
        try:
            target_pts, case = _v37_target_third_points(team, snap)
        except Exception:
            target_pts, case = None, None
    lines = [f'рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« вҖ” {team}', '']
    if target_pts is None:
        lines.append(f'Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ЩҲШ§Ш¶Шӯ ШӯШ§Щ„ЩҠЩӢШ§ ЩҠШ¬Ш№Щ„ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)} ШЁШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ©.')
        lines.append('ШҘШ°Ш§ ШӘШәЩҠЩ‘ШұШӘ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш«ШҢ ШіЩҠШӯШіШЁЩҮ Ш§Щ„ШЁЩҲШӘ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§.')
        return '\n'.join(lines).strip()
    lines.append(f'{team} ЩҠШіШӘШ·ЩҠШ№ ШӯШіШ§ШЁЩҠЩӢШ§ ШҘЩҶЩҮШ§ШЎ {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«.')
    lines.append('')
    if case:
        reqs = _v38_scenario_required_lines(team, case.get('scenario') or {}, snap, max_lines=6) if '_v38_scenario_required_lines' in globals() else []
        if reqs:
            lines.append('Щ…Ш«Ш§Щ„ Щ…ШіШ§Шұ Щ…Щ…ЩғЩҶ:')
            for i, r in enumerate(reqs, start=1):
                lines.append(f'{i}. {r}')
            lines.append('')
        rows_case = ((case.get('case') or {}).get('rows') or (case.get('scenario') or {}).get('rows') or [])[:4]
        if rows_case:
            lines.append('Ш§Щ„ШӘШұШӘЩҠШЁ ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„Щ…Ш«Ш§Щ„:')
            for i, rr in enumerate(rows_case, start=1):
                lines.append(f"{i}. {rr.get('team')} вҖ” {rr.get('Pts')} ЩҶЩӮШ§Ш·")
            lines.append('')
            lines.append(f'рҹ“Ң Щ„Щ…Ш§Ш°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§Шҹ')
            lines.append(_v39_why_third(team, rows_case))
            lines.append('')
    lines.append(f'ШЁШ№ШҜЩҮШ§ ЩҠШҜШ®Щ„ {team} ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘШ°Ш§ ЩғШ§ЩҶ ШұШөЩҠШҜЩҮ ЩҠШіЩ…Шӯ ШЁШ§Щ„Щ…ЩҶШ§ЩҒШіШ©.')
    lines.append('')
    try:
        lines.extend(_v37_third_path_summary_block(team, target_pts, snap))
    except Exception:
        lines.append('вҡ пёҸ ШӘЩҒШ§ШөЩҠЩ„ Щ…ЩӮШ§ШұЩҶШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШәЩҠШұ Щ…ШӘЩҲЩҒШұШ© ШӯШ§Щ„ЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


def _v33_how_qualify_keyboard(team):
    team = _v33_find_team(team) or team
    snap = _v33_snapshot(False)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = (snap.get('status') or {}).get(team, '')
    key = _v33_team_button_key(team)
    is_q = ('Щ…ШӘШЈЩҮЩ„' in str(status_txt) and 'ШұШіЩ…ЩҠ' in str(status_txt)) or ('Ш¶Щ…ЩҶ ШұШіЩ…ЩҠ' in str(status_txt))
    is_out = (('Щ…ШіШӘШЁШ№ШҜ' in str(status_txt) or 'ШәШ§ШҜШұ' in str(status_txt)) and 'ШұШіЩ…ЩҠ' in str(status_txt))
    if is_q or is_out:
        btns = []
        if is_q and '_v38e_has_opponent_group' in globals() and _v38e_has_opponent_group(team):
            btns.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Ш®ШөЩ…', callback_data=f'v32|opp_group|{key}')])
        btns.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', callback_data=f'v32|how_group|{key}')])
        btns.append([InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')])
        return InlineKeyboardMarkup(btns)
    possible = set()
    try:
        possible, _examples = _v38d_possible_positions(team, snap)
        possible = set(possible or [])
    except Exception:
        if pos: possible.add(int(pos))
        if _v37_third_case_info(team, snap): possible.add(3)
    rows_btn = []
    row_btn = []
    if 1 in possible:
        row_btn.append(InlineKeyboardButton('рҹҘҮ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„', callback_data=f'v32|how_first|{key}'))
    if 2 in possible:
        row_btn.append(InlineKeyboardButton('рҹҘҲ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ', callback_data=f'v32|how_second|{key}'))
    if row_btn:
        rows_btn.append(row_btn[:2])
    if 3 in possible:
        rows_btn.append([InlineKeyboardButton('рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШӘШӯЩ„ЩҠЩ„ЩҮ', callback_data=f'v32|how_thirds|{key}')])
        rows_btn.append([InlineKeyboardButton('рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ', callback_data=f'v32|opp_all|{key}')])
    rows_btn.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', callback_data=f'v32|how_group|{key}')])
    rows_btn.append([InlineKeyboardButton('рҹ§® Ш¬ШұЩ‘ШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ', callback_data='v32|calc_start'), InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')])
    return InlineKeyboardMarkup(rows_btn)


_V39_PREV_HOW_QUALIFY_TEXT = globals().get('_v33_how_qualify_text')
def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return 'Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ.'
    snap = _v33_snapshot(force)
    status_txt = str((snap.get('status') or {}).get(team, '') or '')
    if ('Щ…ШӘШЈЩҮЩ„' in status_txt and 'ШұШіЩ…ЩҠ' in status_txt) or ('Ш¶Щ…ЩҶ ШұШіЩ…ЩҠ' in status_txt):
        return _v39_official_qualified_text(team, snap)
    if _V39_PREV_HOW_QUALIFY_TEXT:
        return _V39_PREV_HOW_QUALIFY_TEXT(team, force)
    return f'вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ {team}Шҹ\n\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШ§Щ„ЩҠЩӢШ§.'


def _v33_all_opponents_text(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code = _v33_team_group(team)
    slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
    lines = [f'рҹ“Ҡ Ш§Щ„Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ© Ш№Щ„Щү Ш®ШөЩ… {team}', '']
    lines.append(f'ШҘШ°Ш§ ШӘШЈЩҮЩ„ {team} ЩғШ«Ш§Щ„Ш« {_v33_group_label(code)}ШҢ ЩҒШ§Щ„Ш®ШөЩ… Щ„Ш§ ЩҠЩғЩҲЩҶ Щ…ЩҶ Щ…ЩҶШӘШ®ШЁШ§ШӘ Щ…Ш¬Щ…ЩҲШ№ШӘЩҮШҢ ШЁЩ„ Щ…ЩҶ Ш®Ш§ЩҶШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32 Ш§Щ„Ш®Ш§ШөШ© ШЁШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.')
    lines.append('')
    if excluded:
        lines.append('рҹҡ« Ш®Ш§ЩҶШ§ШӘ/Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ШӯЩҸШ°ЩҒШӘ Щ…ЩҶ Ш§Щ„ШӯШіШ§ШЁ Щ„ШЈЩҶЩҮШ§ Щ…ШіШӘШӯЩҠЩ„Ш© ШӯШіШ§ШЁЩҠЩӢШ§:')
        for c, reason in excluded[:8]:
            lines.append(f'вқҢ {_v33_group_label(c)} вҖ” {reason}')
        lines.append('')
    if not slots:
        lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ Ш®Ш§ЩҶШ© Щ…ШӯШӘЩ…Щ„Ш© ЩҲШ§Ш¶ШӯШ© Ш§Щ„ШўЩҶ.')
    else:
        lines.append('рҹҸҹпёҸ Ш§Щ„Ш®Ш§ЩҶШ§ШӘ Ш§Щ„Щ…Щ…ЩғЩҶШ© ШӯШ§Щ„ЩҠЩӢШ§ ШЁШ№ШҜ ШӯШ°ЩҒ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„:')
        for slot in slots:
            leader = _v33_group_leader(slot, snap) or f'Щ…ШӘШөШҜШұ {_v33_group_label(slot)}'
            lines.append(f'- Ш«Ш§Щ„Ш« {_v33_group_label(code)} Г— Щ…ШӘШөШҜШұ {_v33_group_label(slot)}')
            lines.append(f'  Ш§Щ„Ш®ШөЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ ШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„ШӯШ§Щ„ЩҠ: {leader}')
            lines.append('')
    if weak:
        lines.append('вҡ пёҸ Щ…Щ„Ш§ШӯШёШ©: ШЁШ№Ш¶ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ ЩҲШ¶Ш№ЩҮШ§ ШөШ№ШЁ Щ„ЩғЩҶЩҮШ§ Щ„Щ… ШӘЩҸШӯШ°ЩҒ Щ„ШЈЩҶЩҮШ§ Щ…Ш§ ШІШ§Щ„ШӘ Щ…Щ…ЩғЩҶШ© ШӯШіШ§ШЁЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


# ---------- V39: timeout 90s for how qualify ----------
def _v36_team_info_wait_text():
    return 'вҸі Ш¬Ш§ШұЩҠ ШӘШ¬ЩҮЩҠШІ ШӯШіШ§ШЁШ§ШӘ Ш§Щ„ШӘШЈЩҮЩ„вҖҰ\n\nЩӮШҜ ЩҠШіШӘШәШұЩӮ Ш§Щ„ШӯШіШ§ШЁ ШӯШӘЩү ШҜЩӮЩҠЩӮШ© ШЁШіШЁШЁ ШӘШӯШҜЩҠШ« ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҲШ§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӨШ«ШұШ©.'


async def _v36_send_how_for_team(message, team, force=False):
    wait = await message.reply_text(_v36_team_info_wait_text(), reply_markup=_public_main_reply_keyboard())
    try:
        text = await asyncio.wait_for(asyncio.to_thread(_v33_how_qualify_text, team, force), timeout=90)
    except Exception as e:
        text = f'вҡ пёҸ ШӘШ№Ш°Шұ ШӘШ¬ЩҮЩҠШІ Щ…Ш№Щ„ЩҲЩ…Ш§ШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ.\nШ¬ШұЩ‘ШЁ Щ…ШұШ© Ш«Ш§ЩҶЩҠШ© ШЈЩҲ Ш§Ш®ШӘШұ Ш§Щ„Щ…ЩҶШӘШ®ШЁ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©.\n\nШ§Щ„ШіШЁШЁ: {type(e).__name__}: {str(e)[:180]}'
        kb = _public_main_keyboard()
    else:
        kb = _v33_how_qualify_keyboard(team)
    try:
        await wait.edit_text(text, reply_markup=kb)
    except Exception:
        await message.reply_text(text, reply_markup=kb)


