def _v39_fantasy_date_for_day(day):
    try:
        d = datetime(2026, 6, 11) + timedelta(days=int(day)-1)
        return d.strftime('%d/%m/%Y')
    except Exception:
        return ''


def _v39_fantasy_matches_for_day(day):
    d = _v39_fantasy_date_for_day(day)
    rows = []
    try:
        for m in (globals().get('TOURNAMENT_FIXTURES') or []):
            if str(m.get('date') or '') == d:
                rows.append(f"- {m.get('team1')} Г— {m.get('team2')} вҖ” {m.get('time','')}")
    except Exception:
        pass
    return rows


def _v39_fantasy_day_locked(day):
    # ШҘШ°Ш§ Щ…ЩҲШ¬ЩҲШҜ ЩӮЩҒЩ„ ЩӮШҜЩҠЩ… ЩҶШӯШӘШұЩ…ЩҮ. Ш§Щ„ЩӮЩҒЩ„ Ш§Щ„ШӘЩ„ЩӮШ§ШҰЩҠ ЩҠШ№ШӘЩ…ШҜ Ш№Щ„Щү ЩҲЩӮШӘ Ш§Щ„ШіЩҠШұЩҒШұ ШҘЩҶ ШЈЩ…ЩғЩҶ.
    try:
        locked = load_locked_days()
        if str(day) in {str(x) for x in locked}:
            return True
    except Exception:
        pass
    # Щ„Ш§ ЩҶЩӮЩҒЩ„ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§ ШЁШҜЩҲЩҶ timezone Щ…ЩҲШ«ЩҲЩӮ ШӯШӘЩү Щ„Ш§ ЩҶЩӮЩҒЩ„ ЩҠЩҲЩ… ШәЩ„Ш·Шӣ Ш§Щ„Щ…ЩҶШ·ЩӮ Ш§Щ„ШЈШіШ§ШіЩҠ Щ…ЩҲШ¬ЩҲШҜ Щ„Щ„ШӘШ·ЩҲЩҠШұ Ш§Щ„Щ„Ш§ШӯЩӮ.
    return False


def _v39_parse_lineup_text(text):
    raw = str(text or '').strip()
    fields = {'name':'', 'keeper':'', 'p1':'', 'p2':'', 'p3':'', 'captain':''}
    patterns = [
        ('name', r'^(?:Ш§Щ„Ш§ШіЩ…|Ш§ШіЩ…ЩҠ|Ш§ШіЩ…)\s*[:пјҡ\-]\s*(.+)$'),
        ('keeper', r'^(?:рҹ§Ө\s*)?(?:Ш§Щ„ШӯШ§ШұШі|ШӯШ§ШұШі)\s*[:пјҡ\-]\s*(.+)$'),
        ('p1', r'^(?:Ш§Щ„Щ„Ш§Ш№ШЁ\s*1|Щ„Ш§Ш№ШЁ\s*1|Ш§Щ„Щ„Ш§Ш№ШЁ\s*ЩЎ|Щ„Ш§Ш№ШЁ\s*ЩЎ|player\s*1)\s*[:пјҡ\-]\s*(.+)$'),
        ('p2', r'^(?:Ш§Щ„Щ„Ш§Ш№ШЁ\s*2|Щ„Ш§Ш№ШЁ\s*2|Ш§Щ„Щ„Ш§Ш№ШЁ\s*Щў|Щ„Ш§Ш№ШЁ\s*Щў|player\s*2)\s*[:пјҡ\-]\s*(.+)$'),
        ('p3', r'^(?:Ш§Щ„Щ„Ш§Ш№ШЁ\s*3|Щ„Ш§Ш№ШЁ\s*3|Ш§Щ„Щ„Ш§Ш№ШЁ\s*ЩЈ|Щ„Ш§Ш№ШЁ\s*ЩЈ|player\s*3)\s*[:пјҡ\-]\s*(.+)$'),
        ('captain', r'^(?:рҹ‘‘\s*)?(?:Ш§Щ„ЩғШ§ШЁШӘЩҶ|ЩғШ§ШЁШӘЩҶ|Ш§Щ„ЩғШ§ШЁШӘЩҶ\s*рҹ‘‘|captain)\s*[:пјҡ\-]\s*(.+)$'),
    ]
    for line in raw.splitlines():
        line = line.strip()
        if not line: continue
        for key, pat in patterns:
            m = re.match(pat, line, flags=re.I)
            if m:
                fields[key] = normalize_name(m.group(1)).strip()
                break
    return fields


def _v39_missing_field(fields):
    order = [('name','Ш§ШіЩ… Ш§Щ„Щ…ШҙШ§ШұЩғ'),('keeper','Ш§ШіЩ… Ш§Щ„ШӯШ§ШұШі'),('p1','Ш§Щ„Щ„Ш§Ш№ШЁ 1'),('p2','Ш§Щ„Щ„Ш§Ш№ШЁ 2'),('p3','Ш§Щ„Щ„Ш§Ш№ШЁ 3'),('captain','Ш§ШіЩ… Ш§Щ„ЩғШ§ШЁШӘЩҶ')]
    for k, label in order:
        if not fields.get(k):
            return k, label
    return None, None


