def _v47_get(row, *keys, default=None):
    if not isinstance(row, dict):
        return default
    for k in keys:
        if k in row and row.get(k) is not None:
            return row.get(k)
    return default


def _v47_third_is_official(team, row, snap):
    status = str(_v47_get(row, 'third_status', 'status', default='') or '')
    try:
        status += ' ' + str((snap.get('status') or {}).get(team, '') or '')
    except Exception:
        pass
    return ('вң…' in status or 'Щ…ШӘШЈЩҮЩ„' in status or 'Ш¶Щ…ЩҶ' in status) and ('ШұШіЩ…ЩҠ' in status or 'ШЈЩҒШ¶Щ„' in status or 'Ш«Ш§Щ„Ш«' in status)


def _v32_best_thirds_text(force=False):
    snap = _v33_snapshot(force) if '_v33_snapshot' in globals() else (_v32_snapshot(force) if '_v32_snapshot' in globals() else {})
    thirds = list((snap or {}).get('thirds') or [])
    lines = ['рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ', f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {(snap or {}).get('updated_at','-')}", '']
    if not thirds:
        return 'рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ\nЩ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.'

    official_count = 0
    for r in thirds[:8]:
        team = _v47_get(r, 'team', 'name', default='-')
        if _v47_third_is_official(team, r, snap or {}):
            official_count += 1
    lines.append(f'вң… Ш¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«: {official_count}/8')
    lines.append('')
    lines.append('вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§:')

    for i, r in enumerate(thirds[:8], start=1):
        team = _v47_get(r, 'team', 'name', default='-')
        group = _v47_get(r, 'group', 'Group', default='')
        pts = _v47_get(r, 'Pts', 'pts', 'points', default=0)
        played = _v47_get(r, 'P', 'played', default=0)
        gd = _v47_int(_v47_get(r, 'GD', 'gd', default=0)) or 0
        gf = _v47_get(r, 'GF', 'gf', default='-')
        official = _v47_third_is_official(team, r, snap or {})
        mark = ' вң…' if official else ''
        status = 'вң… Ш¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if official else str(_v47_get(r, 'third_status', default='вҸі ЩҠЩҶШӘШёШұ ЩҶШӘШ§ШҰШ¬') or 'вҸі ЩҠЩҶШӘШёШұ ЩҶШӘШ§ШҰШ¬')
        lines.append(f'{i}. {team}{mark} вҖ” {_v32_group_name(group) if "_v32_group_name" in globals() else group}')
        lines.append(f'   Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Щ„Ш№ШЁ: {played}/3 | Ш§Щ„ЩҒШ§ШұЩӮ: {gd:+d} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {gf}')
        lines.append(f'   Ш§Щ„ШӯШ§Щ„Ш©: {status}')
        lines.append('')

    outside = thirds[8:]
    lines.append('вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§:')
    if not outside:
        lines.append('Щ„Ш§ ЩҠЩҲШ¬ШҜ.')
    for i, r in enumerate(outside, start=9):
        team = _v47_get(r, 'team', 'name', default='-')
        group = _v47_get(r, 'group', 'Group', default='')
        pts = _v47_get(r, 'Pts', 'pts', 'points', default=0)
        played = _v47_get(r, 'P', 'played', default=0)
        gd = _v47_int(_v47_get(r, 'GD', 'gd', default=0)) or 0
        gf = _v47_get(r, 'GF', 'gf', default='-')
        lines.append(f'{i}. {team} вҖ” {_v32_group_name(group) if "_v32_group_name" in globals() else group}')
        lines.append(f'   Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Щ„Ш№ШЁ: {played}/3 | Ш§Щ„ЩҒШ§ШұЩӮ: {gd:+d} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {gf}')
        lines.append('   Ш§Щ„ШӯШ§Щ„Ш©: вқҢ Ш®Ш§ШұШ¬ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШ§Щ„ЩҠЩӢШ§')
        lines.append('')
    lines.append('ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 ЩҠШӘШЈЩҮЩ„ЩҲЩҶ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32. Ш§Щ„Ш®ШөЩ… ЩҠШӘШӯШҜШҜ ШӯШіШЁ Ш¬ШҜЩҲЩ„ FIFA Ш§Щ„ШұШіЩ…ЩҠ Щ„ШӘЩҲШІЩҠШ№ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.')
    return '\n'.join(lines).strip()


