V48_EXIT_PROB_CACHE_FILE = "exit_probabilities_cache.json"
V48_EXIT_UPDATE_TASK = None
V48_EXIT_UPDATE_STARTED_AT = ""
V48_EXIT_UPDATE_LOCK = None


def _v48_now_makkah_str():
    try:
        return datetime.now(ZoneInfo("Asia/Riyadh")).strftime("%Y-%m-%d %H:%M")
    except Exception:
        try:
            return datetime.utcnow().strftime("%Y-%m-%d %H:%M")
        except Exception:
            return "-"


def _v48_load_json(path, default=None):
    default = {} if default is None else default
    try:
        if '_v32_load_json' in globals():
            return _v32_load_json(path, default)
    except Exception:
        pass
    try:
        if os.path.exists(path):
            with open(path, 'r', encoding='utf-8') as f:
                return json.load(f)
    except Exception:
        pass
    return default


def _v48_save_json(path, data):
    try:
        if '_v32_save_json' in globals():
            return _v32_save_json(path, data)
    except Exception:
        pass
    tmp = str(path) + '.tmp'
    with open(tmp, 'w', encoding='utf-8') as f:
        json.dump(data or {}, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)


def _v48_team_key(team):
    try:
        return simple_key(team)
    except Exception:
        return re.sub(r'\W+', '', str(team or '')).strip().lower()


def _v48_points(row):
    try:
        return int(row.get('Pts') if row.get('Pts') is not None else row.get('points') or row.get('pts') or 0)
    except Exception:
        return 0


def _v48_played(row):
    try:
        return int(row.get('P') if row.get('P') is not None else row.get('played') or 0)
    except Exception:
        return 0


def _v48_gd(row):
    try:
        return int(row.get('GD') if row.get('GD') is not None else row.get('gd') or 0)
    except Exception:
        return 0


def _v48_group_name(code):
    try:
        return _v32_group_name(code)
    except Exception:
        try:
            return _v33_group_label(code)
        except Exception:
            return f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {code}"


def _v48_remaining_count(row):
    return max(0, 3 - _v48_played(row))


def _v48_team_fixture_lines(team, snap):
    out = []
    try:
        fixtures = _v33_remaining_for_team(team, snap) if '_v33_remaining_for_team' in globals() else []
    except Exception:
        fixtures = []
    for m in fixtures[:2]:
        t1 = m.get('team1') or m.get('home') or ''
        t2 = m.get('team2') or m.get('away') or ''
        opp = t2 if t1 == team else (t1 if t2 == team else (t1 or t2))
        if opp:
            out.append(f"Ш®ШіШ§ШұШ© {team} ШЈЩ…Ш§Щ… {opp}")
    return out


def _v48_simple_team_exit_base(team, snap):
    code, pos, row, rows = _v33_group_row(team, snap) if '_v33_group_row' in globals() else ('', None, None, [])
    pts = _v48_points(row or {})
    played = _v48_played(row or {})
    rem = max(0, 3 - played)
    lines = []
    lines.append(f"рҹ“Ң ШЈЩҲЩ„ЩӢШ§: ЩғЩҠЩҒ ЩӮШҜ ЩҠШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§ ШЈЩҲ ШұШ§ШЁШ№ЩӢШ§Шҹ")
    if row is None:
        lines.append("Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© Ш№ЩҶ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШӯШ§Щ„ЩҠЩӢШ§.")
        return lines, pts
    if rem <= 0:
        lines.append(f"{team} ШЈЩҶЩҮЩү Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ: {pts} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: {played}/3")
        if pos == 3:
            lines.append("ЩҲШ¶Ш№ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ: Ш«Ш§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©ШҢ Щ„Ш°Щ„Щғ ЩҠШҜШ®Щ„ ШӯШіШ§ШЁ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.")
        elif pos == 4:
            lines.append("ЩҲШ¶Ш№ЩҮ Ш§Щ„ШӯШ§Щ„ЩҠ: ШұШ§ШЁШ№ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©ШҢ ЩҲЩҮШ°Ш§ ЩҠШ№ЩҶЩҠ Ш§Щ„Щ…ШәШ§ШҜШұШ© ШҘШ°Ш§ ЩғШ§ЩҶ Ш§Щ„ШӘШұШӘЩҠШЁ ЩҶЩҮШ§ШҰЩҠЩӢШ§.")
        else:
            lines.append("ШҘШ°Ш§ ШЁЩӮЩҠ ЩҒЩҠ Щ…ШұЩғШІ ШӘШЈЩҮЩ„ Щ…ШЁШ§ШҙШұШҢ Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШәШ§ШҜШұШ© Ш№ШЁШұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘЩ„Ш§ ШҘШ°Ш§ ШӘШәЩҠЩ‘Шұ Ш§Щ„ШӘШұШӘЩҠШЁ ШұШіЩ…ЩҠЩӢШ§.")
        target_pts = pts
        return lines, target_pts

    lose_lines = _v48_team_fixture_lines(team, snap)
    if lose_lines:
        for x in lose_lines:
            lines.append(f"- {x}")
        lines.append(f"  вһЎпёҸ ЩҠШөШЁШӯ {team}: {pts} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: 3/3 ШҘШ°Ш§ Ш®ШіШұ ЩғЩ„ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©")
    else:
        lines.append(f"- Ш®ШіШ§ШұШ© Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©")
        lines.append(f"  вһЎпёҸ ЩҠШөШЁШӯ {team}: {pts} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: 3/3")
    if rem == 2:
        lines.append(f"- ШӘШ№Ш§ШҜЩ„ Щ…ШЁШ§ШұШ§Ш© ЩҲШ®ШіШ§ШұШ© Щ…ШЁШ§ШұШ§Ш©")
        lines.append(f"  вһЎпёҸ ЩҠШөШЁШӯ {team}: {pts + 1} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: 3/3")
    lines.append("ШЁШ№ШҜЩҮШ§ ЩҠШӘШӯШҜШҜ Щ…ШұЩғШІЩҮ Ш§Щ„ЩҶЩҮШ§ШҰЩҠ ШӯШіШЁ ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©ШҢ ЩҲЩӮШҜ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШЈЩҲ ШұШ§ШЁШ№ЩӢШ§.")
    return lines, pts


def _v48_third_candidate_rows(snap):
    thirds = []
    try:
        thirds = list((snap or {}).get('thirds') or [])
    except Exception:
        thirds = []
    if thirds:
        return thirds
    try:
        groups = (snap or {}).get('groups') or {}
        out = []
        for code, g in groups.items():
            rows = (g or {}).get('rows') or []
            if len(rows) >= 3:
                r = dict(rows[2]); r['group'] = code; out.append(r)
        return out
    except Exception:
        return []


def _v48_other_thirds_blocks(team, snap, target_pts):
    code = _v33_team_group(team) if '_v33_team_group' in globals() else ''
    thirds = [dict(x) for x in _v48_third_candidate_rows(snap)]
    stronger = []
    equal = []
    for r in thirds:
        t = r.get('team') or r.get('name') or '-'
        g = r.get('group') or r.get('Group') or ''
        if t == team or g == code:
            continue
        pts = _v48_points(r)
        played = _v48_played(r)
        rem = max(0, 3 - played)
        max_pts = pts + rem * 3
        gd = _v48_gd(r)
        # Ш§Щ„ШЈЩҮЩ…: Ш§Щ„Щ„ЩҠ ЩҠШӘШ№ШҜШ§ЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш· ШЈЩҲЩ„ЩӢШ§ШҢ Ш«Щ… Ш§Щ„Щ„ЩҠ ЩҠШӘШ№Ш§ШҜЩ„ Щ…Ш№ЩҮ.
        if max_pts > target_pts:
            stronger.append((max_pts, pts, played, gd, t, g, rem))
        elif max_pts == target_pts:
            equal.append((max_pts, pts, played, gd, t, g, rem))
    stronger.sort(key=lambda x: (-x[0], -x[1], -x[3], x[4]))
    equal.sort(key=lambda x: (-x[0], -x[3], x[4]))
    lines = []
    lines.append("рҹҘү Ш«Ш§ЩҶЩҠЩӢШ§: ЩғЩҠЩҒ ШӘШ°ЩҮШЁ Ш№Щ„ЩҠЩҮ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«Шҹ")
    lines.append("")
    lines.append(f"ШҘШ°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҖ{target_pts} ЩҶЩӮШ§Ш·ШҢ ЩҒЩҮЩҲ ЩҠШӯШӘШ§Ш¬ ШЈЩҶ ЩҠЩғЩҲЩҶ Ш¶Щ…ЩҶ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12.")
    lines.append("")
    lines.append("рҹ”Ҙ Щ…ЩҶШӘШ®ШЁШ§ШӘ ЩӮШҜ ШӘШӘШ¬Ш§ЩҲШІЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш·:")
    if not stronger:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ЩҲШ§Ш¶Шӯ ШӯШ§Щ„ЩҠЩӢШ§ Щ„ШӘШ¬Ш§ЩҲШІЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш· Щ…ЩҶ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…ШӘШ§ШӯШ©.")
    for i, (_mx, pts, played, gd, t, g, rem) in enumerate(stronger[:8], start=1):
        if rem > 0:
            req = "Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Щ…ШЁШ§ШұШ§Ш© Щ…ШӘШЁЩӮЩҠШ©" if rem == 1 else "Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©"
            become = pts + rem * 3
        else:
            req = "ЩҮЩҲ ШЈЩ…Ш§Щ…ЩҮ ШӯШ§Щ„ЩҠЩӢШ§ ШЁШ§Щ„ЩҶЩӮШ§Ш·"
            become = pts
        lines.append(f"{i}. {_v48_group_name(g)}")
        lines.append(f"{req} вҖ” {t}")
        lines.append(f"вһЎпёҸ {t} ЩӮШҜ ЩҠШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§ ШЁЩҖ{become} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: 3/3")
        lines.append(f"вһЎпёҸ ЩҠШӘЩӮШҜЩ… Ш№Щ„Щү {team} ШЁШ§Щ„ЩҶЩӮШ§Ш·")
        lines.append("")
    lines.append("вҡ–пёҸ Щ…ЩҶШӘШ®ШЁШ§ШӘ ЩӮШҜ ШӘШӘШ№Ш§ШҜЩ„ Щ…Ш№ЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш· ЩҲШӘШӘЩҒЩҲЩӮ ШЁШ§Щ„ЩҒШ§ШұЩӮ:")
    if not equal:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ШӘШ№Ш§ШҜЩ„ ЩҲШ§Ш¶Шӯ ШӯШ§Щ„ЩҠЩӢШ§ ШӯШіШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    for i, (_mx, pts, played, gd, t, g, rem) in enumerate(equal[:8], start=1):
        req = "Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Щ…ШЁШ§ШұШ§Ш© Щ…ШӘШЁЩӮЩҠШ©" if rem == 1 else ("Ш§Щ„ЩҒЩҲШІ ЩҒЩҠ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©" if rem > 1 else "ЩҠШЁЩӮЩү Ш№Щ„Щү ЩҶЩҒШі ШұШөЩҠШҜЩҮ")
        lines.append(f"{i}. {_v48_group_name(g)}")
        lines.append(f"{req} вҖ” {t}")
        lines.append(f"вһЎпёҸ {t} ЩӮШҜ ЩҠШөЩ„ ШҘЩ„Щү {target_pts} ЩҶЩӮШ§Ш· | Щ„Ш№ШЁ: 3/3")
        lines.append(f"вһЎпёҸ ЩҠШӯШӘШ§Ш¬ ЩҒШ§ШұЩӮ ШЈЩҮШҜШ§ЩҒ ШЈЩҲ ШЈЩҮШҜШ§ЩҒ Щ…ШіШ¬Щ„Ш© ШЈЩҒШ¶Щ„ Щ…ЩҶ {team}")
        lines.append("")
    lines.append("рҹ“Ҡ Ш§Щ„ЩҶШӘЩҠШ¬Ш©:")
    lines.append(f"ШҘШ°Ш§ ШөШ§Шұ ШЈЩ…Ш§Щ… {team} 8 Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш«Ш§Щ„Ш«Ш© ШЈЩҒШ¶Щ„ Щ…ЩҶЩҮШҢ ЩҠШәШ§ШҜШұ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШұШәЩ… ШЈЩҶЩҮ Ш«Ш§Щ„Ш«.")
    lines.append("")
    lines.append("вҡ пёҸ ЩҮШ°Ш§ ШіЩҠЩҶШ§ШұЩҠЩҲ Щ…ШӯШӘЩ…Щ„ШҢ ЩҲЩ„ЩҠШі Ш§ШіШӘШЁШ№Ш§ШҜЩӢШ§ ШұШіЩ…ЩҠЩӢШ§.")
    return lines


def _v48_build_exit_text_for_team(team, snap=None, updated_at=None):
    team = _v33_find_team(team) if '_v33_find_team' in globals() else team
    if not team:
        return "вҡ пёҸ Щ„Щ… ЩҠШӘЩ… Ш§Щ„ШӘШ№ШұЩҒ Ш№Щ„Щү Ш§Щ„Щ…ЩҶШӘШ®ШЁ."
    snap = snap or (_v33_snapshot(False) if '_v33_snapshot' in globals() else {})
    updated_at = updated_at or _v48_now_makkah_str()
    lines = [f"вқҢ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© вҖ” {team}", f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {updated_at} ШЁШӘЩҲЩӮЩҠШӘ Щ…ЩғШ©", ""]
    lines.append(f"{team} ЩӮШҜ ЩҠШәШ§ШҜШұ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШЁШ·ШұЩҠЩӮШӘЩҠЩҶ:")
    lines.append("1. ШЈЩҶ ЩҠЩҶЩҮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШұШ§ШЁШ№.")
    lines.append("2. ШЈЩҶ ЩҠЩҶЩҮЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш«Ш§Щ„Ш«ЩӢШ§ШҢ Щ„ЩғЩҶЩҮ Щ„Ш§ ЩҠЩғЩҲЩҶ Ш¶Щ…ЩҶ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12.")
    lines.append("")
    base, target_pts = _v48_simple_team_exit_base(team, snap)
    lines.extend(base)
    lines.append("")
    lines.extend(_v48_other_thirds_blocks(team, snap, target_pts))
    return "\n".join(lines).strip()


def _v48_load_exit_cache():
    data = _v48_load_json(V48_EXIT_PROB_CACHE_FILE, {})
    return data if isinstance(data, dict) else {}


def _v48_save_exit_cache(data):
    _v48_save_json(V48_EXIT_PROB_CACHE_FILE, data or {})


def _v48_get_cached_exit_text(team):
    team = _v33_find_team(team) if '_v33_find_team' in globals() else team
    data = _v48_load_exit_cache()
    teams = data.get('teams') or {}
    item = teams.get(team) or teams.get(_v48_team_key(team))
    if isinstance(item, dict) and item.get('text'):
        return item.get('text')
    updated = data.get('updated_at') or '-'
    return (
        f"вҡ пёҸ Щ„Щ… ЩҠШӘЩ… ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© Щ„ЩҮШ°Ш§ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ШЁШ№ШҜ.\n\n"
        f"ШўШ®Шұ ШӘШӯШҜЩҠШ« Щ…ШӯЩҒЩҲШё: {updated}\n"
        "ШіЩҠШӘЩ… Ш№ШұШ¶ЩҮШ§ ШЁШ№ШҜ ШӘШӯШҜЩҠШ« Ш§Щ„ШҘШҜШ§ШұШ©."
    )


def _v48_update_exit_probabilities_all():
    updated_at = _v48_now_makkah_str()
    snap = _v33_snapshot(True) if '_v33_snapshot' in globals() else {}
    teams = list(globals().get('WORLD_CUP_TEAMS') or [])
    if not teams:
        try:
            teams = [t for _c, arr in WORLD_CUP_GROUPS for t in arr]
        except Exception:
            teams = []
    cache = {"updated_at": updated_at, "teams": {}, "count": 0}
    for team in teams:
        try:
            txt = _v48_build_exit_text_for_team(team, snap, updated_at)
            cache['teams'][team] = {"text": txt, "updated_at": updated_at}
            cache['teams'][_v48_team_key(team)] = {"text": txt, "updated_at": updated_at}
            cache['count'] += 1
        except Exception as e:
            cache['teams'][team] = {"text": f"вҡ пёҸ ШӘШ№Ш°Шұ ШӘШ¬ЩҮЩҠШІ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© вҖ” {team}\nШ§Щ„ШіШЁШЁ: {type(e).__name__}", "updated_at": updated_at}
    _v48_save_exit_cache(cache)
    return cache


async def _v48_refresh_exit_probs_bg(bot, chat_id):
    global V48_EXIT_UPDATE_TASK, V48_EXIT_UPDATE_STARTED_AT, V48_EXIT_UPDATE_LOCK
    try:
        if V48_EXIT_UPDATE_LOCK is None:
            V48_EXIT_UPDATE_LOCK = asyncio.Lock()
        async with V48_EXIT_UPDATE_LOCK:
            data = await asyncio.to_thread(_v48_update_exit_probabilities_all)
            try:
                await bot.send_message(chat_id=chat_id, text=f"вң… ШӘЩ… ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©\nШўШ®Шұ ШӘШӯШҜЩҠШ«: {data.get('updated_at','-')} ШЁШӘЩҲЩӮЩҠШӘ Щ…ЩғШ©\nШ№ШҜШҜ Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ: {data.get('count',0)}")
            except Exception:
                pass
    except Exception as e:
        try:
            await bot.send_message(chat_id=chat_id, text=f"вқҢ ШӘШ№Ш°Шұ ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©\n{type(e).__name__}: {str(e)[:220]}")
        except Exception:
            pass
    finally:
        V48_EXIT_UPDATE_TASK = None
        V48_EXIT_UPDATE_STARTED_AT = ""


async def v48_refresh_exit_probs_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    global V48_EXIT_UPDATE_TASK, V48_EXIT_UPDATE_STARTED_AT
    msg = update.effective_message
    if V48_EXIT_UPDATE_TASK and not V48_EXIT_UPDATE_TASK.done():
        await msg.reply_text(f"вҸі ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ© ШҙШәШ§Щ„ ШЁШ§Щ„ЩҒШ№Щ„ Щ…ЩҶ: {V48_EXIT_UPDATE_STARTED_AT or '-'}")
        return
    V48_EXIT_UPDATE_STARTED_AT = _v48_now_makkah_str()
    await msg.reply_text("вҸі ШЁШҜШЈ ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШЁШ§Щ„Ш®Щ„ЩҒЩҠШ©...\nШӘЩӮШҜШұ ШӘШіШӘШ®ШҜЩ… Ш§Щ„ШЁЩҲШӘ Ш№Ш§ШҜЩҠ.")
    try:
        V48_EXIT_UPDATE_TASK = context.application.create_task(_v48_refresh_exit_probs_bg(context.bot, msg.chat_id))
    except Exception:
        V48_EXIT_UPDATE_TASK = asyncio.create_task(_v48_refresh_exit_probs_bg(context.bot, msg.chat_id))


# ШІШұ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШҜШ§Ш®Щ„ ШЈШІШұШ§Шұ ЩғЩҠЩҒ ШӘШӘШЈЩҮЩ„ вҖ” ЩҠШ№ШұШ¶ ШўШ®Шұ ЩғШ§Шҙ ЩҒЩӮШ·.
try:
    _V48_PREV_HOW_KEYBOARD = _v33_how_qualify_keyboard
except Exception:
    _V48_PREV_HOW_KEYBOARD = None

def _v33_how_qualify_keyboard(team):
    team = _v33_find_team(team) if '_v33_find_team' in globals() else team
    key = _v33_team_button_key(team) if '_v33_team_button_key' in globals() else _v48_team_key(team)
    try:
        kb = _V48_PREV_HOW_KEYBOARD(team) if _V48_PREV_HOW_KEYBOARD else InlineKeyboardMarkup([])
        rows = [list(r) for r in (getattr(kb, 'inline_keyboard', None) or [])]
    except Exception:
        rows = []
    cb = f"v32|exit_cached|{key}"
    exists = any(getattr(btn, 'callback_data', '') == cb for row in rows for btn in row)
    if not exists:
        # ЩӮШЁЩ„ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©/Ш§Щ„ШұШ¬ЩҲШ№ ШҘЩҶ ШЈЩ…ЩғЩҶ.
        insert_at = max(0, len(rows) - 2)
        rows.insert(insert_at, [InlineKeyboardButton("вқҢ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©", callback_data=cb)])
    return InlineKeyboardMarkup(rows)


try:
    _V48_PREV_V32_CALLBACK = v32_callback
except Exception:
    _V48_PREV_V32_CALLBACK = None
async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    parts = data.split('|')
    action = parts[1] if len(parts) > 1 else ''
    if action == 'exit_cached' and len(parts) >= 3:
        try: await q.answer()
        except Exception: pass
        team = _v33_team_from_button_key(parts[2]) if '_v33_team_from_button_key' in globals() else parts[2]
        text = _v48_get_cached_exit_text(team)
        try:
            await q.edit_message_text(text[:3900], reply_markup=_v33_how_qualify_keyboard(team))
        except Exception:
            await q.message.reply_text(text[:3900], reply_markup=_v33_how_qualify_keyboard(team))
        return
    if _V48_PREV_V32_CALLBACK:
        return await _V48_PREV_V32_CALLBACK(update, context)


# ШІШұ ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ© ЩҒЩҠ Ш§Щ„ШҘШҜШ§ШұШ©.
try:
    _V48_PREV_ADMIN_KEYBOARD = _v38e_admin_keyboard
except Exception:
    _V48_PREV_ADMIN_KEYBOARD = None

def _v38e_admin_keyboard():
    try:
        kb = _V48_PREV_ADMIN_KEYBOARD() if _V48_PREV_ADMIN_KEYBOARD else InlineKeyboardMarkup([])
        rows = [list(r) for r in (getattr(kb, 'inline_keyboard', None) or [])]
    except Exception:
        rows = []
    exists = any(getattr(btn, 'callback_data', '') == 'v32adm|refresh_exit_probs' for row in rows for btn in row)
    if not exists:
        rows.append([InlineKeyboardButton("рҹ”„ ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ©", callback_data="v32adm|refresh_exit_probs")])
    return InlineKeyboardMarkup(rows)


try:
    _V48_PREV_ADMIN_CALLBACK = v32_admin_callback
except Exception:
    _V48_PREV_ADMIN_CALLBACK = None
async def v32_admin_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    parts = (q.data or '').split('|')
    action = parts[1] if len(parts) > 1 else ''
    if action == 'refresh_exit_probs':
        try: await q.answer()
        except Exception: pass
        if not is_admin_user(update):
            await q.message.reply_text('ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’'); return
        global V48_EXIT_UPDATE_TASK, V48_EXIT_UPDATE_STARTED_AT
        if V48_EXIT_UPDATE_TASK and not V48_EXIT_UPDATE_TASK.done():
            await q.message.reply_text(f"вҸі ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ© ШҙШәШ§Щ„ ШЁШ§Щ„ЩҒШ№Щ„ Щ…ЩҶ: {V48_EXIT_UPDATE_STARTED_AT or '-'}")
            return
        V48_EXIT_UPDATE_STARTED_AT = _v48_now_makkah_str()
        await q.message.reply_text("вҸі ШЁШҜШЈ ШӘШӯШҜЩҠШ« Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш© ШЁШ§Щ„Ш®Щ„ЩҒЩҠШ©...\nШӘЩӮШҜШұ ШӘШіШӘШ®ШҜЩ… Ш§Щ„ШЁЩҲШӘ Ш№Ш§ШҜЩҠ.")
        try:
            V48_EXIT_UPDATE_TASK = context.application.create_task(_v48_refresh_exit_probs_bg(context.bot, q.message.chat_id))
        except Exception:
            V48_EXIT_UPDATE_TASK = asyncio.create_task(_v48_refresh_exit_probs_bg(context.bot, q.message.chat_id))
        return
    if _V48_PREV_ADMIN_CALLBACK:
        return await _V48_PREV_ADMIN_CALLBACK(update, context)

# ==================== END V48 EXIT PROBABILITIES CACHED ADMIN PATCH вҖ” FAHAD ====================


# ==================== V49 FINAL AGREEMENTS PATCH вҖ” FAHAD ====================
# Ш§Ш№ШӘЩ…Ш§ШҜ ЩҒЩҮШҜ:
# - Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ ЩҠШӯШҜШ« ЩғЩ„ ШҜЩӮЩҠЩӮШӘЩҠЩҶ Щ…ЩҶ 6Щ… ШҘЩ„Щү 10Шө ШЁШӘЩҲЩӮЩҠШӘ Щ…ЩғШ©ШҢ ШЁШҜЩҲЩҶ ШұШіШ§ШҰЩ„ Щ…ШІШ№Ш¬Ш©.
# - ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ШЁШ·ЩҲЩ„Ш©: ESPN ШЈШіШ§ШіЩҠ + SofaScore Ш§ШӯШӘЩҠШ§Ш·ЩҠ ШҘШ°Ш§ ESPN Щ…ШӘШЈШ®Шұ/ЩҶШ§ЩӮШөШҢ ШЁШҜЩҲЩҶ ЩғШ§Шҙ ШӘЩӮЩҶЩҠ ШёШ§ЩҮШұ.
# - ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„/ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©/Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«/Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ ШЁШөЩҠШә Щ…ЩҲШӯШҜШ©.
# - Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©: ШӘШҙШәЩҠЩ„ ШҘШҜШ§ШұЩҠ Щ…ЩҶЩҒШөЩ„ ШЁЩ…ЩҮЩ„Ш© 240 Ш«Ш§ЩҶЩҠШ©ШҢ Ш§Щ„Щ…ШіШӘШ®ШҜЩ… ЩҠЩӮШұШЈ Ш§Щ„ЩғШ§Шҙ ЩҒЩӮШ·.
# - ШӯШ°ЩҒ ШІШұ Щ…ШіШ¬Щ„ЩҠ Ш§Щ„ШЈЩҮШҜШ§ЩҒ Щ…ЩҶ ШЈШұШҙЩҠЩҒ Ш§Щ„ШЁШ·ЩҲЩ„Ш©.

import subprocess as _v49_subprocess
import sys as _v49_sys

V49_EXIT_TIMEOUT_SECONDS = 240
V49_LIVE_REFRESH_INTERVAL = 120
V49_LIVE_TRACKED_MESSAGES = {}
V49_LIVE_LAST_DAY_REFRESH = {"date": "", "ts": 0}
_V49_TOP_SCORERS_LAST_META = {"source": "-", "fetched_at": "-", "error": ""}


def _v49_now_makkah_dt():
    try:
        return _v33_now_riyadh_dt()
    except Exception:
        try:
            return datetime.utcnow() + timedelta(hours=3)
        except Exception:
            return datetime.now()


def _v49_now_makkah_str():
    try:
        return _v49_now_makkah_dt().strftime("%d/%m/%Y вҖ” %I:%M %p").replace("AM", "Шө").replace("PM", "Щ…")
    except Exception:
        return "-"


def _v49_in_live_refresh_window(now=None):
    now = now or _v49_now_makkah_dt()
    try:
        h = int(now.hour)
        return h >= 18 or h < 10
    except Exception:
        return False


def _v49_points_word(n):
    try:
        n = int(n or 0)
    except Exception:
        n = 0
    return "ЩҶЩӮШ·Ш©" if n == 1 else "ЩҶЩӮШ§Ш·"


def _v49_safe_int(v, default=0):
    try:
        return int(v or 0)
    except Exception:
        return default


def _v49_sort_matches(matches):
    def key(m):
        try:
            dt = _v33_parse_fixture_datetime(m)
            if dt:
                return dt
        except Exception:
            pass
        return datetime.max
    try:
        return sorted(list(matches or []), key=key)
    except Exception:
        return list(matches or [])


def _v49_match_lines(m):
    t1 = m.get('team1') or m.get('home') or '-'
    t2 = m.get('team2') or m.get('away') or '-'
    d = m.get('date') or ''
    tm = m.get('time') or ''
    line1 = f"{t1} Г— {t2}"
    line2 = ""
    if d and tm:
        line2 = f"   {d} вҖ” {tm}"
    elif d:
        line2 = f"   {d}"
    elif tm:
        line2 = f"   {tm}"
    return [line1, line2] if line2 else [line1]


def _v49_remaining_for_team(team, group_code=None, snap=None):
    snap = snap or (_v33_snapshot(False) if '_v33_snapshot' in globals() else {})
    group_code = group_code or (_v33_team_group(team) if '_v33_team_group' in globals() else '')
    out = []
    try:
        for m in _v33_group_remaining(group_code, snap) or []:
            if team in (m.get('team1'), m.get('team2')):
                out.append(m)
    except Exception:
        pass
    return _v49_sort_matches(out)


# ---------- ШӘЩҶШіЩҠЩӮ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© + ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ ----------
def _v38d_group_rows_lines(code, rows):
    lines = []
    for i, r in enumerate(rows or [], start=1):
        name = r.get('team') or '-'
        pts = _v49_safe_int(r.get('Pts'))
        gd = _v49_safe_int(r.get('GD'))
        gf = _v49_safe_int(r.get('GF'))
        lines.append(f"{i}. {name} вҖ” {pts} {_v49_points_word(pts)} | ЩҒШ§ШұЩӮ {gd:+d} | ШЈЩҮШҜШ§ЩҒ {gf}")
    return lines or ["Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ШӘШұШӘЩҠШЁ ЩғШ§ЩҒЩҠШ© ШӯШ§Щ„ЩҠЩӢШ§."]


def _v38d_group_remaining_lines(code, snap=None):
    snap = snap or (_v33_snapshot(False) if '_v33_snapshot' in globals() else {})
    try:
        rem = _v49_sort_matches(_v33_group_remaining(code, snap) or [])
    except Exception:
        rem = []
    lines = []
    for i, m in enumerate(rem, start=1):
        ml = _v49_match_lines(m)
        lines.append(f"{i}. {ml[0]}")
        if len(ml) > 1:
            lines.append(ml[1])
        if i != len(rem):
            lines.append("")
    return lines or ["Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ШӘШЁЩӮЩҠШ© ЩҒЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."]


def _v38d_group_details_text(team):
    team = _v33_find_team(team) or team
    snap = _v33_snapshot(False)
    code, pos, row, rows = _v33_group_row(team, snap)
    lines = [f"рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ {_v33_group_label(code)}", ""]
    lines.extend(_v38d_group_rows_lines(code, rows))
    lines.append("")
    lines.append("рҹ“… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:")
    lines.append("")
    lines.extend(_v38d_group_remaining_lines(code, snap))
    return "\n".join(lines).strip()


def _v49_possible_summary(team, snap=None):
    snap = snap or _v33_snapshot(False)
    possible = set()
    try:
        possible, _examples = _v38d_possible_positions(team, snap)
        possible = set(possible or [])
    except Exception:
        pass
    paths = []
    if 1 in possible:
        paths.append("рҹҘҮ ШЈЩҲЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    if 2 in possible:
        paths.append("рҹҘҲ Ш«Ш§ЩҶЩҠ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    if 3 in possible:
        paths.append("рҹҘү ШЈЩҲ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«")
    if not paths:
        return [f"Щ…ЩҲЩӮЩҒ Щ…ЩҶШӘШ®ШЁ {team} ШәЩҠШұ Щ…ШӯШіЩҲЩ…ШҢ ЩҲЩҠШ№ШӘЩ…ШҜ Ш№Щ„Щү ЩҶШӘШ§ШҰШ¬ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҲШЁЩӮЩҠШ© Ш§Щ„Ш«ЩҲШ§Щ„Ш«."]
    return [f"Щ…ЩҶШӘШ®ШЁ {team} Щ…Ш§ ШІШ§Щ„ ЩҠЩ…Щ„Щғ Ш§Щ„Щ…ШіШ§ШұШ§ШӘ Ш§Щ„Щ…Щ…ЩғЩҶШ© Щ„Щ„ШӘШЈЩҮЩ„.", "", "ЩҠЩ…ЩғЩҶЩҮ Ш§Щ„ШӘШЈЩҮЩ„ ЩғЩҖ:"] + paths + ["", "ШӯШіШЁ ЩҶШӘШ§ШҰШ¬ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ ЩҲЩҶШӘШ§ШҰШ¬ ШЁШ§ЩӮЩҠ Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©."]


def _v33_how_qualify_text(team, force=False):
    team = _v33_find_team(team)
    if not team:
        return "Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ. Ш§ЩғШӘШЁ Ш§ШіЩ… Щ…ЩҶШӘШ®ШЁ Щ…Ш«Щ„: Ш§Щ„ШіШ№ЩҲШҜЩҠШ© ШЈЩҲ Щ…ШөШұ ШЈЩҲ Ш§Щ„Ш№ШұШ§ЩӮ."
    snap = _v33_snapshot(force)
    status_txt = str((snap.get('status') or {}).get(team, '') or '')
    if ('Щ…ШӘШЈЩҮЩ„' in status_txt and 'ШұШіЩ…ЩҠ' in status_txt) or ('Ш¶Щ…ЩҶ ШұШіЩ…ЩҠ' in status_txt):
        try:
            return _v39_official_qualified_text(team, snap)
        except Exception:
            pass
    if (('Щ…ШіШӘШЁШ№ШҜ' in status_txt or 'ШәШ§ШҜШұ' in status_txt) and 'ШұШіЩ…ЩҠ' in status_txt):
        # ЩҶШӘШұЩғ ШөЩҠШәШ© Ш§Щ„Ш§ШіШӘШЁШ№Ш§ШҜ Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШӯШӘЩү Щ„Ш§ ЩҶШ®ШұШЁ Ш§Щ„ШӯЩғЩ… Ш§Щ„ШұШіЩ…ЩҠ.
        try:
            return _V39_PREV_HOW_QUALIFY_TEXT(team, force)
        except Exception:
            return f"вқҢ Щ…ЩҶШӘШ®ШЁ {team} Щ…ШіШӘШЁШ№ШҜ ШұШіЩ…ЩҠЩӢШ§."
    code, pos, row, rows = _v33_group_row(team, snap)
    lines = [f"вң… ЩғЩҠЩҒ ЩҠШӘШЈЩҮЩ„ Щ…ЩҶШӘШ®ШЁ {team}Шҹ", ""]
    lines.append(f"рҹ“Ҡ ШӘШұШӘЩҠШЁ {_v33_group_label(code)}:")
    lines.append("")
    lines.extend(_v38d_group_rows_lines(code, rows))
    if row:
        pts = _v49_safe_int(row.get('Pts'))
        lines += [
            "",
            f"рҹ“Ң ЩҲШ¶Ш№ {team} Ш§Щ„ШӯШ§Щ„ЩҠ:",
            f"Ш§Щ„Щ…ШұЩғШІ: {pos}",
            f"Ш§Щ„ЩҶЩӮШ§Ш·: {pts}",
            f"Щ„Ш№ШЁ: {row.get('P')}/3",
            f"Ш§Щ„ЩҒШ§ШұЩӮ: {_v49_safe_int(row.get('GD')):+d}",
        ]
    lines += ["", "рҹ“… Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:", ""]
    lines.extend(_v38d_group_remaining_lines(code, snap))
    lines += ["", "вң… Ш§Щ„Ш®Щ„Ш§ШөШ© Ш§Щ„ШӯШіШ§ШЁЩҠШ©:"]
    lines.extend(_v49_possible_summary(team, snap))
    lines += ["", "Ш§Ш¶ШәШ· Ш§Щ„ШЈШІШұШ§Шұ ШЁШ§Щ„ШЈШіЩҒЩ„ Щ„Щ„ШӘЩҒШ§ШөЩҠЩ„:", ""]
    try:
        possible, _examples = _v38d_possible_positions(team, snap)
        possible = set(possible or [])
    except Exception:
        possible = set()
    if 1 in possible:
        lines.append("рҹҘҮ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„")
    if 2 in possible:
        lines.append("рҹҘҲ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ")
    if 3 in possible:
        lines.append("рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШӘШӯЩ„ЩҠЩ„ЩҮ")
        lines.append("рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ")
    lines.append("рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©")
    return "\n".join(lines).strip()


def _v33_how_qualify_keyboard(team):
    team = _v33_find_team(team) or team
    snap = _v33_snapshot(False)
    code, pos, row, rows = _v33_group_row(team, snap)
    status_txt = str((snap.get('status') or {}).get(team, '') or '')
    key = _v33_team_button_key(team)
    is_q = ('Щ…ШӘШЈЩҮЩ„' in status_txt and 'ШұШіЩ…ЩҠ' in status_txt) or ('Ш¶Щ…ЩҶ ШұШіЩ…ЩҠ' in status_txt)
    is_out = (('Щ…ШіШӘШЁШ№ШҜ' in status_txt or 'ШәШ§ШҜШұ' in status_txt) and 'ШұШіЩ…ЩҠ' in status_txt)
    if is_q or is_out:
        rows_btn = []
        try:
            if is_q and '_v38e_has_opponent_group' in globals() and _v38e_has_opponent_group(team):
                rows_btn.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Щ…Ш¬Щ…ЩҲШ№Ш© Ш§Щ„Ш®ШөЩ…', callback_data=f'v32|opp_group|{key}')])
        except Exception:
            pass
        rows_btn.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', callback_data=f'v32|how_group|{key}')])
        rows_btn.append([InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')])
        return InlineKeyboardMarkup(rows_btn)
    try:
        possible, _examples = _v38d_possible_positions(team, snap)
        possible = set(possible or [])
    except Exception:
        possible = set()
        if pos: possible.add(int(pos))
    rows_btn = []
    row_btn = []
    if 1 in possible:
        row_btn.append(InlineKeyboardButton('рҹҘҮ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„', callback_data=f'v32|how_first|{key}'))
    if 2 in possible:
        row_btn.append(InlineKeyboardButton('рҹҘҲ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ', callback_data=f'v32|how_second|{key}'))
    if row_btn:
        rows_btn.append(row_btn[:2])
    if 3 in possible:
        rows_btn.append([InlineKeyboardButton('рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШӘШӯЩ„ЩҠЩ„ЩҮ', callback_data=f'v32|how_thirds|{key}')])
    rows_btn.append([InlineKeyboardButton('рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ', callback_data=f'v32|opp_all|{key}')])
    rows_btn.append([InlineKeyboardButton('вқҢ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Щ…ШәШ§ШҜШұШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©', callback_data=f'v32|exit_cached|{key}')])
    rows_btn.append([InlineKeyboardButton('рҹ“Ҡ ШӘЩҒШ§ШөЩҠЩ„ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш©', callback_data=f'v32|how_group|{key}')])
    rows_btn.append([InlineKeyboardButton('рҹ§® Ш¬ШұЩ‘ШЁ ШіЩҠЩҶШ§ШұЩҠЩҲ', callback_data='v32|calc_start'), InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')])
    return InlineKeyboardMarkup(rows_btn)


# ---------- Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«: Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ШӘШЁЩӮЩҠШ© + ЩҶШӘЩҠШ¬Ш© ШӘШ¶Шұ ----------
def _v49_third_item_lines(x, target_team, target_pts, mode, snap=None):
    snap = snap or _v33_snapshot(False)
    t = x.get('team') or '-'
    g = x.get('group') or (_v33_team_group(t) if '_v33_team_group' in globals() else '')
    pts = _v49_safe_int(x.get('pts'))
    played = _v49_safe_int(x.get('played'))
    gd = _v49_safe_int(x.get('gd'))
    rem_matches = _v49_remaining_for_team(t, g, snap)
    rem = max(0, 3 - played)
    max_pts = pts + rem * 3
    lines = [
        f"- {t} вҖ” {_v33_group_label(g)}",
        f"  Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Щ„Ш№ШЁ: {played}/3 | Ш§Щ„ЩҒШ§ШұЩӮ: {gd:+d}",
        "",
    ]
    if rem_matches:
        lines.append("  Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:" if len(rem_matches) == 1 else "  Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ©:")
        for m in rem_matches:
            for ml in _v49_match_lines(m):
                lines.append(f"  {ml.strip()}")
        lines.append("")
    else:
        lines.append("  Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ…ШӘШЁЩӮЩҠШ©.")
        lines.append("")
    if mode == 'exceed':
        need = max(1, target_pts + 1 - pts)
        if rem <= 0:
            msg = f"{t} ШЈЩ…Ш§Щ… {target_team} ШЁШ§Щ„ЩҶЩӮШ§Ш· ШӯШ§Щ„ЩҠЩӢШ§." if pts > target_pts else f"Щ„Ш§ ЩҠШіШӘШ·ЩҠШ№ ШӘШ¬Ш§ЩҲШІ {target_team} ШЁШ§Щ„ЩҶЩӮШ§Ш·."
        elif need <= 1:
            msg = f"Ш¬Щ…Ш№ ЩҶЩӮШ·Ш© ЩҲШ§ШӯШҜШ© Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„ вһң ЩҠШӘШ¬Ш§ЩҲШІ {target_team} ШЁШ§Щ„ЩҶЩӮШ§Ш· ШҘШ°Ш§ ШЈШөШЁШӯ Ш«Ш§Щ„Ш«ЩӢШ§."
        elif need <= 3 and rem == 1:
            msg = f"ЩҒЩҲШІ {t} ЩҒЩҠ Щ…ШЁШ§ШұШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© вһң ЩҠШөЩ„ ШҘЩ„Щү {pts+3} ЩҶЩӮШ§Ш· ЩҲЩҠШӘШ¬Ш§ЩҲШІ {target_team} ШЁШ§Щ„ЩҶЩӮШ§Ш·."
        else:
            msg = f"Ш¬Щ…Ш№ ШЈЩғШ«Шұ Щ…ЩҶ {max(0, target_pts-pts)} ЩҶЩӮШ§Ш· Щ…ЩҶ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© вһң ЩӮШҜ ЩҠШөЩ„ ШҘЩ„Щү {max_pts} ЩҶЩӮШ§Ш· ЩҲЩҠШӘШ¬Ш§ЩҲШІ {target_team}."
        lines.append(f"  Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШӘЩҠ ШӘШ¶Шұ {target_team}:")
        lines.append(f"  {msg}")
    elif mode == 'equal':
        need = target_pts - pts
        if need <= 0:
            msg = f"ЩҠШЁЩӮЩү ЩӮШұЩҠШЁЩӢШ§ Щ…ЩҶ {target_team} ШЁШ§Щ„ЩҶЩӮШ§Ш·ШҢ ЩҲШ§Щ„ШӯШіЩ… ЩҠЩғЩҲЩҶ ШЁШ§Щ„ЩҒШ§ШұЩӮ ШҘШ°Ш§ ШӘШіШ§ЩҲЩҠШ§."
        elif need == 1 and rem == 1:
            msg = f"ШӘШ№Ш§ШҜЩ„ {t} ЩҒЩҠ Щ…ШЁШ§ШұШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© вһң ЩҠШөЩ„ ШҘЩ„Щү {target_pts} ЩҶЩӮШ§Ш· ЩҲЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ Щ…Ш№ {target_team}."
        elif need <= 3 and rem == 1:
            msg = f"ЩҒЩҲШІ {t} ЩҒЩҠ Щ…ШЁШ§ШұШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© вһң ЩҠШөЩ„ ШҘЩ„Щү {target_pts} ЩҶЩӮШ§Ш· ЩҲЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ Щ…Ш№ {target_team}."
        else:
            msg = f"Ш¬Щ…Ш№ {need} ЩҶЩӮШ§Ш· Щ…ЩҶ Щ…ШЁШ§ШұЩҠШ§ШӘЩҮ Ш§Щ„Щ…ШӘШЁЩӮЩҠШ© вһң ЩҠШөЩ„ ШҘЩ„Щү {target_pts} ЩҶЩӮШ§Ш· ЩҲЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ Щ…Ш№ {target_team}."
        lines.append(f"  Ш§Щ„ЩҶШӘЩҠШ¬Ш© Ш§Щ„ШӘЩҠ ШӘШ¶Шұ {target_team}:")
        lines.append(f"  {msg}")
    else:
        lines.append(f"  ШӯШӘЩү ЩҒЩҠ ШӯШ§Щ„ Ш§Щ„ЩҒЩҲШІ:")
        lines.append(f"  {t} ЩҠШөЩ„ ШҘЩ„Щү {max_pts} ЩҶЩӮШ§Ш· ЩҒЩӮШ·ШҢ ЩҲЩҠШЁЩӮЩү Ш®Щ„ЩҒ {target_team}.")
    return lines


def _v37_third_path_summary_block(team, target_pts, snap=None):
    snap = snap or _v33_snapshot(False)
    try:
        danger, mixed, compare, safe = _v38e_third_categories(team, target_pts, snap)
    except Exception:
        danger, mixed, compare, safe = [], [], [], []
    exceed = []
    seen = set()
    for x in list(danger or []) + list(mixed or []):
        t = x.get('team')
        if t and t not in seen:
            seen.add(t); exceed.append(x)
    guaranteed = len(safe or [])
    lines = []
    lines.append(f"вң… Ш§Щ„Щ…Ш¶Щ…ЩҲЩҶ Ш®Щ„ЩҒ {team}: {min(guaranteed,4)}/4")
    if guaranteed >= 4:
        lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: вң… {team} ЩҠШ¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш« ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ШЁЩҮШ°Ш§ Ш§Щ„ШұШөЩҠШҜ.")
    else:
        lines.append(f"Ш§Щ„ШӯШ§Щ„Ш©: ЩҠШӯШӘШ§Ш¬ {4-guaranteed} Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш«Ш§Щ„Ш«Ш© ШҘШ¶Ш§ЩҒЩҠШ© ШӘШЁЩӮЩү Ш®Щ„ЩҒЩҮ Щ„Ш¶Щ…Ш§ЩҶ Ш§Щ„ШӘШЈЩҮЩ„.")
    lines.append("")
    lines.append(f"рҹ”Ҙ ЩӮШҜ ЩҠШӘШ¬Ш§ЩҲШІ {team} ШЁШ§Щ„ЩҶЩӮШ§Ш· ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«:")
    if not exceed:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ЩҶШӘШ®ШЁ ЩҲШ§Ш¶Шӯ ЩҠШӘШ¬Ш§ЩҲШІЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш· ШӯШіШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    for x in exceed[:8]:
        lines.extend(_v49_third_item_lines(x, team, int(target_pts or 0), 'exceed', snap)); lines.append("")
    lines.append(f"вҡ–пёҸ ЩӮШҜ ЩҠШӘШ№Ш§ШҜЩ„ Щ…Ш№ {team} ЩҲЩҠШҜШ®Щ„ Щ…ЩӮШ§ШұЩҶШ© Ш§Щ„ЩҒШ§ШұЩӮ:")
    if not compare:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ЩҶШӘШ®ШЁ ЩҲШ§Ш¶Шӯ ЩҠШӘШ№Ш§ШҜЩ„ Щ…Ш№ЩҮ ШЁШ§Щ„ЩҶЩӮШ§Ш· ШӯШіШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    for x in (compare or [])[:8]:
        lines.extend(_v49_third_item_lines(x, team, int(target_pts or 0), 'equal', snap)); lines.append("")
    lines.append(f"вң… Ш®Щ„ЩҒ {team} Щ…Ш¶Щ…ЩҲЩҶ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«:")
    if not safe:
        lines.append("Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ЩҶШӘШ®ШЁ Щ…Ш¶Щ…ЩҲЩҶ Ш®Щ„ЩҒЩҮ ШӯШ§Щ„ЩҠЩӢШ§ ШӯШіШЁ Ш§Щ„ШЁЩҠШ§ЩҶШ§ШӘ Ш§Щ„ШӯШ§Щ„ЩҠШ©.")
    for x in (safe or [])[:6]:
        lines.extend(_v49_third_item_lines(x, team, int(target_pts or 0), 'safe', snap)); lines.append("")
    lines.append('вҡ пёҸ ЩҒЩҠ ШӯШ§Щ„ ШӘШіШ§ЩҲЩҠ Ш§Щ„ЩҶЩӮШ§Ш·ШҢ ЩҠШӘЩ… Ш§Щ„ШӯШіЩ… ШЁЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ Ш«Щ… Ш§Щ„ШЈЩҮШҜШ§ЩҒ Ш§Щ„Щ…ШіШ¬Щ„Ш©.')
    return lines


def _v33_how_thirds_text(team):
    team = _v33_find_team(team) or team
    if not team:
        return 'Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ.'
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    case = _v37_third_case_info(team, snap) if '_v37_third_case_info' in globals() else None
    target_pts = None
    if case:
        target_pts = case.get('pts')
    else:
        try:
            target_pts, case = _v37_target_third_points(team, snap)
        except Exception:
            target_pts, case = None, None
    lines = [f'рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШӘШӯЩ„ЩҠЩ„ЩҮ вҖ” {team}', '']
    if target_pts is None:
        lines.append(f'Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ЩҲШ§Ш¶Шӯ ШӯШ§Щ„ЩҠЩӢШ§ ЩҠШ¬Ш№Щ„ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)} ШЁШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ©.')
        lines.append('ШҘШ°Ш§ ШӘШәЩҠЩ‘ШұШӘ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш«ШҢ ШіЩҠШӯШіШЁЩҮ Ш§Щ„ШЁЩҲШӘ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§.')
        return '\n'.join(lines).strip()
    lines.append(f'{team} ЩҠШіШӘШ·ЩҠШ№ ШӯШіШ§ШЁЩҠЩӢШ§ ШҘЩҶЩҮШ§ШЎ {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«.')
    lines.append('')
    if case:
        reqs = _v38_scenario_required_lines(team, case.get('scenario') or {}, snap, max_lines=6) if '_v38_scenario_required_lines' in globals() else []
        if reqs:
            lines.append('Щ…Ш«Ш§Щ„ Щ…ШіШ§Шұ Щ…Щ…ЩғЩҶ:')
            for i, r in enumerate(reqs, start=1):
                lines.append(f'{i}. {r}')
            lines.append('')
        rows_case = ((case.get('case') or {}).get('rows') or (case.get('scenario') or {}).get('rows') or [])[:4]
        if rows_case:
            lines.append('Ш§Щ„ШӘШұШӘЩҠШЁ ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„Щ…Ш«Ш§Щ„:')
            for i, rr in enumerate(rows_case, start=1):
                p = _v49_safe_int(rr.get('Pts'))
                lines.append(f"{i}. {rr.get('team')} вҖ” {p} {_v49_points_word(p)}")
            lines.append('')
            lines.append(f'рҹ“Ң Щ„Щ…Ш§Ш°Ш§ ШЈШөШЁШӯ {team} Ш«Ш§Щ„Ш«ЩӢШ§Шҹ')
            lines.append(_v39_why_third(team, rows_case))
            lines.append('')
    lines.append(f'ШЁШ№ШҜЩҮШ§ ЩҠШҜШ®Щ„ {team} ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШҘШ°Ш§ ЩғШ§ЩҶ ШұШөЩҠШҜЩҮ ЩҠШіЩ…Шӯ ШЁШ§Щ„Щ…ЩҶШ§ЩҒШіШ©.')
    lines.append('')
    try:
        lines.extend(_v37_third_path_summary_block(team, int(target_pts or 0), snap))
    except Exception:
        lines.append('вҡ пёҸ ШӘЩҒШ§ШөЩҠЩ„ Щ…ЩӮШ§ШұЩҶШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШәЩҠШұ Щ…ШӘЩҲЩҒШұШ© ШӯШ§Щ„ЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


# ---------- Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ: ШЈЩҲЩ„/Ш«Ш§ЩҶЩҠ/ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш« ----------
def _v49_opponent_block_for_position(team, pos, snap=None):
    snap = snap or _v33_snapshot(False)
    label = 'рҹҘҮ ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„:' if int(pos) == 1 else 'рҹҘҲ ШҘШ°Ш§ ШЈЩҶЩҮЩү Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ:'
    try:
        info = _v40_r32_info_for_position(team, pos, snap)
        slot = info.get('slot') or '-'
        opponent = info.get('opponent') or 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§'
        date_line = info.get('date_line') or 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§'
        opp_group = info.get('opp_group')
    except Exception:
        opponent, slot, date_line, opp_group = 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§', '-', 'ЩҠШӘШӯШҜШҜ Щ„Ш§ШӯЩӮЩӢШ§', ''
    lines = [label, str(slot), '', f"      {team}      Г—      {opponent}", '', 'Ш§Щ„Ш®ШөЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ ШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„ШӯШ§Щ„ЩҠ:', f'{opponent}', '', 'рҹ—“пёҸ Щ…ЩҲШ№ШҜ Ш§Щ„Щ…ШЁШ§ШұШ§Ш©:', str(date_line)]
    if opp_group:
        lines += ['', f'вҡ пёҸ ЩӮШҜ ЩҠШӘШәЩҠШұ Ш§Щ„Ш®ШөЩ… ШҘШ°Ш§ ШӘШәЩҠЩ‘Шұ ШӘШұШӘЩҠШЁ {_v33_group_label(opp_group)}.']
    return lines


def _v33_all_opponents_text(team, snap=None):
    snap = snap or _v33_snapshot(False)
    team = _v33_find_team(team) or team
    code = _v33_team_group(team)
    lines = [f'рҹҸҹпёҸ Ш§Щ„Ш®ШөЩҲЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ЩҠЩҶ вҖ” {team}', '', f'ШӯШіШЁ ЩҲШ¶Ш№ {team} Ш§Щ„ШӯШ§Щ„ЩҠШҢ ЩҮШ°ЩҮ Ш®Ш§ЩҶШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32 Ш§Щ„Щ…ШӯШӘЩ…Щ„Ш© ШҘШ°Ш§ ШӘШЈЩҮЩ„:', '']
    try:
        possible, _ex = _v38d_possible_positions(team, snap)
        possible = set(possible or [])
    except Exception:
        possible = {1,2,3}
    if 1 in possible:
        lines.extend(_v49_opponent_block_for_position(team, 1, snap)); lines.append('')
    if 2 in possible:
        lines.extend(_v49_opponent_block_for_position(team, 2, snap)); lines.append('')
    if 3 in possible:
        lines.append(f'рҹҘү ШҘШ°Ш§ ШӘШЈЩҮЩ„ {team} ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«:')
        lines.append('Ш§Щ„Ш®ШөЩ… ЩҠШӘШӯШҜШҜ ШӯШіШЁ Ш®Ш§ЩҶШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ЩҒЩҠ Ш¬ШҜЩҲЩ„ ЩҒЩҠЩҒШ§ Ш§Щ„ШұШіЩ…ЩҠ.')
        lines.append('')
        try:
            slots, excluded, weak = _v33_possible_slots_for_third_group(code, snap)
        except Exception:
            slots, excluded, weak = [], [], []
        if not slots:
            lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ Ш®Ш§ЩҶШ© Щ…ШӯШӘЩ…Щ„Ш© ЩҲШ§Ш¶ШӯШ© Ш§Щ„ШўЩҶ.')
        else:
            lines.append('Ш§Щ„Ш®Ш§ЩҶШ§ШӘ Ш§Щ„Щ…Щ…ЩғЩҶШ© ШӯШ§Щ„ЩҠЩӢШ§ ШЁШ№ШҜ ШӯШ°ЩҒ Ш§Щ„Щ…ШіШӘШӯЩҠЩ„:')
            for slot in slots:
                leader = _v33_group_leader(slot, snap) or f'Щ…ШӘШөШҜШұ {_v33_group_label(slot)}'
                lines.append(f'- Ш«Ш§Щ„Ш« {_v33_group_label(code)} Г— Щ…ШӘШөШҜШұ {_v33_group_label(slot)}')
                lines.append('')
                lines.append(f'      {team}      Г—      {leader}')
                lines.append('')
                lines.append('  Ш§Щ„Ш®ШөЩ… Ш§Щ„Щ…ШӯШӘЩ…Щ„ ШӯШіШЁ Ш§Щ„ШӘШұШӘЩҠШЁ Ш§Щ„ШӯШ§Щ„ЩҠ:')
                lines.append(f'  {leader} вҖ” Щ…ШӘШөШҜШұ {_v33_group_label(slot)}')
                lines.append('')
    lines.append('вҡ пёҸ Щ…Щ„Ш§ШӯШёШ©:')
    lines.append('Ш§Щ„Ш®ШөЩҲЩ… ЩӮШҜ ЩҠШӘШәЩҠШұЩҲЩҶ ШҘШ°Ш§ ШӘШәЩҠЩ‘Шұ ШӘШұШӘЩҠШЁ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘШҢ ШЈЩҲ ШӘШәЩҠЩ‘ШұШӘ ШӘШұЩғЩҠШЁШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…ШӘШЈЩҮЩ„Ш©.')
    return '\n'.join(lines).strip()




# V49.1 вҖ” ЩҶШө Щ…ШЁШ§ШҙШұ Ш§Щ„ШўЩҶ ШӯШіШЁ ЩҶШ§ЩҒШ°Ш© Ш§Щ„ШӘШӯШҜЩҠШ« Ш§Щ„Щ…Ш№ШӘЩ…ШҜШ©
