def _v608_fantasy_available_days(limit=5):
    today = _v608_makkah_now().date()
    dates = []
    for item in _v608_fixture_dates_with_matches():
        dd = item.get('dt')
        if not dd:
            continue
        # Ш§Щ„ЩҠЩҲЩ… Ш§Щ„ШӯШ§Щ„ЩҠ ЩҲЩ…Ш§ ШЁШ№ШҜЩҮШҢ ШЁШҙШұШ· ЩҲШ¬ЩҲШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҒЩҠ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©
        if dd >= today and item.get('matches'):
            dates.append(item)
    if not dates:
        # fallback: ШЈЩӮШұШЁ ШЈЩҠШ§Щ… ЩҒЩҠ Ш§Щ„Ш¬ШҜЩҲЩ„ Щ„ЩҲ Ш§Щ„ШӘШ§ШұЩҠШ® Ш®Ш§ШұШ¬ Ш§Щ„ЩҶШ·Ш§ЩӮ
        dates = [x for x in _v608_fixture_dates_with_matches() if x.get('matches')]
    return dates[:max(1, int(limit or 5))]


