def _v608_time_sort_key(t):
    s = str(t or '')
    # ШӘШұШӘЩҠШЁ ШЁШіЩҠШ· ШӯШіШЁ Ш§Щ„ЩҶШө Ш§Щ„Щ…ЩҲШ¬ЩҲШҜ ЩҒЩҠ Ш§Щ„Ш¬ШҜЩҲЩ„
    if '10:00' in s or '8:00' in s or '7:00' in s:
        return (0, s)
    if '11:00' in s or '12:00' in s or '1:00' in s:
        return (1, s)
    if '2:30' in s or '3:00' in s or '4:00' in s or '5:00' in s or '6:00' in s:
        return (2, s)
    return (3, s)


def _v608_watch_day_keyboard(date_str):
    matches = _fixtures_for_date(date_str) if '_fixtures_for_date' in globals() else []
    times = []
    for m in matches:
        t = str((m or {}).get('time') or '').strip()
        if t and t not in times:
            times.append(t)
    times = sorted(times, key=_v608_time_sort_key)
    rows = []
    for t in times:
        key = _v608_watch_day_button_key(date_str)
        safe_t = str(t).replace('|', ' ')
        rows.append([InlineKeyboardButton(f'вҸ° {t}', callback_data=f'watch608|time|{key}|{safe_t}')])
    rows.append([InlineKeyboardButton('в¬…пёҸ Ш§Щ„ШЈЩҠШ§Щ…', callback_data='mainmenu|watch_last_round'), InlineKeyboardButton('рҹҸ  Ш§Щ„ШұШҰЩҠШіЩҠШ©', callback_data='mainmenu|home')])
    return InlineKeyboardMarkup(rows)


def _v608_watch_day_text(date_str):
    item = None
    for x in _v608_fixture_dates_with_matches():
        if x.get('date') == date_str:
            item = x; break
    title = date_str
    if item:
        title = f"Ш§Щ„ЩҠЩҲЩ… {item.get('day_num') or _v608_tournament_day_from_date(date_str)} вҖ” {item.get('day_name') or ''} {date_str}".strip()
    matches = _fixtures_for_date(date_str) if '_fixtures_for_date' in globals() else []
    lines = ['рҹ‘Җ ЩҲШҙ ШЈШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©Шҹ', '', title, '', 'Ш§Ш®ШӘШұ Ш§Щ„ШӘЩҲЩӮЩҠШӘ:']
    if not matches:
        lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ЩҠЩҲЩ… ЩҒЩҠ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ.')
    else:
        by_time = {}
        for m in matches:
            by_time.setdefault(str((m or {}).get('time') or '').strip(), []).append(m)
        for t in sorted(by_time, key=_v608_time_sort_key):
            lines.append(f'вҖў {t} вҖ” {len(by_time[t])} Щ…ШЁШ§ШұШ§Ш©')
    return '\n'.join(lines).strip()


def _v608_match_importance_line(m):
    g = str((m or {}).get('group') or '')
    t1 = str((m or {}).get('team1') or '')
    t2 = str((m or {}).get('team2') or '')
    names = f'{t1} Г— {t2}'
    if any(x in names for x in ['Ш§Щ„ШіШ№ЩҲШҜЩҠШ©', 'Щ…ШөШұ', 'Ш§Щ„ШЈШұШҜЩҶ', 'ЩӮШ·Шұ', 'Ш§Щ„Ш№ШұШ§ЩӮ', 'Ш§Щ„Щ…ШәШұШЁ']):
        return 'рҹ”Ҙ ШЈЩҲЩ„ЩҲЩҠШ© Ш№Ш§Щ„ЩҠШ© Щ„Щ„Ш¬Щ…ЩҮЩҲШұ Ш§Щ„Ш№ШұШЁЩҠ ЩҲШӯШіШ§ШЁШ§ШӘ Ш§Щ„ШӘШЈЩҮЩ„.'
    if any(x in names for x in ['Ш§Щ„ШЁШұШ§ШІЩҠЩ„', 'Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ', 'ЩҒШұЩҶШіШ§', 'ШҘЩҶШ¬Щ„ШӘШұШ§', 'ШҘШіШЁШ§ЩҶЩҠШ§', 'ШЈЩ„Щ…Ш§ЩҶЩҠШ§', 'Ш§Щ„ШЁШұШӘШәШ§Щ„', 'Ш§Щ„Щ…ЩғШіЩҠЩғ', 'Ш§Щ„ЩҲЩ„Ш§ЩҠШ§ШӘ Ш§Щ„Щ…ШӘШӯШҜШ©']):
        return 'вӯҗ Щ…ШЁШ§ШұШ§Ш© Ш¬Щ…Ш§ЩҮЩҠШұЩҠШ© ЩҲЩӮШҜ ШӘШӨШ«Шұ Ш№Щ„Щү Ш§Щ„ШөШҜШ§ШұШ© ШЈЩҲ Щ…ШіШ§Шұ ШҜЩҲШұ Ш§Щ„ЩҖ32.'
    if g:
        return f'рҹ“Ң Щ…ШӨШ«ШұШ© Ш№Щ„Щү ШӘШұШӘЩҠШЁ {g} ЩҲШӯШіШ§ШЁШ§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ/Ш§Щ„Ш«Ш§Щ„Ш«.'
    return 'рҹ“Ң Щ…ШЁШ§ШұШ§Ш© Щ…ШұШ§ЩӮШЁШ© Ш¶Щ…ЩҶ ШӯШіШ§ШЁШ§ШӘ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©.'


def _v608_watch_time_text(date_str, time_label):
    matches = []
    for m in (_fixtures_for_date(date_str) if '_fixtures_for_date' in globals() else []):
        if str((m or {}).get('time') or '').strip() == str(time_label or '').strip():
            matches.append(m)
    lines = [f'вҸ° Щ…ШЁШ§ШұЩҠШ§ШӘ {time_label}', '', 'рҹҺҜ ЩҲШҙ ШӘШӘШ§ШЁШ№Шҹ', '']
    if not matches:
        lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…ШЁШ§ШұЩҠШ§ШӘ Щ„ЩҮШ°Ш§ Ш§Щ„ШӘЩҲЩӮЩҠШӘ ЩҒЩҠ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ.')
        return '\n'.join(lines).strip()
    # Ш§Ш®ШӘЩҠШ§Шұ Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈЩҮЩ…: Ш№ШұШЁЩҠШ© ШЈЩҲ Щ…ЩҶШӘШ®ШЁ ЩғШЁЩҠШұ Ш«Щ… Ш§Щ„ШЈЩҲЩ„Щү.
    def score(m):
        names = f"{m.get('team1')} {m.get('team2')}"
        s = 0
        for x in ['Ш§Щ„ШіШ№ЩҲШҜЩҠШ©','Щ…ШөШұ','Ш§Щ„ШЈШұШҜЩҶ','ЩӮШ·Шұ','Ш§Щ„Ш№ШұШ§ЩӮ','Ш§Щ„Щ…ШәШұШЁ']:
            if x in names: s += 5
        for x in ['Ш§Щ„ШЁШұШ§ШІЩҠЩ„','Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ','ЩҒШұЩҶШіШ§','ШҘЩҶШ¬Щ„ШӘШұШ§','ШҘШіШЁШ§ЩҶЩҠШ§','ШЈЩ„Щ…Ш§ЩҶЩҠШ§','Ш§Щ„ШЁШұШӘШәШ§Щ„','Ш§Щ„Щ…ЩғШіЩҠЩғ','Ш§Щ„ЩҲЩ„Ш§ЩҠШ§ШӘ Ш§Щ„Щ…ШӘШӯШҜШ©']:
            if x in names: s += 3
        return -s
    ordered = sorted(matches, key=score)
    main = ordered[0]
    lines.append(f"рҹ“ә Ш§Щ„Щ…ШЁШ§ШұШ§Ш© Ш§Щ„ШЈЩҮЩ…: {main.get('team1')} Г— {main.get('team2')}")
    if len(ordered) > 1:
        watch = ordered[1]
        lines.append(f"рҹ‘Җ Щ…ШЁШ§ШұШ§Ш© ШӘШұШ§ЩӮШЁЩҮШ§: {watch.get('team1')} Г— {watch.get('team2')}")
    lines += ['', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'рҹҸҹпёҸ Щ…ШЁШ§ШұЩҠШ§ШӘ ЩҮШ°Ш§ Ш§Щ„ШӘЩҲЩӮЩҠШӘ:']
    has_argentina = False
    for m in ordered:
        t1, t2 = m.get('team1'), m.get('team2')
        lines.append(f"вҖў {t1} Г— {t2} вҖ” {m.get('group','')}")
        lines.append(_v608_match_importance_line(m))
        if 'Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ' in f'{t1} {t2}':
            has_argentina = True
    lines += ['', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'рҹҘү ШӘШЈШ«ЩҠШұ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«:', 'ЩҶШӘШ§ШҰШ¬ ЩҮШ°Ш§ Ш§Щ„ШӘЩҲЩӮЩҠШӘ ЩӮШҜ ШӘШәЩҠЩ‘Шұ ШӘШұШӘЩҠШЁ ШЈШөШӯШ§ШЁ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«ШҢ Щ„ШЈЩҶ ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« ЩҒЩӮШ· Щ…ЩҶ ШЈШөЩ„ 12 ЩҠШӘШЈЩҮЩ„ЩҲЩҶ.']
    if has_argentina:
        lines += ['', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', _V608_MESSI_TEXT]
    return '\n'.join(lines).strip()


# ---------- V60.8: Щ„ЩҲШӯШ© ШұШҰЩҠШіЩҠШ© Щ…Ш№ ШІШұ ЩҲШҙ ШЈШӘШ§ШЁШ№ШҢ ШЁШҜЩҲЩҶ Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ© ----------
_V608_PREV_PUBLIC_MAIN_KEYBOARD = globals().get('_public_main_keyboard')
def _public_main_keyboard():
    try:
        kb = _V608_PREV_PUBLIC_MAIN_KEYBOARD() if callable(_V608_PREV_PUBLIC_MAIN_KEYBOARD) else InlineKeyboardMarkup([])
        rows = [list(r) for r in (getattr(kb, 'inline_keyboard', None) or [])]
    except Exception:
        rows = []
    rows = _v608_filter_buttons(rows, banned_text=('Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШәШ§ШҜШұШ©','ШіЩҠЩҶШ§ШұЩҠЩҲЩҮШ§ШӘ Ш§Щ„Ш®ШұЩҲШ¬'), banned_data=('exit_cached','refresh_exit_probs','exit_prob'))
    exists = any(_v608_btn_data(btn) == 'mainmenu|watch_last_round' or _v608_btn_text(btn) == 'рҹ‘Җ ЩҲШҙ ШЈШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©Шҹ' for row in rows for btn in row)
    if not exists:
        # ЩӮШЁЩ„ Ш§Щ„ШұШ¬ЩҲШ№/ШўШ®Шұ ШөЩҒ ШҘШ°Ш§ ШЈЩ…ЩғЩҶ
        insert_at = max(0, len(rows) - 1)
        rows.insert(insert_at, [InlineKeyboardButton('рҹ‘Җ ЩҲШҙ ШЈШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©Шҹ', callback_data='mainmenu|watch_last_round')])
    return InlineKeyboardMarkup(rows)


_V608_PREV_PUBLIC_REPLY_MENU_ROUTER = globals().get('public_reply_menu_router')
async def public_reply_menu_router(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        txt = normalize_name(update.message.text or '').strip()
    except Exception:
        txt = str(getattr(getattr(update, 'message', None), 'text', '') or '').strip()
    if txt in {'рҹ‘Җ ЩҲШҙ ШЈШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©Шҹ', 'ЩҲШҙ ШЈШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„ШЈШ®ЩҠШұШ©', 'ЩҲШҙ Ш§ШӘШ§ШЁШ№ Ш§Щ„Ш¬ЩҲЩ„Ш© Ш§Щ„Ш§Ш®ЩҠШұШ©', 'ЩҲШҙ ШЈШӘШ§ШЁШ№', 'ЩҲШҙ Ш§ШӘШ§ШЁШ№'}:
        await update.effective_message.reply_text(_v608_watch_home_text(), reply_markup=_v608_watch_home_keyboard())
        return
    if callable(_V608_PREV_PUBLIC_REPLY_MENU_ROUTER):
        return await _V608_PREV_PUBLIC_REPLY_MENU_ROUTER(update, context)


_V608_PREV_PUBLIC_MENU_CALLBACK = globals().get('public_menu_callback')
async def public_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    if data == 'mainmenu|watch_last_round':
        try: await q.answer()
        except Exception: pass
        try:
            await q.edit_message_text(_v608_watch_home_text(), reply_markup=_v608_watch_home_keyboard())
        except Exception:
            await q.message.reply_text(_v608_watch_home_text(), reply_markup=_v608_watch_home_keyboard())
        return
    if data.startswith('watch608|'):
        try: await q.answer()
        except Exception: pass
        parts = data.split('|')
        action = parts[1] if len(parts) > 1 else ''
        if action == 'day' and len(parts) >= 3:
            d = _v608_watch_date_from_key(parts[2])
            await q.edit_message_text(_v608_watch_day_text(d), reply_markup=_v608_watch_day_keyboard(d))
            return
        if action == 'time' and len(parts) >= 4:
            d = _v608_watch_date_from_key(parts[2]); t = parts[3]
            await q.edit_message_text(_v608_watch_time_text(d, t), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton('в¬…пёҸ ШӘЩҲЩӮЩҠШӘШ§ШӘ Ш§Щ„ЩҠЩҲЩ…', callback_data=f'watch608|day|{parts[2]}')],[InlineKeyboardButton('рҹҸ  Ш§Щ„ШұШҰЩҠШіЩҠШ©', callback_data='mainmenu|home')]]))
            return
    if callable(_V608_PREV_PUBLIC_MENU_CALLBACK):
        return await _V608_PREV_PUBLIC_MENU_CALLBACK(update, context)


