# ---------- V60.8: ШӯШ§Щ„Ш© Ш§Щ„ЩҒШ§ЩҶШӘШІЩҠ Ш§Щ„ШҜЩҠЩҶШ§Щ…ЩҠЩғЩҠШ© Щ„Щ„Щ…ШҙШұЩҒ ----------
_V608_PREV_FANTASY_MENU_CALLBACK = globals().get('fantasy_menu_callback')
async def fantasy_menu_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    parts = data.split('|')
    action = parts[1] if len(parts) > 1 else ''
    if action == 'admin_status' and is_admin_user(update):
        try: await q.answer()
        except Exception: pass
        days = _v608_fantasy_available_days(5)
        lines = ['рҹ”’ ШӯШ§Щ„Ш© Ш§Щ„ШӘШіШ¬ЩҠЩ„', '', 'Ш§Щ„ШЈЩҠШ§Щ… Ш§Щ„Щ…ШӘШ§ШӯШ© Щ„Щ„ШӘШіШ¬ЩҠЩ„ ШӘЩҸЩӮШұШЈ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§ Щ…ЩҶ Ш¬ШҜЩҲЩ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш© PDF:', '']
        if not days:
            lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ ШЈЩҠШ§Щ… ЩӮШ§ШҜЩ…Ш© Щ…ШӘШ§ШӯШ© ЩҒЩҠ Ш§Щ„Ш¬ШҜЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ.')
        for item in days:
            dn = item.get('day_num') or _v608_tournament_day_from_date(item.get('date'))
            lines.append(f"- Ш§Щ„ЩҠЩҲЩ… {dn} вҖ” {item.get('day_name') or item.get('date')} вҖ” {len(item.get('matches') or [])} Щ…ШЁШ§ШұЩҠШ§ШӘ")
        lines += ['', 'Ш§Щ„ЩӮЩҒЩ„ Ш§Щ„ЩҠШҜЩҲЩҠ ЩҠШЁЩӮЩү Ш№ШЁШұ ШЈЩҲШ§Щ…Шұ ЩӮЩҒЩ„/ЩҒШӘШӯ Ш§Щ„ЩҠЩҲЩ… Ш§Щ„Щ…ЩҲШ¬ЩҲШҜШ©.']
        await q.edit_message_text('\n'.join(lines), reply_markup=_v39_fantasy_keyboard(update))
        return
    if callable(_V608_PREV_FANTASY_MENU_CALLBACK):
        return await _V608_PREV_FANTASY_MENU_CALLBACK(update, context)

