# ==================== V61 FAHAD FINAL AGREEMENTS PATCH ====================
# ШӘШ№ШҜЩҠЩ„Ш§ШӘ Щ…Ш№ШӘЩ…ШҜШ© ШЁШҜЩҲЩҶ Щ„Щ…Ші ШЁШ§ЩӮЩҠ Ш§Щ„ШЁЩҲШӘ:
# - ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШЁШөЩҠШәШӘЩҮ Ш§Щ„ЩҶЩҮШ§ШҰЩҠШ©.
# - Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ ШЁШӘЩҒШ§ШөЩҠЩ„ ШӘШӯШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ.
# - ШІШұ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32 ЩҒЩҠ Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ШұШҰЩҠШіЩҠШ© ЩҲЩҠШ№ШұШ¶ ЩғЩ„ Ш§Щ„ЩҖ16 Щ…ШЁШ§ШұШ§Ш©.
# - Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ: ЩҲШ¶Ш№ ШӘЩ„ЩӮШ§ШҰЩҠ/ЩҠШҜЩҲЩҠ Щ…ЩҶ Щ„ЩҲШӯШ© Ш§Щ„ШҜШ№Щ… ЩҒЩӮШ·.
# - Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« Щ…ШұШӘШЁШ©.

# ---------- ШЈШҜЩҲШ§ШӘ V61 ----------
def _v61_safe_int(x, default=0):
    try:
        return int(float(str(x).strip()))
    except Exception:
        return default


def _v61_signed(x):
    try:
        return f"{int(float(str(x).strip())):+d}"
    except Exception:
        s = str(x or '').strip()
        return s if s else '+0'


def _v61_group_letters(codes):
    out = []
    for c in list(codes or []):
        try:
            out.append(_v33_group_ar(str(c).upper()))
        except Exception:
            out.append(str(c).upper())
    return '/'.join(out)


def _v61_group_label_short(code):
    try:
        return _v33_group_label(code)
    except Exception:
        return f"Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {code}"


def _v61_status_text(team, snap=None):
    try:
        snap = snap or _v33_snapshot(False)
        return str((snap.get('status') or {}).get(team, '') or '')
    except Exception:
        return ''


def _v61_is_official_qualified(team, snap=None):
    st = _v61_status_text(team, snap)
    return (('Щ…ШӘШЈЩҮЩ„' in st and 'ШұШіЩ…ЩҠ' in st) or ('Ш¶Щ…ЩҶ ШұШіЩ…ЩҠ' in st))


def _v61_is_official_best_third(team, row=None, snap=None):
    st = _v61_status_text(team, snap)
    try:
        st += ' ' + str((row or {}).get('third_status') or '')
    except Exception:
        pass
    return ('ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' in st or 'ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«' in st or 'ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' in st) and ('ШұШіЩ…ЩҠ' in st or 'Ш¶Щ…ЩҶ' in st or 'Щ…ШӘШЈЩҮЩ„' in st)


def _v61_now_text(snap=None):
    try:
        return str((snap or {}).get('updated_at') or _now_riyadh_text())
    except Exception:
        try:
            return _now_riyadh_text()
        except Exception:
            return '-'


def _v61_date_line(m):
    day = str((m or {}).get('day') or '').strip()
    date = str((m or {}).get('date') or '').strip()
    time_s = str((m or {}).get('time') or '').strip()
    # ШЁШҜЩҲЩҶ ЩғЩ„Щ…Ш© Ш§Щ„Щ…ЩҲШ№ШҜ ШӯШіШЁ Ш§Щ„Ш§Ш№ШӘЩ…Ш§ШҜ.
    left = ' '.join([x for x in [day, date[:5] if date else ''] if x]).strip()
    return f"рҹ—“пёҸ {left} вҖ” {time_s}".strip(' вҖ”')


# ---------- ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« вҖ” Ш§Щ„ШөЩҠШәШ© Ш§Щ„Щ…Ш№ШӘЩ…ШҜШ© ----------
def _v32_best_thirds_text(force=False):
    snap = _v33_snapshot(force) if '_v33_snapshot' in globals() else (_v32_snapshot(force) if '_v32_snapshot' in globals() else {})
    thirds = list((snap or {}).get('thirds') or [])
    lines = [
        'рҹҘү ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« Ш§Щ„ШўЩҶ',
        '',
        'Ш§Щ„ЩҶШёШ§Щ…: ЩҠШӘШЈЩҮЩ„ ШЈЩҒШ¶Щ„ 8 Щ…ЩҶШӘШ®ШЁШ§ШӘ ШЈШөШӯШ§ШЁ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 Щ…Ш¬Щ…ЩҲШ№Ш©.',
        'ЩҠШ№ЩҶЩҠ ЩғЩ„ Ш«Ш§Щ„Ш« Щ…Ш¬Щ…ЩҲШ№Ш© Щ„Ш§ ЩҠЩҶШ§ЩҒШі Щ…Ш¬Щ…ЩҲШ№ШӘЩҮ ЩҒЩӮШ·ШҢ ШЁЩ„ ЩҠЩҶШ§ЩҒШі ШЁЩӮЩҠШ© Ш«ЩҲШ§Щ„Ш« Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ Ш№Щ„Щү 8 Щ…ЩӮШ§Ш№ШҜ ЩҒЩӮШ·.',
        '',
        'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ',
        f"ШўШ®Шұ ШӘШӯШҜЩҠШ«: {_v61_now_text(snap)}",
        '',
    ]
    if not thirds:
        lines.append('Щ„Ш§ ШӘЩҲШ¬ШҜ ШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ© ШӯШӘЩү Ш§Щ„ШўЩҶ.')
        return '\n'.join(lines).strip()

    inside = thirds[:8]
    outside = thirds[8:]
    official_count = 0
    for r in inside:
        if _v61_is_official_best_third(r.get('team') or '', r, snap):
            official_count += 1
    lines.append(f'вң… ШҜШ§Ш®Щ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШ§Щ„ЩҠЩӢШ§: {len(inside)}/8')
    lines.append(f'рҹҸҒ Ш¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«: {official_count}/8')
    lines.append('')

    lines.append('вң… ШҜШ§Ш®Щ„ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§:')
    lines.append('')
    for i, r in enumerate(inside, start=1):
        team = r.get('team') or '-'
        g = r.get('group') or ''
        pts = _v61_safe_int(r.get('Pts', r.get('points', 0)))
        played = _v61_safe_int(r.get('P', r.get('played', 0)))
        gd = _v61_signed(r.get('GD', r.get('gd', 0)))
        gf = _v61_safe_int(r.get('GF', r.get('gf', 0)))
        state = 'рҹҸҒ Ш¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if _v61_is_official_best_third(team, r, snap) else 'вң… ШҜШ§Ш®Щ„ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШ§Щ„ЩҠЩӢШ§'
        lines.append(f'{i}. {team} вҖ” {_v61_group_label_short(g)}')
        lines.append(f'   Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Щ„Ш№ШЁ: {played}/3 | Ш§Щ„ЩҒШ§ШұЩӮ: {gd} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {gf}')
        lines.append(f'   Ш§Щ„ШӯШ§Щ„Ш©: {state}')
        lines.append('')

    lines.append('вқҢ Ш®Ш§ШұШ¬ЩҠЩҶ ШӯШ§Щ„ЩҠЩӢШ§:')
    if not outside:
        lines.append('Щ„Ш§ ЩҠЩҲШ¬ШҜ Ш®Ш§ШұШ¬ЩҲЩҶ ШӯШ§Щ„ЩҠЩӢШ§.')
    for i, r in enumerate(outside, start=9):
        team = r.get('team') or '-'
        g = r.get('group') or ''
        pts = _v61_safe_int(r.get('Pts', r.get('points', 0)))
        played = _v61_safe_int(r.get('P', r.get('played', 0)))
        gd = _v61_signed(r.get('GD', r.get('gd', 0)))
        gf = _v61_safe_int(r.get('GF', r.get('gf', 0)))
        lines.append(f'{i}. {team} вҖ” {_v61_group_label_short(g)}')
        lines.append(f'   Ш§Щ„ЩҶЩӮШ§Ш·: {pts} | Щ„Ш№ШЁ: {played}/3 | Ш§Щ„ЩҒШ§ШұЩӮ: {gd} | Ш§Щ„ШЈЩҮШҜШ§ЩҒ: {gf}')
        lines.append('   Ш§Щ„ШӯШ§Щ„Ш©: вқҢ Ш®Ш§ШұШ¬ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШӯШ§Щ„ЩҠЩӢШ§')
        lines.append('')

    lines += [
        'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ',
        'вң… Ш§Щ„ШҜШ®ЩҲЩ„ Ш§Щ„ШӯШ§Щ„ЩҠ Щ„Ш§ ЩҠШ№ЩҶЩҠ Ш§Щ„ШӘШЈЩҮЩ„ Ш§Щ„ШұШіЩ…ЩҠШҢ Щ„ШЈЩҶ Ш§Щ„ШӘШұШӘЩҠШЁ ЩӮШҜ ЩҠШӘШәЩҠШұ ШЁШ№ШҜ ЩҶШӘШ§ШҰШ¬ ШЁЩӮЩҠШ© Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш§ШӘ.',
        '',
        'ШҘШ°Ш§ Ш¶Щ…ЩҶ Щ…ЩҶШӘШ®ШЁ Ш§Щ„ШӘШЈЩҮЩ„ ШӯШіШ§ШЁЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«ШҢ ШӘШёЩҮШұ ШӯШ§Щ„ШӘЩҮ:',
        'рҹҸҒ Ш¶Щ…ЩҶ Ш§Щ„ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«',
        '',
        'ШЈЩҒШ¶Щ„ 8 Ш«ЩҲШ§Щ„Ш« Щ…ЩҶ ШЈШөЩ„ 12 ЩҠШӘШЈЩҮЩ„ЩҲЩҶ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32ШҢ ЩҲШ§Щ„Ш®ШөЩ… ЩҠШӘШӯШҜШҜ ШӯШіШЁ Ш¬ШҜЩҲЩ„ FIFA Ш§Щ„ШұШіЩ…ЩҠ Щ„ШӘЩҲШІЩҠШ№ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.',
    ]
    return '\n'.join(lines).strip()


# ---------- Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ вҖ” Ш§Щ„ШӘЩҒШ§ШөЩҠЩ„ ШӘШӯШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ ----------
def _v61_rank_label_for_team(team, snap=None):
    snap = snap or (_v33_snapshot(False) if '_v33_snapshot' in globals() else {})
    try:
        code, pos, row, rows = _v33_group_row(team, snap)
        # ШҘШ°Ш§ Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© Щ…ЩғШӘЩ…Щ„Ш© ЩҠЩғЩҲЩҶ Ш§Щ„Щ…ШұЩғШІ ЩҶЩҮШ§ШҰЩҠЩӢШ§.
        g = ((snap.get('groups') or {}).get(code) or {})
        complete = bool(g.get('remaining') == 0 or all(_v61_safe_int((rr or {}).get('P')) >= 3 for rr in (rows or [])[:4]))
        if complete and pos:
            return {1:'Ш§Щ„ШЈЩҲЩ„', 2:'Ш§Щ„Ш«Ш§ЩҶЩҠ', 3:'Ш§Щ„Ш«Ш§Щ„Ш«', 4:'Ш§Щ„ШұШ§ШЁШ№'}.get(int(pos), str(pos))
        # ШҘШ°Ш§ Ш§Щ„ШӯШ§Щ„Ш© ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш« ШұШіЩ…ЩҠ.
        if _v61_is_official_best_third(team, None, snap):
            return 'ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«'
        # ЩҶШ№ШұШ¶ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШӯШ§Щ„ЩҠ ЩҒЩӮШ· ШҘШ°Ш§ ЩғШ§ЩҶ Щ…ЩҶШөЩҲШөЩӢШ§ Ш№Щ„ЩҠЩҮ Ш¶Щ…ЩҶ ЩҶШөЩҲШө ЩӮШҜЩҠЩ…Ш©ШҢ ЩҲШҘЩ„Ш§ ЩҶШӯШ§ЩҒШё Ш№Щ„Щү Ш§Щ„ШҜЩӮШ©.
        st = _v61_status_text(team, snap)
        if 'Ш§Щ„Щ…ШұЩғШІ Ш§Щ„ШЈЩҲЩ„' in st or 'Ш§Щ„ШЈЩҲЩ„' in st:
            return 'Ш§Щ„ШЈЩҲЩ„'
        if 'Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§ЩҶЩҠ' in st or 'Ш§Щ„Ш«Ш§ЩҶЩҠ' in st:
            return 'Ш§Щ„Ш«Ш§ЩҶЩҠ'
    except Exception:
        pass
    return 'Щ„Щ… ЩҠЩҸШӯШіЩ… ШЁШ№ШҜ'


def _v61_qualified_text(force=False):
    snap = _v33_snapshot(force) if '_v33_snapshot' in globals() else {}
    try:
        teams = list(_v32_calculated_qualified() or [])
    except Exception:
        teams = list((snap or {}).get('qualified') or [])
    lines = ['вң… Ш§Щ„Щ…ШӘШЈЩҮЩ„ЩҲЩҶ ШұШіЩ…ЩҠЩӢШ§ Щ„ШҜЩҲШұ Ш§Щ„ЩҖ32', '']
    if not teams:
        lines.append('Щ„Ш§ ЩҠЩҲШ¬ШҜ ШӯШӘЩү Ш§Щ„ШўЩҶ.')
    for i, team in enumerate(teams, start=1):
        best_third = _v61_is_official_best_third(team, None, snap)
        status_line = 'вң… ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if best_third else 'вң… ШӘШЈЩҮЩ„ ШұШіЩ…ЩҠЩӢШ§'
        lines.append(f'{i}. {team}')
        lines.append(f'   {status_line}')
        lines.append(f'   рҹ“Ң Ш§Щ„Щ…ШұЩғШІ: {_v61_rank_label_for_team(team, snap)}')
        lines.append('')
    lines.append('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ')
    lines.append('вң… ЩҮШ°ЩҮ Ш§Щ„ЩӮШ§ШҰЩ…Ш© ШӘШ№ШұШ¶ ЩҒЩӮШ· Ш§Щ„Щ…ЩҶШӘШ®ШЁШ§ШӘ Ш§Щ„ШӘЩҠ Ш¶Щ…ЩҶШӘ Ш§Щ„ШӘШЈЩҮЩ„ ШӯШіШ§ШЁЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


# ---------- ШҜЩҲШұ Ш§Щ„ЩҖ32 вҖ” ЩҠШёЩҮШұ ШҜШ§ШҰЩ…ЩӢШ§ ЩҲЩҠШ№ШұШ¶ ЩғЩ„ Ш§Щ„ЩҖ16 ----------
def _v33_round32_has_official_match(snap=None):
    return True


V61_R32_SLOTS = [
    ('R32-1',  ('pos','A',2), ('pos','B',2)),
    ('R32-2',  ('pos','C',1), ('pos','F',2)),
    ('R32-3',  ('pos','E',1), ('third','ABCDF')),
    ('R32-4',  ('pos','F',1), ('pos','C',2)),
    ('R32-5',  ('pos','E',2), ('pos','I',2)),
    ('R32-6',  ('pos','I',1), ('third','CDFGH')),
    ('R32-7',  ('pos','A',1), ('third','CEFHI')),
    ('R32-8',  ('pos','L',1), ('third','EHIJK')),
    ('R32-9',  ('pos','G',1), ('third','AEHIJ')),
    ('R32-10', ('pos','D',1), ('third','BEFIJ')),
    ('R32-11', ('pos','H',1), ('pos','J',2)),
    ('R32-12', ('pos','K',2), ('pos','L',2)),
    ('R32-13', ('pos','B',1), ('third','EFGIJ')),
    ('R32-14', ('pos','D',2), ('pos','G',2)),
    ('R32-15', ('pos','J',1), ('pos','H',2)),
    ('R32-16', ('pos','K',1), ('third','DEIJL')),
]


def _v61_r32_fixture(mid):
    for m in (globals().get('TOURNAMENT_FIXTURES') or []):
        if str(m.get('id') or '') == mid:
            return m
    return {'id': mid, 'day': '', 'date': '', 'time': '', 'stage': 'ШҜЩҲШұ Ш§Щ„ЩҖ32'}


def _v61_group_rows(code, snap):
    try:
        return (((snap.get('groups') or {}).get(code) or {}).get('rows') or [])
    except Exception:
        return []


def _v61_pos_phrase(code, pos):
    ar = _v33_group_ar(code) if '_v33_group_ar' in globals() else code
    return ('ШЈЩҲЩ„' if int(pos) == 1 else 'Ш«Ш§ЩҶЩҠ') + f' Ш§Щ„Щ…Ш¬Щ…ЩҲШ№Ш© {ar}'


def _v61_resolve_pos_slot(code, pos, snap):
    rows = _v61_group_rows(code, snap)
    team = ''
    try:
        team = (rows[int(pos)-1] or {}).get('team') or ''
    except Exception:
        team = ''
    confirmed = bool(team and _v61_is_official_qualified(team, snap))
    return {
        'kind': 'pos', 'code': code, 'pos': int(pos), 'phrase': _v61_pos_phrase(code, pos),
        'team': team if confirmed else '', 'predicted': team or '', 'confirmed': confirmed,
        'status': 'вң… Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§' if confirmed else '',
    }


def _v61_third_assignment(snap):
    try:
        groups = [r.get('group') for r in (snap.get('thirds') or [])[:8] if r.get('group')]
        if len(groups) >= 8 and '_v33_assign_thirds_to_slots' in globals():
            # ШӘШұШ¬Ш№ group_third -> winner_slot. ЩҶЩӮЩ„ШЁЩҮШ§ ШҘЩ„Щү winner_slot -> third_group.
            mp = _v33_assign_thirds_to_slots(groups) or {}
            return {v: k for k, v in mp.items() if v and k}
    except Exception:
        pass
    return {}


def _v61_resolve_third_slot(candidates, snap):
    cand = ''.join([c for c in str(candidates or '').upper() if c.isalpha()])
    slot_to_third = _v61_third_assignment(snap)
    # ЩҶШӯШҜШҜ Ш®Ш§ЩҶШ© Ш§Щ„ЩҒШ§ШҰШІ Щ…ЩҶ Щ…ЩҒШ§ШӘЩҠШӯ Ш§Щ„Щ…ШұШҙШӯЩҠЩҶШҢ ШҘЩҶ ЩҲШ¬ШҜШӘ ЩҒЩҠ Ш§Щ„Ш®ШұЩҠШ·Ш© Ш§Щ„Щ…Ш№ШӘЩ…ШҜШ©.
    winner_slot = ''
    try:
        for k, vals in (globals().get('V33_THIRD_SLOT_CANDIDATES') or {}).items():
            if ''.join(vals) == cand:
                winner_slot = k
                break
    except Exception:
        pass
    third_group = slot_to_third.get(winner_slot) if winner_slot else ''
    third_row = _v33_third_row_for_group(third_group, snap) if third_group and '_v33_third_row_for_group' in globals() else None
    team = (third_row or {}).get('team') or ''
    confirmed = bool(team and _v61_is_official_best_third(team, third_row, snap))
    return {
        'kind': 'third', 'candidates': cand, 'phrase': f"ШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш« Щ…ЩҶ {_v61_group_letters(cand)}",
        'team': team if confirmed else '', 'predicted': team or '', 'confirmed': confirmed,
        'status': 'вң… Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if confirmed else '',
    }


def _v61_resolve_slot(slot, snap):
    if slot[0] == 'pos':
        return _v61_resolve_pos_slot(slot[1], slot[2], snap)
    return _v61_resolve_third_slot(slot[1], snap)


def _v61_r32_rows(force=False):
    snap = _v33_snapshot(force) if '_v33_snapshot' in globals() else {}
    rows = []
    for idx, (mid, s1, s2) in enumerate(V61_R32_SLOTS, start=1):
        m = _v61_r32_fixture(mid)
        a = _v61_resolve_slot(s1, snap)
        b = _v61_resolve_slot(s2, snap)
        complete = bool(a.get('confirmed') and b.get('confirmed'))
        one_side = bool(a.get('confirmed') ^ b.get('confirmed'))
        if complete:
            group = 'complete'
        elif one_side:
            group = 'one'
        else:
            group = 'none'
        rows.append({'idx': idx, 'fixture': m, 'a': a, 'b': b, 'group': group})
    return rows


def _v61_r32_main_line(r):
    a, b = r['a'], r['b']
    if r['group'] == 'complete':
        return f"{r['idx']}. {a.get('team')} Г— {b.get('team')}"
    if r['group'] == 'one':
        team = a.get('team') if a.get('confirmed') else b.get('team')
        return f"{r['idx']}. {team} Г— Щ„Щ… ЩҠШӘШӯШҜШҜ"
    return f"{r['idx']}. {a.get('phrase')} Г— {b.get('phrase')}"


def _v61_r32_row_lines(r):
    a, b, m = r['a'], r['b'], r['fixture']
    lines = [_v61_r32_main_line(r)]
    if r['group'] == 'complete':
        lines.append(f"   {a.get('status') or 'вң… Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§'}: {a.get('team')}") if False else None
        lines.append(f"   вң… {a.get('team')}: {'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if a.get('kind') == 'third' else 'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§'}")
        lines.append(f"   вң… {b.get('team')}: {'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if b.get('kind') == 'third' else 'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§'}")
    elif r['group'] == 'one':
        confirmed = a if a.get('confirmed') else b
        waiting = b if a.get('confirmed') else a
        lines.append(f"   вң… {confirmed.get('team')}: {'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§ ЩғШЈЩҒШ¶Щ„ Ш«Ш§Щ„Ш«' if confirmed.get('kind') == 'third' else 'Щ…ШӘШЈЩҮЩ„Ш© ШұШіЩ…ЩҠЩӢШ§'}")
        lines.append(f"   вҸі {waiting.get('phrase')}")
        if waiting.get('predicted'):
            lines.append(f"   рҹ”Һ Ш§Щ„Щ…ШӘЩҲЩӮШ№ ШӯШ§Щ„ЩҠЩӢШ§: {waiting.get('predicted')}")
    # ШҘШ°Ш§ Щ„Щ… ЩҠШӘШӯШҜШҜ ШЈЩҠ Ш·ШұЩҒШҢ ЩҶЩғШӘЩҒЩҠ ШЁШіШ·Шұ Ш§Щ„Ш®Ш§ЩҶШ© + Ш§Щ„ШӘШ§ШұЩҠШ®.
    dl = _v61_date_line(m)
    if dl:
        lines.append(f"   {dl}")
    return lines


def _v33_round32_text(force=False):
    rows = _v61_r32_rows(force)
    complete = [r for r in rows if r['group'] == 'complete']
    one = [r for r in rows if r['group'] == 'one']
    none = [r for r in rows if r['group'] == 'none']
    lines = ['рҹҸҹпёҸ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32', '', f'вң… Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§ЩғШӘЩ…Щ„ Ш·ШұЩҒШ§ЩҮШ§: {len(complete)}/16']
    if complete:
        lines += ['', 'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'вң… Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„Щ…ШӨЩғШҜШ© ШұШіЩ…ЩҠЩӢШ§:', '']
        for r in complete:
            lines.extend(_v61_r32_row_lines(r)); lines.append('')
    if one:
        lines += ['в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'рҹҹЎ Ш§Щ„Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Ш§Щ„ШӘЩҠ Ш§ЩғШӘЩ…Щ„ ШЈШӯШҜ Ш·ШұЩҒЩҠЩҮШ§:', '']
        for r in one:
            lines.extend(_v61_r32_row_lines(r)); lines.append('')
    if none:
        lines += ['в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ', 'вҡӘ Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ Щ„Щ… ШӘШӘШӯШҜШҜ ШЁШ№ШҜ:', '']
        for r in none:
            lines.extend(_v61_r32_row_lines(r)); lines.append('')
    return '\n'.join(lines).strip()


