_V61_PREV_PUBLIC_MAIN_KEYBOARD = globals().get('_public_main_keyboard')
def _public_main_keyboard():
    try:
        kb = _V61_PREV_PUBLIC_MAIN_KEYBOARD() if callable(_V61_PREV_PUBLIC_MAIN_KEYBOARD) else InlineKeyboardMarkup([])
        rows = [list(r) for r in (getattr(kb, 'inline_keyboard', None) or [])]
    except Exception:
        rows = []
    # ШҘШІШ§Щ„Ш© Ш§Щ„ЩҶШіШ® Ш§Щ„ЩӮШҜЩҠЩ…Ш© Щ…ЩҶ ШІШұ ШҜЩҲШұ Ш§Щ„ЩҖ32 Ш«Щ… ШҘШ¶Ш§ЩҒШ© Ш§Щ„Ш§ШіЩ… Ш§Щ„Щ…Ш№ШӘЩ…ШҜ.
    clean = []
    for row in rows:
        nr = []
        for btn in row:
            t = str(getattr(btn, 'text', '') or '')
            d = str(getattr(btn, 'callback_data', '') or '')
            if 'ШҜЩҲШұ Ш§Щ„ЩҖ32' in t or 'ШҜЩҲШұ 32' in t or d == 'v32|r32' or d == 'mainmenu|r32':
                continue
            nr.append(btn)
        if nr:
            clean.append(nr)
    insert_at = 3 if len(clean) >= 3 else len(clean)
    clean.insert(insert_at, [InlineKeyboardButton('рҹҸҹпёҸ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32', callback_data='v32|r32')])
    return InlineKeyboardMarkup(clean)


_V61_PREV_PUBLIC_REPLY_KEYBOARD = globals().get('_public_main_reply_keyboard')
def _public_main_reply_keyboard():
    try:
        kb = _V61_PREV_PUBLIC_REPLY_KEYBOARD() if callable(_V61_PREV_PUBLIC_REPLY_KEYBOARD) else ReplyKeyboardMarkup([[]])
        rows = [list(r) for r in (getattr(kb, 'keyboard', None) or [])]
    except Exception:
        rows = []
    # PTB ЩӮШҜ ЩҠШ®ШІЩҶ KeyboardButton ШЈЩҲ ЩҶШөЩҲШөШӣ ЩҶШӯШ§ЩҒШё Ш№Щ„Щү Ш§Щ„ЩҶШөЩҲШө.
    out = []
    exists = False
    for row in rows:
        nr = []
        for btn in row:
            txt = str(getattr(btn, 'text', btn) or '')
            if txt == 'рҹҸҹпёҸ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32':
                exists = True
            # ЩҶШӯШ°ЩҒ "Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ" Ш§Щ„ЩӮШҜЩҠЩ…Ш© Щ„ЩҲ ЩҲШ¬ШҜШӘ.
            if 'Щ…ЩҲШ§Ш¬ЩҮШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32' in txt:
                continue
            nr.append(btn)
        if nr:
            out.append(nr)
    if not exists:
        idx = 3 if len(out) >= 3 else len(out)
        out.insert(idx, ['рҹҸҹпёҸ Щ…ШЁШ§ШұЩҠШ§ШӘ ШҜЩҲШұ Ш§Щ„ЩҖ32'])
    return ReplyKeyboardMarkup(out, resize_keyboard=True, one_time_keyboard=False, input_field_placeholder='Ш§Ш®ШӘШұ Щ…ЩҶ Ш§Щ„ЩӮШ§ШҰЩ…Ш©')


# ---------- Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ: ШӘЩ„ЩӮШ§ШҰЩҠ/ЩҠШҜЩҲЩҠ ШҜШ§Ш®Щ„ Ш§Щ„ШҜШ№Щ… ----------
V61_TOP_SCORERS_MODE_FILE = 'top_scorers_mode_state.json'


def _v61_load_scorers_mode():
    try:
        return _v33_safe_load_json(V61_TOP_SCORERS_MODE_FILE, {'mode': 'auto', 'manual_items': [], 'updated_at': ''})
    except Exception:
        if os.path.exists(V61_TOP_SCORERS_MODE_FILE):
            try:
                with open(V61_TOP_SCORERS_MODE_FILE, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except Exception:
                pass
        return {'mode': 'auto', 'manual_items': [], 'updated_at': ''}


def _v61_save_scorers_mode(data):
    data = data or {}
    data.setdefault('mode', 'auto')
    data.setdefault('manual_items', [])
    data.setdefault('updated_at', '')
    try:
        return _v33_safe_save_json(V61_TOP_SCORERS_MODE_FILE, data)
    except Exception:
        with open(V61_TOP_SCORERS_MODE_FILE, 'w', encoding='utf-8') as f:
            json.dump(data, f, ensure_ascii=False, indent=2)


def _v61_parse_manual_scorers(text):
    body = str(text or '')
    body = re.sub(r'^/(?:ШӘШӯШҜЩҠШ«_ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ|ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ|Ш§Ш¶Ш§ЩҒШ©_ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ|ШҘШ¶Ш§ЩҒШ©_ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ)\s*', '', body, flags=re.I).strip()
    items = []
    for line in body.splitlines():
        line = normalize_name(line)
        if not line or line.startswith('/'):
            continue
        # ЩҠШҜШ№Щ…: Щ…ШЁШ§ШЁЩҠ 5 ЩҒШұЩҶШіШ§ | Щ…ШЁШ§ШЁЩҠ|ЩҒШұЩҶШіШ§|5 | Щ…ШЁШ§ШЁЩҠ - ЩҒШұЩҶШіШ§ - 5
        parts = [p.strip() for p in re.split(r'[|ШҢ,\-вҖ“вҖ”]+', line) if p.strip()]
        name = team = ''
        goals = None
        if len(parts) >= 3:
            # ЩҶШЁШӯШ« Ш№ЩҶ Ш§Щ„ШұЩӮЩ… ШЈЩҠЩҶЩ…Ш§ ЩҲШ¬ШҜ.
            for p in parts:
                if re.fullmatch(r'\d{1,2}', p):
                    goals = int(p); break
            non = [p for p in parts if not re.fullmatch(r'\d{1,2}', p)]
            if non:
                name = non[0]
            if len(non) >= 2:
                team = canonical_team_name(non[1]) or non[1]
        else:
            m = re.match(r'(.+?)\s+(\d{1,2})(?:\s+(.+))?$', line)
            if m:
                name = normalize_name(m.group(1)); goals = int(m.group(2)); team = canonical_team_name(m.group(3) or '') or normalize_name(m.group(3) or '')
        if name and goals is not None:
            items.append({'name': name, 'team': team or '-', 'played': '', 'goals': goals})
    items.sort(key=lambda x: (-int(x.get('goals') or 0), str(x.get('name') or '')))
    return items


def _v61_scorers_mode_text():
    data = _v61_load_scorers_mode()
    mode = data.get('mode') or 'auto'
    label = 'ШӘЩ„ЩӮШ§ШҰЩҠ' if mode == 'auto' else 'ЩҠШҜЩҲЩҠ'
    lines = ['рҹҸҶ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ', f'Ш§Щ„ШӯШ§Щ„Ш© Ш§Щ„ШӯШ§Щ„ЩҠШ©: {label}', '']
    if mode == 'auto':
        lines.append('Ш§Щ„ШЁЩҲШӘ ЩҠШЈШ®Ш° Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Щ…ЩҶ Ш§Щ„Щ…ШөШҜШұ Ш§Щ„ШұШҰЩҠШіЩҠ.')
    else:
        lines.append('Ш§Щ„ШЁЩҲШӘ ЩҠШ№ШұШ¶ Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ Ш§Щ„ЩҠШҜЩҲЩҠЩҠЩҶ ЩғШ§ШӯШӘЩҠШ§Ш· Щ…ШӨЩӮШӘ.')
        items = data.get('manual_items') or []
        if items:
            lines.append('')
            lines.append('Ш§Щ„ЩӮШ§ШҰЩ…Ш© Ш§Щ„ЩҠШҜЩҲЩҠШ© Ш§Щ„ШӯШ§Щ„ЩҠШ©:')
            for i, it in enumerate(items[:15], start=1):
                lines.append(f"{i}. {it.get('name')} вҖ” {it.get('team','-')} вҖ” {it.get('goals',0)}")
    lines.append('')
    lines.append('Щ„Щ„ШӘШӯШҜЩҠШ« Ш§Щ„ЩҠШҜЩҲЩҠ ШЈШұШіЩ„:')
    lines.append('/ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ')
    lines.append('Щ…ШЁШ§ШЁЩҠ 5 ЩҒШұЩҶШіШ§')
    lines.append('Щ…ЩҠШіЩҠ 4 Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ')
    return '\n'.join(lines).strip()


