async def v61_manual_scorers_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not is_admin_user(update):
        await update.effective_message.reply_text('ЩҮШ°Ш§ Ш§Щ„Ш®ЩҠШ§Шұ Щ„Щ„Щ…ШҙШұЩҒЩҠЩҶ ЩҒЩӮШ· рҹ”’')
        return
    items = _v61_parse_manual_scorers(update.effective_message.text or '')
    if not items:
        await update.effective_message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ЩҮШҜШ§ЩҒЩҠЩҶ_ЩҠШҜЩҲЩҠ\nЩ…ШЁШ§ШЁЩҠ 5 ЩҒШұЩҶШіШ§\nЩ…ЩҠШіЩҠ 4 Ш§Щ„ШЈШұШ¬ЩҶШӘЩҠЩҶ')
        return
    data = _v61_load_scorers_mode()
    data['mode'] = 'manual'
    data['manual_items'] = items
    data['updated_at'] = _v61_now_text({})
    _v61_save_scorers_mode(data)
    await update.effective_message.reply_text(f'вң… ШӘЩ… ШӘШӯШҜЩҠШ« Ш§Щ„ЩҮШҜШ§ЩҒЩҠЩҶ ЩҠШҜЩҲЩҠЩӢШ§ ЩҲШӘЩҒШ№ЩҠЩ„ Ш§Щ„ЩҲШ¶Ш№ Ш§Щ„ЩҠШҜЩҲЩҠ.\nШ№ШҜШҜ Ш§Щ„ШЈШіЩ…Ш§ШЎ: {len(items)}', reply_markup=_v61_scorers_mode_keyboard())


# ---------- Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« вҖ” ШӘШұШӘЩҠШЁ Щ…Ш№ШӘЩ…ШҜ ----------
def _v33_how_thirds_text(team):
    team = _v33_find_team(team) or team
    if not team:
        return 'Щ…Ш§ Ш№ШұЩҒШӘ Ш§Щ„Щ…ЩҶШӘШ®ШЁ.'
    snap = _v33_snapshot(False)
    code = _v33_team_group(team)
    case = _v37_third_case_info(team, snap) if '_v37_third_case_info' in globals() else None
    target_pts = None
    if case:
        target_pts = case.get('pts')
    else:
        try:
            target_pts, case = _v37_target_third_points(team, snap)
        except Exception:
            target_pts, case = None, None
    lines = [f'рҹҘү Ш§ШӯШӘЩ…Ш§Щ„Ш§ШӘ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш« ЩҲШӘШӯЩ„ЩҠЩ„ЩҮ вҖ” {team}', '']
    if target_pts is None:
        lines.append(f'Щ„Ш§ ЩҠЩҲШ¬ШҜ Щ…ШіШ§Шұ ЩҲШ§Ш¶Шӯ ШӯШ§Щ„ЩҠЩӢШ§ ЩҠШ¬Ш№Щ„ {team} Ш«Ш§Щ„Ш« {_v33_group_label(code)} ШЁШЁЩҠШ§ЩҶШ§ШӘ ЩғШ§ЩҒЩҠШ©.')
        lines.append('ШҘШ°Ш§ ШӘШәЩҠЩ‘ШұШӘ Ш§Щ„ЩҶШӘШ§ШҰШ¬ ЩҲШёЩҮШұ Щ…ШіШ§Шұ Ш«Ш§Щ„Ш«ШҢ ШіЩҠШӯШіШЁЩҮ Ш§Щ„ШЁЩҲШӘ ШӘЩ„ЩӮШ§ШҰЩҠЩӢШ§.')
        return '\n'.join(lines).strip()
    lines.append('рҹ“Ң Ш§Щ„Ш®Щ„Ш§ШөШ©:')
    lines.append(f'Ш§Щ„Щ…ЩҶШӘШ®ШЁ {team} ЩҠШіШӘШ·ЩҠШ№ ШӯШіШ§ШЁЩҠЩӢШ§ ШҘЩҶЩҮШ§ШЎ {_v33_group_label(code)} ЩҒЩҠ Ш§Щ„Щ…ШұЩғШІ Ш§Щ„Ш«Ш§Щ„Ш«ШҢ Ш«Щ… ЩҠШҜШ®Щ„ ШӯШіШ§ШЁШ§ШӘ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«.')
    lines.append('')
    lines.append('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ')
    if case:
        reqs = _v38_scenario_required_lines(team, case.get('scenario') or {}, snap, max_lines=6) if '_v38_scenario_required_lines' in globals() else []
        if reqs:
            lines.append('рҹӣЈпёҸ Щ…Ш«Ш§Щ„ Щ„Щ…ШіШ§Шұ Щ…Щ…ЩғЩҶ:')
            lines.append('')
            for i, r in enumerate(reqs, start=1):
                lines.append(f'{i}. {r}')
            lines.append('')
        rows_case = ((case.get('case') or {}).get('rows') or (case.get('scenario') or {}).get('rows') or [])[:4]
        if rows_case:
            lines.append('рҹ“Ҡ Ш§Щ„ШӘШұШӘЩҠШЁ ЩҒЩҠ ЩҮШ°Ш§ Ш§Щ„ШіЩҠЩҶШ§ШұЩҠЩҲ:')
            for i, rr in enumerate(rows_case, start=1):
                p = _v61_safe_int(rr.get('Pts'))
                word = _v49_points_word(p) if '_v49_points_word' in globals() else 'ЩҶЩӮШ§Ш·'
                lines.append(f"{i}. {rr.get('team')} вҖ” {p} {word}")
            lines.append('')
            lines.append(f'рҹ“Ң Щ„Щ…Ш§Ш°Ш§ ЩҠШөШЁШӯ Ш§Щ„Щ…ЩҶШӘШ®ШЁ {team} Ш«Ш§Щ„Ш«ЩӢШ§Шҹ')
            lines.append(_v39_why_third(team, rows_case) if '_v39_why_third' in globals() else 'ШЁШіШЁШЁ ЩғШіШұ Ш§Щ„ШӘШ№Ш§ШҜЩ„ Щ…Ш«Щ„ ЩҒШ§ШұЩӮ Ш§Щ„ШЈЩҮШҜШ§ЩҒ ШЈЩҲ Ш§Щ„ШЈЩҮШҜШ§ЩҒ Ш§Щ„Щ…ШіШ¬Щ„Ш©.')
            lines.append('')
    lines.append('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ')
    lines.append(f'рҹҘү ЩҲШ¶Ш№ {team} ЩҒЩҠ ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш«:')
    lines.append('')
    try:
        lines.extend(_v37_third_path_summary_block(team, int(target_pts or 0), snap))
    except Exception:
        lines.append('вҡ пёҸ ШӘЩҒШ§ШөЩҠЩ„ Щ…ЩӮШ§ШұЩҶШ© ШЈЩҒШ¶Щ„ Ш§Щ„Ш«ЩҲШ§Щ„Ш« ШәЩҠШұ Щ…ШӘЩҲЩҒШұШ© ШӯШ§Щ„ЩҠЩӢШ§.')
    return '\n'.join(lines).strip()


# ---------- ШұШ§ЩҲШӘШұШ§ШӘ ЩҶЩҮШ§ШҰЩҠШ© ----------
_V61_PREV_V32_CALLBACK = globals().get('v32_callback')
async def v32_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    if not q:
        return
    data = q.data or ''
    parts = data.split('|')
    action = parts[1] if len(parts) > 1 else ''
    if action in ('r32', 'round32'):
        try: await q.answer()
        except Exception: pass
        try:
            await q.edit_message_text(_v33_round32_text(False), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')]]))
        except Exception:
            await q.message.reply_text(_v33_round32_text(False), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')]]))
        return
    if action == 'qualified':
        try: await q.answer()
        except Exception: pass
        await q.edit_message_text(_v61_qualified_text(False), reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton('в¬…пёҸ Щ„ЩҲШӯШ© Ш§Щ„ШЁШ·ЩҲЩ„Ш©', callback_data='v32|board')]]))
        return
    if action == 'thirds':
        try: await q.answer()
        except Exception: pass
        await q.edit_message_text(_v32_best_thirds_text(False), reply_markup=_v32_board_keyboard())
        return
    if action == 'thirds_force':
        try: await q.answer()
        except Exception: pass
        await q.edit_message_text(_v32_best_thirds_text(True), reply_markup=_v32_board_keyboard())
        return
    if callable(_V61_PREV_V32_CALLBACK):
        return await _V61_PREV_V32_CALLBACK(update, context)


