# ==================== V61.1 HOTFIX: highlights no-freeze safe pagination ====================
# ШҘШөЩ„Ш§Шӯ ЩҒЩҮШҜ: Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ ЩғШ§ЩҶШӘ Щ…Щ…ЩғЩҶ ШӘШ№Щ„ЩӮ ШЁШіШЁШЁ Щ…ШіШ§ШұШ§ШӘ ЩӮШҜЩҠЩ…Ш© ШӘШ№ШұШ¶ ЩғЩ„ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ Щ…ШұШ© ЩҲШ§ШӯШҜШ©.
# ЩҮШ°Ш§ Ш§Щ„ЩҮЩҲШӘЩҒЩғШі ЩҠШ№ШІЩ„ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ ЩҒЩӮШ·: ШөЩҒШӯШ§ШӘ Ш®ЩҒЩҠЩҒШ© + ШЈШІШұШ§Шұ URL + ШЁШҜЩҲЩҶ ШұЩҲШ§ШЁШ· ШҜШ§Ш®Щ„ callback_data.

V61_HIGHLIGHTS_PAGE_SIZE = 8


def _v61_highlights_rows(stage_key=None, team=None):
    data = _load_highlights() if '_load_highlights' in globals() else {}
    rows = []
    for key, item in (data or {}).items():
        if not isinstance(item, dict) or not item.get('url'):
            continue
        t1 = item.get('team1') or ''
        t2 = item.get('team2') or ''
        url = item.get('url') or ''
        if team:
            q = simple_key(team)
            if q not in simple_key(t1) and q not in simple_key(t2):
                continue
        if stage_key and stage_key != 'all':
            stg = item.get('stage') or ''
            # ЩҒЩ„ШӘШұШ© ШЁШіЩҠШ·Ш© ЩҒЩӮШ·ШҢ ШЁШҜЩҲЩҶ Ш§Щ„ШЁШӯШ« Ш§Щ„Ш«ЩӮЩҠЩ„ ЩҒЩҠ ЩғЩ„ Ш¬ШҜЩҲЩ„ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ.
            sk = _v32_stage_key(stg) if '_v32_stage_key' in globals() else 'all'
            if sk == 'all':
                # ШЈШәЩ„ШЁ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШЁЩ„Ш§ stageШҢ ЩҶШ®Щ„ЩҠЩҮШ§ ШӘШёЩҮШұ ЩҒЩҠ ЩғШ§Щ…Щ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш© ЩҒЩӮШ· ЩҲЩ„Ш§ ЩҶШ«ЩӮЩ„ Ш§Щ„ШЁШӯШ«.
                if stage_key != 'all':
                    continue
            elif sk != stage_key:
                continue
        rows.append((key, item))
    return sorted(rows, key=lambda kv: str((kv[1] or {}).get('updated_at') or ''), reverse=True)


def _v61_highlights_home_keyboard():
    return InlineKeyboardMarkup([
        [InlineKeyboardButton('рҹҶ• ШўШ®Шұ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ', callback_data='v32|hls_last|0')],
        [InlineKeyboardButton('рҹҸҶ ЩғШ§Щ…Щ„ Ш§Щ„ШЁШ·ЩҲЩ„Ш©', callback_data='v32|hls_stage|all|0')],
        [InlineKeyboardButton('рҹ”Һ ШЁШӯШ« Ш№ЩҶ Щ…Щ„Ш®Шө', callback_data='v32|hls_search_help')],
        [InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№', callback_data='mainmenu|home')],
    ])


def _v61_paginated_highlights_keyboard(rows, callback_prefix, page=0):
    try:
        page = max(0, int(page or 0))
    except Exception:
        page = 0
    total = len(rows or [])
    start = page * V61_HIGHLIGHTS_PAGE_SIZE
    chunk = (rows or [])[start:start + V61_HIGHLIGHTS_PAGE_SIZE]
    kb = []
    if not chunk:
        kb.append([InlineKeyboardButton('Щ„Ш§ ШӘЩҲШ¬ШҜ Щ…Щ„Ш®ШөШ§ШӘ', callback_data='v32|hls_home')])
    for key, item in chunk:
        label = f"рҹҺҘ {item.get('team1','')} Г— {item.get('team2','')}".strip()
        url = item.get('url') or ''
        # ШІШұ URL Щ…ШЁШ§ШҙШұ: Щ…Ш§ ЩҶШӯШ· Ш§Щ„ШұШ§ШЁШ· ЩҒЩҠ callback_data ЩҶЩҮШ§ШҰЩҠЩӢШ§.
        if re.match(r'https?://', url, re.I):
            kb.append([InlineKeyboardButton(label[:60], url=url)])
        else:
            kb.append([InlineKeyboardButton(label[:60], callback_data=f'v32|hls_show|{key}')])
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton('в¬…пёҸ Ш§Щ„ШіШ§ШЁЩӮ', callback_data=f'{callback_prefix}|{page-1}'))
    if start + V61_HIGHLIGHTS_PAGE_SIZE < total:
        nav.append(InlineKeyboardButton('Ш§Щ„ШӘШ§Щ„ЩҠ вһЎпёҸ', callback_data=f'{callback_prefix}|{page+1}'))
    if nav:
        kb.append(nav)
    kb.append([InlineKeyboardButton('в¬…пёҸ ШұШ¬ЩҲШ№ Щ„Щ„Щ…Щ„Ш®ШөШ§ШӘ', callback_data='v32|hls_home')])
    return InlineKeyboardMarkup(kb)


def _v61_highlights_page_title(page, total, title='рҹҺ¬ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ'):
    pages = max(1, (total + V61_HIGHLIGHTS_PAGE_SIZE - 1) // V61_HIGHLIGHTS_PAGE_SIZE)
    return f"{title}\n\nШ§Щ„ШөЩҒШӯШ© {page + 1}/{pages} вҖ” Ш§Щ„Щ…Ш№ШұЩҲШ¶ {min(V61_HIGHLIGHTS_PAGE_SIZE, max(0, total - page*V61_HIGHLIGHTS_PAGE_SIZE))} Щ…ЩҶ {total}"


# ЩҶШіШӘШЁШҜЩ„ Ш§Щ„ШҜШ§Щ„Ш© Ш§Щ„ЩӮШҜЩҠЩ…Ш© ШӯШӘЩү ШЈЩҠ Щ…ШіШ§Шұ ЩӮШҜЩҠЩ… Щ…Ш§ ЩҠШұШіЩ„ ЩғЩ„ Ш§Щ„Щ…Щ„Ш®ШөШ§ШӘ Щ…ШұШ© ЩҲШ§ШӯШҜШ©.
def _highlights_keyboard(page=0):
    rows = _v61_highlights_rows()
    return _v61_paginated_highlights_keyboard(rows, 'v32|hls_last', page)


async def v32_highlights_command(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        _v32_track_user(update)
    except Exception:
        pass
    text = getattr(update.effective_message, 'text', '') or ''
    body = _v32_cmd_body(text) if '_v32_cmd_body' in globals() else re.sub(r'^/\S+', '', text).strip()
    if text.startswith('/ШЁШӯШ«') or body:
        if not body:
            await update.effective_message.reply_text('Ш§ЩғШӘШЁЩҮШ§ ЩғШ°Ш§:\n/ШЁШӯШ«_Щ…Щ„Ш®Шө Ш§Щ„ЩҠШ§ШЁШ§ЩҶ')
            return
        rows = _v61_highlights_rows(team=body)
        if not rows:
            await update.effective_message.reply_text(f'Щ…Ш§ Щ„ЩӮЩҠШӘ Щ…Щ„Ш®ШөШ§ШӘ Щ„ЩҖ: {body}')
            return
        await update.effective_message.reply_text(
            _v61_highlights_page_title(0, len(rows), f'рҹ”Һ ЩҶШӘШ§ШҰШ¬ Ш§Щ„ШЁШӯШ« Ш№ЩҶ: {body}'),
            reply_markup=_v61_paginated_highlights_keyboard(rows, f'v32|hls_search|{simple_key(body)}', 0)
        )
        return
    await update.effective_message.reply_text('рҹҺ¬ Щ…Щ„Ш®ШөШ§ШӘ Ш§Щ„Щ…ШЁШ§ШұЩҠШ§ШӘ', reply_markup=_v61_highlights_home_keyboard())


_V611_PREV_PUBLIC_REPLY_MENU_ROUTER = globals().get('public_reply_menu_router')
