        f'JobQueue: {"Щ…Ш¬ШҜЩҲЩ„ вң…" if globals().get("V64_GOAL_JOB_QUEUE_SCHEDULED") else "ШӯЩ„ЩӮШ© Ш§ШӯШӘЩҠШ§Ш·/ШәЩҠШұ Щ…Ш¬ШҜЩҲЩ„"}',
        f'ШӯЩ„ЩӮШ© Ш§Щ„Ш§ШӯШӘЩҠШ§Ш·: {"ШӘШ№Щ…Щ„ вң…" if (globals().get("V64_GOAL_ALERT_LOOP_TASK") and not globals().get("V64_GOAL_ALERT_LOOP_TASK").done()) else "Щ…ШӘЩҲЩӮЩҒШ©"}',
        f'ШЁШҜШЈШӘ Ш§Щ„Ш§ШӯШӘЩҠШ§Ш·: {globals().get("V64_GOAL_ALERT_LOOP_STARTED_AT") or "-"}',
